def get_db():
    """Get database connection (request-scoped, auto-closed at request end)."""
    if '_database' not in g:
        g._database = sqlite3.connect(config.DB_PATH)
        g._database.row_factory = sqlite3.Row
        g._database.execute("PRAGMA busy_timeout = 5000")
        g._database.execute("PRAGMA foreign_keys = ON")
        g._database.execute("PRAGMA journal_mode = WAL")
    return g._database

@app.teardown_appcontext
def close_db(exception):
    """Auto-close DB connection at end of every request."""
    db = g.pop('_database', None)
    if db is not None:
        db.close()

def get_db_direct():
    """Get a standalone DB connection for background threads (no request context).
    Caller MUST use: with closing(get_db_direct()) as conn: ..."""
    conn = sqlite3.connect(config.DB_PATH)
    conn.row_factory = sqlite3.Row
    conn.execute("PRAGMA busy_timeout = 5000")
    conn.execute("PRAGMA foreign_keys = ON")
    conn.execute("PRAGMA journal_mode = WAL")
    return conn

def hash_password(password):
    """Hash password with salt."""
    salt = secrets.token_hex(16)
    hash_obj = hashlib.pbkdf2_hmac('sha256', password.encode(), salt.encode(), 100000)
    return f"{salt}${hash_obj.hex()}"

def verify_password(password, stored_hash):
    """Verify password against stored hash.

    Hygiene-fix Part B clause 5: critical auth path. The previous
    bare-except silently returned False for ANY error, including
    programming bugs (e.g., a future change to the hash format).
    Now: ValueError/AttributeError on malformed stored_hash → False
    silently (expected case for legacy/corrupted records); other
    exceptions are logged and re-raised so they don't hide bugs.
    """
    try:
        salt, hash_value = stored_hash.split('$')
        hash_obj = hashlib.pbkdf2_hmac('sha256', password.encode(), salt.encode(), 100000)
        return hash_obj.hex() == hash_value
    except (ValueError, AttributeError):
        # Malformed stored_hash (no '$', None, etc.) — treat as auth failure.
        return False
    except Exception as _ve:
        print(f'[AUTH] verify_password unexpected error: {type(_ve).__name__}: {_ve}',
              flush=True)
        return False

def init_db():
    """Initialize database tables."""
    conn = get_db_direct()
