    cursor.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            email TEXT UNIQUE,
            password_hash TEXT NOT NULL,
            role TEXT DEFAULT 'user',
            is_active INTEGER DEFAULT 1,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            last_login TIMESTAMP
        )
    ''')
    
    # Add columns if they don't exist (for existing databases).
    # Hygiene-fix Part B clause 5: schema migration clarity. Each
    # ALTER TABLE will raise sqlite3.OperationalError ("duplicate
    # column name: ...") if the column already exists — that's the
    # expected idempotent case. Anything else (e.g., a typo'd column
    # name, a database lock, a permissions issue) should be logged
    # so operators can spot it instead of swallowed.
    def _add_col_if_missing(sql, col):
        try:
            cursor.execute(sql)
        except sqlite3.OperationalError as _oe:
            if 'duplicate column' not in str(_oe).lower():
                print(f'[SCHEMA-MIGRATION] non-duplicate ALTER failed col={col}: {_oe}',
                      flush=True)
        except Exception as _e:
            print(f'[SCHEMA-MIGRATION] unexpected ALTER error col={col}: {type(_e).__name__}: {_e}',
                  flush=True)

    _add_col_if_missing('ALTER TABLE users ADD COLUMN email TEXT UNIQUE', 'email')
    _add_col_if_missing('ALTER TABLE users ADD COLUMN ai_provider_generate TEXT DEFAULT "auto"', 'ai_provider_generate')
    _add_col_if_missing('ALTER TABLE users ADD COLUMN ai_provider_review TEXT DEFAULT "auto"', 'ai_provider_review')
    _add_col_if_missing('ALTER TABLE users ADD COLUMN role TEXT DEFAULT "user"', 'role')
    _add_col_if_missing('ALTER TABLE users ADD COLUMN is_active INTEGER DEFAULT 1', 'is_active')
    _add_col_if_missing('ALTER TABLE users ADD COLUMN last_login TIMESTAMP', 'last_login')
    
