def normalize_domain(raw: str) -> str:
    """Return canonical domain code for any domain input variant.

    Accepts English display names, Arabic display names, short codes,
    slug forms, and mixed-case variants. Falls back to 'cyber' if
    the input is unrecognised (preserves existing behaviour for callers
    that historically defaulted to Cyber Security).

    Examples:
        normalize_domain('Enterprise Risk Management') → 'erm'
        normalize_domain('enterprise_risk_management') → 'erm'
        normalize_domain('إدارة المخاطر المؤسسية')     → 'erm'
        normalize_domain('ERM')                        → 'erm'
    """
    if not raw:
        return "cyber"
    code = _DOMAIN_CODE_MAP.get(raw.strip())
    if code:
        return code
    code = _DOMAIN_CODE_MAP.get(raw.strip().lower())
    if code:
        return code
    # Last-resort: check if any key starts with the input (partial match)
    lower = raw.strip().lower()
    for key, val in _DOMAIN_CODE_MAP.items():
        if key.lower().startswith(lower) or lower.startswith(key.lower()):
            return val
    return "cyber"


def domain_display_name(raw: str, lang: str = "en") -> str:
    """Return the canonical display name for a domain.

    Examples:
        domain_display_name('erm')                    → 'Enterprise Risk Management'
        domain_display_name('erm', 'ar')              → 'إدارة المخاطر المؤسسية'
        domain_display_name('enterprise_risk_management') → 'Enterprise Risk Management'
    """
    code = normalize_domain(raw)
    if lang == "ar":
        return _DOMAIN_DISPLAY_AR.get(code, raw)
    return _DOMAIN_DISPLAY_EN.get(code, raw)


def domain_slug(raw: str) -> str:
    """Return a filename-safe ASCII slug for a domain.

    Examples:
        domain_slug('Enterprise Risk Management') → 'enterprise_risk_management'
        domain_slug('Cyber Security')             → 'cyber_security'
    """
    return domain_display_name(raw, "en").lower().replace(" ", "_")


def strategy_document_title(domain_raw: str, lang: str = "en") -> str:
    """Return the canonical strategy document title for a domain.

    Examples:
        strategy_document_title('Enterprise Risk Management')     → 'Enterprise Risk Management Strategy'
        strategy_document_title('erm', 'ar')                      → 'استراتيجية إدارة المخاطر المؤسسية'
        strategy_document_title('enterprise_risk_management')     → 'Enterprise Risk Management Strategy'
    """
    disp = domain_display_name(domain_raw, lang)
    if lang == "ar":
        return f"استراتيجية {disp}"
    return f"{disp} Strategy"


def strategy_filename_slug(domain_raw: str) -> str:
    """Return a stable download filename slug for a strategy document.

    Examples:
        strategy_filename_slug('Enterprise Risk Management') → 'enterprise_risk_management_strategy'
        strategy_filename_slug('Cyber Security')             → 'cyber_security_strategy'
    """
    return f"{domain_slug(domain_raw)}_strategy"

# ── END canonical domain registry ────────────────────────────────────────────

