@app.route('/profile')
@login_required
def profile_page():
    """User profile page."""
    lang = request.args.get('lang', session.get('lang', 'en'))
    session['lang'] = lang
    txt = get_text(lang)
    
    conn = get_db()
    user = conn.execute('SELECT * FROM users WHERE id = ?', (session['user_id'],)).fetchone()
    
    # Get per-domain usage stats
    domain_stats = {}
    en_domains = TRANSLATIONS['en']['domains']
    ar_domains = TRANSLATIONS['ar']['domains']
    # Build EN→AR mapping for looking up both languages
    domain_en_ar = dict(zip(en_domains, ar_domains))
    for domain in en_domains:
        ar_domain = domain_en_ar.get(domain, domain)
        s_count = conn.execute('SELECT COUNT(*) FROM strategies WHERE user_id = ? AND domain IN (?, ?)', (session['user_id'], domain, ar_domain)).fetchone()[0]
        p_count = conn.execute('SELECT COUNT(*) FROM policies WHERE user_id = ? AND domain IN (?, ?) AND COALESCE(is_procedure, 0) = 0', (session['user_id'], domain, ar_domain)).fetchone()[0]
        proc_count = conn.execute('SELECT COUNT(*) FROM policies WHERE user_id = ? AND domain IN (?, ?) AND is_procedure = 1', (session['user_id'], domain, ar_domain)).fetchone()[0]
        a_count = conn.execute('SELECT COUNT(*) FROM audits WHERE user_id = ? AND domain IN (?, ?)', (session['user_id'], domain, ar_domain)).fetchone()[0]
        r_count = conn.execute('SELECT COUNT(*) FROM risks WHERE user_id = ? AND domain IN (?, ?)', (session['user_id'], domain, ar_domain)).fetchone()[0]
        total = s_count + p_count + proc_count + a_count + r_count
        domain_stats[domain] = {
            'strategies': s_count, 'policies': p_count, 'procedures': proc_count,
            'audits': a_count, 'risks': r_count, 'total': total,
            'strategy_limit': 10, 'policy_limit': 10, 'procedure_limit': 10, 'audit_limit': 10, 'risk_limit': 10
        }
    
    total_docs = conn.execute('''
        SELECT 
            (SELECT COUNT(*) FROM strategies WHERE user_id = ?) +
            (SELECT COUNT(*) FROM policies WHERE user_id = ?) +
            (SELECT COUNT(*) FROM audits WHERE user_id = ?) +
            (SELECT COUNT(*) FROM risks WHERE user_id = ?)
    ''', (session['user_id'], session['user_id'], session['user_id'], session['user_id'])).fetchone()[0]
    
    # Get user's AI preferences
    ai_pref_generate = 'auto'
    ai_pref_review = 'auto'
    try:
        ai_pref_generate = user['ai_provider_generate'] or 'auto'
        ai_pref_review = user['ai_provider_review'] or 'auto'
    except:
        pass
    
    # Map backend → frontend provider values for dropdown selection
    backend_to_frontend = {
        'anthropic': 'claude', 'openai': 'gpt', 'google': 'gemini',
        'groq': 'groq', 'deepseek': 'deepseek', 'auto': 'auto',
        # Already frontend values (backward compat)
        'claude': 'claude', 'gpt': 'gpt', 'gemini': 'gemini',
    }
    ai_pref_generate_ui = backend_to_frontend.get(ai_pref_generate, 'claude')
    ai_pref_review_ui = backend_to_frontend.get(ai_pref_review, 'gpt')
    
    # ── Token quota data for progress bar ──
    token_usage = 0
    token_limit = 500000
    try:
        token_usage = user['token_usage'] or 0
        token_limit = user['token_limit'] or 500000
    except (KeyError, TypeError):
        pass
    
    # ── User Command Center data ──
    # Tasks
    user_tasks = conn.execute('''
        SELECT * FROM project_tasks WHERE user_id = ? ORDER BY created_at DESC LIMIT 50
    ''', (session['user_id'],)).fetchall()
    
    task_stats = {
        'total': len(user_tasks),
        'todo': sum(1 for t in user_tasks if t['status'] == 'todo'),
        'in_progress': sum(1 for t in user_tasks if t['status'] == 'in_progress'),
        'done': sum(1 for t in user_tasks if t['status'] == 'done'),
    }
    
    # Risk Register — include computed score for template
    user_risks = conn.execute('''
        SELECT *, name AS risk_name, (likelihood * impact) AS risk_score
        FROM risk_register WHERE user_id = ? ORDER BY (likelihood * impact) DESC, created_at DESC LIMIT 50
    ''', (session['user_id'],)).fetchall()
    
    # KPIs
    user_kpis = []
    try:
        user_kpis = conn.execute('''
            SELECT * FROM kpis WHERE user_id = ? ORDER BY created_at DESC LIMIT 50
        ''', (session['user_id'],)).fetchall()
    except Exception:
        pass  # Table may not exist yet
    
    # Audit logs (recent 50)
    user_audit = conn.execute('''
        SELECT * FROM audit_logs WHERE user_id = ? ORDER BY created_at DESC LIMIT 50
    ''', (session['user_id'],)).fetchall()
    
    
    return render_template('profile.html',
                          txt=txt, lang=lang, config=config,
                          is_rtl=(lang == 'ar'),
                          username=session.get('username'),
                          user=user,
                          domain_stats=domain_stats,
                          total_docs=total_docs,
                          ai_available=check_ai_available(),
                          ai_providers=get_available_providers(),
                          ai_pref_generate=ai_pref_generate_ui,
                          ai_pref_review=ai_pref_review_ui,
                          ai_prefs={'generate': ai_pref_generate_ui, 'review': ai_pref_review_ui},
                          domains=txt['domains'],
                          token_usage=token_usage,
                          token_limit=token_limit,
                          user_tasks=user_tasks,
                          task_stats=task_stats,
                          user_risks=user_risks,
                          user_kpis=user_kpis,
                          user_audit=user_audit,
                          strategies=conn.execute('SELECT id,domain,language,created_at FROM strategies WHERE user_id=? ORDER BY created_at DESC LIMIT 30',(session['user_id'],)).fetchall(),
                          policies=conn.execute('SELECT id,domain,policy_name,language,created_at FROM policies WHERE user_id=? ORDER BY created_at DESC LIMIT 30',(session['user_id'],)).fetchall(),
                          audits=conn.execute('SELECT id,domain,language,created_at FROM audits WHERE user_id=? ORDER BY created_at DESC LIMIT 30',(session['user_id'],)).fetchall(),
                          risks=conn.execute('SELECT id,domain,threat,language,created_at FROM risks WHERE user_id=? ORDER BY created_at DESC LIMIT 30',(session['user_id'],)).fetchall())

@app.route('/profile/change-password', methods=['POST'])
@login_required
def change_password():
    """Change user password."""
    lang = session.get('lang', 'en')
    txt = get_text(lang)
    
    current_password = request.form.get('current_password', '')
    new_password = request.form.get('new_password', '')
    confirm_password = request.form.get('confirm_password', '')
    
    if new_password != confirm_password:
        flash(txt['password_mismatch'], 'error')
        return redirect(url_for('profile_page', lang=lang))
    
    valid, msg = validate_password(new_password)
    if not valid:
        flash(msg, 'error')
        return redirect(url_for('profile_page', lang=lang))
    
    conn = get_db()
    user = conn.execute('SELECT * FROM users WHERE id = ?', (session['user_id'],)).fetchone()
    
    if not verify_password(current_password, user['password_hash']):
        flash(txt['wrong_password'], 'error')
        return redirect(url_for('profile_page', lang=lang))
    
    conn.execute('UPDATE users SET password_hash = ? WHERE id = ?',
                (hash_password(new_password), session['user_id']))
    conn.commit()
    
    flash(txt['password_updated'], 'success')
    return redirect(url_for('profile_page', lang=lang))

