@app.route('/api/export-all', methods=['GET'])
@login_required
def export_all_documents():
    """Export all user documents as a ZIP file.

    Only includes artifacts in publishable or final state — draft and reviewed
    artifacts are excluded to enforce the same gate as individual exports.
    """
    import zipfile
    from io import BytesIO

    lang = session.get('lang', 'en')
    user_id = session['user_id']
    username = session.get('username', 'user')

    conn = get_db()

    buffer = BytesIO()
    _EXPORTABLE = ('publishable', 'final')

    with zipfile.ZipFile(buffer, 'w', zipfile.ZIP_DEFLATED) as zf:
        doc_count = 0

        # Export strategies — publishable/final only
        strategies = conn.execute(
            "SELECT * FROM strategies WHERE user_id=? AND artifact_status IN ('publishable','final') ORDER BY created_at DESC",
            (user_id,)
        ).fetchall()
        for s in strategies:
            fname = f"strategies/{s['domain']}_{s['language']}_{s['id']}.md"
            zf.writestr(fname, s['content'] or '')
            doc_count += 1

        # Export policies — publishable/final only
        policies = conn.execute(
            "SELECT * FROM policies WHERE user_id=? AND artifact_status IN ('publishable','final') ORDER BY created_at DESC",
            (user_id,)
        ).fetchall()
        for p in policies:
            fname = f"policies/{p['domain']}_{p['policy_name']}_{p['language']}_{p['id']}.md"
            zf.writestr(fname, p['content'] or '')
            doc_count += 1

        # Export audits — publishable/final only
        audits = conn.execute(
            "SELECT * FROM audits WHERE user_id=? AND artifact_status IN ('publishable','final') ORDER BY created_at DESC",
            (user_id,)
        ).fetchall()
        for a in audits:
            fname = f"audits/{a['domain']}_{a['language']}_{a['id']}.md"
            zf.writestr(fname, a['content'] or '')
            doc_count += 1

        # Export risks — publishable/final only
        risks = conn.execute(
            "SELECT * FROM risks WHERE user_id=? AND artifact_status IN ('publishable','final') ORDER BY created_at DESC",
            (user_id,)
        ).fetchall()
        for r in risks:
            fname = f"risk_analyses/{r['domain']}_{r['language']}_{r['id']}.md"
            zf.writestr(fname, r['analysis'] or '')
            doc_count += 1

        # Add summary
        summary = (
            f"# Mizan GRC — Document Export\n"
            f"**User:** {username}\n"
            f"**Date:** {datetime.now().strftime('%Y-%m-%d %H:%M')}\n"
            f"**Total Documents:** {doc_count}\n\n"
            f"Only publishable/final artifacts are included.\n\n"
            f"- Strategies: {len(strategies)}\n"
            f"- Policies: {len(policies)}\n"
            f"- Audits: {len(audits)}\n"
            f"- Risk Analyses: {len(risks)}\n"
        )
        zf.writestr('README.md', summary)

    if doc_count == 0:
        return jsonify({
            'error': ('No publishable or final documents to export. '
                      'Run Quality Review and promote artifacts to Publishable state first.')
        }), 404

    buffer.seek(0)
    from flask import send_file
    return send_file(
        buffer, mimetype='application/zip',
        as_attachment=True,
        download_name=f'mizan_documents_{username}_{datetime.now().strftime("%Y%m%d")}.zip'
    )

