@app.route('/history')
@login_required
def document_history():
    """Document history page - view all generated documents."""
    lang = request.args.get('lang', session.get('lang', 'en'))
    session['lang'] = lang
    txt = get_text(lang)
    
    user_id = session['user_id']
    conn = get_db()
    
    # Get all documents for this user
    strategies = conn.execute('''
        SELECT id, domain, org_name, sector, language, created_at,
               document_title, 'strategy' as doc_type,
               artifact_status, publishability_score
        FROM strategies WHERE user_id = ? ORDER BY created_at DESC
    ''', (user_id,)).fetchall()
    
    policies = conn.execute('''
        SELECT id, domain, policy_name, framework, language, created_at, 'policy' as doc_type,
               artifact_status, publishability_score, 0 as is_procedure
        FROM policies WHERE user_id = ? AND COALESCE(is_procedure,0)=0 ORDER BY created_at DESC
    ''', (user_id,)).fetchall()

    procedures = conn.execute('''
        SELECT id, domain, policy_name, framework, language, created_at, 'procedure' as doc_type,
               artifact_status, publishability_score, 1 as is_procedure
        FROM policies WHERE user_id = ? AND is_procedure=1 ORDER BY created_at DESC
    ''', (user_id,)).fetchall()

    audits = conn.execute('''
        SELECT id, domain, framework, scope, language, created_at, 'audit' as doc_type,
               artifact_status, publishability_score
        FROM audits WHERE user_id = ? ORDER BY created_at DESC
    ''', (user_id,)).fetchall()

    risks = conn.execute('''
        SELECT id, domain, asset_name, threat, risk_level, created_at, 'risk' as doc_type,
               artifact_status, publishability_score
        FROM risks WHERE user_id = ? ORDER BY created_at DESC
    ''', (user_id,)).fetchall()
    
    
    # Combine and sort all documents
    all_documents = []
    
    for s in strategies:
        all_documents.append({
            'id': s['id'],
            'type': 'strategy',
            'type_label': txt.get('strategies', 'Strategy'),
            'domain': s['domain'],
            'title': (s['document_title']
                      if s['document_title']
                      else strategy_document_title(s['domain'] or '', s['language'] or 'en')),
            'subtitle': s['sector'] or '',
            'language': s['language'],
            'created_at': s['created_at'],
            'artifact_status': s['artifact_status'] if 'artifact_status' in s.keys() else 'draft',
            'publishability_score': s['publishability_score'] if 'publishability_score' in s.keys() else None,
        })
    
    def _safe_status(row):
        keys = row.keys() if hasattr(row, 'keys') else []
        return {
            'artifact_status': row['artifact_status'] if 'artifact_status' in keys else 'draft',
            'publishability_score': row['publishability_score'] if 'publishability_score' in keys else None,
        }

    for p in policies:
        all_documents.append({
            'id': p['id'],
            'type': 'policy',
            'type_label': txt.get('policies', 'Policy'),
            'domain': p['domain'],
            'title': p['policy_name'] or 'Policy',
            'subtitle': p['framework'] or '',
            'language': p['language'],
            'created_at': p['created_at'],
            **_safe_status(p)
        })

    for pr in procedures:
        all_documents.append({
            'id': pr['id'],
            'type': 'procedure',
            'type_label': txt.get('procedures', 'Procedure'),
            'domain': pr['domain'],
            'title': pr['policy_name'] or 'Procedure',
            'subtitle': pr['framework'] or '',
            'language': pr['language'],
            'created_at': pr['created_at'],
            **_safe_status(pr)
        })

    for a in audits:
        all_documents.append({
            'id': a['id'],
            'type': 'audit',
            'type_label': txt.get('audits', 'Audit'),
            'domain': a['domain'],
            'title': a['framework'] or 'Audit Report',
            'subtitle': a['scope'] or '',
            'language': a['language'],
            'created_at': a['created_at'],
            **_safe_status(a)
        })
    
    for r in risks:
        all_documents.append({
            'id': r['id'],
            'type': 'risk',
            'type_label': txt.get('risks', 'Risk Analysis'),
            'domain': r['domain'],
            'title': r['asset_name'] or 'Risk Analysis',
            'subtitle': r['risk_level'] or '',
            'language': r['language'] if 'language' in r.keys() else 'en',
            'created_at': r['created_at'],
            **_safe_status(r)
        })
    
    # Sort by date descending
    all_documents.sort(key=lambda x: x['created_at'] or '', reverse=True)
    
    # Get unique domains for filter
    domains = list(set([d['domain'] for d in all_documents if d['domain']]))
    
    # Get audit logs for timeline
    audit_logs = conn.execute('''
        SELECT * FROM audit_logs WHERE user_id = ? ORDER BY created_at DESC LIMIT 100
    ''', (session['user_id'],)).fetchall()
    
    # Count actions by type for summary stats
    action_counts = {}
    for log in audit_logs:
        act = log['action'] or ''
        base_act = act.split('_')[0] if '_' in act else act
        action_counts[base_act] = action_counts.get(base_act, 0) + 1

    return render_template('history.html',
                          txt=txt,
                          lang=lang,
                          is_rtl=(lang == 'ar'),
                          username=session.get('username'),
                          documents=all_documents,
                          domains=domains,
                          total_count=len(all_documents),
                          audit_logs=audit_logs,
                          action_counts=action_counts)

