def ensure_gap_guide_coverage(sections, lang, domain, fw_short):
    """Synthesize per-gap Implementation Guides for every gap row that lacks one.
    Idempotent: only adds guides for indices that don't already have them.
    Generates type-specific 6-step guides based on gap keywords (governance,
    data protection, awareness, policy, monitoring, risk, IAM, continuity,
    technical, or generic fallback).
    """
    gaps = sections.get('gaps', '') or ''
    rows = _ts_extract_gap_rows(gaps)
    if not rows:
        return
    existing = set()
    for m in _ts_re.finditer(
        r'####\s*(?:Gap\s*#?(\d+)\s*Implementation Guide|دليل تنفيذ الفجوة\s*(?:رقم|#)?\s*(\d+))',
        gaps, _ts_re.IGNORECASE,
    ):
        idx = m.group(1) or m.group(2)
        if idx:
            existing.add(idx)
    is_ar = (lang == 'ar')
    guides_hdr_re = _ts_re.compile(
        r'###\s*(?:Gap Implementation Guidance|أدلة تنفيذ الفجوات)',
        _ts_re.IGNORECASE,
    )
    has_guides_hdr = bool(guides_hdr_re.search(gaps))
    new_guides = []
    if not has_guides_hdr:
        new_guides.append('\n\n### أدلة تنفيذ الفجوات'
                          if is_ar else '\n\n### Gap Implementation Guidance')
        new_guides.append('')
    for idx, name, desc, pri in rows:
        if idx in existing:
            continue
        gap_type = _gap_type(name, desc, is_ar)
        if is_ar:
            steps = _gap_guide_steps_ar(gap_type, domain, fw_short, name)
            # Priority label for the header badge
            pri_label = {'حرج': '🔴 حرجة', 'عالي': '🟠 عالية', 'عالية': '🟠 عالية',
                         'متوسط': '🟡 متوسطة', 'منخفض': '🟢 منخفضة'}.get(
                pri.strip() if pri else '', f'الأولوية: {pri}' if pri else '')
            new_guides.extend([
                f'#### دليل تنفيذ الفجوة رقم {idx}: {name}',
                '',
                f'**السياق:** {desc}' if desc and desc != '—' else '',
                f'**الأولوية:** {pri_label}' if pri_label else '',
                '',
                '| الخطوة | الإجراء | المسؤول | الجدول الزمني | الناتج |',
                '|--------|---------|---------|----------------|--------|',
            ] + steps + [''])
        else:
            steps = _gap_guide_steps_en(gap_type, domain, fw_short, name)
            pri_label = {'critical': '🔴 Critical', 'high': '🟠 High',
                         'medium': '🟡 Medium', 'low': '🟢 Low'}.get(
                (pri or '').strip().lower(), f'Priority: {pri}' if pri else '')
            new_guides.extend([
                f'#### Gap #{idx} Implementation Guide: {name}',
                '',
                f'**Context:** {desc}' if desc and desc != '—' else '',
                f'**Priority:** {pri_label}' if pri_label else '',
                '',
                '| Step | Action | Owner | Timeline | Output |',
                '|------|--------|-------|----------|--------|',
            ] + steps + [''])
    if len(new_guides) > 2 or (new_guides and has_guides_hdr):
        sections['gaps'] = gaps.rstrip() + '\n' + '\n'.join(new_guides)

def dedupe_confidence_section(sections, lang):
    """Collapse duplicate Confidence Score / Score Justification blocks into
    exactly one of each. Preserves Critical Success Factors and Key Risks
    sub-sections at the end. Idempotent.
    """
    conf = sections.get('confidence', '') or ''
    if not conf.strip():
        return
    # Strip duplicate '## 7. Confidence Assessment & Risks' headings (keep first).
    head_re = _ts_re.compile(
        r'^##\s*7\.\s*(?:Confidence Assessment\s*&\s*Risks|تقييم الثقة والمخاطر)\s*$',
        _ts_re.MULTILINE | _ts_re.IGNORECASE,
    )
    matches = list(head_re.finditer(conf))
    if len(matches) > 1:
        # Keep the first heading; remove subsequent ones
        new_parts = [conf[:matches[0].end()]]
        last = matches[0].end()
        for m in matches[1:]:
            new_parts.append(conf[last:m.start()])
            last = m.end()
        new_parts.append(conf[last:])
        conf = ''.join(new_parts)
    # Strip duplicate '**Confidence Score:** N%' lines (keep first).
    score_re = _ts_re.compile(
        r'^\*\*(?:Confidence Score|درجة الثقة)\s*:?\s*\*\*\s*:?\s*\d+\s*%[^\n]*\n?',
        _ts_re.MULTILINE | _ts_re.IGNORECASE,
    )
    score_hits = list(score_re.finditer(conf))
    if len(score_hits) > 1:
        # Keep first, remove all others
        kept = score_hits[0].group(0)
        # Replace all → empty, then re-insert kept at first position
        first_pos = score_hits[0].start()
        # Remove all subsequent occurrences
        new_parts = [conf[:score_hits[0].end()]]
        last = score_hits[0].end()
        for h in score_hits[1:]:
            new_parts.append(conf[last:h.start()])
            last = h.end()
        new_parts.append(conf[last:])
        conf = ''.join(new_parts)
    # Strip duplicate '**Score Justification:**' label + paragraph (keep first).
    # Pattern: label line + greedy text up to next blank line or section header.
    just_re = _ts_re.compile(
        r'(?:^|\n)\*\*(?:Score Justification|مبررات التقييم)\s*:?\s*\*\*[\s\S]*?'
        r'(?=\n\s*\n|\n#{1,4}\s|\Z)',
        _ts_re.IGNORECASE,
    )
    just_hits = list(just_re.finditer(conf))
    if len(just_hits) > 1:
        new_parts = [conf[:just_hits[0].end()]]
        last = just_hits[0].end()
        for h in just_hits[1:]:
            new_parts.append(conf[last:h.start()])
            last = h.end()
        new_parts.append(conf[last:])
        conf = ''.join(new_parts)
    # Collapse 3+ consecutive blank lines
    conf = _ts_re.sub(r'\n{3,}', '\n\n', conf)
    sections['confidence'] = conf

def _validate_board_schema(sections):
    """Board-specific validation that detects schema contamination caused by
    repair prompts appending content to the wrong section.

    Returns a list of (defect_tag, detail) tuples. An empty list means
    the board output is schema-clean.

    Defects detected:
      - board_gap_summary_empty: heading present but no populated rows
      - board_strategic_options_contaminated: Strategic Options section
        contains a Step/Action/Tool/System/Owner/Output header (from gap
        implementation guides) or a KPI table header
      - board_cockpit_under_kpi_header: Performance Dashboard rows appear
        inside a KPI-table scope (between KPI header and next heading)
      - board_raci_under_kpi_header: RACI rows appear inside a KPI scope
    """
    defects = []
    gaps_text = sections.get('gaps', '') or ''
    kpis_text = sections.get('kpis', '') or ''

    # Detect: Board-Level Gap Summary heading with no populated rows.
    # Heading pattern: '### Board-Level Gap Summary' / 'ملخص فجوات مجلس'
    bgs_re = _ts_re.compile(
        r'###\s*(?:Board-Level Gap Summary|ملخص فجوات مجلس(?:\s+الإدارة)?)\s*:?',
        _ts_re.IGNORECASE,
    )
    m_bgs = bgs_re.search(gaps_text)
    if m_bgs:
        # Slice content from the heading to the next '##' or '###' that
        # isn't the heading itself, or EOF.
        after = gaps_text[m_bgs.end():]
        m_next = _ts_re.search(r'\n#{2,4}\s+', after)
        block = after[:m_next.start()] if m_next else after
        # Must contain at least one data row (pipe row with digit in col 1)
        has_rows = bool(_ts_re.search(
            r'^\|\s*\d+\s*\|', block, _ts_re.MULTILINE))
        if not has_rows:
            defects.append(('board_gap_summary_empty',
                            f'heading found but no populated rows'))

    # Detect: Strategic Options section contaminated with KPI/Step headers.
    opts_re = _ts_re.compile(
        r'###\s*(?:Strategic Options for the Board|الخيارات الاستراتيجية)\s*:?',
        _ts_re.IGNORECASE,
    )
    m_opts = opts_re.search(gaps_text)
    if m_opts:
        after = gaps_text[m_opts.end():]
        m_next = _ts_re.search(r'\n#{2,4}\s+', after)
        block = after[:m_next.start()] if m_next else after
        # Contamination: block contains a Step|Action|Tool|Owner|Output
        # header (from a gap-implementation-guide table) or a KPI main header
        contam_step = bool(_ts_re.search(
            r'^\|\s*(?:Step|Action|Tool\s*/\s*System|Owner|Output)\s*\|',
            block, _ts_re.MULTILINE | _ts_re.IGNORECASE))
        contam_kpi = bool(_ts_re.search(
            r'^\|\s*#\s*\|\s*(?:KPI Description|وصف المؤشر|KPI)\s*\|',
            block, _ts_re.MULTILINE | _ts_re.IGNORECASE))
        if contam_step or contam_kpi:
            defects.append(('board_strategic_options_contaminated',
                            f'step_header={contam_step} kpi_header={contam_kpi}'))

    # Detect: Performance Dashboard / RACI rendering under KPI-table scope.
    # If a KPI main header appears in kpis_text, the Dashboard and RACI
    # headings MUST appear AFTER the KPI block ends (i.e. there must be a
    # blank line or non-pipe line between the last KPI row and the
    # Dashboard/RACI heading). If they appear without a proper break, that
    # is a schema violation.
    kpi_hdr_re = _ts_re.compile(
        r'^\|\s*#\s*\|\s*(?:KPI Description|وصف المؤشر|KPI)\s*\|[^\n]*$',
        _ts_re.MULTILINE | _ts_re.IGNORECASE,
    )
    m_kpi = kpi_hdr_re.search(kpis_text)
    if m_kpi:
        # Start scanning from the line AFTER the KPI header (skip the
        # separator line too — that's always pipe content, not a break).
        lines_after_hdr = kpis_text[m_kpi.end():].split('\n')
        # Drop leading empty first element (split artifact after `$` match)
        if lines_after_hdr and not lines_after_hdr[0].strip():
            lines_after_hdr = lines_after_hdr[1:]
        # Scan forward. If we encounter a Dashboard or RACI heading BEFORE
        # hitting an empty line, flag as contamination.
        saw_break = False
        for ln in lines_after_hdr:
            s = ln.strip()
            if not s:
                saw_break = True
                continue
            if s.startswith('|'):
                # Still inside a pipe-table region — stay inside KPI scope
                # unless we saw a break first.
                if saw_break:
                    break
                continue
            # Non-pipe, non-blank line — check for board heading
            if _ts_re.match(
                r'###\s*(?:Board Performance Dashboard|لوحة أداء المجلس)\b',
                s, _ts_re.IGNORECASE,
            ):
                if not saw_break:
                    defects.append(('board_cockpit_under_kpi_header',
                                    'dashboard heading appears without scope break'))
                break
            if _ts_re.match(
                r'###\s*(?:Board Accountability\s*\(RACI\)|المسؤولية\s*\(راسي\))',
                s, _ts_re.IGNORECASE,
            ):
                if not saw_break:
                    defects.append(('board_raci_under_kpi_header',
                                    'RACI heading appears without scope break'))
                break
            # Any other non-pipe content — scope-break inferred
            saw_break = True
    return defects


def _validate_arabic_section_contamination(sections, lang):
    """Detect content-in-wrong-canonical-section contamination for Arabic
    (and English — it's language-agnostic, run for both).

    Returns a list of (defect_tag, detail) tuples. Empty list = clean.

    Checks:
      - environment must NOT contain Gap Implementation Guides or a Gap table
      - roadmap must NOT contain KPI Assessment Guides or a KPI main table
      - kpis must NOT contain Phase/Quarter headings (roadmap content)
      - confidence must NOT be empty and must NOT contain other section markers
      - gaps must NOT contain Confidence Score block
      - vision must NOT contain KPI/Gap tables (SO only)
    Pass-8 prompt requirement #3 of Defect 2.
    """
    defects = []
    env      = sections.get('environment', '') or ''
    roadmap  = sections.get('roadmap', '') or ''
    kpis     = sections.get('kpis', '') or ''
    conf     = sections.get('confidence', '') or ''
    gaps     = sections.get('gaps', '') or ''
    vision   = sections.get('vision', '') or ''

    gap_guide_re = _ts_re.compile(
        r'####\s*(?:Gap\s*#?\d+\s*Implementation Guide'
        r'|دليل\s+(?:تنفيذ|معالجة)\s+الفجوة\s*(?:رقم|#)?\s*\d+)',
        _ts_re.IGNORECASE,
    )
    gap_table_hdr_re = _ts_re.compile(
        r'^\|\s*#\s*\|\s*(?:Gap|الفجوة|الفجوات)\s*\|',
        _ts_re.MULTILINE | _ts_re.IGNORECASE,
    )
    kpi_guide_re = _ts_re.compile(
        r'####\s*(?:KPI\s*#?\d+\s*Assessment Guide'
        r'|دليل تقييم المؤشر\s*(?:رقم|#)?\s*\d+)',
        _ts_re.IGNORECASE,
    )
    kpi_table_hdr_re = _ts_re.compile(
        r'^\|\s*#\s*\|\s*(?:KPI Description|وصف المؤشر|KPI)\s*\|',
        _ts_re.MULTILINE | _ts_re.IGNORECASE,
    )
    phase_heading_re = _ts_re.compile(
        r'^#{2,4}\s*(?:Phase\s*\d|Quarter\s*\d|المرحلة\s*\d|الربع\s*\d)',
        _ts_re.MULTILINE | _ts_re.IGNORECASE,
    )
    conf_score_re = _ts_re.compile(
        r'\*\*(?:Confidence Score|درجة الثقة)\s*:?\s*\*\*\s*:?\s*\d+\s*%',
        _ts_re.IGNORECASE,
    )

    # environment ← gap guides / gap table
    if gap_guide_re.search(env):
        defects.append(('environment_contains_gap_guides',
                        'Gap Implementation Guide heading found in environment section'))
    if gap_table_hdr_re.search(env):
        defects.append(('environment_contains_gap_table',
                        'Gap table header found in environment section'))
    # environment ← KPI guides / KPI table (PASS-10 prompt clause B)
    if kpi_guide_re.search(env):
        defects.append(('environment_contains_kpi_guides',
                        'KPI Assessment Guide heading found in environment section'))
    if kpi_table_hdr_re.search(env):
        defects.append(('environment_contains_kpi_table',
                        'KPI main table header found in environment section'))

    # roadmap ← KPI guides / KPI table
    if kpi_guide_re.search(roadmap):
        defects.append(('roadmap_contains_kpi_guides',
                        'KPI Assessment Guide heading found in roadmap section'))
    if kpi_table_hdr_re.search(roadmap):
        defects.append(('roadmap_contains_kpi_table',
                        'KPI main table header found in roadmap section'))

    # kpis ← phase headings (roadmap content)
    if phase_heading_re.search(kpis):
        defects.append(('kpis_contains_roadmap_phases',
                        'Phase/Quarter heading found in kpis section'))

    # confidence must not be empty
    if not conf.strip():
        defects.append(('confidence_empty',
                        'Confidence section is empty'))
    else:
        # confidence should contain its own canonical content; if it
        # contains Gap/KPI tables, that's contamination.
        if gap_table_hdr_re.search(conf) or kpi_table_hdr_re.search(conf):
            defects.append(('confidence_contaminated',
                            'Gap or KPI table leaked into confidence section'))

    # gaps ← confidence score block
    if conf_score_re.search(gaps):
        defects.append(('gaps_contains_confidence',
                        'Confidence Score block leaked into gaps section'))

    # vision ← KPI or Gap tables (SO section should only contain SO table)
    if kpi_table_hdr_re.search(vision):
        defects.append(('vision_contains_kpi_table',
                        'KPI main table leaked into vision section'))
    if gap_table_hdr_re.search(vision):
        defects.append(('vision_contains_gap_table',
                        'Gap table leaked into vision section'))

    # pillars ← KPI or Gap tables (Pillars should narratively describe the 3-4
    # strategic pillars; tables here indicate AI section-misordering)
    pillars = sections.get('pillars', '') or ''
    if kpi_table_hdr_re.search(pillars):
        defects.append(('pillars_contains_kpi_table',
                        'KPI main table leaked into pillars section'))
    if gap_table_hdr_re.search(pillars):
        defects.append(('pillars_contains_gap_table',
                        'Gap table leaked into pillars section'))

    return defects


def _validate_technical_table_completeness(sections, lang):
    """Detect single-row degradation in the three mandatory technical tables.

    Acceptance minima — UNIFIED with the canonical _RICHNESS_MIN_*
    constants so completeness checks, richness gates, and rebuild
    helpers cannot diverge (root cause of the serial-blocker pattern).

    Reuses count_valid_objective_rows / count_substantive_kpis /
    count_substantive_gaps — no duplicated counting logic.
    """
    defects = []
    n_so = count_valid_objective_rows(sections.get('vision', '') or '')
    if n_so < _RICHNESS_MIN_SO_ROWS:
        defects.append(('so_rows_insufficient',
                        f'{n_so}/{_RICHNESS_MIN_SO_ROWS}'))
    n_kpi = count_substantive_kpis(sections.get('kpis', '') or '')
    if n_kpi < _RICHNESS_MIN_KPI_ROWS:
        defects.append(('kpi_rows_insufficient',
                        f'{n_kpi}/{_RICHNESS_MIN_KPI_ROWS}'))
    n_gap = count_substantive_gaps(sections.get('gaps', '') or '')
    if n_gap < _RICHNESS_MIN_GAP_ROWS:
        defects.append(('gap_rows_insufficient',
                        f'{n_gap}/{_RICHNESS_MIN_GAP_ROWS}'))
    return defects


# ────────────────────────────────────────────────────────────────────────────
# TECHNICAL STRATEGY SEMANTIC RICHNESS VALIDATORS
#
# Upgrade from "structural presence" to "consultancy-grade semantic contract".
# These validators run on the FINAL canonical payload (post repair, resection,
# dedupe, residue cleanup, family collapse, placeholder enrichment) and detect
# thin/shallow sections that pass every structural gate but still fall below
# the Big4 Technical Strategy bar. A failure here is a HARD BLOCKER — no
# save-with-warning path applies.
#
# Richness contract (per prompt clause A):
#   Vision / Strategic Objectives:  ≥ 4 valid SO rows
#   Strategic Pillars:              ≥ 3 pillars, each with substantive body
#   Environment / Threat Context:   ≥ 2 narrative paragraphs (≥ 80 chars each)
#                                   AND either a structured table OR ≥ 3
#                                   substantive bullet lines
#   Gap Analysis:                   ≥ 2 gap rows
#   Roadmap:                        ≥ 4 substantive roadmap activity rows
#                                   across any schema
#   KPIs:                           ≥ 4 substantive KPI rows + 1:1 guide
#                                   coverage
#   Confidence & Risks:             ≥ 4 CSF rows + ≥ 4 Key-Risk rows, each
#                                   risk row having a non-placeholder
#                                   mitigation cell
# ────────────────────────────────────────────────────────────────────────────

_RICHNESS_MIN_SO_ROWS        = 4
_RICHNESS_MIN_PILLARS        = 3
_RICHNESS_MIN_ENV_PARAS      = 2
_RICHNESS_MIN_ENV_PARA_CHARS = 80
_RICHNESS_MIN_ENV_BULLETS    = 3
_RICHNESS_MIN_GAP_ROWS       = 2
_RICHNESS_MIN_ROADMAP_ROWS   = 4
_RICHNESS_MIN_KPI_ROWS       = 4
_RICHNESS_MIN_CSF_ROWS       = 4
_RICHNESS_MIN_RISK_ROWS      = 4


def _count_substantive_paragraphs(text, min_chars=_RICHNESS_MIN_ENV_PARA_CHARS):
    """Count narrative paragraphs in `text` of at least `min_chars` real
    characters. Excludes: headings, markdown tables, bullet/numbered lists,
    blockquotes (draft banners), and HTML comments. Paragraph boundary =
    blank line.
    """
    if not text:
        return 0
    blocks = _ts_re.split(r'\n\s*\n', text)
    n = 0
    for blk in blocks:
        raw = (blk or '').strip()
        if not raw:
            continue
        if raw.startswith('#'):
            continue
        if raw.lstrip().startswith('>'):
            continue
        # Skip if the block is a table
        if any(ln.strip().startswith('|') for ln in raw.splitlines()):
            continue
        # Skip if block is predominantly a bullet/numbered list
        non_blank = [ln.strip() for ln in raw.splitlines() if ln.strip()]
        if non_blank and all(
            _ts_re.match(r'^(?:[-*\u2022]\s|\d+[.)]\s)', ln)
            for ln in non_blank
        ):
            continue
        # Strip formatting for length measurement
        stripped = _ts_re.sub(r'[*_`#>|\-]+', '', raw)
        stripped = _ts_re.sub(r'\s+', ' ', stripped).strip()
        if len(stripped) >= min_chars:
            n += 1
    return n


# ────────────────────────────────────────────────────────────────────────────
# CANONICAL DIAGNOSTIC MODEL
#
# Per prompt Part 1: a single authoritative diagnostic model object carried
# through the entire strategy-generation pipeline. Every synthesizer,
# validator, and gate that needs user-specific grounding pulls from this
# model instead of accessing `data` directly or falling back to domain
# templates. This prevents "different sections use different partial
# subsets" — the failure mode the prompt explicitly calls out.
#
# The model is built once from the request payload + the diagnostic
# pre-pass outputs, then threaded through _apply_final_synthesis_pass
# and every downstream validator via ctx.
# ────────────────────────────────────────────────────────────────────────────

def build_diagnostic_model(data, lang='en', diagnostic_gaps=None,
                           derived_risks=None, derived_objectives=None,
                           answered_questions=None,
                           benchmark_context=None,
                           traceability_context=None):
    """Build a single authoritative diagnostic model from the full user
    payload + diagnostic pre-pass outputs. Returns a dict with canonical
    keys — no partial subsets.

    Normalizes values so downstream code can rely on:
      - org_structure_is_none (bool) — True when user selected "none",
        "not defined", "no structure", empty string, or the Arabic
        equivalents. Drives the "structural-gap must appear" contract.
      - maturity_lc (str) — lowercase canonical maturity token
        (initial|developing|defined|managed|optimized)
      - frameworks_list (list[str]) — normalized list of framework codes
      - technologies_list (list[str]) — normalized list of tech stacks
      - additional_tech (list[str]) — user-typed extra technologies (the
        domain form captures this as a separate free-text field beyond
        the technologies select)
      - answered_questions (dict) — raw diagnostic questionnaire payload
        keyed by question id; passed through verbatim for prompt/LLM
        grounding
      - benchmark_context (dict|None) — per-prompt Part 1 item; any
        benchmark data the pipeline has for this domain/sector/size
      - traceability_context (dict|None) — per-prompt Part 1 item;
        placeholder for row-level traceability maps built elsewhere
      - challenge_flags (dict[str,bool]) — including continuity and
        monitoring alongside awareness/IR/staffing/suppliers/compliance
      - tech_coverage (dict[str,bool]) — signals which tech categories
        the user DOES have (siem/soar/edr/iam/dlp/monitoring); inverse
        drives "technologies missing in key areas → pillar/roadmap
        reflects it" contract
      - challenges_text (str) — free-text challenges as a single string
      - diagnostic_gaps (list[dict]) — pre-pass derived gaps
      - derived_risks / derived_objectives — pre-pass derived lists
    """
    # Raw fetches with safe defaults
    org_name = (data.get('org_name') or '').strip() or (
        'المنظمة' if lang == 'ar' else 'The Organization')
    sector = (data.get('sector') or '').strip() or (
        'حكومي' if lang == 'ar' else 'Government')
    size = (data.get('size') or '').strip() or (
        'متوسطة' if lang == 'ar' else 'Medium')
    budget = (data.get('budget') or '').strip() or (
        'غير محدد' if lang == 'ar' else 'Not specified')
    frameworks = data.get('frameworks') or []
    if isinstance(frameworks, str):
        frameworks = [f.strip() for f in frameworks.split(',') if f.strip()]
    org_structure_raw = (data.get('org_structure') or '').strip()
    technologies = data.get('technologies') or []
    if isinstance(technologies, str):
        technologies = [t.strip() for t in technologies.split(',')
                        if t.strip()]
    # Additional free-text tech field (separate from `technologies`
    # dropdown selections in the form). Merge into combined list for
    # downstream queries without losing the original split for trace.
    additional_tech_raw = data.get('additional_tech') or ''
    if isinstance(additional_tech_raw, list):
        additional_tech_raw = '; '.join(str(a) for a in additional_tech_raw if a)
    additional_tech_raw = str(additional_tech_raw).strip()
    additional_tech = [
        t.strip() for t in _ts_re.split(r'[,;\n]+', additional_tech_raw)
        if t.strip()
    ] if additional_tech_raw else []
    all_tech_combined = list(technologies) + [
        t for t in additional_tech if t not in technologies
    ]
    maturity = (data.get('maturity_level') or 'initial').strip()
    challenges = data.get('challenges') or ''
    if isinstance(challenges, list):
        challenges = '; '.join(str(c) for c in challenges if c)
    challenges = str(challenges).strip()
    generation_mode = (data.get('generation_mode') or 'consulting').strip()
    domain = (data.get('domain') or '').strip()

    # Derived flags — the prompt explicitly calls out the "no defined
    # organizational structure" case as one that MUST be reflected across
    # gaps/objectives/pillars/roadmap/confidence. Normalize the detection
    # here once so every downstream synthesizer sees the same boolean.
    _os_lc = org_structure_raw.lower()
    org_structure_is_none = (
        not org_structure_raw
        or _os_lc in ('none', 'not defined', 'not_defined', 'no structure',
                      'no_structure', 'undefined', 'n/a', 'na', '-')
        or 'لا يوجد' in org_structure_raw
        or 'غير معرف' in org_structure_raw
        or 'غير محدد' in org_structure_raw
        or 'لا يوجد هيكل' in org_structure_raw
    )
    maturity_lc = maturity.lower().strip()
    if maturity_lc not in ('initial', 'developing', 'defined', 'managed',
                            'optimized', 'ad-hoc', 'ad hoc'):
        # Accept Arabic/variant forms
        _mat_map = {
            'أولي': 'initial', 'مبتدئ': 'initial',
            'قيد التطوير': 'developing', 'تطويري': 'developing',
            'معرّف': 'defined', 'محدد': 'defined',
            'مُدار': 'managed', 'تحت الإدارة': 'managed',
            'مُحسّن': 'optimized', 'محسن': 'optimized',
        }
        maturity_lc = _mat_map.get(maturity, 'initial')

    # Challenge keyword flags — the prompt names 7 categories: awareness,
    # incident response, staffing, suppliers, compliance, CONTINUITY, and
    # MONITORING. Continuity and monitoring were missing in the earlier
    # version of this model and are now added.
    _chal_lc = challenges.lower()
    challenge_flags = {
        'awareness': any(t in _chal_lc for t in
                         ('awareness', 'training', 'phishing',
                          'وعي', 'تدريب', 'تصيد')),
        'incident_response': any(t in _chal_lc for t in
                                 ('incident', 'response', 'soc', 'siem',
                                  'حوادث', 'استجابة')),
        'staffing': any(t in _chal_lc for t in
                        ('staff', 'skill', 'workforce', 'hiring',
                         'موظفين', 'مهارات', 'كفاءات', 'كوادر')),
        'suppliers': any(t in _chal_lc for t in
                         ('supplier', 'vendor', 'third-party', 'third party',
                          'supply chain',
                          'موردين', 'أطراف ثالثة', 'سلسلة الإمداد')),
        'compliance': any(t in _chal_lc for t in
                          ('compliance', 'audit', 'regulation',
                           'امتثال', 'تدقيق', 'تنظيمي')),
        # NEW: continuity — business continuity / DR / recovery gaps
        'continuity': any(t in _chal_lc for t in
                          ('continuity', 'business continuity', 'bcp',
                           'disaster recovery', 'dr ', 'resilience',
                           'backup',
                           'استمرارية', 'استمرار الأعمال',
                           'التعافي', 'الكوارث', 'النسخ الاحتياطي')),
        # NEW: monitoring — continuous monitoring / observability /
        # detection-coverage gaps (distinct from incident_response which
        # is about reaction, this is about visibility)
        'monitoring': any(t in _chal_lc for t in
                          ('monitoring', 'observability', 'visibility',
                           'continuous monitoring', 'detection coverage',
                           'logging gap',
                           'رصد', 'المراقبة المستمرة', 'الرؤية',
                           'الكشف', 'تغطية الكشف')),
    }

    # Derive tech_coverage — which tech categories the user HAS selected.
    # Used by pillars / roadmap synth to emit priority rows for MISSING
    # categories (Part 2B/2E: "if technologies missing in key areas,
    # pillars/roadmap reflect that").
    _tech_blob = ' '.join(str(t).lower() for t in all_tech_combined)
    tech_coverage = {
        'siem':       any(k in _tech_blob for k in ('siem', 'splunk',
                                                     'sentinel', 'qradar',
                                                     'elastic security')),
        'soar':       any(k in _tech_blob for k in ('soar', 'phantom',
                                                     'tines', 'xsoar')),
        'edr':        any(k in _tech_blob for k in ('edr', 'xdr', 'crowdstrike',
                                                     'sentinelone',
                                                     'defender for endpoint',
                                                     'carbon black')),
        'iam':        any(k in _tech_blob for k in ('iam', 'okta',
                                                     'active directory',
                                                     'azure ad', 'auth0',
                                                     'pam', 'privileged access')),
        'dlp':        any(k in _tech_blob for k in ('dlp', 'data loss',
                                                     'forcepoint', 'symantec dlp')),
        'backup':     any(k in _tech_blob for k in ('backup', 'veeam',
                                                     'commvault', 'rubrik',
                                                     'snapshot')),
        'tprm':       any(k in _tech_blob for k in ('tprm', 'onetrust',
                                                     'prevalent', 'bitsight',
                                                     'securityscorecard')),
        'vuln_mgmt':  any(k in _tech_blob for k in ('vulnerability',
                                                     'qualys', 'rapid7',
                                                     'tenable', 'nessus')),
    }
    # Tech gap list — categories the user does NOT have. Used by synths
    # to pick which "technology-missing" priority rows to inject.
    tech_gaps = [k for k, present in tech_coverage.items() if not present]

    # Normalize answered_questions / benchmark_context / traceability_context.
    # These are pass-through structures — the model just carries them
    # forward so downstream code can inspect them without re-fetching.
    _answered = answered_questions or data.get('answered_questions') or {}
    if not isinstance(_answered, dict):
        _answered = {}
    _bench = benchmark_context or data.get('benchmark_context') or None
    _trace_ctx = traceability_context or data.get('traceability_context') or None

    model = {
        'org_name': org_name,
        'sector': sector,
        'size': size,
        'budget': budget,
        'frameworks': frameworks,
        'frameworks_str': ', '.join(frameworks) if frameworks else 'N/A',
        'org_structure': org_structure_raw or (
            'لا يوجد' if lang == 'ar' else 'Not specified'),
        'org_structure_is_none': org_structure_is_none,
        'technologies': technologies,
        'additional_tech': additional_tech,
        'all_tech': all_tech_combined,
        'technologies_str': ', '.join(all_tech_combined) if all_tech_combined else 'N/A',
        'tech_coverage': tech_coverage,
        'tech_gaps': tech_gaps,
        'maturity': maturity_lc,
        'maturity_raw': maturity,
        'challenges': challenges,
        'challenge_flags': challenge_flags,
        'answered_questions': _answered,
        'benchmark_context': _bench,
        'traceability_context': _trace_ctx,
        'generation_mode': generation_mode,
        'domain': domain,
        'lang': lang,
        'diagnostic_gaps': list(diagnostic_gaps or []),
        'derived_risks': list(derived_risks or []),
        'derived_objectives': list(derived_objectives or []),
    }
    return model


def diagnostic_model_to_ctx(model):
    """Flatten the diagnostic model into the ctx dict shape accepted by
    _apply_final_synthesis_pass and the individual synthesizers. Keeps
    backward-compat with ctx callers that don't pass a model.
    """
    if not model:
        return {}
    return {
        'sector': model.get('sector', 'General'),
        'org_name': model.get('org_name', 'The Organization'),
        'maturity': model.get('maturity', 'initial'),
        'generation_mode': model.get('generation_mode', 'drafting'),
        'challenges': model.get('challenges', ''),
        'size': model.get('size', ''),
        'budget': model.get('budget', ''),
        'technologies': model.get('technologies', []),
        'additional_tech': model.get('additional_tech', []),
        'all_tech': model.get('all_tech', []),
        'tech_coverage': model.get('tech_coverage', {}),
        'tech_gaps': model.get('tech_gaps', []),
        'org_structure': model.get('org_structure', ''),
        'org_structure_is_none': model.get('org_structure_is_none', False),
        'frameworks': model.get('frameworks', []),
        'diagnostic_gaps': model.get('diagnostic_gaps', []),
        'risks': model.get('derived_risks', []),
        'objectives': model.get('derived_objectives', []),
        'challenge_flags': model.get('challenge_flags', {}),
        'answered_questions': model.get('answered_questions', {}),
        'benchmark_context': model.get('benchmark_context'),
        'traceability_context': model.get('traceability_context'),
    }


def log_diagnostic_model(model, tag='build'):
    """Prompt Part 7: log the model at key checkpoints."""
    if not model:
        print(f'[STRATEGY-DIAG] diagnostic_model_{tag}=None', flush=True)
        return
    # Only print keys that are decision-relevant; keep the log terse.
    summary = {
        'sector': model.get('sector'),
        'size': model.get('size'),
        'budget': model.get('budget'),
        'maturity': model.get('maturity'),
        'frameworks': model.get('frameworks'),
        'org_structure_is_none': model.get('org_structure_is_none'),
        'technologies_n': len(model.get('technologies', []) or []),
        'challenges_len': len(model.get('challenges', '') or ''),
        'challenge_flags': model.get('challenge_flags'),
        'diagnostic_gaps_n': len(model.get('diagnostic_gaps', []) or []),
        'generation_mode': model.get('generation_mode'),
    }
    print(f'[STRATEGY-DIAG] diagnostic_model_{tag}={summary}', flush=True)




def _count_env_bullets(text, min_chars=40):
    """Count substantive bullet/numbered-list lines (≥ min_chars real
    content). Used as a fallback when the environment section presents
    structured bullets instead of paragraphs.
    """
    if not text:
        return 0
    n = 0
    for ln in text.splitlines():
        s = ln.strip()
        if not _ts_re.match(r'^(?:[-*\u2022]\s|\d+[.)]\s)', s):
            continue
        body = _ts_re.sub(r'^(?:[-*\u2022]\s+|\d+[.)]\s+)', '', s)
        body = _ts_re.sub(r'[*_`]+', '', body).strip()
        if len(body) >= min_chars:
            n += 1
    return n


def _env_has_structured_table(text):
    """True if the section contains at least one markdown table with ≥ 2
    real (non-separator, non-header) rows."""
    if not text:
        return False
    lines = text.splitlines()
    i = 0
    while i < len(lines):
        s = lines[i].strip()
        if (s.startswith('|') and s.endswith('|') and
                i + 1 < len(lines) and
                _ts_re.match(r'^\|[\s\-:|]+\|$', lines[i + 1].strip())):
            # header + separator detected — count data rows
            j = i + 2
            data_rows = 0
            while j < len(lines):
                t = lines[j].strip()
                if not (t.startswith('|') and t.endswith('|')):
                    break
                if _ts_re.match(r'^\|[\s\-:|]+\|$', t):
                    j += 1
                    continue
                data_rows += 1
                j += 1
            if data_rows >= 2:
                return True
            i = j
            continue
        i += 1
    return False


def _count_substantive_pillars(pillars_text):
    """Count `### Pillar ...` headings (or AR equivalents) followed by a
    substantive body — either a pipe-table initiative row with real
    content, or a narrative block ≥ 80 characters.

    Primary pattern accepts canonical "Pillar N" / "الركيزة N" headings.
    Fallback widens to ANY `### heading` followed by substantive body,
    so that pillars emitted with non-canonical title prefixes (e.g.,
    "### بناء القدرات التقنية...", "### Technology Capability Build-out")
    are still counted. This closes the
    `pillars_below_richness_minimum_2/3` gap where the synth's
    technology-priority pillar title lacked the "الركيزة" prefix and
    the validator silently skipped it.
    """
    if not pillars_text:
        return 0
    pillar_hdr_re = _ts_re.compile(
        r'^###\s+(?:Pillar\s*\d*|Strategic\s+Pillar\s*\d*|'
        r'الركيزة(?:\s+الاستراتيجية)?\s*\d*)[^\n]*',
        _ts_re.MULTILINE | _ts_re.IGNORECASE,
    )
    matches = list(pillar_hdr_re.finditer(pillars_text))
    # Fallback: if fewer than 3 canonical matches, also treat any
    # `### heading` with substantive body as a pillar. This is the
    # widened behaviour that catches non-canonical titles.
    if len(matches) < 3:
        any_heading_matches = list(_ts_re.finditer(
            r'^###\s+[^\n]+$', pillars_text, _ts_re.MULTILINE,
        ))
        # Only use the wider set if it would produce more substantive
        # pillars; keep canonical set otherwise to preserve strictness.
        if len(any_heading_matches) > len(matches):
            matches = any_heading_matches
    n = 0
    for i, m in enumerate(matches):
        start = m.end()
        end = matches[i + 1].start() if i + 1 < len(matches) else len(pillars_text)
        body = pillars_text[start:end].strip()
        if not body:
            continue
        has_tbl_row = False
        for ln in body.splitlines():
            s = _TRACE_STRIP_RE.sub('', ln).strip()
            if (s.startswith('|') and s.endswith('|') and
                    not _ts_re.match(r'^\|[\s\-:|]+\|$', s)):
                cells = [c.strip() for c in _strip_trace_comments(s).split('|')[1:-1]]
                if len(cells) >= 3 and sum(
                    1 for c in cells[1:] if not _ts_is_placeholder(c)
                ) >= 2:
                    has_tbl_row = True
                    break
        if has_tbl_row:
            n += 1
            continue
        stripped = _ts_re.sub(r'[*_`#>|\-]+', '', body)
        stripped = _ts_re.sub(r'\s+', ' ', stripped).strip()
        if len(stripped) >= 80:
            n += 1
    return n


def _count_substantive_roadmap_rows(roadmap_text):
    """Count substantive roadmap activity rows across all common schemas:
      5-col: | # | Activity | Owner | Timeline | Deliverable |
      5-col: | Phase | Step | Description | Owner | Deliverable |
      6-col: | Phase | Step | Action | Owner | Deliverable | Timeframe |
    A row is "substantive" ONLY when EVERY non-# data cell is non-placeholder
    — per prompt clause B3.2 "each row must include: activity, owner,
    timeframe, deliverable / output". Relaxing to ≥ 3 of 4 would let a
    roadmap with an empty Deliverable column pass, which defeats the
    purpose of the richness contract. Arabic column names are accepted.
    """
    if not roadmap_text:
        return 0
    header_tokens = _ts_re.compile(
        r'(?:Activity|Phase|Step|Owner|Deliverable|Timeline|Timeframe|'
        r'النشاط|المرحلة|الخطوة|المسؤول|المخرج|الإطار|الجدول\s*الزمني)',
        _ts_re.IGNORECASE,
    )
    n = 0
    in_tbl = False
    for ln in roadmap_text.split('\n'):
        s = _TRACE_STRIP_RE.sub('', ln).strip()
        if not (s.startswith('|') and s.endswith('|')):
            in_tbl = False
            continue
        if _ts_re.match(r'^\|[\s\-:|]+\|$', s):
            continue
        # Strip trace comments so pipe chars inside them don't create phantom columns.
        cells = [c.strip() for c in _strip_trace_comments(s).split('|')[1:-1]]
        header_hits = sum(1 for c in cells if header_tokens.search(c or ''))
        if header_hits >= 2 and not in_tbl:
            in_tbl = True
            continue
        if not in_tbl:
            continue
        if len(cells) < 3:
            continue
        data_cells = (cells[1:] if cells and cells[0].replace('.', '').isdigit()
                      else cells[:])
        # HARD BAR: all data cells must be non-placeholder.
        if data_cells and all(not _ts_is_placeholder(c) for c in data_cells):
            n += 1
    return n


def _count_csf_rows(conf_text):
    """Count Critical Success Factors rows where Factor + Description/Why +
    Importance are non-placeholder.
    """
    if not conf_text:
        return 0
    hdr = _ts_re.compile(
        r'^\|\s*#\s*\|\s*(?:Factor|العامل)\s*\|',
        _ts_re.IGNORECASE,
    )
    n = 0
    for cells in _ts_table_rows(conf_text, hdr):
        if len(cells) < 4:
            continue
        if not cells[0].replace('.', '').isdigit():
            continue
        if any(_ts_is_placeholder(cells[i]) for i in (1, 2, 3)):
            continue
        n += 1
    return n


def _count_risk_rows_with_mitigation(conf_text):
    """Count Key Risks rows where Risk + Likelihood + Impact + Mitigation
    are all non-placeholder. Mitigation is the last column and is
    specifically required by prompt clause A.7.
    """
    if not conf_text:
        return 0
    hdr = _ts_re.compile(
        r'^\|\s*#\s*\|\s*(?:Risk|المخاطر|الخطر)\s*\|',
        _ts_re.IGNORECASE,
    )
    n = 0
    for cells in _ts_table_rows(conf_text, hdr):
        if len(cells) < 5:
            continue
        if not cells[0].replace('.', '').isdigit():
            continue
        if any(_ts_is_placeholder(cells[i]) for i in (1, 2, 3, 4)):
            continue
        n += 1
    return n


def _check_environment_topic_coverage(env_text):
    """Return a dict of {category: bool} for regulatory / threat /
    business coverage in the environment section. Per prompt clause B3.1:
    environment "must include: regulatory context, threat context,
    business/operational context". Bilingual keyword detection — a
    category is considered covered when the section text contains at
    least one keyword from its category list.
    """
    if not env_text:
        return {'regulatory': False, 'threat': False, 'business': False}
    lower = env_text.lower()
    regulatory_en = (
        'regulatory', 'regulation', 'compliance', 'law', 'statute',
        'act', 'directive', 'mandate', 'ncae', 'nca', 'ecc', 'pdpl',
        'gdpr', 'sama', 'citc', 'framework',
    )
    regulatory_ar = (
        'تنظيمي', 'تنظيمية', 'اللوائح', 'الأنظمة', 'الامتثال', 'نظام',
        'قانون', 'مرسوم', 'إلزام', 'الإطار التنظيمي', 'هيئة',
    )
    threat_en = (
        'threat', 'attack', 'adversary', 'ransomware', 'phishing',
        'intrusion', 'breach', 'malware', 'exploit', 'supply-chain',
        'supply chain', 'incident',
    )
    threat_ar = (
        'تهديد', 'التهديدات', 'هجوم', 'الهجمات', 'اختراق', 'اقتحام',
        'برامج الفدية', 'التصيد', 'الحوادث', 'سلاسل الإمداد',
        'سلسلة الإمداد',
    )
    business_en = (
        'business', 'operational', 'continuity', 'transformation',
        'digital transformation', 'services', 'customer', 'operations',
        'sector', 'strategic priority',
    )
    business_ar = (
        'الأعمال', 'تشغيلي', 'تشغيلية', 'استمرارية', 'التحول الرقمي',
        'الخدمات', 'العملاء', 'العمليات', 'القطاع', 'الاستراتيجي',
    )
    def _has_any(text_l, tokens_en, tokens_ar):
        for t in tokens_en:
            if t in text_l:
                return True
        # Arabic keywords are case-preserving; check against original text
        for t in tokens_ar:
            if t in env_text:
                return True
        return False
    return {
        'regulatory': _has_any(lower, regulatory_en, regulatory_ar),
        'threat':     _has_any(lower, threat_en, threat_ar),
        'business':   _has_any(lower, business_en, business_ar),
    }


def validate_environment_richness(sections, lang, generation_mode='consulting'):
    """Environment / Threat Context must be a real standalone section with
    narrative paragraphs and either a structured table or a structured
    bullet block, AND must cover all three required categories
    (regulatory + threat + business). Prompt clause A.3 + B3.1.

    In consulting/assurance mode the environment paragraph count bar is
    raised to 3 (one per category — regulatory, threat, business — each
    substantive enough for board-level consumption).
    """
    _is_consulting_grade = str(generation_mode).lower() in ('consulting', 'assurance')
    _min_env_paras = max(_RICHNESS_MIN_ENV_PARAS, 3) if _is_consulting_grade else _RICHNESS_MIN_ENV_PARAS
    defects = []
    env = sections.get('environment', '') or ''
    if not env.strip():
        defects.append(('environment_missing',
                        'Environment / Threat Context section is empty'))
        return defects
    n_paras = _count_substantive_paragraphs(env)
    has_tbl = _env_has_structured_table(env)
    n_bullets = _count_env_bullets(env)
    has_structured_block = has_tbl or n_bullets >= _RICHNESS_MIN_ENV_BULLETS
    if n_paras < _min_env_paras:
        defects.append((
            'environment_paragraphs_insufficient',
            f'{n_paras}/{_min_env_paras} substantive paragraphs',
        ))
    if not has_structured_block:
        defects.append((
            'environment_structured_block_missing',
            f'no table and only {n_bullets} substantive bullets '
            f'(min {_RICHNESS_MIN_ENV_BULLETS})',
        ))
    # Category coverage: regulatory + threat + business must all be present
    coverage = _check_environment_topic_coverage(env)
    missing_cats = [k for k, v in coverage.items() if not v]
    if missing_cats:
        defects.append((
            'environment_topic_coverage_incomplete',
            f'missing categories: {sorted(missing_cats)}',
        ))
    return defects


def validate_roadmap_richness(sections, lang, generation_mode='consulting'):
    """Roadmap must be a real execution roadmap with ≥ 4 substantive rows
    across any schema. In consulting/assurance mode the bar is raised to
    ≥ 8 rows (covering 3 phases × ≥ 2–3 activities each). Prompt clause A.5.
    """
    _is_consulting_grade = str(generation_mode).lower() in ('consulting', 'assurance')
    _min_roadmap = max(_RICHNESS_MIN_ROADMAP_ROWS, 8) if _is_consulting_grade else _RICHNESS_MIN_ROADMAP_ROWS
    defects = []
    roadmap = sections.get('roadmap', '') or ''
    if not roadmap.strip():
        defects.append(('roadmap_missing',
                        'Roadmap section is empty'))
        return defects
    n = _count_substantive_roadmap_rows(roadmap)
    if n < _min_roadmap:
        defects.append((
            'roadmap_rows_insufficient_for_richness',
            f'{n}/{_min_roadmap} substantive roadmap activities',
        ))
    return defects


def validate_kpi_richness(sections, lang, generation_mode='consulting'):
    """KPI section must have ≥ 4 substantive KPI rows AND 1:1 guide
    coverage. In consulting/assurance mode the bar is raised to ≥ 6 KPIs
    (Big-4 scorecards carry 8–12; 6 is the floor for a single-domain
    strategy). Prompt clause A.6 / B3.3 — "each KPI must include: name,
    target, formula, justification, timeframe". Uses the STRICT counter
    that requires all 5 data cells non-placeholder.
    """
    _is_consulting_grade = str(generation_mode).lower() in ('consulting', 'assurance')
    _min_kpis = max(_RICHNESS_MIN_KPI_ROWS, 6) if _is_consulting_grade else _RICHNESS_MIN_KPI_ROWS
    defects = []
    kpis = sections.get('kpis', '') or ''
    if not kpis.strip():
        defects.append(('kpi_section_missing',
                        'KPI section is empty'))
        return defects
    n_kpis   = count_substantive_kpis_strict(kpis)
    n_guides = count_kpi_guides(kpis)
    if n_kpis < _min_kpis:
        defects.append((
            'kpi_rows_insufficient_for_richness',
            f'{n_kpis}/{_min_kpis} strictly-substantive KPI rows '
            f'(each must have description, target, formula, justification, timeframe)',
        ))
    if n_kpis > 0 and n_guides < n_kpis:
        defects.append((
            'kpi_guide_coverage_incomplete',
            f'{n_guides}/{n_kpis} guide coverage',
        ))
    return defects


def validate_confidence_richness(sections, lang, generation_mode='consulting'):
    """Confidence section must have ≥ 4 critical success factors AND ≥ 4
    risk rows with non-placeholder mitigation. Per prompt clause B3.4
    the richness contract ALSO requires:
      - confidence score present (e.g. "Confidence Score: 75%" or
        "درجة الثقة: 75%")
      - score justification present (inline paragraph OR "Score
        Justification" / "مبررات التقييم" heading followed by prose)

    Gap 7 — Consulting/assurance mode additionally requires a maturity
    trajectory statement: the current maturity level (numeric or label)
    AND a 12–24 month target projection must appear in the section.
    """
    _is_consulting_grade = str(generation_mode).lower() in ('consulting', 'assurance')
    _min_csf  = max(_RICHNESS_MIN_CSF_ROWS, 5) if _is_consulting_grade else _RICHNESS_MIN_CSF_ROWS
    _min_risk = max(_RICHNESS_MIN_RISK_ROWS, 5) if _is_consulting_grade else _RICHNESS_MIN_RISK_ROWS
    defects = []
    conf = sections.get('confidence', '') or ''
    if not conf.strip():
        defects.append(('confidence_missing',
                        'Confidence section is empty'))
        return defects

    # Score detection — EN + AR variants. Accept "**Confidence Score:** NN%",
    # "Confidence Score: NN%", and the Arabic "درجة الثقة: NN%" forms.
    score_re = _ts_re.compile(
        r'(?:\*\*)?(?:Confidence\s+Score|درجة\s+الثقة)(?:\*\*)?\s*:?\s*'
        r'(?:\*\*)?\s*\d{1,3}\s*%',
        _ts_re.IGNORECASE,
    )
    if not score_re.search(conf):
        defects.append((
            'confidence_score_missing_in_richness',
            'No Confidence Score / درجة الثقة value found in section',
        ))

    # Score justification — heading OR a paragraph that mentions justification
    # in context of the score. Either signal is acceptable.
    just_heading_re = _ts_re.compile(
        r'^#{2,4}\s*(?:Score\s+Justification|مبررات?\s+(?:التقييم|الثقة))',
        _ts_re.MULTILINE | _ts_re.IGNORECASE,
    )
    just_inline_re = _ts_re.compile(
        r'(?:justification|rationale|مبررات?|أسباب|تفسير)',
        _ts_re.IGNORECASE,
    )
    has_justification = bool(just_heading_re.search(conf)) or bool(
        just_inline_re.search(conf)
    )
    if not has_justification:
        defects.append((
            'confidence_justification_missing_in_richness',
            'No score justification heading or rationale language found',
        ))

    n_csf = _count_csf_rows(conf)
    n_risks = _count_risk_rows_with_mitigation(conf)
    if n_csf < _min_csf:
        defects.append((
            'confidence_csf_insufficient',
            f'{n_csf}/{_min_csf} critical success factors',
        ))
    if n_risks < _min_risk:
        defects.append((
            'confidence_risks_insufficient',
            f'{n_risks}/{_min_risk} risk rows with mitigation',
        ))

    # Gap 7: consulting/assurance mode — maturity trajectory check.
    # Big-4 confidence sections always state current maturity level AND a
    # 12–24 month target projection (e.g., "Level 1.8 → Level 3.2 within
    # 18 months" or "initial → managed maturity within 24 months").
    if _is_consulting_grade:
        _maturity_current_re = _ts_re.compile(
            r'(?:current\s+maturity|maturity\s+level|current\s+level'
            r'|مستوى\s+النضج\s+الحالي|النضج\s+الحالي|المستوى\s+الحالي'
            r'|initial|developing|defined|managed|optimized'
            r'|ابتدائي|تطويري|محدد|مُدار|محسّن)',
            _ts_re.IGNORECASE,
        )
        _maturity_target_re = _ts_re.compile(
            r'(?:target\s+maturity|target\s+level|within\s+1[2-9]\s*months?'
            r'|within\s+2[0-4]\s*months?|by\s+(?:month|year)'
            r'|مستوى\s+النضج\s+المستهدف|المستوى\s+المستهدف'
            r'|خلال\s+1[2-9]\s+شهر|خلال\s+2[0-4]\s+شهر)',
            _ts_re.IGNORECASE,
        )
        has_current_maturity = bool(_maturity_current_re.search(conf))
        has_target_maturity  = bool(_maturity_target_re.search(conf))
        if not has_current_maturity:
            defects.append((
                'confidence_maturity_current_missing',
                'Confidence section lacks a current-maturity-level statement '
                '(required for consulting-grade deliverable)',
            ))
        if not has_target_maturity:
            defects.append((
                'confidence_maturity_trajectory_missing',
                'Confidence section lacks a 12–24 month maturity target projection '
                '(required for consulting-grade deliverable)',
            ))
    return defects


def validate_arabic_strategy_semantic_richness(sections, lang, doc_subtype=None,
                                               generation_mode='consulting'):
    """Orchestrator for semantic richness of the final Technical Strategy
    payload. Runs per-section richness validators and aggregates defects.

    Does NOT run for board-level executive summaries — those have their
    own dedicated schema validator. Returns a list of (tag, detail)
    tuples. Empty list = clean.

    generation_mode adjusts the richness bar:
      consulting / assurance → higher minimums (Big-4 grade)
      drafting               → base minimums

    Name preserved from prompt clause D even though the check is applied
    bilingually; Arabic is the primary risk surface, but the richness bar
    applies to English Technical Strategy output as well.
    """
    if doc_subtype == 'board':
        return []
    defects = []
    is_ar = (lang == 'ar')
    _is_consulting_grade = str(generation_mode).lower() in ('consulting', 'assurance')

    # ── Canonical heading checks ─────────────────────────────────────────────
    if is_ar:
        headings_map = _CANONICAL_SECTION_HEADINGS.get('ar', {})
        section_h2_re = _ts_re.compile(r'^##\s*\d+\.?\s*([^\n]+)', _ts_re.MULTILINE)
        seen_headings = {}
        for key, canonical in headings_map.items():
            text = sections.get(key, '') or ''
            if not text.strip():
                continue
            m = section_h2_re.search(text)
            if m:
                found_title = m.group(1).strip()
                canonical_title = _ts_re.sub(r'^##\s*\d+\.?\s*', '', canonical).strip()
                if found_title != canonical_title:
                    defects.append((
                        f'{key}_canonical_heading_mismatch',
                        f'Section "{key}" heading is "{found_title}"; '
                        f'expected "{canonical_title}"',
                    ))
                # Track for duplicate heading detection
                if found_title in seen_headings:
                    defects.append((
                        'duplicate_section_heading',
                        f'Heading "{found_title}" appears in both '
                        f'"{seen_headings[found_title]}" and "{key}"',
                    ))
                else:
                    seen_headings[found_title] = key

    # ── Roadmap must not appear inside KPI section ───────────────────────────
    kpis_text = sections.get('kpis', '') or ''
    if kpis_text.strip() and is_ar:
        roadmap_cols = ['النشاط', 'المسؤول', 'الإطار الزمني', 'المخرج']
        tbl_hdr_re = _ts_re.compile(r'^\|.+\|$', _ts_re.MULTILINE)
        m = tbl_hdr_re.search(kpis_text)
        if m:
            hdr_line = m.group(0)
            road_cols_found = [c for c in roadmap_cols if c in hdr_line]
            if len(road_cols_found) >= 2:
                defects.append((
                    'kpis_contains_roadmap_columns',
                    f'KPI section table header contains roadmap columns: '
                    f'{road_cols_found}',
                ))

    # ── Risk section must not be duplicated ─────────────────────────────────
    if is_ar:
        conf_text = sections.get('confidence', '') or ''
        dup_risk_re = _ts_re.compile(r'###\s*المخاطر\s+الرئيسية', _ts_re.MULTILINE)
        n_risk_hdrs = len(dup_risk_re.findall(conf_text))
        if n_risk_hdrs > 1:
            defects.append((
                'duplicate_risk_header',
                f'"المخاطر الرئيسية" heading appears {n_risk_hdrs} times; '
                f'must appear exactly once',
            ))

    # ── Risk register must be valid (non-empty rows) ─────────────────────────
    if is_ar:
        conf_text = sections.get('confidence', '') or ''
        n_risks = _count_risk_rows_with_mitigation(conf_text)
        if conf_text.strip() and n_risks == 0:
            # Check if there's a risk header at all
            if _ts_re.search(r'###\s*المخاطر\s+الرئيسية', conf_text):
                defects.append((
                    'risk_register_empty',
                    'Confidence section has a "المخاطر الرئيسية" header but '
                    'contains no valid risk rows',
                ))

    # ── Cybersecurity capabilities must be present across sections ───────────
    _all_strategy_text = ' '.join(
        (sections.get(k) or '') for k in
        ('vision', 'pillars', 'environment', 'gaps', 'roadmap', 'kpis')
    )
    _caps_required = {
        'IAM/PAM': ('iam', 'pam', 'هوية', 'هويات', 'الهوية', 'وصول مميز', 'identity'),
        'MFA': ('mfa', 'multi-factor', 'عامل مصادقة متعدد', 'المصادقة الثنائية'),
        'SIEM/SOC': ('siem', 'soc', 'مراقبة', 'monitoring'),
        'Incident Response': ('incident', 'استجابة', 'حوادث', 'response'),
        'Vulnerability Management': ('vulnerability', 'ثغرات', 'vulner', 'التصحيح'),
        'Backup/DR': ('backup', 'نسخ احتياطي', 'dr', 'تعافي', 'استعادة'),
        'Awareness': ('awareness', 'توعية', 'phishing', 'تصيد', 'التدريب'),
        'Data Protection': ('dlp', 'data protection', 'حماية البيانات', 'encryption', 'تشفير'),
    }
    _all_lc = _all_strategy_text.lower()
    _missing_caps = []
    for _cap_name, _tokens in _caps_required.items():
        if not any(t in _all_lc or t in _all_strategy_text for t in _tokens):
            _missing_caps.append(_cap_name)
    if _missing_caps:
        defects.append((
            'cybersecurity_capabilities_missing',
            f'Missing technical capabilities: {", ".join(_missing_caps)}',
        ))

    # ── Gap guides must be unique (not identical repeated templates) ──────────
    gaps_text = sections.get('gaps', '') or ''
    if gaps_text.strip():
        # Find all guide section headings in gaps
        guide_hdr_re = _ts_re.compile(
            r'^####\s+(?:دليل|Gap\s+#\d+\s+Implementation)', _ts_re.MULTILINE)
        guide_bodies = guide_hdr_re.split(gaps_text)
        if len(guide_bodies) > 2:
            # Compare content of consecutive guide bodies (stripped)
            stripped_bodies = [b.strip()[:200] for b in guide_bodies[1:]]
            unique_bodies = set(stripped_bodies)
            if len(unique_bodies) < len(stripped_bodies):
                defects.append((
                    'gap_guides_not_unique',
                    f'{len(stripped_bodies) - len(unique_bodies)} duplicate '
                    f'gap guide(s) detected; guides must be gap-specific',
                ))

    # ── KPIs must have owner, data source, frequency ─────────────────────────
    kpis_text = sections.get('kpis', '') or ''
    if kpis_text.strip():
        kpi_owner_tokens = ('مالك', 'owner', 'مسؤول', 'responsible')
        kpi_freq_tokens = ('تكرار', 'frequency', 'دورية', 'شهري', 'monthly', 'quarterly', 'ربع سنوي')
        kpi_src_tokens = ('مصدر', 'source', 'بيانات', 'data')
        _kpi_lc = kpis_text.lower()
        if not any(t in _kpi_lc for t in kpi_owner_tokens):
            defects.append((
                'kpis_missing_owner_column',
                'KPI section has no owner/responsible column',
            ))
        if not any(t in _kpi_lc for t in kpi_freq_tokens):
            defects.append((
                'kpis_missing_frequency_column',
                'KPI section has no frequency/periodicity column',
            ))

    # ── Risks must have owner, mitigation plan, warning indicator ────────────
    if is_ar:
        conf_text = sections.get('confidence', '') or ''
        risk_sec_re = _ts_re.compile(r'###\s*المخاطر\s+الرئيسية', _ts_re.MULTILINE)
        risk_m = risk_sec_re.search(conf_text)
        if risk_m:
            risk_section = conf_text[risk_m.start():]
            _r_lc = risk_section.lower()
            if not any(t in risk_section for t in ('المالك', 'المسؤول', 'owner')):
                defects.append((
                    'risk_register_missing_owner',
                    'Risk register table has no owner/المالك column',
                ))
            if not any(t in risk_section for t in ('خطة المعالجة', 'mitigation', 'المعالجة')):
                defects.append((
                    'risk_register_missing_mitigation',
                    'Risk register table has no mitigation plan column',
                ))

    # ── Higher SO-row bar (4 base; 6 for consulting/assurance) ──────────────
    _min_so = _RICHNESS_MIN_SO_ROWS if not _is_consulting_grade else max(_RICHNESS_MIN_SO_ROWS, 6)
    n_so = count_valid_objective_rows(sections.get('vision', '') or '')
    if n_so < _min_so:
        defects.append((
            'so_rows_insufficient_for_richness',
            f'{n_so}/{_min_so} valid SO rows',
        ))
    # ── Pillar minimum: 3 base; 4 for consulting/assurance ───────────────────
    _min_pillars = _RICHNESS_MIN_PILLARS if not _is_consulting_grade else max(_RICHNESS_MIN_PILLARS, 4)
    n_pill = _count_substantive_pillars(sections.get('pillars', '') or '')
    if n_pill < _min_pillars:
        defects.append((
            'pillars_insufficient_for_richness',
            f'{n_pill}/{_min_pillars} substantive pillars',
        ))
    # Check that every substantive pillar has ≥ 3 initiative rows
    # (consulting-grade depth requirement).
    _pillars_text = sections.get('pillars', '') or ''
    if _pillars_text.strip():
        _pill_matches = list(_PILLAR_HEADING_RE_GLOBAL.finditer(_pillars_text))
        if not _pill_matches:
            _pill_matches = list(_ts_re.finditer(
                r'^###\s+[^\n]+', _pillars_text, _ts_re.MULTILINE,
            ))
        _thin_pillars = []
        for _idx, _pm in enumerate(_pill_matches):
            _pend = (_pill_matches[_idx + 1].start()
                     if _idx + 1 < len(_pill_matches)
                     else len(_pillars_text))
            _pbody = _pillars_text[_pm.end():_pend]
            _n_init = _count_pillar_initiative_rows(_pbody)
            if _n_init < _RICHNESS_MIN_PILLAR_INITIATIVES:
                _pname = _ts_re.sub(r'^###\s+', '', _pillars_text[_pm.start():_pm.end()]).strip()
                _thin_pillars.append(f'"{_pname}"({_n_init})')
        if _thin_pillars:
            defects.append((
                'pillar_initiatives_insufficient',
                f'pillars with <{_RICHNESS_MIN_PILLAR_INITIATIVES} initiatives: '
                + ', '.join(_thin_pillars),
            ))
        # Gap 4: consulting-mode pillar narrative check.
        # Every pillar must have ≥ 1 non-table paragraph of ≥ 100 chars
        # BEFORE its initiative table — the consultative narrative that
        # explains strategic logic, root causes, and framework linkage.
        if _is_consulting_grade:
            _narrative_missing = []
            for _idx, _pm in enumerate(_pill_matches):
                _pend = (_pill_matches[_idx + 1].start()
                         if _idx + 1 < len(_pill_matches)
                         else len(_pillars_text))
                _pbody = _pillars_text[_pm.end():_pend]
                # Collect text before the first pipe-table line
                _pre_table_lines = []
                for _ln in _pbody.splitlines():
                    _s = _ln.strip()
                    if _s.startswith('|') and _s.endswith('|'):
                        break
                    _pre_table_lines.append(_ln)
                _pre_table_text = '\n'.join(_pre_table_lines)
                _n_narrative = _count_substantive_paragraphs(
                    _pre_table_text, min_chars=100)
                if _n_narrative == 0:
                    _pname = _ts_re.sub(
                        r'^###\s+', '',
                        _pillars_text[_pm.start():_pm.end()],
                    ).strip()
                    _narrative_missing.append(f'"{_pname}"')
            if _narrative_missing:
                defects.append((
                    'pillar_narrative_missing',
                    'pillars lacking a consultative narrative paragraph (≥100 chars) '
                    'before the initiative table: ' + ', '.join(_narrative_missing),
                ))
    n_gap = count_substantive_gaps(sections.get('gaps', '') or '')
    # Gap rows: 2 base; 5 for consulting/assurance (Big 4 gap analyses have ≥5)
    _min_gaps = _RICHNESS_MIN_GAP_ROWS if not _is_consulting_grade else max(_RICHNESS_MIN_GAP_ROWS, 5)
    if n_gap < _min_gaps:
        defects.append((
            'gap_rows_insufficient_for_richness',
            f'{n_gap}/{_min_gaps} substantive gap rows',
        ))
    defects.extend(validate_environment_richness(sections, lang,
                                                  generation_mode=generation_mode))
    defects.extend(validate_roadmap_richness(sections, lang,
                                              generation_mode=generation_mode))
    defects.extend(validate_kpi_richness(sections, lang,
                                          generation_mode=generation_mode))
    defects.extend(validate_confidence_richness(sections, lang,
                                                 generation_mode=generation_mode))
    return defects


# ────────────────────────────────────────────────────────────────────────────
# TECHNICAL STRATEGY DETERMINISTIC DEPTH SYNTHESIZERS
#
# These builders run BEFORE the richness gate in the save pipeline (inside
# _enforce_technical_strategy_completeness). They enrich thin sections up to
# the richness bar using whatever context is available (domain, framework
# shortcode, sector, org_name). They NEVER replace real AI content — they
# only append deterministic rows/paragraphs when the count falls below the
# richness minimum. Appending is idempotent: running twice produces the same
# payload.
# ────────────────────────────────────────────────────────────────────────────


def synthesize_environment_context(sections, lang, domain='Cyber Security',
                                   fw_short='NCA ECC', sector='General',
                                   org_name='The Organization',
                                   generation_mode='drafting',
                                   maturity='initial',
                                   challenges='',
                                   frameworks=None):
    """Append deterministic regulatory + threat + business/operational
    paragraphs and a structured context table to the environment section
    when it falls below the richness bar. Returns a dict of what was added.

    Each paragraph explicitly contains the category's detection keywords
    (regulatory / تنظيمي, threat / تهديد, business/operational / أعمال)
    so `_check_environment_topic_coverage` recognises the coverage. The
    three category paragraphs are ALWAYS generated together as a bundle
    — producing only 2 of 3 would still fail the topic-coverage check.

    generation_mode adjusts tone:
      drafting  → concise single-paragraph per category
      consulting → regulatory paragraph appends an advisory sentence
      assurance → regulatory paragraph explicitly references evidence posture
    maturity affects regulatory pressure framing:
      initial / developing → emphasises foundational gaps
      defined / managed / optimized → emphasises optimization pressure
    challenges (free-text from the diagnostic) is woven into the business
    paragraph when present.

    Idempotent: uses a sentinel marker comment so re-runs don't double-
    append.
    """
    summary = {}
    env = sections.get('environment', '') or ''
    marker = '<!-- mizan-synth-env-v2 -->'
    if marker in env:
        return summary
    is_ar = (lang == 'ar')

    # Evaluate current richness + category coverage
    n_paras = _count_substantive_paragraphs(env)
    has_tbl = _env_has_structured_table(env)
    n_bullets = _count_env_bullets(env)
    has_structured_block = has_tbl or n_bullets >= _RICHNESS_MIN_ENV_BULLETS
    coverage = _check_environment_topic_coverage(env)
    all_categories_covered = all(coverage.values())

    if (n_paras >= _RICHNESS_MIN_ENV_PARAS
            and has_structured_block
            and all_categories_covered):
        return summary

    head = ''
    if not env.strip():
        head = ('## 3. البيئة التنظيمية والتهديدات\n\n' if is_ar
                else '## 3. Business Environment & Regulatory Context\n\n')

    # Mode + maturity-conditioned suffixes appended to category paragraphs.
    low_maturity = str(maturity).lower() in ('initial', 'developing', 'ad-hoc', 'ad hoc')
    if is_ar:
        _mode_advisory = {
            'consulting': ' ويستلزم ذلك مراجعة سنوية للمتطلبات التنظيمية مع تحديث خطة الامتثال.',
            'assurance':  ' ويجب توثيق أدلة الامتثال لكل ضابط إلزامي بصورة قابلة للتدقيق المستقل.',
        }.get(str(generation_mode).lower(), '')
        _maturity_frame = (' إذ تكشف القدرات الأساسية عن فجوات يجب سدّها قبل تحقيق أي التزام مستدام.'
                           if low_maturity else
                           ' في وقتٍ تتركز فيه الأولوية على تحسين النضج التشغيلي والحفاظ على الاستدامة.')
        _challenges_clause = ''
        if challenges and str(challenges).strip():
            _challenges_clause = (f" كما تتضمن التحديات المُعلنة لـ{org_name} "
                                  f"ما يلي: {str(challenges).strip()[:200]}.")
    else:
        _mode_advisory = {
            'consulting': ' Annual re-assessment against regulatory change and compliance-plan refresh are required.',
            'assurance':  ' Each mandatory control must be evidenced in an independently-auditable form.',
        }.get(str(generation_mode).lower(), '')
        _maturity_frame = (' Foundational capabilities currently show gaps that must be closed '
                           'before any sustainable compliance stance.'
                           if low_maturity else
                           ' The priority is now centred on optimising operational maturity '
                           'and sustaining that posture.')
        _challenges_clause = ''
        if challenges and str(challenges).strip():
            _challenges_clause = (f" The stated challenges for {org_name} include: "
                                  f"{str(challenges).strip()[:200]}.")

    # ── PER-FRAMEWORK REFERENCE CLAUSE (prompt clause 3) ───────
    # Synth must emit at least one canonical reference for EACH
    # selected framework so the validator (which uses the same
    # canonical_framework_aliases helper) can recognise it. We pick
    # the second-best alias when available — typically the bare
    # acronym (PDPL, NDMO, NCA ECC) — because it reads more naturally
    # in prose than the full parenthetical label, while still being
    # recognised by the validator's canonical alias set.
    _selected_fw_list = list(frameworks) if frameworks else []
    _fw_pretty_list = []
    for _fw in _selected_fw_list:
        try:
            _aliases = canonical_framework_aliases(_fw)
        except Exception:
            _aliases = [str(_fw)] if _fw else []
        # Prefer alias index 1 (typically bare acronym for "X (Long)"
        # forms; "X" for "X Y Z" forms). Fall back to index 0 (full).
        if len(_aliases) >= 2:
            _fw_pretty_list.append(_aliases[1])
        elif _aliases:
            _fw_pretty_list.append(_aliases[0])
    _fw_pretty_str = '، '.join(_fw_pretty_list) if is_ar else \
                     ', '.join(_fw_pretty_list)
    if is_ar:
        _fw_clause = (
            (f" وتشمل الأُطر التنظيمية المختارة المُلزِمة لـ{org_name}: "
             f"{_fw_pretty_str}.")
            if _fw_pretty_list else ''
        )
    else:
        _fw_clause = (
            (f" The selected regulatory frameworks binding {org_name} "
             f"include: {_fw_pretty_str}.")
            if _fw_pretty_list else ''
        )

    # Build the three category paragraphs. Each paragraph is keyword-rich
    # so `_check_environment_topic_coverage` recognises the category.
    if is_ar:
        cat_regulatory = (
            f"**السياق التنظيمي:** يفرض الإطار التنظيمي المُطبَّق على "
            f"{org_name} — وعلى رأسه متطلبات {fw_short} المعمول بها في "
            f"قطاع {sector} — التزامات محدّدة على حوكمة {domain}، بما "
            f"يشمل إثبات تطبيق الضوابط والحوكمة المستمرة وإعداد أدلة "
            f"التدقيق وفق اللوائح والأنظمة السارية."
            + _fw_clause
            + _maturity_frame + _mode_advisory
        )
        cat_threat = (
            f"**سياق التهديدات:** تُشير البيانات العامة لفرق الاستجابة "
            f"الوطنية خلال آخر دورة تقرير إلى ارتفاع ملحوظ في حوادث "
            f"اختراق سلاسل الإمداد، والتصيد الموجّه، وحملات برامج الفدية "
            f"— مما يرفع أولوية تحصين ضوابط {domain} لدى {org_name} "
            f"وتسريع النضج التشغيلي في الاستجابة للحوادث."
        )
        cat_business = (
            f"**السياق التشغيلي وسياق الأعمال:** يترتب على {org_name} "
            f"موازنة متطلبات التحول الرقمي مع الحفاظ على استمرارية "
            f"الأعمال والعمليات في قطاع {sector}، وضمان أن تواكب "
            f"استثمارات {domain} وتيرة توسع الخدمات والعمليات دون "
            f"إحداث فجوات تدقيقية أو ضغط تشغيلي على الكوادر."
            + _challenges_clause
        )
    else:
        cat_regulatory = (
            f"**Regulatory context:** The regulatory framework applicable "
            f"to {org_name} — primarily the {fw_short} obligations for "
            f"the {sector} sector — places explicit compliance obligations "
            f"on {domain} governance, including demonstrable control "
            f"implementation, ongoing governance, and the ability to "
            f"produce audit evidence under regulation, law, and statute."
            + _fw_clause
            + _maturity_frame + _mode_advisory
        )
        cat_threat = (
            f"**Threat context:** Public reporting from national CERT "
            f"bodies over the last reporting cycle shows a marked rise "
            f"in supply-chain compromise incidents, targeted phishing "
            f"attacks, and ransomware campaigns — raising the priority "
            f"of hardening {org_name}'s core {domain} controls and "
            f"accelerating operational maturity in incident response."
        )
        cat_business = (
            f"**Business & operational context:** {org_name} must "
            f"balance digital transformation timelines against "
            f"operational continuity obligations specific to the "
            f"{sector} sector, ensuring that {domain} investments keep "
            f"pace with service and customer-operations growth without "
            f"introducing audit gaps or operational pressure on staff."
            + _challenges_clause
        )

    chunk = '\n\n'.join([cat_regulatory, cat_threat, cat_business])
    env = env.rstrip() + '\n\n' + chunk + '\n'
    summary['paragraphs_added'] = 3
    summary['categories_covered'] = ['regulatory', 'threat', 'business']
    summary['generation_mode'] = generation_mode
    summary['maturity'] = maturity

    # Gap 3: consulting-mode — inject a 5-column sector-specific threat matrix
    # (Actor → Attack Vector → Likelihood → Impact → Current Control) so the
    # environment section matches Big-4 threat-context deliverables. The matrix
    # is only appended when the mode is consulting/assurance AND no existing
    # threat matrix header is already present (idempotent).
    _is_consulting_env = str(generation_mode).lower() in ('consulting', 'assurance')
    _has_threat_matrix = (
        'Threat Actor' in env or 'جهة التهديد' in env
        or 'Attack Vector' in env or 'ناقل الهجوم' in env
    )
    if _is_consulting_env and not _has_threat_matrix:
        if is_ar:
            threat_matrix = (
                "\n\n**مصفوفة التهديدات القطاعية:**\n\n"
                "| جهة التهديد | ناقل الهجوم | الاحتمالية | التأثير | الضابط الحالي |\n"
                "|-------------|------------|------------|---------|----------------|\n"
                f"| مجموعات التهديد المتقدمة (APT) | التصيد الموجّه واستغلال الثغرات | عالية | حرج | {fw_short} — الكشف والاستجابة |\n"
                f"| برامج الفدية المنظّمة | استغلال بيانات اعتماد مسرّبة | عالية | حرج | عزل الشبكة + النسخ الاحتياطي |\n"
                f"| مخاطر سلسلة الإمداد الرقمية | اختراق طرف ثالث موثوق | متوسطة | عالٍ | إدارة مخاطر الموردين ({fw_short}) |\n"
                f"| التهديد الداخلي (قصد أو إهمال) | سوء استخدام الصلاحيات المميزة | منخفضة–متوسطة | عالٍ | PAM + مراقبة السلوك |\n"
                f"| الهجمات على البنية التحتية الحيوية | هجمات DDoS وحقن التهديدات | متوسطة | عالٍ | أنظمة مكافحة DDoS والتصفية |\n"
            )
        else:
            threat_matrix = (
                "\n\n**Sector Threat Matrix:**\n\n"
                "| Threat Actor | Attack Vector | Likelihood | Impact | Current Control |\n"
                "|--------------|---------------|------------|--------|-----------------|\n"
                f"| Advanced Persistent Threat (APT) groups | Spear-phishing + zero-day exploitation | High | Critical | {fw_short} detection & response controls |\n"
                f"| Organised ransomware affiliates | Credential theft via dark-web leaks | High | Critical | Network segmentation + backup recovery |\n"
                f"| Digital supply-chain attackers | Trusted third-party compromise | Medium | High | Third-party risk management ({fw_short}) |\n"
                f"| Insider threat (malicious or negligent) | Privileged access abuse | Low–Medium | High | PAM controls + behavioural monitoring |\n"
                f"| Critical-infrastructure attackers | DDoS + OT/IT boundary exploitation | Medium | High | Anti-DDoS + network filtering |\n"
            )
        env = env.rstrip() + threat_matrix
        summary['threat_matrix_added'] = True

    if not has_structured_block:
        if is_ar:
            tbl = (
                "\n\n| البُعد | الإشارة / المصدر | التأثير المحتمل |\n"
                "|--------|------------------|----------------|\n"
                f"| تنظيمي | متطلبات {fw_short} على قطاع {sector} | عالٍ |\n"
                f"| تهديد | ارتفاع حوادث سلاسل الإمداد والتصيد الموجّه | عالٍ |\n"
                f"| أعمال | ضغط التحوّل الرقمي واستمرارية خدمات {domain} | متوسط |\n"
            )
        else:
            tbl = (
                "\n\n| Dimension | Signal / Source | Potential Impact |\n"
                "|-----------|-----------------|------------------|\n"
                f"| Regulatory | {fw_short} obligations applicable to {sector} | High |\n"
                f"| Threat | Rising supply-chain compromise & targeted phishing | High |\n"
                f"| Business | Digital-transformation pressure on {domain} continuity | Medium |\n"
            )
        env = env.rstrip() + tbl
        summary['context_table_added'] = True

    sections['environment'] = head + env.rstrip() + '\n\n' + marker + '\n'
    return summary


def synthesize_objectives_depth(sections, lang, domain='Cyber Security',
                                 fw_short='NCA ECC', sector='General',
                                 org_name='The Organization',
                                 org_structure_is_none=False,
                                 challenge_flags=None,
                                 diagnostic_gaps=None,
                                 maturity='initial',
                                 generation_mode='drafting'):
    """Diagnostic-driven Strategic Objectives synth.

    Ensures the vision section contains a Strategic Objectives table with
    ≥ 3 substantive rows. Contract (prompt Part 2A):
      - If org_structure_is_none=True, at least one objective addresses
        governance-structure establishment.
      - For each true challenge_flag, an objective targets that theme
        (e.g. awareness → 'raise workforce awareness to X%').
      - Existing substantive objectives are preserved; synth only fills
        gaps below the richness bar or missing thematic coverage.

    Returns dict with rebuilt/preserved/injected details.
    """
    summary = {'rebuilt': False, 'preserved': 0, 'injected': []}
    vision = sections.get('vision', '') or ''
    is_ar = (lang == 'ar')
    challenge_flags = challenge_flags or {}
    diagnostic_gaps = diagnostic_gaps or []

    # Existing objectives — parse + dedupe
    # MULTILINE is REQUIRED here: the same `hdr` regex is used twice —
    # by `_ts_table_rows` (which strips per line, so MULTILINE is moot)
    # AND by `hdr.search(vision)` below at the canonical-replace branch
    # (which needs `^` to match at any line start). Without MULTILINE
    # the search returns None for any vision text where the table is
    # not at character 0, the synth falls into the "no existing table"
    # branch, and APPENDS a second `### Strategic Objectives` heading
    # + table below the original — violating the prompt's clause 6
    # "no duplicate objectives table".
    hdr = _ts_re.compile(
        r'^\|\s*#\s*\|\s*(?:Objective|الهدف(?:\s+الاستراتيجي)?|الأهداف)\s*\|',
        _ts_re.IGNORECASE | _ts_re.MULTILINE,
    )
    # Must be identical to the tf_re in count_valid_objective_rows so
    # that `len(existing_rows)` == count_valid_objective_rows() and the
    # early-return gate never fires while the audit gate still fails.
    # Singular forms (month/year/week/day) are already covered by the
    # plural-or-singular alternatives (months?/years?/weeks?/days?).
    # Bound the leading digit group to \d{1,6} (any real timeframe fits
    # within 6 digits) so the NFA does not need to try all O(n) split
    # points when the input contains a long run of digit characters.
    tf_re = _ts_re.compile(
        r'\d{1,6}\s*(?:months?|years?|weeks?|days?'
        r'|أشهر|شهر|شهراً|سنوات|سنة|أسابيع|أسبوع|أيام|يوم)'
        r'|(?:within|خلال)\s+\d{1,6}'
        r'|(?:within|خلال)\s+(?:months?|years?|weeks?|days?'
        r'|أشهر|شهر|شهراً|سنوات|سنة|أسابيع|أسبوع|أيام|يوم)',
        _ts_re.IGNORECASE,
    )
    existing_rows = []  # list of cell-lists (without #)
    for cells in _ts_table_rows(vision, hdr):
        if len(cells) != 5:
            continue
        if not cells[0].replace('.', '').isdigit():
            continue
        if any(_ts_is_placeholder(cells[i]) for i in (1, 2, 3)):
            continue
        if not tf_re.search(cells[4] or ''):
            continue
        if tf_re.search(cells[1] or ''):
            continue
        existing_rows.append(list(cells[1:]))
    summary['preserved'] = len(existing_rows)

    # Determine what's needed
    _existing_blob = ' | '.join(' '.join(str(c) for c in r)
                                 for r in existing_rows)

    def _mentions(row_blob, en_tokens, ar_tokens):
        tl = row_blob.lower()
        for t in en_tokens:
            if t in tl:
                return True
        for t in ar_tokens:
            if t in row_blob:
                return True
        return False

    coverage = {
        'structural': _mentions(_existing_blob,
            ('governance', 'structure', 'committee', 'charter',
             'org design'),
            ('حوكمة', 'هيكل', 'لجنة', 'ميثاق', 'توجيه')),
        'awareness': _mentions(_existing_blob,
            ('awareness', 'training', 'phishing'),
            ('وعي', 'تدريب', 'تصيد')),
        'incident_response': _mentions(_existing_blob,
            ('soc', 'siem', 'incident', 'detection', 'response'),
            ('مراقبة', 'استجابة', 'حوادث', 'كشف')),
        'suppliers': _mentions(_existing_blob,
            ('supplier', 'vendor', 'third-party', 'third party'),
            ('موردين', 'أطراف ثالثة', 'سلسلة الإمداد')),
        'compliance': _mentions(_existing_blob,
            ('compliance', 'audit'),
            ('امتثال', 'تدقيق')),
    }

    need_structural = (org_structure_is_none and not coverage['structural'])
    need_challenges = [k for k, v in challenge_flags.items()
                       if v and not coverage.get(k, False)]
    # Use richness threshold so synth fires when below the gate's bar
    # (4), not the older 3-row contract.
    below_min = len(existing_rows) < max(3, _RICHNESS_MIN_SO_ROWS)

    if not need_structural and not need_challenges and not below_min:
        summary['rebuilt'] = False
        return summary

    # Priority-objective bank — each row is a full 4-tuple
    # (objective, target_metric, justification, timeframe)
    if is_ar:
        priority_bank = {
            'structural': (
                f'إنشاء هيكل حوكمة {domain} الرسمي لـ{org_name}',
                'اعتماد ميثاق اللجنة وهيكل RACI',
                f'يغلق فجوة البنية التنظيمية المشخّصة - أساس {fw_short}',
                'خلال 6 أشهر',
            ),
            'awareness': (
                f'رفع نسبة اجتياز التوعية بـ{domain} لكوادر {org_name}',
                '≥ 90%',
                'يغلق فجوة الوعي المشخّصة في التشخيص',
                'خلال 9 أشهر',
            ),
            'incident_response': (
                f'تشغيل قدرات الكشف والاستجابة لحوادث {domain}',
                'اعتماد كتيب الاستجابة وتشغيل SOC',
                f'يغلق فجوة الاستجابة وفق {fw_short}',
                'خلال 12 شهراً',
            ),
            'staffing': (
                f'بناء الكفاءات المتخصصة في {domain}',
                'سد 80% من الشواغر المتخصصة',
                'يعالج نقص الكوادر المشخّص',
                'خلال 18 شهراً',
            ),
            'suppliers': (
                f'تفعيل إدارة مخاطر الأطراف الثالثة',
                '100% من الموردين الحرجين مُقيّمون',
                f'يعالج فجوة مخاطر سلسلة الإمداد وفق {fw_short}',
                'خلال 12 شهراً',
            ),
            'compliance': (
                f'الامتثال الكامل لمتطلبات {fw_short}',
                '100% من الضوابط المطبقة مع أدلة تدقيق',
                'يعالج فجوة إثبات الامتثال',
                'خلال 12 شهراً',
            ),
            'baseline': (
                f'تنفيذ خط الأساس لضوابط {fw_short}',
                '100% من ضوابط الأولوية العليا مطبقة',
                'يعالج فجوات النضج الأولية',
                'خلال 12 شهراً',
            ),
        }
    else:
        priority_bank = {
            'structural': (
                f'Establish formal {domain} governance structure at {org_name}',
                'Approved committee charter + RACI',
                f'Closes diagnosed structural gap — foundation for {fw_short}',
                'Within 6 months',
            ),
            'awareness': (
                f'Raise {domain} awareness pass rate across {org_name} workforce',
                '≥ 90%',
                'Closes diagnosed awareness gap',
                'Within 9 months',
            ),
            'incident_response': (
                f'Operationalize {domain} detection & incident response',
                'Approved IR runbook + operational SOC',
                f'Closes IR capability gap per {fw_short}',
                'Within 12 months',
            ),
            'staffing': (
                f'Build specialist {domain} workforce capability',
                '80% of specialist roles filled',
                'Addresses diagnosed staffing shortage',
                'Within 18 months',
            ),
            'suppliers': (
                'Activate third-party risk management',
                '100% of critical suppliers assessed',
                f'Closes supply-chain risk gap per {fw_short}',
                'Within 12 months',
            ),
            'compliance': (
                f'Full {fw_short} compliance',
                '100% controls implemented with audit evidence',
                'Closes compliance-evidence gap',
                'Within 12 months',
            ),
            'baseline': (
                f'Implement {fw_short} control baseline',
                '100% of highest-priority controls deployed',
                'Addresses foundational maturity gaps',
                'Within 12 months',
            ),
        }

    new_rows = []
    if need_structural:
        new_rows.append(priority_bank['structural'])
        summary['injected'].append('structural')
    for k in need_challenges:
        if k in priority_bank:
            new_rows.append(priority_bank[k])
            summary['injected'].append(k)
    for dg in diagnostic_gaps:
        if isinstance(dg, dict):
            title = str(dg.get('title') or '').strip()
        elif isinstance(dg, str):
            title = dg.strip()
        else:
            continue
        if not title:
            continue
        # Skip if already covered
        tl = title.lower()
        if (tl in _existing_blob.lower()
                or any(tl in str(nr[0]).lower() for nr in new_rows)):
            continue
        if is_ar:
            new_rows.append((
                f'معالجة: {title}',
                '100% إغلاق',
                f'ناتج مباشر عن تشخيص {org_name}',
                'خلال 12 شهراً',
            ))
        else:
            new_rows.append((
                f'Remediate: {title}',
                '100% closure',
                f'Direct outcome of {org_name} diagnostic',
                'Within 12 months',
            ))
        summary['injected'].append(f'dx:{title[:30]}')

    # ── Top-up to RICHNESS threshold (prompt clause 3) ─────────
    # The richness gate requires _RICHNESS_MIN_SO_ROWS (4) substantive
    # SO rows; the previous "below 3" top-up loop only ever filled to
    # 3, so a clean run with no diagnostic challenges still 422'd at
    # so_rows_insufficient_for_richness. Fix: iterate the priority
    # bank in a deterministic diagnostic-relevance order, skipping
    # entries already chosen, so the top-up emits DISTINCT rows
    # aligned to existing context (not duplicate baseline filler).
    _topup_order = ('baseline', 'compliance', 'structural', 'awareness',
                    'incident_response', 'staffing', 'suppliers')
    _already = {tuple(r) for r in new_rows}
    _i = 0
    _min_target = max(3, _RICHNESS_MIN_SO_ROWS)
    while ((len(existing_rows) + len(new_rows)) < _min_target
           and _i < len(_topup_order) * 2):
        _key = _topup_order[_i % len(_topup_order)]
        _i += 1
        _row = priority_bank.get(_key)
        if not _row or tuple(_row) in _already:
            continue
        new_rows.append(_row)
        _already.add(tuple(_row))
        summary['injected'].append(f'topup:{_key}')

    # Now rebuild the vision section. Strategy: preserve everything in
    # vision BEFORE the Strategic Objectives table, replace the objectives
    # table canonically, and preserve everything AFTER (rare).
    if is_ar:
        obj_heading = '### الأهداف الاستراتيجية'
        obj_header = '| # | الهدف الاستراتيجي | المقياس المستهدف | المبرر | الإطار الزمني |'
        obj_sep = '|---|-------------------|-------------------|--------|----------------|'
    else:
        obj_heading = '### Strategic Objectives'
        obj_header = '| # | Objective | Target Metric | Justification | Timeframe |'
        obj_sep = '|---|-----------|---------------|---------------|-----------|'

    # Find existing objectives-table span to replace
    obj_hdr_m = hdr.search(vision)
    if obj_hdr_m:
        # Find where the table ends (first non-pipe line after header)
        before_table = vision[:obj_hdr_m.start()]
        # Trim trailing whitespace + optional preceding ### heading line
        # so we can re-emit obj_heading consistently
        _head_m = _ts_re.search(
            r'###\s+(?:Strategic\s+Objectives|الأهداف(?:\s+الاستراتيجية)?)'
            r'[^\n]*\n',
            before_table, _ts_re.IGNORECASE,
        )
        if _head_m:
            before_table = before_table[:_head_m.start()]
        # Walk from table header to end of table
        _pos = obj_hdr_m.start()
        _lines = vision[_pos:].split('\n')
        _i = 0
        while _i < len(_lines):
            s = _lines[_i].strip()
            if s.startswith('|') and s.endswith('|'):
                _i += 1
                continue
            if s == '':
                # allow one blank then stop
                _i += 1
                break
            break
        after_table = '\n'.join(_lines[_i:])
        pre_block = before_table.rstrip()
    else:
        # No existing objectives table — but a stale `### Strategic
        # Objectives` heading (without a table) may exist from an
        # earlier malformed AI emission. Strip it so the canonical
        # emit below does not produce a duplicate heading. Without
        # this, repair would APPEND `### الأهداف الاستراتيجية` AND its
        # canonical table BELOW the orphan heading, violating prompt
        # clause 6 ("no duplicate objective headers/tables").
        pre_block = vision.rstrip()
        _orphan_m = _ts_re.search(
            r'###\s+(?:Strategic\s+Objectives|الأهداف(?:\s+الاستراتيجية)?)'
            r'[^\n]*(?:\n[^\n#|]*)*',
            pre_block, _ts_re.IGNORECASE,
        )
        if _orphan_m:
            pre_block = (pre_block[:_orphan_m.start()]
                         + pre_block[_orphan_m.end():]).rstrip()
        after_table = ''

    # Emit canonical objectives block
    all_rows = existing_rows + [list(t) for t in new_rows]
    out = []
    if pre_block:
        out.append(pre_block)
        out.append('')
    out.append(obj_heading)
    out.append('')
    out.append(obj_header)
    out.append(obj_sep)
    for idx, r in enumerate(all_rows, start=1):
        # Ensure 4 cells
        while len(r) < 4:
            r.append('—')
        out.append('| ' + ' | '.join([str(idx)] + [str(c) for c in r[:4]]) + ' |')
    out.append('')
    if after_table.strip():
        out.append(after_table.rstrip())

    sections['vision'] = '\n'.join(out).rstrip() + '\n'
    summary['rebuilt'] = True
    summary['total_after'] = len(all_rows)
    return summary


def synthesize_roadmap_depth(sections, lang, domain='Cyber Security',
                             fw_short='NCA ECC',
                             generation_mode='drafting',
                             org_structure_is_none=False,
                             challenge_flags=None,
                             diagnostic_gaps=None,
                             technologies=None,
                             sector='General',
                             org_name='The Organization'):
    """Diagnostic-driven roadmap row synthesis.

    Prepends PRIORITY rows reflecting diagnosed signals BEFORE the generic
    template bank:
      - If org_structure_is_none=True: a governance-setup row is injected
        at position 1 (earliest timeframe).
      - For each true challenge_flag (awareness/incident_response/
        staffing/suppliers/compliance): matching activity row is injected
        when absent.
      - If diagnostic_gaps list provided: each entry becomes a row.
    After priority rows, generic templates fill any remaining slots to
    reach the richness minimum.

    generation_mode affects padding above the minimum:
      drafting  → min
      consulting → min + 1
      assurance → min + 2
    Returns count of rows added.
    """
    roadmap = sections.get('roadmap', '') or ''
    current = _count_substantive_roadmap_rows(roadmap)
    is_ar = (lang == 'ar')
    challenge_flags = challenge_flags or {}
    diagnostic_gaps = diagnostic_gaps or []
    technologies = technologies or []

    # Existing roadmap coverage check (same pattern as gaps synth): does a
    # substantive row already address each diagnostic signal? Used to
    # avoid double-injection and to determine whether to force synthesis
    # even when count ≥ minimum (governance-is-none contract).
    def _row_mentions(row_text, en_tokens, ar_tokens):
        tl = row_text.lower()
        for t in en_tokens:
            if t in tl:
                return True
        for t in ar_tokens:
            if t in row_text:
                return True
        return False

    # Parse existing rows to check signal coverage.
    _simple_hdr = _ts_re.compile(
        r'^\|\s*#\s*\|\s*(?:Activity|النشاط)\s*\|',
        _ts_re.IGNORECASE,
    )
    existing_rows_text = []
    for cells in _ts_table_rows(roadmap, _simple_hdr):
        if cells and cells[0].replace('.', '').isdigit():
            existing_rows_text.append(' '.join(str(c) for c in cells))
    _existing_blob = ' | '.join(existing_rows_text)

    coverage = {
        'structural': _row_mentions(_existing_blob,
            ('governance', 'structure', 'steering', 'committee',
             'organizational', 'charter', 'org design'),
            ('حوكمة', 'هيكل', 'لجنة', 'ميثاق', 'توجيه')),
        'awareness': _row_mentions(_existing_blob,
            ('awareness', 'training', 'phishing'),
            ('وعي', 'تدريب', 'تصيد')),
        'incident_response': _row_mentions(_existing_blob,
            ('soc', 'siem', 'incident', 'detection', 'response'),
            ('مراقبة', 'استجابة', 'حوادث', 'كشف')),
        'staffing': _row_mentions(_existing_blob,
            ('staff', 'hiring', 'recruit', 'skill'),
            ('تعيين', 'كوادر', 'كفاءات', 'مهارات')),
        'suppliers': _row_mentions(_existing_blob,
            ('supplier', 'vendor', 'third-party', 'third party'),
            ('موردين', 'أطراف ثالثة', 'سلسلة الإمداد')),
        'compliance': _row_mentions(_existing_blob,
            ('audit', 'evidence', 'compliance'),
            ('تدقيق', 'أدلة', 'امتثال')),
        'continuity': _row_mentions(_existing_blob,
            ('continuity', 'bcp', 'disaster recovery', 'resilience', 'backup'),
            ('استمرارية', 'التعافي', 'الكوارث', 'النسخ الاحتياطي')),
        'monitoring': _row_mentions(_existing_blob,
            ('monitoring', 'observability', 'visibility',
             'continuous monitoring'),
            ('رصد', 'المراقبة المستمرة', 'الرؤية')),
    }
    # Decide which priority rows are needed
    priority_slots = []
    if org_structure_is_none and not coverage['structural']:
        priority_slots.append('structural')
    for k in ('awareness', 'incident_response', 'staffing',
              'suppliers', 'compliance', 'continuity', 'monitoring'):
        if challenge_flags.get(k) and not coverage.get(k, False):
            priority_slots.append(k)
    # Technology-gap priority (Part 2E: "if technologies selected are
    # weak / missing, roadmap must include targeted implementation or
    # enhancement steps"). Uses the synth's own tech detection since
    # ctx might not have it.
    _tech_blob_rm = ' '.join(str(t).lower() for t in (technologies or []))
    _rm_has = {
        'siem': any(k in _tech_blob_rm for k in
                    ('siem', 'splunk', 'sentinel', 'qradar')),
        'edr':  any(k in _tech_blob_rm for k in
                    ('edr', 'xdr', 'crowdstrike', 'sentinelone')),
        'iam':  any(k in _tech_blob_rm for k in
                    ('iam', 'okta', 'active directory', 'azure ad')),
        'backup': any(k in _tech_blob_rm for k in
                      ('backup', 'veeam', 'commvault')),
    }
    _rm_missing_key = [k for k, v in _rm_has.items() if not v]
    # Only add technology priority slot if NOT already covered by
    # an existing row AND ≥ 2 key categories missing (or nothing selected)
    _tech_covered_in_roadmap = (
        'siem' in _existing_blob.lower()
        or 'edr' in _existing_blob.lower()
        or 'نشر' in _existing_blob  # "deploy" in Arabic
    )
    if ((not technologies or len(_rm_missing_key) >= 2)
            and not _tech_covered_in_roadmap):
        priority_slots.append('technology_gap')

    # If count already meets minimum AND no priority injection is needed,
    # short-circuit.
    _mode_lc = str(generation_mode).lower()
    _is_consulting_roadmap = _mode_lc in ('consulting', 'assurance')
    needed_floor = _RICHNESS_MIN_ROADMAP_ROWS
    if _mode_lc == 'consulting':
        needed_floor += 2   # Gap 5: raise consulting floor (was +1)
    elif _mode_lc == 'assurance':
        needed_floor += 3   # assurance gets even more depth
    if (current >= needed_floor and not priority_slots
            and not diagnostic_gaps):
        return 0

    # Gap 5: consulting/assurance mode uses specific named roles (CISO, DPO,
    # etc.) and quantified deliverables (≥ X% of Y classified, etc.) rather
    # than generic "Team" owners and "Approved document" deliverables.
    if _is_consulting_roadmap:
        if is_ar:
            priority_bank = {
                'structural': (
                    f'تأسيس هيكل حوكمة {domain} الرسمي لـ{org_name}',
                    f'المدير التنفيذي / CISO',
                    'الشهر 1 إلى الشهر 3',
                    (f'ميثاق لجنة حوكمة معتمد + مصفوفة RACI كاملة لأدوار {domain} '
                     f'+ تعيين CISO رسمياً — يغلق فجوة الهيكل البنيوي ({fw_short})'),
                ),
                'awareness': (
                    f'برنامج توعية وتدريب {domain} لكوادر {org_name}',
                    'مسؤول الموارد البشرية + CISO',
                    'الشهر 2 إلى الشهر 9',
                    f'≥ 90% من الكوادر يجتازون التدريب + ≤ 5% معدل الوقوع بالتصيد',
                ),
                'incident_response': (
                    f'تأسيس SOC وتشغيل قدرات الكشف والاستجابة لحوادث {domain}',
                    'CISO + مسؤول SOC',
                    'الشهر 2 إلى الشهر 6',
                    (f'SOC عامل 24/7 (MTTD ≤ 60 دق) + SIEM منتج + '
                     f'كتيب الاستجابة معتمد وفق {fw_short}'),
                ),
                'staffing': (
                    f'بناء الكفاءات المتخصصة في {domain}',
                    'مسؤول الموارد البشرية',
                    'الشهر 3 إلى الشهر 12',
                    '≥ 80% من الشواغر المتخصصة مشغولة + خطط تطوير مهني موثقة',
                ),
                'suppliers': (
                    f'إطلاق برنامج إدارة مخاطر الأطراف الثالثة لـ{org_name}',
                    'مسؤول مخاطر الأطراف الثالثة (TPRM) / DPO',
                    'الشهر 4 إلى الشهر 10',
                    f'100% من الموردين الحرجين مُقيَّمون وفق {fw_short} + نماذج تعاقدية معتمدة',
                ),
                'compliance': (
                    f'بناء منظومة أدلة الامتثال لـ{fw_short}',
                    'مسؤول الحوكمة والمخاطر والامتثال (GRC)',
                    'الشهر 3 إلى الشهر 9',
                    '100% من الضوابط الحرجة موثقة بأدلة تدقيق + تقارير ربعية للإدارة العليا',
                ),
                'continuity': (
                    f'تفعيل إطار استمرارية الأعمال والتعافي لـ{org_name}',
                    'مسؤول الاستمرارية التشغيلية + مدير تقنية المعلومات',
                    'الشهر 4 إلى الشهر 12',
                    ('خطة BCP/DR معتمدة + ≥ 2 اختبار تعافٍ سنوي + '
                     '100% تغطية الأصول الحيوية بنسخ احتياطية مُختبَرة'),
                ),
                'monitoring': (
                    f'تطوير قدرات الرصد والمراقبة المستمرة لأصول {domain}',
                    'CISO + مهندس المراقبة الأمنية',
                    'الشهر 2 إلى الشهر 8',
                    ('≥ 95% تغطية الأصول الحيوية بالرصد الآني + '
                     f'لوحات مراقبة تشغيلية وفق {fw_short}'),
                ),
                'technology_gap': (
                    f'اقتناء ونشر القدرات التقنية الأساسية المفقودة',
                    'مدير تقنية المعلومات + CISO',
                    'الشهر 1 إلى الشهر 9',
                    ('SIEM/EDR/IAM/Backup منتجة ومدمجة + '
                     f'أدلة تشغيل موثقة وفق {fw_short}'),
                ),
            }
        else:
            priority_bank = {
                'structural': (
                    f'Establish formal {domain} governance structure for {org_name}',
                    'CEO / CISO', 'Months 1-3',
                    (f'Approved governance committee charter + full RACI matrix '
                     f'for {domain} roles + formal CISO appointment — '
                     f'satisfies {fw_short} governance domain'),
                ),
                'awareness': (
                    f'{domain} awareness & security training programme for {org_name} staff',
                    'CISO / HR Director', 'Months 2-9',
                    f'≥ 90% of staff pass annual training; ≤ 5% phishing simulation click-rate',
                ),
                'incident_response': (
                    f'Establish SOC and {domain} detection/response capability',
                    'CISO / SOC Manager', 'Months 2-6',
                    (f'24/7 SOC operational (MTTD ≤ 60 min; MTTR ≤ 4 hrs) + '
                     f'production SIEM + approved {fw_short}-compliant IR runbook'),
                ),
                'staffing': (
                    f'Build {domain} specialist workforce at {org_name}',
                    'HR Director', 'Months 3-12',
                    f'≥ 80% of specialist {domain} roles filled + documented development plans',
                ),
                'suppliers': (
                    f'Launch third-party risk management programme at {org_name}',
                    'TPRM Lead / DPO', 'Months 4-10',
                    f'100% of critical suppliers assessed per {fw_short} controls + approved contract templates',
                ),
                'compliance': (
                    f'Build {fw_short} compliance-evidence system',
                    'GRC Director', 'Months 3-9',
                    f'100% of critical controls documented with audit evidence + quarterly executive reporting',
                ),
                'continuity': (
                    f'Activate business continuity & DR framework at {org_name}',
                    'COO / IT Director', 'Months 4-12',
                    ('Approved BCP/DR plan + ≥ 2 recovery tests per year + '
                     '100% of critical assets covered by tested backup procedures'),
                ),
                'monitoring': (
                    f'Build continuous monitoring capability for {domain} assets',
                    'CISO / Security Architect', 'Months 2-8',
                    (f'≥ 95% of critical assets under real-time monitoring + '
                     f'operational dashboards aligned to {fw_short}'),
                ),
                'technology_gap': (
                    f'Acquire and deploy missing foundational {domain} technical capabilities',
                    'CIO / CISO', 'Months 1-9',
                    (f'SIEM/EDR/IAM/Backup production-ready + integrated + '
                     f'documented per {fw_short} technical controls'),
                ),
            }
    else:
        # Drafting-mode priority bank — generic owners and deliverables
        if is_ar:
            priority_bank = {
                'structural': (
                    f'تأسيس هيكل حوكمة {domain} الرسمي لـ{org_name}',
                    f'رئيس {org_name}',
                    'الشهر 1 إلى الشهر 3',
                    (f'ميثاق لجنة الحوكمة معتمد + هيكل تنظيمي + مصفوفة RACI '
                     f'لأدوار {domain} — يغلق فجوة الهيكل البنيوي'),
                ),
                'awareness': (
                    f'برنامج توعية وتدريب {domain} لكوادر {org_name}',
                    'الموارد البشرية',
                    'الشهر 2 إلى الشهر 9',
                    'مسار تدريبي معتمد + سجل الاجتياز الدوري',
                ),
                'incident_response': (
                    f'تأسيس SOC وتشغيل قدرات الكشف والاستجابة لحوادث {domain}',
                    f'عمليات {domain}',
                    'الشهر 2 إلى الشهر 6',
                    (f'SOC عامل 24/7 + SIEM منتج + كتيب الاستجابة '
                     f'لحوادث {domain}'),
                ),
                'staffing': (
                    f'بناء الكفاءات المتخصصة في {domain}',
                    'الموارد البشرية + التدريب',
                    'الشهر 3 إلى الشهر 12',
                    'خطة توظيف + شهادات تخصصية + مسار تطوير مهني',
                ),
                'suppliers': (
                    f'إطلاق برنامج إدارة مخاطر الأطراف الثالثة لـ{org_name}',
                    f'إدارة {domain}',
                    'الشهر 4 إلى الشهر 10',
                    f'سجل تقييم الموردين وفق {fw_short} + نماذج تعاقدية',
                ),
                'compliance': (
                    f'بناء منظومة أدلة الامتثال لـ{fw_short}',
                    'الحوكمة والامتثال',
                    'الشهر 3 إلى الشهر 9',
                    'مستودع أدلة التدقيق + خطة الإبلاغ الدوري',
                ),
                'continuity': (
                    f'تفعيل إطار استمرارية الأعمال والتعافي لـ{org_name}',
                    f'إدارة {domain} وتقنية المعلومات',
                    'الشهر 4 إلى الشهر 12',
                    ('خطة BCP/DR معتمدة + اختبار تعافي دوري + '
                     'مستودع نسخ احتياطي منتظم'),
                ),
                'monitoring': (
                    f'تطوير قدرات الرصد والمراقبة المستمرة لأصول {domain}',
                    f'عمليات {domain}',
                    'الشهر 2 إلى الشهر 8',
                    ('لوحات مراقبة حية + تغطية رصد كاملة + '
                     'إجراءات استجابة مرتبطة'),
                ),
                'technology_gap': (
                    f'اقتناء ونشر القدرات التقنية الأساسية المفقودة',
                    f'تقنية المعلومات و{domain}',
                    'الشهر 1 إلى الشهر 9',
                    ('قدرات تقنية منتجة: SIEM/EDR/IAM/Backup مدمجة ومختبرة '
                     'مع أدلة التشغيل'),
                ),
            }
        else:
            priority_bank = {
                'structural': (
                    f'Establish formal {domain} governance structure for {org_name}',
                    f'{org_name} CEO', 'Months 1-3',
                    (f'Approved committee charter + org structure + RACI '
                     f'matrix — closes structural gap'),
                ),
                'awareness': (
                    f'{domain} awareness & training programme for {org_name} staff',
                    'HR', 'Months 2-9',
                    'Approved training curriculum + periodic pass-rate records',
                ),
                'incident_response': (
                    f'Establish SOC and {domain} detection/response capability',
                    f'{domain} Operations', 'Months 2-6',
                    f'24/7 SOC + production SIEM + {domain} IR runbook',
                ),
                'staffing': (
                    f'Build {domain} specialist workforce',
                    'HR + Training', 'Months 3-12',
                    'Hiring plan + certifications + professional-development track',
                ),
                'suppliers': (
                    f'Launch third-party risk management programme at {org_name}',
                    f'{domain} Management', 'Months 4-10',
                    f'{fw_short}-aligned supplier assessment register + contracts',
                ),
                'compliance': (
                    f'Build {fw_short} compliance-evidence system',
                    'GRC', 'Months 3-9',
                    'Audit-evidence repository + periodic reporting plan',
                ),
                'continuity': (
                    f'Activate business continuity & DR framework at {org_name}',
                    f'{domain} Management + IT', 'Months 4-12',
                    ('Approved BCP/DR plan + periodic recovery testing + '
                     'regular backup repository'),
                ),
                'monitoring': (
                    f'Build continuous monitoring capability for {domain} assets',
                    f'{domain} Operations', 'Months 2-8',
                    ('Live monitoring dashboards + full detection coverage + '
                     'linked response procedures'),
                ),
                'technology_gap': (
                    f'Acquire and deploy missing foundational technical capabilities',
                    f'IT + {domain}', 'Months 1-9',
                    ('Production tech capabilities: SIEM/EDR/IAM/Backup '
                     'integrated and tested with operations runbooks'),
                ),
            }

    # Build new rows: priority first, then diagnostic_gaps entries, then
    # generic fill.
    has_header = bool(_ts_re.compile(
        r'^\|\s*#\s*\|\s*(?:Activity|النشاط)\s*\|\s*(?:Owner|المسؤول)\s*\|',
        _ts_re.IGNORECASE | _ts_re.MULTILINE,
    ).search(roadmap))
    existing_row_nums = set()
    if has_header:
        for cells in _ts_table_rows(roadmap, _simple_hdr):
            if cells and cells[0].replace('.', '').isdigit():
                existing_row_nums.add(int(cells[0]))
    next_n = max(existing_row_nums) + 1 if existing_row_nums else 1

    templates_ar = [
        (f'تنفيذ موجة المعالجة الأولى وإغلاق الفجوات الحرجة',
         f'تقنية المعلومات', 'الشهر 4 إلى الشهر 9',
         'أدلة إغلاق الضوابط الحرجة'),
        (f'إجراء تقييم الضوابط وفق {fw_short} وإصدار خطة المعالجة',
         'فريق الحوكمة والامتثال', 'الشهر 3 إلى الشهر 6',
         'تقرير التقييم وخطة المعالجة'),
        (f'تطوير قدرات المراقبة المستمرة وتكامل الأدوات',
         f'عمليات {domain}', 'الشهر 5 إلى الشهر 10',
         'لوحات المراقبة التشغيلية'),
        # ── Additional context-driven substantive templates (prompt
        # clause 2 + 5) so the floor (4) is always reachable even
        # when no priority slots and no diagnostic_gaps fire.
        (f'إعداد سياسات وإجراءات {domain} وفق متطلبات {fw_short}',
         f'فريق الحوكمة في {org_name}', 'الشهر 2 إلى الشهر 5',
         'حزمة سياسات وإجراءات معتمدة قابلة للتدقيق'),
        (f'تنفيذ برنامج التدقيق الداخلي والتقارير التنفيذية لـ{domain}',
         'التدقيق الداخلي', 'الشهر 6 إلى الشهر 12',
         'تقارير تدقيق ربعية وخطط معالجة موثقة'),
        (f'إدارة سجل المخاطر التشغيلية لـ{domain} في قطاع {sector}',
         f'إدارة المخاطر في {org_name}', 'الشهر 1 إلى الشهر 12',
         'سجل مخاطر مُحدَّث + خطة استجابة مفعَّلة'),
    ]
    templates_en = [
        ('Execute first remediation wave and close critical gaps',
         'IT Operations', 'Months 4-9', 'Critical-control closure evidence'),
        (f'Conduct {fw_short} control assessment and produce remediation plan',
         'GRC Team', 'Months 3-6', 'Assessment report & remediation plan'),
        ('Develop continuous monitoring capability and tool integration',
         f'{domain} Operations', 'Months 5-10', 'Operational monitoring dashboards'),
        # Additional context-driven substantive templates
        (f'Develop {domain} policies and procedures aligned to {fw_short}',
         f'{org_name} Governance', 'Months 2-5',
         'Approved auditable policy + procedures pack'),
        (f'Run internal audit programme and executive reporting for {domain}',
         'Internal Audit', 'Months 6-12',
         'Quarterly audit reports + documented remediation plans'),
        (f'Operate {domain} risk register for the {sector} sector',
         f'{org_name} Risk Management', 'Months 1-12',
         'Live risk register + active response plan'),
    ]
    generic_templates = templates_ar if is_ar else templates_en

    # Assemble new_tuples (activity, owner, timeline, deliverable)
    new_tuples = []
    for slot in priority_slots:
        new_tuples.append(priority_bank[slot])

    for dg in diagnostic_gaps:
        if isinstance(dg, dict):
            title = str(dg.get('title') or dg.get('name') or '').strip()
            if not title:
                continue
        elif isinstance(dg, str):
            title = dg.strip()
        else:
            continue
        # Skip if existing rows or priority rows already cover it
        tl = title.lower()
        dup = (_row_mentions(_existing_blob, (tl,), (title,)) or
               any(tl in t[0].lower() for t in new_tuples))
        if dup:
            continue
        if is_ar:
            new_tuples.append((
                f'معالجة: {title}',
                f'فريق {domain}',
                'الشهر 3 إلى الشهر 9',
                f'أدلة إغلاق الفجوة وفق {fw_short}',
            ))
        else:
            new_tuples.append((
                f'Remediate: {title}',
                f'{domain} Team', 'Months 3-9',
                f'Gap-closure evidence aligned to {fw_short}',
            ))

    # Fill to reach the floor
    gi = 0
    while (current + len(new_tuples)) < needed_floor and gi < len(generic_templates):
        new_tuples.append(generic_templates[gi])
        gi += 1

    if not new_tuples:
        return 0

    # If no header, inject one
    if not has_header:
        if is_ar:
            skeleton = (
                ('## 5. خارطة طريق التنفيذ\n\n' if '## 5' not in roadmap else '')
                + '| # | النشاط | المسؤول | الإطار الزمني | المخرج |\n'
                + '|---|--------|---------|---------------|--------|\n'
            )
        else:
            skeleton = (
                ('## 5. Implementation Roadmap\n\n' if '## 5' not in roadmap else '')
                + '| # | Activity | Owner | Timeline | Deliverable |\n'
                + '|---|----------|-------|----------|-------------|\n'
            )
        roadmap = roadmap.rstrip() + ('\n\n' if roadmap.strip() else '') + skeleton

    # Append rows
    lines = roadmap.split('\n')
    insert_after = len(lines) - 1
    for idx in range(len(lines) - 1, -1, -1):
        s = lines[idx].strip()
        if s.startswith('|') and s.endswith('|'):
            insert_after = idx
            break

    new_rows = []
    for offset, tpl in enumerate(new_tuples):
        new_rows.append(
            f'| {next_n + offset} | {tpl[0]} | {tpl[1]} | {tpl[2]} | {tpl[3]} |'
        )
    lines = lines[:insert_after + 1] + new_rows + lines[insert_after + 1:]
    sections['roadmap'] = '\n'.join(lines)
    return len(new_rows)


def synthesize_kpi_depth(sections, lang, domain='Cyber Security',
                         fw_short='NCA ECC',
                         generation_mode='drafting',
                         org_structure_is_none=False,
                         challenge_flags=None,
                         diagnostic_gaps=None,
                         sector='General',
                         org_name='The Organization'):
    """Diagnostic-driven KPI row synthesis.

    Prioritized KPI injection order (prompt Part 2F):
      - If org_structure_is_none=True: "governance implementation" KPI
      - For each active challenge_flag: matching KPI (awareness pass rate,
        IR detection time, TPRM coverage, etc.)
      - Generic fallback templates last, only if still below floor
    generation_mode adjusts padding (drafting=bar, consulting=+1,
    assurance=+2).
    Returns count of rows added.
    """
    kpis = sections.get('kpis', '') or ''
    current = count_substantive_kpis(kpis)
    is_ar = (lang == 'ar')
    challenge_flags = challenge_flags or {}
    diagnostic_gaps = diagnostic_gaps or []

    _mode_lc = str(generation_mode).lower()
    needed_floor = _RICHNESS_MIN_KPI_ROWS
    if _mode_lc == 'consulting':
        needed_floor += 1
    elif _mode_lc == 'assurance':
        needed_floor += 2

    hdr_re = _ts_re.compile(
        r'^\|\s*#\s*\|\s*(?:KPI Description|وصف المؤشر|KPI|المؤشر|Metric)\s*\|',
        _ts_re.IGNORECASE,
    )
    existing_row_nums = set()
    existing_blob_parts = []
    for cells in _ts_table_rows(kpis, hdr_re):
        if cells and cells[0].replace('.', '').isdigit():
            existing_row_nums.add(int(cells[0]))
            existing_blob_parts.append(' '.join(str(c) for c in cells))
    _existing_blob = ' | '.join(existing_blob_parts)
    next_n = max(existing_row_nums) + 1 if existing_row_nums else 1
    has_header = bool(hdr_re.search(kpis))

    def _mentions(en_tokens, ar_tokens):
        tl = _existing_blob.lower()
        for t in en_tokens:
            if t in tl:
                return True
        for t in ar_tokens:
            if t in _existing_blob:
                return True
        return False

    coverage = {
        'structural': _mentions(
            ('governance', 'charter', 'committee', 'structure',
             'organizational'),
            ('حوكمة', 'ميثاق', 'لجنة', 'هيكل')),
        'awareness': _mentions(
            ('awareness', 'training', 'phishing'),
            ('وعي', 'تدريب', 'تصيد')),
        'incident_response': _mentions(
            ('soc', 'siem', 'incident', 'detection', 'response time'),
            ('مراقبة', 'استجابة', 'حوادث', 'كشف')),
        'suppliers': _mentions(
            ('supplier', 'vendor', 'third-party', 'third party'),
            ('موردين', 'أطراف ثالثة', 'سلسلة الإمداد')),
        'compliance': _mentions(
            ('control implementation', 'compliance', 'audit'),
            ('تطبيق الضوابط', 'امتثال', 'تدقيق')),
        'staffing': _mentions(
            ('staff', 'skill', 'workforce', 'hiring'),
            ('كوادر', 'مهارات', 'توظيف')),
    }

    need_slots = []
    if org_structure_is_none and not coverage['structural']:
        need_slots.append('structural')
    for k in ('awareness', 'incident_response', 'suppliers',
              'compliance', 'staffing'):
        if challenge_flags.get(k) and not coverage[k]:
            need_slots.append(k)

    # If row count meets floor AND no diagnostic injection needed, no-op
    if (current >= needed_floor and not need_slots and not diagnostic_gaps):
        return 0

    # Priority KPI bank — each entry is a 5-tuple
    # (description, target, formula, justification, timeframe)
    if is_ar:
        priority_bank = {
            'structural': (
                f'نسبة اكتمال تأسيس هيكل حوكمة {domain}',
                '100%',
                '(الخطوات المنجزة ÷ خطوات التأسيس) × 100',
                'يقيس إغلاق فجوة الهيكل البنيوي المشخّصة',
                'خلال 6 أشهر',
            ),
            'awareness': (
                f'نسبة اجتياز تدريبات التوعية بـ{domain}',
                '≥ 90%',
                '(المجتازين ÷ المستهدفين) × 100',
                f'يعكس إغلاق فجوة الوعي لدى كوادر {org_name}',
                'خلال 9 أشهر',
            ),
            'incident_response': (
                'متوسط زمن الاستجابة للحوادث (MTTR)',
                '≤ 4 ساعات',
                '(مجموع زمن الاستجابة ÷ عدد الحوادث)',
                f'يقيس قدرة SOC المنفذ ضمن خارطة الطريق',
                'خلال 6 أشهر',
            ),
            'suppliers': (
                'نسبة تغطية تقييم الأطراف الثالثة',
                '100% للموردين الحرجين',
                '(المُقيَّم ÷ الإجمالي) × 100',
                f'يقيس إغلاق فجوة مخاطر سلسلة الإمداد',
                'خلال 12 شهراً',
            ),
            'compliance': (
                f'نسبة تطبيق ضوابط {fw_short} مع أدلة التدقيق',
                '≥ 95%',
                '(المطبّق المُوَثَّق ÷ الإجمالي) × 100',
                'يقيس إغلاق فجوة إثبات الامتثال',
                'خلال 12 شهراً',
            ),
            'staffing': (
                'نسبة سدّ الشواغر المتخصصة',
                '≥ 80%',
                '(الشواغر المسدودة ÷ المطلوبة) × 100',
                'يعالج نقص الكوادر المشخّص',
                'خلال 18 شهراً',
            ),
            'baseline': (
                f'نسبة إغلاق الفجوات المشخّصة',
                '100%',
                '(المغلقة ÷ الإجمالي) × 100',
                f'يعكس تقدم {org_name} على خارطة الطريق',
                'خلال 12 شهراً',
            ),
        }
    else:
        priority_bank = {
            'structural': (
                f'{domain} governance structure establishment completion',
                '100%',
                '(Steps completed ÷ Setup steps) × 100',
                'Measures closure of diagnosed structural gap',
                'Within 6 months',
            ),
            'awareness': (
                f'{domain} awareness training pass rate',
                '≥ 90%',
                '(Passed ÷ Enrolled) × 100',
                f'Reflects closure of awareness gap at {org_name}',
                'Within 9 months',
            ),
            'incident_response': (
                'Mean time to respond (MTTR)',
                '≤ 4 hours',
                '(Sum response time ÷ # incidents)',
                'Measures SOC capability delivered via roadmap',
                'Within 6 months',
            ),
            'suppliers': (
                'Third-party assessment coverage',
                '100% of critical suppliers',
                '(Assessed ÷ Total) × 100',
                'Measures closure of supply-chain risk gap',
                'Within 12 months',
            ),
            'compliance': (
                f'{fw_short} control implementation with audit evidence',
                '≥ 95%',
                '(Implemented & evidenced ÷ Total) × 100',
                'Measures closure of compliance-evidence gap',
                'Within 12 months',
            ),
            'staffing': (
                'Specialist role fill rate',
                '≥ 80%',
                '(Filled ÷ Required) × 100',
                'Addresses diagnosed staffing shortage',
                'Within 18 months',
            ),
            'baseline': (
                f'Diagnosed-gap closure rate',
                '100%',
                '(Closed ÷ Total) × 100',
                f'Reflects {org_name} progress on roadmap',
                'Within 12 months',
            ),
        }

    # Inject header if missing
    if not has_header:
        if is_ar:
            skeleton = (
                ('## 6. مؤشرات الأداء الرئيسية\n\n' if '## 6' not in kpis else '')
                + '| # | وصف المؤشر | القيمة المستهدفة | صيغة الاحتساب | المبرر | الإطار الزمني |\n'
                + '|---|-------------|-----------------|----------------|--------|----------------|\n'
            )
        else:
            skeleton = (
                ('## 6. Key Performance Indicators\n\n' if '## 6' not in kpis else '')
                + '| # | KPI Description | Target Value | Calculation Formula | Justification | Timeframe |\n'
                + '|---|-----------------|--------------|---------------------|---------------|-----------|\n'
            )
        kpis = kpis.rstrip() + ('\n\n' if kpis.strip() else '') + skeleton

    # Assemble new rows: priority → diagnostic_gaps → baseline fill
    new_tuples = []
    for slot in need_slots:
        new_tuples.append(priority_bank[slot])

    for dg in diagnostic_gaps:
        if isinstance(dg, dict):
            title = str(dg.get('title') or dg.get('name') or '').strip()
        elif isinstance(dg, str):
            title = dg.strip()
        else:
            continue
        if not title:
            continue
        tl = title.lower()
        if tl in _existing_blob.lower():
            continue
        if any(tl[:30] in str(t[0]).lower() for t in new_tuples):
            continue
        if is_ar:
            new_tuples.append((
                f'مؤشر إغلاق: {title}',
                '100%', '(المُنجز ÷ الإجمالي) × 100',
                'ناتج مباشر عن تشخيص الفجوة', 'خلال 12 شهراً',
            ))
        else:
            new_tuples.append((
                f'Closure KPI: {title}',
                '100%', '(Completed ÷ Total) × 100',
                'Direct diagnostic outcome', 'Within 12 months',
            ))

    # Baseline fill
    while (current + len(new_tuples)) < needed_floor:
        new_tuples.append(priority_bank['baseline'])
        if len(new_tuples) > 15:
            break

    if not new_tuples:
        sections['kpis'] = kpis
        return 0

    lines = kpis.split('\n')
    insert_after = -1
    in_tbl = False
    for idx, ln in enumerate(lines):
        s = ln.strip()
        if not in_tbl:
            if hdr_re.match(s):
                in_tbl = True
            continue
        if s.startswith('|') and s.endswith('|'):
            insert_after = idx
        else:
            break
    if insert_after < 0:
        insert_after = len(lines) - 1

    new_rows = []
    for offset, tpl in enumerate(new_tuples):
        new_rows.append(
            f'| {next_n + offset} | {tpl[0]} | {tpl[1]} | {tpl[2]} | {tpl[3]} | {tpl[4]} |'
        )
    lines = lines[:insert_after + 1] + new_rows + lines[insert_after + 1:]
    sections['kpis'] = '\n'.join(lines)
    return len(new_rows)


def synthesize_confidence_depth(sections, lang, domain='Cyber Security',
                                 fw_short='NCA ECC',
                                 org_name='The Organization',
                                 maturity='initial',
                                 generation_mode='drafting',
                                 roadmap_rows=None):
    """Ensure Confidence section has ≥ _RICHNESS_MIN_CSF_ROWS CSF rows and
    ≥ _RICHNESS_MIN_RISK_ROWS risk rows (each with non-placeholder
    mitigation). Also ensures a Confidence Score value and a score
    justification paragraph are present. Appends deterministic rows/
    paragraphs where counts fall short.

    Maturity drives the default score (if no score is present):
      initial     → 55%
      developing  → 65%
      defined     → 75%
      managed     → 82%
      optimized   → 88%

    Mitigation-plan linkage (prompt Part 2G): when `roadmap_rows` is
    provided as a list of (row_number, short_activity_text) tuples,
    risk mitigation text references specific roadmap row numbers by
    theme matching — e.g. a "Resource & Skills Constraints" risk
    references the staffing-related roadmap row. Falls back to
    generic mitigation phrasing when no matching roadmap row exists.

    generation_mode does not currently alter deterministic CSF / risk
    phrasing (they are already comprehensive) but is accepted for
    signature compatibility with _apply_final_synthesis_pass.

    Returns dict with keys: csf_added, risks_added, score_added,
    justification_added, mitigation_links (list of {risk, roadmap_row}
    for each risk row whose mitigation was linked to a specific
    roadmap row).
    """
    summary = {'csf_added': 0, 'risks_added': 0,
               'score_added': False, 'justification_added': False,
               'mitigation_links': []}
    conf = sections.get('confidence', '') or ''
    is_ar = (lang == 'ar')

    # ── Extract roadmap rows for mitigation linkage (prompt Part 2G)
    # If the caller didn't pass `roadmap_rows` explicitly, parse the
    # roadmap section ourselves. Each roadmap row is stored as a tuple
    # (row_number, activity_text_stripped).
    if roadmap_rows is None:
        roadmap_rows = []
        roadmap_text = sections.get('roadmap', '') or ''
        if roadmap_text:
            _rm_hdr = _ts_re.compile(
                r'^\|\s*#\s*\|\s*(?:Activity|النشاط)\s*\|',
                _ts_re.IGNORECASE,
            )
            for _cells in _ts_table_rows(roadmap_text, _rm_hdr):
                if (_cells and _cells[0].replace('.', '').isdigit()
                        and len(_cells) >= 2
                        and not _ts_is_placeholder(_cells[1])):
                    try:
                        roadmap_rows.append((int(_cells[0]),
                                              _cells[1].strip()))
                    except (ValueError, IndexError):
                        continue

    # Helper: find the roadmap row number whose activity text contains
    # any of the given tokens. Returns None if no match.
    def _find_roadmap_row_for(en_tokens, ar_tokens):
        for _rn, _act in roadmap_rows:
            _lc = _act.lower()
            for _t in en_tokens:
                if _t in _lc:
                    return _rn
            for _t in ar_tokens:
                if _t in _act:
                    return _rn
        return None

    # Maturity → default score percentage
    _maturity_lc = str(maturity).lower().strip()
    _score_pct = {
        'initial':    55,
        'ad-hoc':     55,
        'ad hoc':     55,
        'developing': 65,
        'defined':    75,
        'managed':    82,
        'optimized':  88,
    }.get(_maturity_lc, 65)

    # Initialize canonical structure if section is empty.
    if not conf.strip():
        if is_ar:
            conf = (
                "## 7. تقييم الثقة والمخاطر\n\n"
                f"**درجة الثقة:** {_score_pct}%\n\n"
                "### مبررات التقييم\n\n"
                f"تستند هذه الدرجة إلى مستوى النضج الحالي لـ{org_name} "
                f"والفجوات المحددة في ضوابط {domain} وفق {fw_short}، "
                "إضافةً إلى القدرة التنفيذية المتاحة لتنفيذ خطة المعالجة "
                "خلال أفق ثمانية عشر شهراً.\n\n"
                "### عوامل النجاح الحرجة:\n\n"
                "| # | العامل | الوصف | الأهمية |\n"
                "|---|-------|-------|--------|\n"
                "### المخاطر الرئيسية:\n\n"
                "| # | المخاطر | الاحتمالية | التأثير | خطة المعالجة |\n"
                "|---|--------|-----------|--------|-------------|\n"
            )
        else:
            conf = (
                "## 7. Confidence Assessment & Risks\n\n"
                f"**Confidence Score:** {_score_pct}%\n\n"
                "### Score Justification\n\n"
                f"This score reflects the current maturity posture of "
                f"{org_name} and the gaps identified in {domain} controls "
                f"against {fw_short}, together with the executive capacity "
                "available to execute the remediation plan over an "
                "18-month horizon.\n\n"
                "### Critical Success Factors:\n\n"
                "| # | Factor | Description | Importance |\n"
                "|---|--------|-------------|------------|\n"
                "### Key Risks:\n\n"
                "| # | Risk | Likelihood | Impact | Mitigation Plan |\n"
                "|---|------|------------|--------|-----------------|\n"
            )
        summary['score_added'] = True
        summary['justification_added'] = True
    else:
        # Score injection when absent
        score_re = _ts_re.compile(
            r'(?:\*\*)?(?:Confidence\s+Score|درجة\s+الثقة)(?:\*\*)?\s*:?\s*'
            r'(?:\*\*)?\s*\d{1,3}\s*%',
            _ts_re.IGNORECASE,
        )
        if not score_re.search(conf):
            if is_ar:
                score_line = f"\n\n**درجة الثقة:** {_score_pct}%\n"
            else:
                score_line = f"\n\n**Confidence Score:** {_score_pct}%\n"
            conf = conf.rstrip() + score_line
            summary['score_added'] = True

        # Justification injection when absent
        just_re = _ts_re.compile(
            r'^#{2,4}\s*(?:Score\s+Justification|مبررات?\s+(?:التقييم|الثقة))'
            r'|(?:justification|rationale|مبررات?)',
            _ts_re.MULTILINE | _ts_re.IGNORECASE,
        )
        if not just_re.search(conf):
            if is_ar:
                just_block = (
                    "\n\n### مبررات التقييم\n\n"
                    f"تستند هذه الدرجة إلى مستوى النضج الحالي لـ{org_name} "
                    f"والفجوات المحددة في ضوابط {domain} وفق {fw_short}، "
                    "إضافةً إلى القدرة التنفيذية المتاحة لتنفيذ خطة المعالجة.\n"
                )
            else:
                just_block = (
                    "\n\n### Score Justification\n\n"
                    f"This score reflects the current maturity posture of "
                    f"{org_name} and the gaps identified in {domain} controls "
                    f"against {fw_short}, together with the executive capacity "
                    "available to execute the remediation plan.\n"
                )
            conf = conf.rstrip() + just_block
            summary['justification_added'] = True

    # CSF top-up
    n_csf = _count_csf_rows(conf)
    if n_csf < _RICHNESS_MIN_CSF_ROWS:
        csf_needed = _RICHNESS_MIN_CSF_ROWS - n_csf
        csf_hdr = _ts_re.compile(
            r'^\|\s*#\s*\|\s*(?:Factor|العامل)\s*\|',
            _ts_re.IGNORECASE,
        )
        # If no CSF table exists yet in this section, inject heading +
        # table skeleton so the appended rows land under a real header.
        if not csf_hdr.search(conf):
            if is_ar:
                csf_skel = (
                    "\n\n### عوامل النجاح الحرجة:\n\n"
                    "| # | العامل | الوصف | الأهمية |\n"
                    "|---|-------|-------|--------|\n"
                )
            else:
                csf_skel = (
                    "\n\n### Critical Success Factors:\n\n"
                    "| # | Factor | Description | Importance |\n"
                    "|---|--------|-------------|------------|\n"
                )
            conf = conf.rstrip() + csf_skel
        csf_rows = list(_ts_table_rows(conf, csf_hdr))
        existing = {int(c[0]) for c in csf_rows
                    if c and c[0].replace('.', '').isdigit()}
        next_n = max(existing) + 1 if existing else 1
        templates_ar = [
            (f'دعم القيادة التنفيذية',
             f'رعاية فعّالة من الإدارة العليا لـ{org_name} لتنفيذ استراتيجية {domain}',
             'حرج'),
            (f'توفر الموارد والكوادر المؤهلة',
             f'كفاءات بشرية قادرة على تشغيل ضوابط {fw_short} وإدارتها',
             'عالٍ'),
            (f'إطار حوكمة {domain} قابل للتشغيل',
             'لجنة توجيه دورية وصلاحيات قرار واضحة ومسار تصعيد محدّد',
             'عالٍ'),
            (f'تمويل كافٍ ومستقر',
             'ميزانية متعددة السنوات مرتبطة بأولويات خطة المعالجة وليست بندوداً سنوية',
             'عالٍ'),
            (f'بيئة تقنية متكاملة',
             f'منصات {domain} متكاملة مع الأنظمة التشغيلية وسجلات موحدة',
             'متوسط'),
        ]
        templates_en = [
            ('Executive Leadership Support',
             f'Active sponsorship from {org_name} senior leadership to '
             f'execute the {domain} strategy', 'Critical'),
            ('Qualified Resources & Talent',
             f'Competent personnel able to operate and govern {fw_short} controls',
             'High'),
            (f'Operable {domain} Governance Framework',
             'Standing steering committee with clear decision rights and '
             'escalation paths', 'High'),
            ('Stable Multi-Year Funding',
             'Multi-year budget tied to remediation plan priorities rather '
             'than annual line items', 'High'),
            ('Integrated Technology Environment',
             f'{domain} platforms integrated with operational systems and '
             'unified logging', 'Medium'),
        ]
        templates = templates_ar if is_ar else templates_en
        new_rows = []
        for offset in range(csf_needed):
            tpl = templates[offset % len(templates)]
            new_rows.append(
                f'| {next_n + offset} | {tpl[0]} | {tpl[1]} | {tpl[2]} |'
            )
        # Insert after last CSF-table line
        conf = _append_rows_under_header(conf, csf_hdr, new_rows)
        summary['csf_added'] = csf_needed

    # Risk top-up
    n_risks = _count_risk_rows_with_mitigation(conf)
    if n_risks < _RICHNESS_MIN_RISK_ROWS:
        risks_needed = _RICHNESS_MIN_RISK_ROWS - n_risks
        risk_hdr = _ts_re.compile(
            r'^\|\s*#\s*\|\s*(?:Risk|المخاطر|الخطر)\s*\|',
            _ts_re.IGNORECASE,
        )
        # If no Risk table exists yet, inject heading + skeleton.
        if not risk_hdr.search(conf):
            if is_ar:
                risk_skel = (
                    "\n\n### المخاطر الرئيسية:\n\n"
                    "| # | المخاطر | الاحتمالية | التأثير | خطة المعالجة |\n"
                    "|---|--------|-----------|--------|-------------|\n"
                )
            else:
                risk_skel = (
                    "\n\n### Key Risks:\n\n"
                    "| # | Risk | Likelihood | Impact | Mitigation Plan |\n"
                    "|---|------|------------|--------|-----------------|\n"
                )
            conf = conf.rstrip() + risk_skel
        risk_rows = list(_ts_table_rows(conf, risk_hdr))
        existing = {int(c[0]) for c in risk_rows
                    if c and c[0].replace('.', '').isdigit()}
        next_n = max(existing) + 1 if existing else 1
        # Each entry is (risk_title, likelihood, impact, fallback_mitigation,
        # linkage_tokens_en, linkage_tokens_ar).
        # When a roadmap row matches the linkage tokens, the mitigation
        # text is suffixed with "(see Roadmap Row #N)" or the Arabic
        # equivalent "(انظر صف خارطة الطريق رقم N)".
        risks_ar = [
            ('محدودية الموارد والكفاءات', 'متوسط', 'عالٍ',
             'التنفيذ المرحلي وتحديد أولويات وفق المخاطر وتدبير الكوادر مبكراً',
             ('staff', 'skill', 'hiring', 'workforce'),
             ('كوادر', 'مهارات', 'توظيف')),
            ('مقاومة التغيير', 'عالٍ', 'متوسط',
             'برنامج إدارة تغيير شامل مدعوم تنفيذياً وحملات توعية موجّهة',
             ('awareness', 'training', 'change'),
             ('وعي', 'تدريب', 'تغيير')),
            ('تأخر موردي التقنية', 'متوسط', 'متوسط',
             'تعدّد المصادر وتضمين عقوبات تعاقدية مرتبطة بالأداء',
             ('supplier', 'vendor', 'third-party', 'deploy', 'siem', 'edr'),
             ('موردين', 'أطراف ثالثة', 'نشر', 'تقني')),
            ('تضخم النطاق', 'متوسط', 'عالٍ',
             'لجنة ضبط تغييرات رسمية وحوكمة صارمة لأي توسعات نطاق',
             ('governance', 'committee', 'charter', 'steering'),
             ('حوكمة', 'لجنة', 'ميثاق', 'توجيه')),
            ('تغيّر المتطلبات التنظيمية', 'متوسط', 'عالٍ',
             'آلية رصد تنظيمي دورية ومراجعة خطة المعالجة ربع سنوياً',
             ('compliance', 'audit', 'evidence'),
             ('امتثال', 'تدقيق', 'أدلة')),
        ]
        risks_en = [
            ('Resource & Skills Constraints', 'Medium', 'High',
             'Phased implementation, risk-based prioritisation, early '
             'talent sourcing',
             ('staff', 'skill', 'hiring', 'workforce'),
             ('كوادر', 'مهارات', 'توظيف')),
            ('Change Resistance', 'High', 'Medium',
             'Comprehensive change-management programme with executive '
             'sponsorship and targeted awareness',
             ('awareness', 'training', 'change'),
             ('وعي', 'تدريب', 'تغيير')),
            ('Technology Vendor Delays', 'Medium', 'Medium',
             'Dual-sourcing strategy with performance-linked contractual '
             'penalties',
             ('supplier', 'vendor', 'third-party', 'deploy', 'siem', 'edr'),
             ('موردين', 'أطراف ثالثة', 'نشر', 'تقني')),
            ('Scope Creep', 'Medium', 'High',
             'Formal change-control committee and strict governance for '
             'any scope expansions',
             ('governance', 'committee', 'charter', 'steering'),
             ('حوكمة', 'لجنة', 'ميثاق', 'توجيه')),
            ('Regulatory Change', 'Medium', 'High',
             'Regulatory-monitoring cadence with quarterly remediation-plan '
             'review',
             ('compliance', 'audit', 'evidence'),
             ('امتثال', 'تدقيق', 'أدلة')),
        ]
        templates = risks_ar if is_ar else risks_en
        new_rows = []
        for offset in range(risks_needed):
            tpl = templates[offset % len(templates)]
            # Unpack with roadmap-linkage tokens
            _title, _lk, _imp, _mit_fb, _en_tok, _ar_tok = tpl
            # Try to find a matching roadmap row for this risk theme.
            _matched_row = _find_roadmap_row_for(_en_tok, _ar_tok)
            if _matched_row is not None:
                if is_ar:
                    _mit = (f'{_mit_fb} (انظر صف خارطة الطريق رقم '
                            f'{_matched_row})')
                else:
                    _mit = f'{_mit_fb} (see Roadmap Row #{_matched_row})'
                summary['mitigation_links'].append({
                    'risk': _title,
                    'roadmap_row': _matched_row,
                })
            else:
                _mit = _mit_fb
            new_rows.append(
                f'| {next_n + offset} | {_title} | {_lk} | {_imp} | {_mit} |'
            )
        conf = _append_rows_under_header(conf, risk_hdr, new_rows)
        summary['risks_added'] = risks_needed

    sections['confidence'] = conf
    return summary


def _append_rows_under_header(text, hdr_re, new_rows):
    """Insert new_rows immediately after the last existing data-row of the
    table whose header matches hdr_re. If no matching table exists,
    appends the rows at the end of text (caller is responsible for the
    skeleton). Returns the new text.
    """
    if not new_rows:
        return text
    lines = text.split('\n')
    insert_after = -1
    in_tbl = False
    for idx, ln in enumerate(lines):
        s = ln.strip()
        if not in_tbl:
            if hdr_re.match(s):
                in_tbl = True
            continue
        if s.startswith('|') and s.endswith('|'):
            insert_after = idx
        else:
            # Table ended.
            break
    if insert_after < 0:
        return text.rstrip() + '\n' + '\n'.join(new_rows) + '\n'
    lines = lines[:insert_after + 1] + new_rows + lines[insert_after + 1:]
    return '\n'.join(lines)


# ────────────────────────────────────────────────────────────────────────────
# STRATEGIC PILLARS DEPTH SYNTHESIS
#
# Arabic Technical Strategy requires ≥ 3 substantive pillars (each with a
# real title + ≥ 1 substantive initiative row OR ≥ 80-char narrative body).
# When the AI's pillars section falls below that bar, we rebuild it
# canonically from structured data tied to the user's domain / sector /
# framework / challenges / gaps / risks — same pattern as the KPI
# canonical rebuilder. No incremental patching of thin pillars.
# ────────────────────────────────────────────────────────────────────────────

_PILLAR_HEADING_RE_GLOBAL = _ts_re.compile(
    r'^###\s+(?:Pillar\s*\d*|Strategic\s+Pillar\s*\d*|'
    r'الركيزة(?:\s+الاستراتيجية)?\s*\d*)[^\n]*',
    _ts_re.MULTILINE | _ts_re.IGNORECASE,
)

# Single source of truth: alias to the canonical _RICHNESS_MIN_PILLARS
# defined upstream so completeness checks, richness gates, synth, and
# integrity gates cannot diverge on this threshold.
_RICHNESS_MIN_PILLARS_LOCAL = _RICHNESS_MIN_PILLARS


def _extract_existing_pillars(pillars_text):
    """Extract (title, body) tuples for each ### pillar heading in the
    pillars section. Used by rebuild_pillars_section to preserve AI-
    generated pillar content when it is already substantive.
    """
    if not pillars_text:
        return []
    matches = list(_PILLAR_HEADING_RE_GLOBAL.finditer(pillars_text))
    if not matches:
        # Fallback: any ### heading
        matches = list(_ts_re.finditer(
            r'^###\s+[^\n]+$', pillars_text, _ts_re.MULTILINE,
        ))
    out = []
    for i, m in enumerate(matches):
        title_line = pillars_text[m.start():m.end()]
        title = _ts_re.sub(r'^###\s+', '', title_line).strip()
        body_start = m.end()
        body_end = (matches[i + 1].start() if i + 1 < len(matches)
                    else len(pillars_text))
        body = pillars_text[body_start:body_end].strip()
        out.append((title, body))
    return out


def _pillar_is_substantive(body):
    """Mirror _count_substantive_pillars body check: has a pipe-table row
    with ≥ 2 non-placeholder cells OR narrative ≥ 80 chars of content.
    """
    if not body or not body.strip():
        return False
    for ln in body.splitlines():
        s = ln.strip()
        if (s.startswith('|') and s.endswith('|') and
                not _ts_re.match(r'^\|[\s\-:|]+\|$', s)):
            cells = [c.strip() for c in s.split('|')[1:-1]]
            if len(cells) >= 3 and sum(
                1 for c in cells[1:] if not _ts_is_placeholder(c)
            ) >= 2:
                return True
    stripped = _ts_re.sub(r'[*_`#>|\-]+', '', body)
    stripped = _ts_re.sub(r'\s+', ' ', stripped).strip()
    return len(stripped) >= 80


def _pillar_has_substantive_initiative(body):
    """Stricter gate-aligned check: a pillar body has a substantive
    initiative IFF it contains a pipe-table data row (under any header
    matching pillar-initiative tokens) with ≥ 2 non-placeholder cells
    in columns after `#`.

    Used by synthesize_pillars_depth's PRESERVE filter so a user-
    supplied narrative-only `### الركيزة...` heading (no initiative
    table) is REJECTED from `preserved` and the slot gets filled by a
    bank pillar that DOES carry a proper initiative table. This aligns
    the synth's preserve decision with the
    `pillars_missing_substantive_initiative` integrity gate at the
    save path; previously the synth's narrative-only fallback let
    `_pillar_is_substantive` accept these pillars while the gate
    later rejected them.
    """
    if not body or not body.strip():
        return False
    _hdr_tokens = _ts_re.compile(
        r'(?:Initiative|Description|Deliverable|Output|Expected|'
        r'المبادرة|الوصف|المخرج|المتوقع)',
        _ts_re.IGNORECASE,
    )
    in_table = False
    for ln in body.splitlines():
        s = ln.strip()
        if not (s.startswith('|') and s.endswith('|')):
            in_table = False
            continue
        if _ts_re.match(r'^\|[\s\-:|]+\|$', s):
            continue
        cells = [c.strip() for c in s.split('|')[1:-1]]
        # Header row detection (≥ 2 header tokens in cells)
        _hdr_hits = sum(1 for c in cells if _hdr_tokens.search(c or ''))
        if _hdr_hits >= 2 and not in_table:
            in_table = True
            continue
        if not in_table:
            continue
        if len(cells) < 2:
            continue
        # Drop leading # column when present
        _data = (cells[1:] if cells
                 and cells[0].replace('.', '').isdigit()
                 else cells[:])
        if (_data and sum(
                1 for c in _data
                if c and not _ts_is_placeholder(c)) >= 2):
            return True
    return False


# ────────────────────────────────────────────────────────────────────────────
# GAP ANALYSIS DIAGNOSTIC-DRIVEN SYNTHESIS
#
# Prompt Part 2D: gaps must reflect user selections and diagnostic outputs.
# If org_structure=none → the structural gap MUST appear. If challenges
# mention awareness/incident response/staffing/suppliers, corresponding
# gaps must appear. Gaps must not be replaced by generic domain defaults
# when diagnosis is available.
#
# This synthesizer REBUILDS the gaps section canonically when it is
# below the richness bar, or when the required diagnostic gaps
# (structural, challenge-keyword-driven) are missing from it. Preserves
# existing substantive gap rows; injects only gaps that are absent.
# ────────────────────────────────────────────────────────────────────────────

def _extract_existing_gap_rows(gaps_text):
    """Extract the non-placeholder data rows under the gaps main table.
    Returns a list of cell-lists (WITHOUT the # column).
    Also captures any trailing '#### دليل تنفيذ الفجوة ...' guide blocks
    keyed by row-number so they can be re-emitted if the gap row is
    preserved.
    """
    if not gaps_text:
        return [], {}
    hdr = _ts_re.compile(
        r'^\|\s*#\s*\|\s*(?:Gap|الفجوة|الفجوات)\s*\|',
        _ts_re.IGNORECASE,
    )
    rows = []
    seen_sigs = set()
    for cells in _ts_table_rows(gaps_text, hdr):
        if len(cells) < 3:
            continue
        if not cells[0].replace('.', '').isdigit():
            continue
        if any(_ts_is_placeholder(cells[i]) for i in (1, 2)):
            continue
        sig = '||'.join(cells[1:]).strip().lower()
        if sig in seen_sigs:
            continue
        seen_sigs.add(sig)
        # Pad to 5 cells (# | Gap | Description | Priority | Status)
        data_cells = list(cells[1:])
        while len(data_cells) < 4:
            data_cells.append('—')
        rows.append(data_cells)
    # Extract existing guide blocks
    guides = {}
    guide_re = _ts_re.compile(
        r'^####\s*(?:Gap\s*#?(?P<num_en>\d+)\s*Implementation Guide|'
        r'دليل تنفيذ الفجوة\s*(?:رقم|#)?\s*(?P<num_ar>\d+))'
        r'[^\n]*',
        _ts_re.MULTILINE | _ts_re.IGNORECASE,
    )
    matches = list(guide_re.finditer(gaps_text))
    for i, m in enumerate(matches):
        num = m.group('num_en') or m.group('num_ar')
        if not num or num in guides:
            continue
        start = m.start()
        end = matches[i + 1].start() if i + 1 < len(matches) else len(gaps_text)
        # Stop at next top-level ## heading
        h_m = _ts_re.search(r'^##[^#]', gaps_text[start:end], _ts_re.MULTILINE)
        if h_m:
            end = start + h_m.start()
        block = gaps_text[start:end].rstrip()
        if block.count('\n') >= 1 and len(block) >= 30:
            guides[num] = block
    return rows, guides


def synthesize_gaps_depth(sections, lang, domain='Cyber Security',
                          fw_short='NCA ECC', sector='General',
                          org_name='The Organization',
                          org_structure_is_none=False,
                          challenge_flags=None,
                          technologies=None,
                          diagnostic_gaps=None,
                          maturity='initial',
                          generation_mode='drafting'):
    """Diagnostic-driven rebuild of the Gap Analysis section.

    Contract (prompt Part 2D):
      1. If org_structure_is_none=True, a structural governance gap
         MUST be present (row 1).
      2. For each true challenge_flag (awareness / incident_response /
         staffing / suppliers / compliance), a matching gap row is
         emitted when absent.
      3. Existing substantive gap rows are preserved verbatim.
      4. If a diagnostic_gaps list is provided by the caller, each entry
         is emitted as a row (keyed by a 'title' / 'description' dict
         or a simple string).
      5. Minimum row count remains `_RICHNESS_MIN_GAP_ROWS` (2) — if
         after injection the count is below, pads from generic bank.

    Returns dict with:
      - rebuilt: bool
      - rows_before / rows_after
      - structural_gap_injected: bool
      - challenge_driven_gaps_injected: list[str]
      - diagnostic_gaps_used: int
    """
    summary = {
        'rebuilt': False,
        'structural_gap_injected': False,
        'challenge_driven_gaps_injected': [],
        'diagnostic_gaps_used': 0,
    }
    gaps = sections.get('gaps', '') or ''
    is_ar = (lang == 'ar')
    challenge_flags = challenge_flags or {}
    diagnostic_gaps = diagnostic_gaps or []

    rows_before, existing_guides = _extract_existing_gap_rows(gaps)
    summary['rows_before'] = len(rows_before)

    # Detect whether structural gap already exists (bilingual keyword check)
    def _is_structural_row(r):
        joined = ' '.join(str(c) for c in r).lower()
        return (('governance' in joined and 'structur' in joined) or
                ('organizational' in joined and 'structur' in joined) or
                'الهيكل التنظيمي' in joined or
                'حوكمة' in joined and 'هيكل' in joined)

    def _row_mentions(r, en_tokens, ar_tokens):
        joined = ' '.join(str(c) for c in r)
        joined_lc = joined.lower()
        for t in en_tokens:
            if t in joined_lc:
                return True
        for t in ar_tokens:
            if t in joined:
                return True
        return False

    has_structural = any(_is_structural_row(r) for r in rows_before)
    # Challenge-flag coverage check: does an existing row mention each
    # flagged challenge area?
    coverage = {}
    coverage['awareness'] = any(
        _row_mentions(r, ('awareness', 'training', 'phishing'),
                      ('وعي', 'تدريب', 'تصيد')) for r in rows_before)
    coverage['incident_response'] = any(
        _row_mentions(r, ('incident', 'soc', 'siem', 'response'),
                      ('حوادث', 'استجابة', 'مراقبة', 'كشف')) for r in rows_before)
    coverage['staffing'] = any(
        _row_mentions(r, ('staff', 'skill', 'workforce', 'hiring'),
                      ('موظفين', 'مهارات', 'كفاءات', 'كوادر')) for r in rows_before)
    coverage['suppliers'] = any(
        _row_mentions(r, ('supplier', 'vendor', 'third-party', 'third party'),
                      ('موردين', 'أطراف ثالثة', 'سلسلة الإمداد')) for r in rows_before)
    coverage['compliance'] = any(
        _row_mentions(r, ('compliance', 'audit', 'regulation'),
                      ('امتثال', 'تدقيق', 'تنظيمي')) for r in rows_before)

    # Decide: do we need to rebuild? Rebuild iff any of:
    #   - row count < min
    #   - org_structure_is_none and no structural row
    #   - any true challenge_flag with no coverage
    needs_inject_structural = (org_structure_is_none and not has_structural)
    needs_challenge_injection = [
        k for k, v in challenge_flags.items()
        if v and not coverage.get(k, False)
    ]
    below_min = len(rows_before) < _RICHNESS_MIN_GAP_ROWS
    if (not needs_inject_structural and not needs_challenge_injection
            and not below_min and not diagnostic_gaps):
        summary['rows_after'] = len(rows_before)
        return summary

    # ── Build the canonical section
    rows_out = list(rows_before)  # preserve existing

    # 1. Structural gap (row 1 if needed)
    if needs_inject_structural:
        if is_ar:
            struct_row = [
                'غياب هيكل حوكمة الأمن السيبراني الرسمي',
                (f'كشف التشخيص أن {org_name} لا يمتلك لجنة حوكمة معرّفة '
                 f'أو هيكلاً تنظيمياً رسمياً لإدارة {domain} — فجوة بنيوية '
                 f'أساسية تسبق كل ضوابط {fw_short} التشغيلية.'),
                'حرجة',
                'مفتوحة',
            ]
        else:
            struct_row = [
                'Absence of formal cybersecurity governance structure',
                (f'Diagnostic identified that {org_name} lacks a defined '
                 f'governance committee or formal organizational structure '
                 f'for {domain} — a foundational structural gap that '
                 f'precedes all operational {fw_short} controls.'),
                'Critical',
                'Open',
            ]
        # Prepend so it's row #1
        rows_out.insert(0, struct_row)
        summary['structural_gap_injected'] = True

    # 2. Challenge-flag-driven injection
    _chal_bank_ar = {
        'awareness': [
            'قصور الوعي الأمني لدى الكوادر',
            (f'التشخيص يشير إلى ضعف ثقافة الوعي بـ{domain} لدى كوادر {org_name}؛ '
             'يلزم برنامج تدريب ممتد وقياس نسب الاجتياز دورياً.'),
            'عالية', 'مفتوحة',
        ],
        'incident_response': [
            'غياب قدرات الكشف والاستجابة للحوادث',
            (f'التشخيص يكشف عن نقص في قدرات SOC / SIEM / IR اللازمة '
             f'لكشف حوادث {domain} في {org_name} خلال وقت مقبول وفق {fw_short}.'),
            'عالية', 'مفتوحة',
        ],
        'staffing': [
            'نقص الكفاءات المتخصصة',
            (f'التشخيص يوضح أن {org_name} لا يمتلك العدد أو المستوى المطلوب '
             f'من كوادر {domain} لتشغيل الضوابط بصورة مستدامة.'),
            'عالية', 'مفتوحة',
        ],
        'suppliers': [
            'ضعف إدارة مخاطر الأطراف الثالثة',
            (f'التشخيص يشير إلى غياب برنامج منظم لتقييم موردي {domain} '
             f'في {org_name} وفق متطلبات {fw_short}.'),
            'متوسطة', 'مفتوحة',
        ],
        'compliance': [
            'قصور في إثبات الامتثال والتدقيق',
            (f'التشخيص يكشف عن غياب أدلة تدقيق قابلة للإظهار لضوابط {fw_short} '
             f'المطبقة على {org_name}.'),
            'عالية', 'مفتوحة',
        ],
    }
    _chal_bank_en = {
        'awareness': [
            'Workforce security awareness deficit',
            (f'Diagnostic indicates low {domain} awareness culture among '
             f'{org_name} staff; a sustained training programme with '
             'periodic pass-rate measurement is required.'),
            'High', 'Open',
        ],
        'incident_response': [
            'Detection & incident response capability absent',
            (f'Diagnostic identifies deficient SOC / SIEM / IR capability '
             f'needed to detect {domain} incidents at {org_name} within '
             f'acceptable time per {fw_short}.'),
            'High', 'Open',
        ],
        'staffing': [
            'Specialist workforce shortage',
            (f'Diagnostic shows {org_name} lacks sufficient {domain} '
             f'headcount / skill level to operate controls sustainably.'),
            'High', 'Open',
        ],
        'suppliers': [
            'Third-party risk management weakness',
            (f'Diagnostic indicates no structured programme to assess '
             f'{domain} suppliers at {org_name} against {fw_short}.'),
            'Medium', 'Open',
        ],
        'compliance': [
            'Compliance evidence & audit gap',
            (f'Diagnostic identifies missing audit-ready evidence for '
             f'{fw_short} controls as implemented at {org_name}.'),
            'High', 'Open',
        ],
    }
    chal_bank = _chal_bank_ar if is_ar else _chal_bank_en
    for k in needs_challenge_injection:
        if k in chal_bank:
            rows_out.append(list(chal_bank[k]))
            summary['challenge_driven_gaps_injected'].append(k)

    # 3. Diagnostic gaps list (if provided) — each entry is either a
    #    dict {'title', 'description', 'priority'(opt), 'status'(opt)}
    #    or a plain string.
    for dg in diagnostic_gaps:
        if isinstance(dg, dict):
            title = str(dg.get('title') or dg.get('name') or '').strip()
            desc = str(dg.get('description') or dg.get('detail') or '').strip()
            prio = str(dg.get('priority') or ('عالية' if is_ar else 'High'))
            stat = str(dg.get('status') or ('مفتوحة' if is_ar else 'Open'))
        elif isinstance(dg, str):
            title = dg.strip()
            desc = (f'فجوة تم تشخيصها في {org_name}' if is_ar
                    else f'Diagnosed gap at {org_name}')
            prio = 'عالية' if is_ar else 'High'
            stat = 'مفتوحة' if is_ar else 'Open'
        else:
            continue
        if not title:
            continue
        # Skip if an existing row already has this title
        title_lc = title.lower()
        dup = any(title_lc in (r[0] or '').lower()
                  or (r[0] or '').lower() in title_lc
                  for r in rows_out)
        if dup:
            continue
        rows_out.append([title, desc or title, prio, stat])
        summary['diagnostic_gaps_used'] += 1

    # 4. Generic-bank top-up ONLY if we are still below minimum.
    _generic_bank_ar = [
        ['ضعف الضوابط التقنية الأساسية',
         (f'ضوابط {fw_short} الأساسية غير مطبقة بالكامل في {org_name}، '
          f'خاصة في مجال {domain}.'),
         'عالية', 'مفتوحة'],
        ['محدودية المراقبة والرصد',
         (f'غياب القدرة على المراقبة المستمرة لأصول {domain} الحيوية '
          f'في {org_name}.'),
         'متوسطة', 'مفتوحة'],
        ['غياب خطط استمرارية الأعمال',
         (f'خطط استمرارية الأعمال الخاصة بـ{domain} غير مكتملة أو غير '
          f'مختبرة في {org_name}.'),
         'متوسطة', 'مفتوحة'],
    ]
    _generic_bank_en = [
        ['Foundational technical-control weakness',
         (f'Core {fw_short} controls are not fully implemented at {org_name}, '
          f'particularly in the {domain} domain.'),
         'High', 'Open'],
        ['Monitoring & detection limitations',
         (f'No sustained monitoring capability for critical {domain} assets '
          f'at {org_name}.'),
         'Medium', 'Open'],
        ['Business continuity planning gaps',
         (f'{domain}-specific business continuity plans at {org_name} are '
          f'incomplete or untested.'),
         'Medium', 'Open'],
    ]
    generic_bank = _generic_bank_ar if is_ar else _generic_bank_en
    gi = 0
    while len(rows_out) < _RICHNESS_MIN_GAP_ROWS and gi < len(generic_bank):
        candidate = generic_bank[gi]
        dup = any(candidate[0].lower() in (r[0] or '').lower()
                  or (r[0] or '').lower() in candidate[0].lower()
                  for r in rows_out)
        if not dup:
            rows_out.append(list(candidate))
        gi += 1

    # ── Emit canonical section
    if is_ar:
        section_heading = '## 4. تحليل الفجوات'
        table_header = '| # | الفجوة | الوصف | الأولوية | الحالة |'
        table_sep = '|---|--------|-------|---------|--------|'
    else:
        section_heading = '## 4. Gap Analysis'
        table_header = '| # | Gap | Description | Priority | Status |'
        table_sep = '|---|-----|-------------|----------|--------|'
    out = [section_heading, '', table_header, table_sep]
    for idx, r in enumerate(rows_out, start=1):
        # Ensure 4 data cells
        while len(r) < 4:
            r.append('—')
        out.append('| ' + ' | '.join([str(idx)] + [str(c) for c in r[:4]]) + ' |')
    out.append('')

    # Re-emit existing guides for rows that were preserved. The row-number
    # for a preserved row may have shifted (structural gap is now row 1),
    # so we key off the gap TITLE. For any existing guide whose referenced
    # title matches a preserved row's title, re-emit it. Gaps that need
    # fresh guides are synthesized generically.
    for idx, r in enumerate(rows_out, start=1):
        title_lc = (r[0] or '').lower()
        # Try to find a prior guide by fuzzy title match in existing_guides
        guide_block = None
        for _num, block in existing_guides.items():
            # Check if guide's header line mentions this gap title
            first_line = block.split('\n', 1)[0]
            if title_lc and (title_lc[:30] in first_line.lower()
                             or first_line.lower().endswith(title_lc[:30])):
                guide_block = block
                break
        if guide_block:
            # Replace the guide's row-number in its heading so numbering
            # stays consistent.
            out.append(_ts_re.sub(
                r'(#?\s*)(Gap\s*#?\d+|الفجوة\s*(?:رقم|#)?\s*\d+)',
                lambda _m: (_m.group(1) + (
                    f'الفجوة رقم {idx}' if is_ar
                    else f'Gap #{idx}')),
                guide_block.split('\n', 1)[0]
            ))
            body = guide_block.split('\n', 1)[1] if '\n' in guide_block else ''
            if body:
                out.append(body)
            out.append('')
            continue
        # Synthesize a deterministic guide
        if is_ar:
            out.extend([
                f'#### دليل تنفيذ الفجوة رقم {idx}: {r[0]}',
                '',
                '| الخطوة | الإجراء | المسؤول | الإطار الزمني | الناتج |',
                '|--------|---------|---------|----------------|--------|',
                f'| 1 | التقييم التفصيلي | فريق {domain} | الشهر 1 | تقرير التقييم |',
                f'| 2 | تصميم خطة المعالجة | رئيس {domain} | شهر 2-3 | خطة المعالجة المعتمدة |',
                f'| 3 | تنفيذ الضوابط | فريق {domain} | شهر 4-6 | ضوابط مطبقة |',
                f'| 4 | التحقق والإغلاق | رئيس {domain} | شهر 7 | تقرير الإغلاق |',
                '',
            ])
        else:
            out.extend([
                f'#### Gap #{idx} Implementation Guide: {r[0]}',
                '',
                '| Step | Action | Owner | Timeframe | Output |',
                '|------|--------|-------|-----------|--------|',
                f'| 1 | Detailed assessment | {domain} Team | Month 1 | Assessment report |',
                f'| 2 | Remediation plan design | {domain} Lead | Month 2-3 | Approved plan |',
                f'| 3 | Control implementation | {domain} Team | Month 4-6 | Deployed controls |',
                f'| 4 | Validation & closure | {domain} Lead | Month 7 | Closure report |',
                '',
            ])

    sections['gaps'] = '\n'.join(out).rstrip() + '\n'
    summary['rebuilt'] = True
    summary['rows_after'] = len(rows_out)
    return summary


def synthesize_pillars_depth(sections, lang, domain='Cyber Security',
                              fw_short='NCA ECC', sector='General',
                              org_name='The Organization',
                              maturity='initial',
                              generation_mode='drafting',
                              diagnostic_gaps=None,
                              risks=None,
                              objectives=None,
                              org_structure_is_none=False,
                              challenge_flags=None,
                              technologies=None):
    """If the Strategic Pillars section has fewer than
    _RICHNESS_MIN_PILLARS_LOCAL substantive pillars, REBUILD it
    canonically from structured data. Preserves existing substantive
    pillars verbatim; fills the remaining slots from a deterministic
    bank of domain-relevant consultancy-grade pillar templates.

    Diagnostic-aware priority (prompt Part 2B):
      - If org_structure_is_none=True, a GOVERNANCE-STRUCTURE pillar is
        prepended first (before any other bank entry) because the user
        explicitly reported no defined organizational structure.
      - If maturity='initial', the pillar set prioritizes baseline
        establishment over optimization — governance + operational
        controls first, detection/TPRM/awareness after.
      - If challenge_flags indicate awareness/IR/TPRM/staffing gaps,
        the pillar pick-order weights those pillars higher.

    Rebuild — not patch — matches the prompt's "if pillars are thin,
    rebuild them" directive. Returns dict with:
      - pillars_before / pillars_after
      - rebuilt: bool
      - preserved_titles: list of AI-pillar titles kept
      - synthesized_titles: list of deterministic-pillar titles added
      - governance_pillar_injected: True when org_structure_is_none
        triggered the structural governance pillar
    """
    summary = {'rebuilt': False, 'preserved_titles': [],
               'synthesized_titles': [],
               'governance_pillar_injected': False}
    pillars = sections.get('pillars', '') or ''
    n_before = _count_substantive_pillars(pillars)
    summary['pillars_before'] = n_before
    # Even when n_before >= minimum, we STILL need to check that the
    # org_structure_is_none contract is satisfied — the prompt says
    # "if there is no defined organizational structure, one pillar must
    # explicitly address governance structure". If the existing pillars
    # don't contain a governance/structure pillar, we must rebuild to
    # inject one. Detect that below before early-returning.
    #
    # ALSO (gate alignment): if `n_before` counted narrative-only
    # pillars via `_count_substantive_pillars`'s ≥80-char fallback,
    # those would later FAIL the integrity gate's per-pillar
    # initiative-table check. Re-count strictly here using the gate-
    # aligned helper so synth doesn't bail when initiative tables are
    # missing.
    _existing_with_init = sum(
        1 for (_t, _b) in _extract_existing_pillars(pillars)
        if _pillar_has_substantive_initiative(_b)
    )
    n_before_strict = _existing_with_init
    if (n_before_strict >= _RICHNESS_MIN_PILLARS_LOCAL
            and not org_structure_is_none):
        summary['pillars_after'] = n_before
        return summary
    if (n_before_strict >= _RICHNESS_MIN_PILLARS_LOCAL
            and org_structure_is_none):
        # Look for an existing governance/structure pillar. If one exists,
        # early-return. If not, rebuild to inject it.
        _gov_tokens_ar = ('الحوكمة', 'حوكمة', 'الهيكل', 'هيكل',
                          'الهيكلة', 'هيكلة', 'اللجنة', 'لجنة',
                          'التوجيه', 'توجيه')
        _gov_tokens_en = ('governance', 'structure', 'steering',
                          'committee', 'organizational',
                          'reporting model', 'org design')
        _has_gov = False
        _pl = pillars.lower()
        for t in _gov_tokens_en:
            if t in _pl:
                _has_gov = True
                break
        if not _has_gov:
            for t in _gov_tokens_ar:
                if t in pillars:
                    _has_gov = True
                    break
        if _has_gov:
            summary['pillars_after'] = n_before
            return summary
        # else: fall through to rebuild, injecting governance pillar

    is_ar = (lang == 'ar')
    diagnostic_gaps = diagnostic_gaps or []
    risks = risks or []
    objectives = objectives or []
    challenge_flags = challenge_flags or {}
    technologies = technologies or []

    # Extract any existing pillars from the section — keep the substantive
    # ones, discard the thin ones.
    # PRESERVE FILTER: align with integrity gate. The gate at the save
    # path requires every counted pillar to have a substantive
    # initiative table row (`pillars_missing_substantive_initiative`).
    # The previous filter used `_pillar_is_substantive` which accepted
    # narrative-only pillars (≥80 chars). Those passed the synth's
    # internal counter but failed the downstream gate. Now: require
    # a substantive initiative table — so narrative-only `### الركيزة`
    # entries get dropped here and the slot is filled by a bank pillar
    # that carries a proper initiative table.
    existing = _extract_existing_pillars(pillars)
    preserved = [(t, b) for (t, b) in existing
                 if _pillar_has_substantive_initiative(b)]
    summary['preserved_titles'] = [t for t, _ in preserved]

    # Deterministic consultancy-grade pillar bank. Each pillar is designed
    # to pass _count_substantive_pillars — it has an initiative row AND a
    # narrative body well over 80 chars. Content references the user's
    # domain / framework / sector / organization. Each pillar carries
    # 3 initiative rows so synthesized pillars pass the 3+ initiative
    # depth check without requiring a separate enrichment pass.
    if is_ar:
        pillar_bank = [
            {
                'title': f'الركيزة الأولى: الحوكمة والامتثال وإدارة مخاطر {domain}',
                'narrative': (
                    f"تؤسس هذه الركيزة إطار حوكمة {domain} الرسمي لـ{org_name} "
                    f"بما يحقق الامتثال لمتطلبات {fw_short} في قطاع {sector}. "
                    "تشمل ميثاق الأمن السيبراني، وصلاحيات لجنة التوجيه، ومصفوفة "
                    "RACI، وسجل الضوابط، ومسارات التصعيد، وإعداد التقارير الدورية "
                    "للإدارة العليا، وربط القرارات بالأولويات المؤسسية."
                ),
                'initiatives': [
                    (
                        f'ميثاق الأمن السيبراني ولجنة الحوكمة',
                        f'إعداد ميثاق {domain} المعتمد وتشكيل لجنة توجيه برئاسة تنفيذية مع اختصاصات واضحة وجداول اجتماعات دورية',
                        f'ميثاق {domain} المعتمد + اختصاصات لجنة الحوكمة + محاضر الاجتماعات الربعية',
                    ),
                    (
                        f'مصفوفة RACI وإطار السياسات',
                        f'توثيق مصفوفة RACI لأدوار {domain} ومسؤولياتها وإعداد حزمة السياسات والإجراءات وفق {fw_short}',
                        f'مصفوفة RACI المعتمدة + سياسة {domain} الرئيسية + الإجراءات التشغيلية',
                    ),
                    (
                        f'سجل ضوابط {fw_short} وسجل المخاطر',
                        f'بناء سجل ضوابط {fw_short} المُرقَّم وربطه بسجل مخاطر {domain} مع خطط معالجة موثقة',
                        f'سجل ضوابط {fw_short} + سجل مخاطر نشط + خطط المعالجة الموثقة',
                    ),
                ],
            },
            {
                'title': f'الركيزة الثانية: الحماية التقنية والهندسة الأمنية',
                'narrative': (
                    f"تُحكم هذه الركيزة الضوابط التقنية الأساسية في بنية {org_name} "
                    f"بما يشمل إدارة الهوية والوصول المميز (IAM/PAM)، ونشر منصات "
                    f"الحماية المتطورة (EDR/XDR)، وتطبيق ضوابط حماية البيانات، "
                    f"وذلك وفق خط الأساس الذي يفرضه {fw_short}."
                ),
                'initiatives': [
                    (
                        'إدارة الهوية والوصول المميز (IAM/PAM)',
                        'جرد الحسابات المميزة وتطبيق المصادقة متعددة العوامل (MFA) ونشر حل PAM مع آليات مراجعة الوصول الدورية',
                        'قاموس هويات المستخدمين + خطة نشر PAM/MFA + سجل مراجعة الوصول',
                    ),
                    (
                        'نشر منصات الحماية (EDR/XDR)',
                        f'تطبيق خط الأساس الأمني للنهايات والشبكات عبر نشر EDR/XDR مع ضوابط {fw_short} التشغيلية',
                        'سياسة تكوين النهايات + خط الأساس الأمني EDR/XDR + سجل تغطية الأجهزة',
                    ),
                    (
                        'حماية البيانات والتصنيف',
                        f'تنفيذ مخطط تصنيف البيانات وضوابط التشفير وسياسات DLP وفق متطلبات {fw_short}',
                        'مخطط تصنيف البيانات + سياسة التشفير + قواعد DLP المفعَّلة',
                    ),
                ],
            },
            {
                'title': f'الركيزة الثالثة: الكشف والاستجابة والمرونة السيبرانية',
                'narrative': (
                    f"ترفع هذه الركيزة قدرة {org_name} على الكشف المبكر والاستجابة "
                    f"الفعّالة لحوادث {domain}، بما يشمل تفعيل SIEM، وإعداد كتب "
                    "الاستجابة للحوادث، وتفعيل برنامج إدارة الثغرات، وضمان استمرارية "
                    "الأعمال والتعافي من الكوارث."
                ),
                'initiatives': [
                    (
                        'SIEM وكتالوج حالات الاستخدام',
                        f'ربط مصادر السجلات بمنصة SIEM وتطوير كتالوج حالات استخدام الكشف المرتبطة بتهديدات {sector}',
                        'مصادر السجلات المُدمجة + كتالوج حالات SIEM + مصفوفة التصعيد',
                    ),
                    (
                        'كتب الاستجابة للحوادث',
                        f'إعداد كتب تشغيل الاستجابة للحوادث الحرجة وإجراء تمارين محاكاة دورية وفق متطلبات {fw_short}',
                        'كتب الاستجابة المعتمدة + تقارير تمارين المحاكاة + مؤشرات MTTD/MTTR',
                    ),
                    (
                        'إدارة الثغرات والنسخ الاحتياطي',
                        f'تطبيق إجراء إدارة الثغرات والتصحيح مع اختبارات استعادة النسخ الاحتياطي بشكل دوري',
                        'سجل الثغرات + تقارير اختبار الاستعادة + أدلة النسخ الاحتياطي',
                    ),
                ],
            },
            {
                'title': f'الركيزة الرابعة: الثقافة والقدرات والضمان المستمر',
                'narrative': (
                    f"تُطوّر هذه الركيزة كفاءات {org_name} في مجال {domain}، وتُعزّز "
                    "ثقافة الأمن السيبراني عبر برامج التوعية ومحاكاة التصيد، وإدارة "
                    "مخاطر الأطراف الثالثة، والضمان المستمر عبر التدقيق الداخلي."
                ),
                'initiatives': [
                    (
                        'برنامج التوعية ومحاكاة التصيد',
                        f'تطوير برنامج توعية {domain} المتدرج مع تمارين محاكاة التصيد ومقاييس فعالية التدريب',
                        'خطة حملة التوعية + تقارير محاكاة التصيد + معدلات الاجتياز',
                    ),
                    (
                        'تقييم مخاطر الأطراف الثالثة',
                        f'تطبيق نموذج تقييم {domain} للموردين الحرجين وفق {fw_short} مع متطلبات تعاقدية واضحة',
                        'نموذج تقييم الأطراف الثالثة + سجل مخاطر الموردين + الشروط التعاقدية',
                    ),
                    (
                        'التدقيق الداخلي والضمان المستمر',
                        f'تشغيل دورة تدقيق داخلي دورية لضوابط {fw_short} مع إصدار تقارير تنفيذية ربعية',
                        'تقارير التدقيق الداخلي + خطط المعالجة + لوحة متابعة الامتثال',
                    ),
                ],
            },
        ]
    else:
        pillar_bank = [
            {
                'title': f'Pillar 1: {domain} Governance, Compliance & Risk Management',
                'narrative': (
                    f"This pillar establishes {org_name}'s formal {domain} "
                    f"governance framework aligned to {fw_short} obligations "
                    f"in the {sector} sector. It covers the cybersecurity "
                    "charter, steering-committee authority, RACI matrix, "
                    "control register, escalation paths, and periodic "
                    "executive reporting."
                ),
                'initiatives': [
                    (
                        f'{domain} Charter & Governance Committee',
                        f'Prepare the approved {domain} charter and form an executive-chaired steering committee with clear ToR and quarterly meeting schedule',
                        f'Approved {domain} charter + Committee ToR + Quarterly meeting minutes',
                    ),
                    (
                        f'RACI Matrix & Policy Framework',
                        f'Document RACI matrix for {domain} roles and produce a policy/procedure pack aligned to {fw_short}',
                        f'Approved RACI matrix + {domain} master policy + Operating procedures',
                    ),
                    (
                        f'{fw_short} Control Register & Risk Register',
                        f'Build a numbered {fw_short} control register and link it to a live {domain} risk register with documented remediation plans',
                        f'{fw_short} control register + Live risk register + Documented remediation plans',
                    ),
                ],
            },
            {
                'title': f'Pillar 2: Technical Protection & Security Engineering',
                'narrative': (
                    f"This pillar hardens the core technical controls in "
                    f"{org_name}'s infrastructure, covering IAM/PAM, "
                    "EDR/XDR deployment, data protection and classification, "
                    f"all aligned to the {fw_short} control baseline."
                ),
                'initiatives': [
                    (
                        'Identity & Privileged Access Management (IAM/PAM)',
                        'Inventory privileged accounts, enforce MFA, and deploy a PAM solution with periodic access-review cycles',
                        'Identity inventory + PAM/MFA deployment plan + Access review register',
                    ),
                    (
                        'EDR/XDR Deployment Baseline',
                        f'Apply the endpoint and network security baseline by deploying EDR/XDR with {fw_short} operational controls',
                        'Endpoint configuration policy + EDR/XDR security baseline + Device coverage register',
                    ),
                    (
                        'Data Protection & Classification',
                        f'Implement a data classification scheme, encryption controls, and DLP policies per {fw_short} requirements',
                        'Data classification scheme + Encryption policy + Active DLP rules',
                    ),
                ],
            },
            {
                'title': 'Pillar 3: Detection, Response & Cyber Resilience',
                'narrative': (
                    f"This pillar raises {org_name}'s capacity for early "
                    f"detection and effective response to {domain} incidents, "
                    "through SIEM activation, incident response playbooks, "
                    "vulnerability management, and backup/DR resilience."
                ),
                'initiatives': [
                    (
                        'SIEM Use-Case Catalogue',
                        f'Connect log sources to the SIEM platform and develop a detection use-case catalogue linked to {sector} threat scenarios',
                        'Integrated log sources + SIEM use-case catalogue + Escalation matrix',
                    ),
                    (
                        'Incident Response Playbooks',
                        f'Develop critical incident response playbooks and run periodic simulation exercises per {fw_short} requirements',
                        'Approved IR playbooks + Simulation exercise reports + MTTD/MTTR metrics',
                    ),
                    (
                        'Vulnerability Management & Backup/DR',
                        f'Implement a vulnerability and patch management procedure with periodic backup restore testing',
                        'Vulnerability register + Restore test reports + Backup evidence',
                    ),
                ],
            },
            {
                'title': f'Pillar 4: Culture, Capabilities & Continuous Assurance',
                'narrative': (
                    f"This pillar develops {org_name}'s {domain} competency "
                    "through tiered awareness programmes, phishing simulations, "
                    "third-party cyber risk management, and continuous "
                    "assurance through internal audit."
                ),
                'initiatives': [
                    (
                        f'{domain} Awareness & Phishing Simulation',
                        f'Develop a tiered {domain} awareness programme with phishing simulations and training effectiveness metrics',
                        'Awareness campaign plan + Phishing simulation reports + Pass-rate metrics',
                    ),
                    (
                        'Third-Party Cyber Risk Assessment',
                        f'Apply a {domain} assessment template for critical suppliers under {fw_short} with clear contractual requirements',
                        'Third-party assessment template + Supplier risk register + Contractual clauses',
                    ),
                    (
                        f'Internal Audit & Continuous Assurance',
                        f'Run a periodic internal audit cycle for {fw_short} controls with quarterly executive reporting',
                        'Internal audit reports + Remediation plans + Compliance dashboard',
                    ),
                ],
            },
        ]

    # Keep existing substantive pillars first (up to 5); fill remaining
    # slots from the bank, skipping any whose title collides with an
    # already-kept pillar.
    preserved_titles_lc = {t.lower().strip() for t, _ in preserved}
    needed = _RICHNESS_MIN_PILLARS_LOCAL - len(preserved)
    # Synthesize at least `needed`, optionally +1 for consulting / +2 for
    # assurance to leave depth margin.
    _mode_lc = str(generation_mode).lower()
    if _mode_lc == 'consulting':
        needed += 1
    elif _mode_lc == 'assurance':
        needed += 2

    picked = []

    # Diagnostic-aware prepend: if org_structure_is_none, ensure the very
    # first synthesized pillar addresses governance structure explicitly,
    # regardless of bank ordering. Prompt Part 2B: "if there is no defined
    # organizational structure, one pillar must explicitly address
    # governance structure / org design / committee / reporting model".
    if org_structure_is_none:
        if is_ar:
            gov_pillar = {
                'title': (f'الركيزة الأولى: إنشاء هيكل حوكمة {domain} — '
                          f'الأساس المؤسسي المفقود'),
                'narrative': (
                    f"كشف التشخيص أن {org_name} لا يمتلك هيكلاً تنظيمياً "
                    f"معرّفاً لإدارة {domain}. تعالج هذه الركيزة هذا الغياب "
                    f"الهيكلي — وهو الأولوية القصوى قبل أي استثمار في "
                    f"الضوابط التشغيلية — عبر إنشاء لجنة الحوكمة، "
                    f"وتوصيف المسؤوليات، واعتماد ميثاق رسمي لـ{domain} "
                    f"وفق متطلبات {fw_short}. بدون هذا الهيكل، لا يمكن "
                    "تطبيق باقي الركائز بصورة مستدامة."
                ),
                'initiatives': [
                    (
                        f'تأسيس هيكل حوكمة {domain} الرسمي',
                        f'تشكيل لجنة حوكمة {domain} برئاسة تنفيذية مع ميثاق '
                        f'معتمد يحدد الصلاحيات والمسؤوليات ومسارات التصعيد',
                        f'ميثاق لجنة الحوكمة + هيكل تنظيمي معتمد + '
                        f'مصفوفة RACI لأدوار {domain}',
                    ),
                    (
                        f'سياسات وإجراءات {domain}',
                        f'إعداد حزمة السياسات والإجراءات الرئيسية لـ{domain} وفق متطلبات {fw_short} مع آليات مراجعة دورية',
                        f'حزمة سياسات {domain} المعتمدة + جدول المراجعة السنوي',
                    ),
                    (
                        f'سجل ضوابط {fw_short}',
                        f'بناء سجل ضوابط {fw_short} مُرقَّم مع تحديد المسؤول عن كل ضابط وحالة التطبيق',
                        f'سجل ضوابط {fw_short} + مسؤولو الضوابط + لوحة حالة الامتثال',
                    ),
                ],
            }
        else:
            gov_pillar = {
                'title': (f'Pillar 1: Establish {domain} Governance '
                          f'Structure — the Missing Foundation'),
                'narrative': (
                    f"The diagnostic identified that {org_name} has no "
                    f"defined organizational structure for {domain}. "
                    f"This pillar closes that structural gap — the "
                    f"highest-priority move before any investment in "
                    f"operational controls — by establishing the "
                    f"governance committee, responsibility definitions, "
                    f"and a formal {domain} charter aligned to {fw_short} "
                    "obligations. Without this structure, no other pillar "
                    "can be executed sustainably."
                ),
                'initiatives': [
                    (
                        f'Establish formal {domain} governance structure',
                        f'Form executive-chaired {domain} governance committee '
                        'with approved charter defining authority, '
                        'responsibilities, and escalation paths',
                        f'Committee charter + approved org structure + '
                        f'RACI matrix for {domain} roles',
                    ),
                    (
                        f'{domain} Policies & Procedures',
                        f'Develop the core {domain} policy and procedure pack per {fw_short} with periodic review mechanisms',
                        f'Approved {domain} policy pack + Annual review schedule',
                    ),
                    (
                        f'{fw_short} Control Register',
                        f'Build a numbered {fw_short} control register assigning an owner and implementation status to each control',
                        f'{fw_short} control register + Control owners + Compliance status dashboard',
                    ),
                ],
            }
        # Only inject if preserved pillars don't already contain one
        _gov_t = gov_pillar['title'].lower()
        if not any(('governance' in t and 'structure' in t) or
                   ('حوكمة' in t and ('هيكل' in t or 'بنية' in t))
                   for t in preserved_titles_lc):
            picked.append(gov_pillar)
            summary['governance_pillar_injected'] = True

    # ── Technology-gap priority pillar (prompt Part 2B)
    # If the user's tech selections are MISSING in ≥ 2 key categories,
    # inject a pillar focused on that foundational capability build-out.
    # Key categories: siem (monitoring), edr (endpoint), iam (identity).
    # This runs AFTER governance-injection so the governance pillar
    # retains the #1 slot when both apply.
    _key_tech_missing = sum(
        1 for cat in ('siem', 'edr', 'iam', 'backup')
        if cat in (technologies or []) and False  # legacy guard
    )
    # Correct derivation — technologies param is the raw list. We need
    # tech_gaps from ctx. Pull from synthesizer signature:
    _tech_gaps_from_ctx = []
    # The signature won't have tech_gaps directly; we derive it locally
    # by scanning the `technologies` list for presence markers.
    _tech_blob_syn = ' '.join(str(t).lower() for t in (technologies or []))
    _has = {
        'siem': any(k in _tech_blob_syn for k in
                    ('siem', 'splunk', 'sentinel', 'qradar')),
        'edr':  any(k in _tech_blob_syn for k in
                    ('edr', 'xdr', 'crowdstrike', 'sentinelone',
                     'defender for endpoint')),
        'iam':  any(k in _tech_blob_syn for k in
                    ('iam', 'okta', 'active directory', 'azure ad')),
        'backup': any(k in _tech_blob_syn for k in
                      ('backup', 'veeam', 'commvault', 'rubrik')),
    }
    _missing_key = [k for k, v in _has.items() if not v]
    # Only inject tech-priority pillar if the user reported no
    # technologies at all OR ≥ 2 key categories are missing.
    _tech_priority_needed = (
        not technologies or len(_missing_key) >= 2
    )
    if _tech_priority_needed:
        _missing_str_ar = '، '.join({
            'siem': 'منصة SIEM للمراقبة',
            'edr':  'حماية نقاط النهاية EDR/XDR',
            'iam':  'إدارة الهوية والوصول',
            'backup': 'حلول النسخ الاحتياطي والتعافي',
        }.get(k, k) for k in _missing_key)
        _missing_str_en = ', '.join({
            'siem': 'SIEM monitoring',
            'edr':  'EDR/XDR endpoint protection',
            'iam':  'identity & access management',
            'backup': 'backup & recovery',
        }.get(k, k) for k in _missing_key)
        if is_ar:
            tech_pillar = {
                'title': (f'بناء القدرات التقنية الأساسية المفقودة في '
                          f'{org_name}'),
                'narrative': (
                    f"كشف التشخيص غياب قدرات تقنية أساسية في {org_name} "
                    f"تشمل: {_missing_str_ar}. تعالج هذه الركيزة هذا "
                    "النقص عبر تصميم وبناء ونشر هذه القدرات بصورة "
                    f"متكاملة مع متطلبات {fw_short}."
                ),
                'initiatives': [
                    (
                        f'نشر القدرات التقنية الأساسية المفقودة',
                        (f'تنفيذ مشاريع اقتناء/نشر/تكامل لـ: {_missing_str_ar} '
                         f'مع ربطها بأُطر الحوكمة والتشغيل'),
                        ('قدرات تقنية منتجة مع أدلة الاختبار والتشغيل الدوري'),
                    ),
                    (
                        'خطة تكامل الأدوات والأنظمة',
                        f'تصميم خطة التكامل بين القدرات المنشورة ومنظومة ضوابط {fw_short}',
                        'خطة التكامل المعتمدة + اختبارات القبول',
                    ),
                    (
                        'توثيق خط الأساس التقني',
                        'توثيق إعدادات الأمان الافتراضية وخط الأساس التقني لجميع القدرات',
                        'وثيقة خط الأساس التقني + سجل الاختلافات',
                    ),
                ],
            }
        else:
            tech_pillar = {
                'title': (f'Build missing foundational technical capabilities '
                          f'at {org_name}'),
                'narrative': (
                    f"Diagnostic identified that {org_name} lacks core "
                    f"technical capabilities including: {_missing_str_en}. "
                    "This pillar closes that gap through acquisition, "
                    "deployment and integration of these capabilities "
                    f"aligned to {fw_short}."
                ),
                'initiatives': [
                    (
                        'Deploy missing foundational technical capabilities',
                        (f'Execute acquisition/deployment/integration for: '
                         f'{_missing_str_en} with governance + operations '
                         'integration'),
                        ('Production capabilities with test evidence and '
                         'periodic operations runbook'),
                    ),
                    (
                        'Tool & System Integration Plan',
                        f'Design an integration plan linking deployed capabilities to the {fw_short} control framework',
                        'Approved integration plan + Acceptance test results',
                    ),
                    (
                        'Technical Baseline Documentation',
                        'Document default security configurations and technical baseline for all new capabilities',
                        'Technical baseline document + Deviation register',
                    ),
                ],
            }
        picked.append(tech_pillar)
        summary['technology_priority_pillar_injected'] = True
        summary['missing_tech_categories'] = _missing_key

    # ── Maturity-conditioned bank ordering (prompt Part 2B)
    # If maturity is initial/ad-hoc, the bank picks must PRIORITIZE
    # baseline / foundational pillars before optimization pillars. We
    # reorder pillar_bank so baseline-focused entries come first, then
    # detection, then optimization.
    _baseline_kw = (
        'baseline', 'foundational', 'operational controls',
        'governance', 'الضوابط التشغيلية', 'الأساس', 'الحوكمة',
    )
    _optim_kw = (
        'optimization', 'optimize', 'advanced', 'continuous improvement',
        'التحسين', 'التحسين المستمر', 'المتقدم',
    )
    _maturity_lc = str(maturity).lower().strip()
    if _maturity_lc in ('initial', 'ad-hoc', 'ad hoc'):
        def _pbank_priority(pb):
            tl = pb['title'].lower()
            # Lower sort-key wins — baseline first, optim last.
            if any(k in tl for k in _baseline_kw):
                return 0
            if any(k in tl for k in _optim_kw):
                return 2
            return 1
        pillar_bank = sorted(pillar_bank, key=_pbank_priority)
        summary['maturity_reordered'] = True

    for pbank in pillar_bank:
        if any(t.lower() in pbank['title'].lower() or
               pbank['title'].lower() in t.lower()
               for t in preserved_titles_lc):
            continue
        # Skip if the governance pillar already covers governance
        if (summary['governance_pillar_injected']
                and ('Governance' in pbank['title']
                     or 'الحوكمة' in pbank['title'])):
            continue
        picked.append(pbank)
        if len(picked) >= needed:
            break

    # Build the canonical section
    # ── ORDINAL NORMALIZATION (pillar validator alignment) ───────
    # The validator regex at `_count_substantive_pillars` requires
    # pillar headings to match the pattern
    #   ### (Pillar \d*|Strategic Pillar \d*|الركيزة[...]\s*\d*)
    # Historically, the governance-priority pillar emitted a title
    # like "الركيزة الأولى: ..." (word ordinal), and the technology-
    # gap pillar emitted "بناء القدرات التقنية..." (no ordinal
    # prefix at all). The latter was NOT matched by the validator
    # — that's the documented production failure
    # `pillars_below_richness_minimum_2/3`. Additionally, the bank
    # entries also carry "الأولى"/"Pillar 1:" in their titles, so
    # after governance-injection we had duplicate "الأولى"/"Pillar 1"
    # labels.
    #
    # Fix: build the final `picked` list (preserved + gov + tech +
    # bank), then REWRITE each pillar's title to use a clean
    # sequential ordinal prefix in the target language. The original
    # descriptive part of the title is preserved — only the ordinal
    # prefix is normalized.
    def _normalize_pillar_titles(plist, is_ar_lang):
        """Rewrite each pillar's title to `### الركيزة N: <desc>` /
        `### Pillar N: <desc>`. Strips any existing ordinal prefix
        (including word ordinals) so the final order is sequential
        and the validator regex matches every entry."""
        # Patterns that may lead an existing title and should be
        # stripped before re-prefixing.
        _strip_ar = _ts_re.compile(
            r'^\s*(?:الركيزة(?:\s+الاستراتيجية)?'
            r'(?:\s+(?:الأولى|الثانية|الثالثة|الرابعة|الخامسة|'
            r'السادسة|السابعة))?\s*\d*)\s*[:：\-—]?\s*',
        )
        _strip_en = _ts_re.compile(
            r'^\s*(?:Strategic\s+)?Pillar\s*\d*\s*[:\-—]?\s*',
            _ts_re.IGNORECASE,
        )
        _num_ar = {1: 'الأولى', 2: 'الثانية', 3: 'الثالثة',
                   4: 'الرابعة', 5: 'الخامسة', 6: 'السادسة',
                   7: 'السابعة'}
        for i, p in enumerate(plist, start=1):
            raw = p.get('title', '') or ''
            desc = _strip_ar.sub('', raw) if is_ar_lang else \
                   _strip_en.sub('', raw)
            desc = desc.strip(' :：-—')
            if not desc:
                desc = raw.strip()
            if is_ar_lang:
                word = _num_ar.get(i, str(i))
                p['title'] = f'الركيزة {word}: {desc}'
            else:
                p['title'] = f'Pillar {i}: {desc}'
        return plist

    # ── DEDUPLICATE by descriptive title (after ordinal strip) ───
    # Prevents the case where gov-priority pillar's descriptive part
    # overlaps with bank pillar 1's (both contain "governance"). The
    # threshold is deliberately STRICT — we only drop when the
    # descriptive parts are essentially the same topic, not just
    # sharing one-or-two common words. Over-aggressive dedup would
    # drop legitimately different pillars like the tech-capability
    # pillar next to the governance one.
    def _dedup_by_desc(plist, is_ar_lang):
        _strip_ar = _ts_re.compile(
            r'^\s*(?:الركيزة(?:\s+الاستراتيجية)?'
            r'(?:\s+(?:الأولى|الثانية|الثالثة|الرابعة|الخامسة|'
            r'السادسة|السابعة))?\s*\d*)\s*[:：\-—]?\s*',
        )
        _strip_en = _ts_re.compile(
            r'^\s*(?:Strategic\s+)?Pillar\s*\d*\s*[:\-—]?\s*',
            _ts_re.IGNORECASE,
        )
        # Low-signal stopwords that should not contribute to similarity.
        _stop = {
            'the', 'and', 'for', 'of', 'at', 'to', 'a', 'an', 'in', 'on',
            'with', 'by', 'establish', 'build', 'missing', 'foundational',
            'cyber', 'security',
            'في', 'من', 'على', 'إلى', 'عبر', 'مع', 'بناء', 'إنشاء',
            'المفقودة', 'الأساسية',
        }
        seen = []   # list of (descriptive_lc, significant_word_set)
        out = []
        for p in plist:
            raw = p.get('title', '') or ''
            desc = (_strip_ar.sub('', raw) if is_ar_lang
                     else _strip_en.sub('', raw))
            desc_lc = desc.strip(' :：-—').lower()
            my_sig = {w for w in desc_lc.split()
                      if w and len(w) > 2 and w not in _stop}
            is_dup = False
            for (kept_desc, kept_sig) in seen:
                # Rule 1: exact 25-char prefix match → dup
                if (desc_lc[:25] and kept_desc[:25]
                        and desc_lc[:25] == kept_desc[:25]):
                    is_dup = True
                    break
                # Rule 2: significant-word overlap ≥ 60% of smaller
                # set AND ≥ 3 shared words (too-small sets give
                # unreliable ratios).
                if my_sig and kept_sig:
                    inter = my_sig & kept_sig
                    smaller = min(len(my_sig), len(kept_sig))
                    if (smaller >= 3 and len(inter) >= 3
                            and len(inter) / smaller >= 0.60):
                        is_dup = True
                        break
            if is_dup:
                continue
            seen.append((desc_lc, my_sig))
            out.append(p)
        return out

    # Apply dedup + ordinal rewrite in order.
    # KEY FIX (root-cause): preserved pillar titles may be non-canonical
    # (e.g., AI-generated headings like "### Governance Strategy" that lack
    # the "Pillar N:" / "الركيزة N:" prefix). _PILLAR_HEADING_RE_GLOBAL —
    # used by _final_strategy_audit and the pre-save integrity gate — ONLY
    # matches canonical prefixes; when at least one canonical heading is
    # already present the fallback to ###\s+ does NOT fire, so non-canonical
    # preserved headings are invisible to the audit. This causes the gate to
    # see fewer than 3 valid pillars even though the synth built 3.
    # Fix: wrap preserved (title, body) pairs into dicts so they can be
    # processed by _normalize_pillar_titles together with picked, giving ALL
    # pillars a canonical "Pillar N:" / "الركيزة N:" heading before output.
    _preserved_dicts = [{'title': t, '_body': b} for t, b in preserved]
    picked = _dedup_by_desc(picked, is_ar)
    # Normalize ALL pillars (preserved + picked) sequentially so every heading
    # in the output section matches _PILLAR_HEADING_RE_GLOBAL.
    _all_pillars = _normalize_pillar_titles(_preserved_dicts + picked, is_ar)

    if is_ar:
        out = ['## 2. الركائز الاستراتيجية', '']
        for p in _all_pillars:
            out.append('### ' + p['title'])
            out.append('')
            if '_body' in p:
                # Preserved pillar: emit the original AI body verbatim
                # (already contains a substantive initiative table).
                out.append(p['_body'].strip())
            else:
                out.append(p['narrative'])
                out.append('')
                out.append('| # | المبادرة | الوصف | المخرج المتوقع |')
                out.append('|---|---------|-------|----------------|')
                # Emit all initiatives (3 per bank pillar for technical depth)
                _inits = p.get('initiatives') or [p['initiative']]
                for _i, _init in enumerate(_inits, 1):
                    out.append(f'| {_i} | {_init[0]} | {_init[1]} | {_init[2]} |')
                summary['synthesized_titles'].append(p['title'])
            out.append('')
    else:
        out = ['## 2. Strategic Pillars', '']
        for p in _all_pillars:
            out.append('### ' + p['title'])
            out.append('')
            if '_body' in p:
                out.append(p['_body'].strip())
            else:
                out.append(p['narrative'])
                out.append('')
                out.append('| # | Initiative | Description | Expected Deliverable |')
                out.append('|---|-----------|-------------|---------------------|')
                # Emit all initiatives (3 per bank pillar for technical depth)
                _inits = p.get('initiatives') or [p['initiative']]
                for _i, _init in enumerate(_inits, 1):
                    out.append(f'| {_i} | {_init[0]} | {_init[1]} | {_init[2]} |')
                summary['synthesized_titles'].append(p['title'])
            out.append('')

    sections['pillars'] = '\n'.join(out).rstrip() + '\n'
    summary['rebuilt'] = True
    summary['pillars_after'] = _count_substantive_pillars(sections['pillars'])
    return summary


# ────────────────────────────────────────────────────────────────────────────
# FINAL SYNTHESIS PASS  (prompt clause B4 — operates on FINAL canonical payload)
#
# Runs AFTER all cleanup passes (resection / dedupe / family collapse /
# residue sanitization) and BEFORE the richness gate. By running at the
# very end of the cleanup pipeline, synthesizers see the fully-canonical
# payload — no misrouted section content confuses their emptiness checks
# and no later pass can undo a synthesized row.
#
# Accepts a `ctx` dict with optional extra context (sector, org_name,
# maturity, generation_mode, challenges, technologies, size, budget,
# diagnostic_gaps, risks, objectives). Synthesizer bodies branch on
# `generation_mode` (drafting / consulting / assurance) and `maturity`
# (initial / developing / defined / managed / optimized) when present.
# ────────────────────────────────────────────────────────────────────────────

def _apply_final_synthesis_pass(sections, lang, domain, fw_short, ctx=None):
    """Run all four semantic-richness synthesizers on the final canonical
    payload. Returns a dict of {synth_name: result} summarizing what was
    added. Each synthesizer is a no-op when the section already meets
    its richness bar.
    """
    ctx = ctx or {}
    sector       = ctx.get('sector', 'General')
    org_name     = ctx.get('org_name', 'The Organization')
    maturity     = ctx.get('maturity', 'initial')
    gen_mode     = ctx.get('generation_mode', 'drafting')
    summary = {}
    # 0a. Strategic Objectives — rebuild canonically with diagnostic-
    # driven injection. Runs first so downstream pillars/roadmap/KPI
    # can thematically align (though today they don't explicitly
    # traceback — that's Part 3/4 scope).
    try:
        _obj_result = synthesize_objectives_depth(
            sections, lang, domain=domain, fw_short=fw_short,
            sector=sector, org_name=org_name,
            org_structure_is_none=ctx.get('org_structure_is_none', False),
            challenge_flags=ctx.get('challenge_flags', {}),
            diagnostic_gaps=ctx.get('diagnostic_gaps', []),
            maturity=maturity, generation_mode=gen_mode)
        if _obj_result and _obj_result.get('rebuilt'):
            summary['objectives'] = _obj_result
    except Exception as _oe:
        print(f'[STRATEGY-DIAG] final_synth_objectives_failed: {_oe}',
              flush=True)
    # 0b. Gaps — rebuild canonically with diagnostic-driven injection.
    # Runs BEFORE pillars because the grounding gate downstream checks
    # that the gaps section contains governance/structural content when
    # org_structure_is_none=True. Failing to populate it here would 422
    # at the grounding gate even if pillars were well-formed.
    try:
        _gaps_result = synthesize_gaps_depth(
            sections, lang, domain=domain, fw_short=fw_short,
            sector=sector, org_name=org_name,
            org_structure_is_none=ctx.get('org_structure_is_none', False),
            challenge_flags=ctx.get('challenge_flags', {}),
            technologies=ctx.get('technologies', []),
            diagnostic_gaps=ctx.get('diagnostic_gaps', []),
            maturity=maturity, generation_mode=gen_mode)
        if _gaps_result and _gaps_result.get('rebuilt'):
            summary['gaps'] = _gaps_result
    except Exception as _ge:
        print(f'[STRATEGY-DIAG] final_synth_gaps_failed: {_ge}',
              flush=True)
    # 1. Strategic Pillars — rebuild canonically if thin. Runs after
    # gaps (phase 0) so grounding-gate downstream sees both. Though
    # pillars don't read from gaps directly, this order keeps
    # diagnostic output in section-number order.
    try:
        _pillars_result = synthesize_pillars_depth(
            sections, lang, domain=domain, fw_short=fw_short,
            sector=sector, org_name=org_name,
            maturity=maturity, generation_mode=gen_mode,
            diagnostic_gaps=ctx.get('diagnostic_gaps', []),
            risks=ctx.get('risks', []),
            objectives=ctx.get('objectives', []),
            org_structure_is_none=ctx.get('org_structure_is_none', False),
            challenge_flags=ctx.get('challenge_flags', {}),
            technologies=ctx.get('technologies', []))
        if _pillars_result and _pillars_result.get('rebuilt'):
            summary['pillars'] = _pillars_result
    except Exception as _pe:
        print(f'[STRATEGY-DIAG] final_synth_pillars_failed: {_pe}',
              flush=True)
    # 1. Environment — forward sector / org_name for in-content mentions.
    try:
        _env_result = synthesize_environment_context(
            sections, lang, domain=domain, fw_short=fw_short,
            sector=sector, org_name=org_name,
            generation_mode=gen_mode, maturity=maturity,
            challenges=ctx.get('challenges', ''),
            frameworks=ctx.get('frameworks', []))
        if _env_result:
            summary['environment'] = _env_result
    except Exception as _se:
        print(f'[STRATEGY-DIAG] final_synth_environment_failed: {_se}',
              flush=True)
    # 2. Roadmap — generation-mode affects activity depth.
    try:
        _rm_added = synthesize_roadmap_depth(
            sections, lang, domain=domain, fw_short=fw_short,
            generation_mode=gen_mode,
            org_structure_is_none=ctx.get('org_structure_is_none', False),
            challenge_flags=ctx.get('challenge_flags', {}),
            diagnostic_gaps=ctx.get('diagnostic_gaps', []),
            technologies=ctx.get('technologies', []),
            sector=sector, org_name=org_name)
        if _rm_added:
            summary['roadmap_rows_added'] = _rm_added
    except Exception as _sre:
        print(f'[STRATEGY-DIAG] final_synth_roadmap_failed: {_sre}',
              flush=True)
    # 3. KPIs — append rows only. Guide coverage is intentionally NOT
    #    synthesized here: doing so would add guides to possibly-broken
    #    KPI content (e.g., still-dup headers from upstream tier repair)
    #    which violates the prompt's "do NOT append guides to a broken
    #    KPI section" rule. The final rebuild_canonical_kpi_section call
    #    runs immediately after this pass in the save path and emits one
    #    guide block per substantive row as the LAST mutation step.
    try:
        _kpi_added = synthesize_kpi_depth(
            sections, lang, domain=domain, fw_short=fw_short,
            generation_mode=gen_mode,
            org_structure_is_none=ctx.get('org_structure_is_none', False),
            challenge_flags=ctx.get('challenge_flags', {}),
            diagnostic_gaps=ctx.get('diagnostic_gaps', []),
            sector=sector, org_name=org_name)
        if _kpi_added:
            summary['kpi_rows_added'] = _kpi_added
    except Exception as _ske:
        print(f'[STRATEGY-DIAG] final_synth_kpi_failed: {_ske}',
              flush=True)
    # 4. Confidence — maturity affects default confidence score, generation
    #    mode affects CSF / risk phrasing.
    try:
        _cf_result = synthesize_confidence_depth(
            sections, lang, domain=domain, fw_short=fw_short,
            org_name=org_name, maturity=maturity,
            generation_mode=gen_mode)
        if (_cf_result.get('csf_added')
                or _cf_result.get('risks_added')
                or _cf_result.get('score_added')
                or _cf_result.get('justification_added')):
            summary['confidence'] = _cf_result
    except Exception as _sce:
        print(f'[STRATEGY-DIAG] final_synth_confidence_failed: {_sce}',
              flush=True)

    # ── TRACEABILITY SUMMARY (prompt Part 3) ────────────────────────────
    # Compute which diagnostic signals each section reflects based on
    # keyword scan of the final synthesized content. This is an operator-
    # visible summary — not inline tags — that proves user input
    # influenced the output. Logged once to [STRATEGY-DIAG] traceability.
    try:
        def _section_signals(txt):
            """Return dict of signal → bool for this section text."""
            if not txt:
                return {}
            tl = txt.lower()
            sig = {}
            sig['structural'] = any(t in tl for t in (
                'governance', 'structure', 'committee', 'charter',
                'steering', 'organizational')) or any(t in txt for t in (
                'حوكمة', 'هيكل', 'لجنة', 'ميثاق', 'توجيه'))
            sig['awareness'] = any(t in tl for t in (
                'awareness', 'training', 'phishing')) or any(t in txt for t in (
                'وعي', 'تدريب', 'تصيد'))
            sig['incident_response'] = any(t in tl for t in (
                'soc', 'siem', 'incident', 'detection', 'response')) or any(
                t in txt for t in ('مراقبة', 'استجابة', 'حوادث', 'كشف'))
            sig['suppliers'] = any(t in tl for t in (
                'supplier', 'vendor', 'third-party', 'third party')) or any(
                t in txt for t in ('موردين', 'أطراف ثالثة', 'سلسلة الإمداد'))
            sig['compliance'] = any(t in tl for t in (
                'compliance', 'audit', 'evidence')) or any(
                t in txt for t in ('امتثال', 'تدقيق', 'أدلة'))
            sig['staffing'] = any(t in tl for t in (
                'staff', 'hiring', 'workforce', 'skill')) or any(
                t in txt for t in ('موظفين', 'مهارات', 'كفاءات', 'كوادر'))
            return sig
        traceability = {
            'model_flags': {
                'org_structure_is_none': ctx.get('org_structure_is_none'),
                'challenge_flags': ctx.get('challenge_flags', {}),
            },
            'sections': {},
        }
        for key in ('vision', 'pillars', 'environment', 'gaps', 'roadmap',
                    'kpis', 'confidence'):
            traceability['sections'][key] = _section_signals(
                sections.get(key, '') or '')
        summary['traceability'] = traceability
        # Score: for each active flag, check that ≥ 2 sections (including
        # the relevant one) mention the signal. Used to spot "signal
        # detected but only reflected in one section" — still-generic
        # output.
        weak_coverage = []
        flags = ctx.get('challenge_flags', {}) or {}
        if ctx.get('org_structure_is_none'):
            hits = sum(1 for s in traceability['sections'].values()
                       if s.get('structural'))
            if hits < 3:
                weak_coverage.append(f'structural in only {hits} section(s)')
        for k, v in flags.items():
            if not v:
                continue
            hits = sum(1 for s in traceability['sections'].values()
                       if s.get(k))
            if hits < 2:
                weak_coverage.append(f'{k} in only {hits} section(s)')
        traceability['weak_coverage'] = weak_coverage
        print(f'[STRATEGY-DIAG] traceability_summary={traceability}',
              flush=True)
    except Exception as _te:
        print(f'[STRATEGY-DIAG] traceability_summary_failed: {_te}',
              flush=True)

    return summary


# ────────────────────────────────────────────────────────────────────────────
# FINAL CONVERGENCE LOOP (systemic-fix prompt clause B)
#
# Root-cause closure for the "every retry reveals a new gate" pattern:
# audit the FINAL canonical sections against the SAME thresholds the
# save gates use, run targeted top-ups for ALL failing sections in one
# cycle, re-audit, repeat until stable or max_iter reached.
#
# The prior `_apply_final_synthesis_pass` runs each synthesizer EXACTLY
# ONCE in a fixed order. If two synthesizers had a feedback loop (e.g.,
# pillars synth fed by gaps that gaps synth had not yet emitted), the
# downstream gate would still fire. This loop closes that race by
# re-running ALL synths until an audit pass shows no failures (or
# until further progress stops, in which case the unrecoverable defect
# set is returned consolidated).
#
# Uses _RICHNESS_MIN_* canonical constants — single source of truth.
# ────────────────────────────────────────────────────────────────────────────


def _final_strategy_audit(sections, lang, doc_subtype=None):
    """Audit sections against the SAME thresholds the save gates use.
    Returns a list of (section_key, defect_tag, count_observed,
    threshold) tuples. Empty list = sections meet all thresholds.

    Reuses existing counters; does NOT reimplement counting logic.
    """
    defects = []
    if doc_subtype == 'board':
        return defects
    # Strategic Objectives
    n_so = count_valid_objective_rows(sections.get('vision', '') or '')
    if n_so < _RICHNESS_MIN_SO_ROWS:
        defects.append(('vision', 'so_rows_insufficient',
                        n_so, _RICHNESS_MIN_SO_ROWS))
    # Pillars — use the GATE-ALIGNED helper, not the laxer counter.
    # `_count_substantive_pillars` accepts narrative-only ≥80-char
    # bodies as substantive (its widened fallback). The downstream
    # `pillars_missing_substantive_initiative` integrity gate at the
    # save path REQUIRES a pipe-table initiative row per pillar.
    # Counting via the laxer helper made the convergence loop report
    # `converged=True` for narrative-only pillars, only for the
    # downstream gate to fire and surface a "pillars" failure that
    # the convergence loop had silently missed. Now: count strictly
    # via `_pillar_has_substantive_initiative` so audit + gate agree.
    pillars_text = sections.get('pillars', '') or ''
    _pill_matches = list(_PILLAR_HEADING_RE_GLOBAL.finditer(pillars_text))
    _pill_all_h3 = list(_ts_re.finditer(
        r'^###[^#\n][^\n]*$', pillars_text, _ts_re.MULTILINE))
    # Use the wider set whenever it finds MORE headings than the canonical
    # pattern. This catches non-canonical AI pillar titles that the canonical
    # regex misses but that carry legitimate initiative tables. Previously
    # the fallback only fired when canonical matches was ZERO — meaning a
    # section with 1 canonical + 2 non-canonical headings would only audit
    # the 1 canonical one and mis-count the total as 1 (below threshold).
    if len(_pill_all_h3) > len(_pill_matches):
        _pill_matches = _pill_all_h3
    n_pill = 0
    for _i, _m in enumerate(_pill_matches):
        _bs = _m.end()
        _be = (_pill_matches[_i + 1].start()
               if _i + 1 < len(_pill_matches) else len(pillars_text))
        _body = pillars_text[_bs:_be]
        if _pillar_has_substantive_initiative(_body):
            n_pill += 1
    if n_pill < _RICHNESS_MIN_PILLARS:
        defects.append(('pillars', 'pillars_insufficient',
                        n_pill, _RICHNESS_MIN_PILLARS))
    # Environment paragraphs
    n_env_p = _count_substantive_paragraphs(
        sections.get('environment', '') or '')
    if n_env_p < _RICHNESS_MIN_ENV_PARAS:
        defects.append(('environment', 'env_paragraphs_insufficient',
                        n_env_p, _RICHNESS_MIN_ENV_PARAS))
    # Gaps
    n_gap = count_substantive_gaps(sections.get('gaps', '') or '')
    if n_gap < _RICHNESS_MIN_GAP_ROWS:
        defects.append(('gaps', 'gap_rows_insufficient',
                        n_gap, _RICHNESS_MIN_GAP_ROWS))
    # Roadmap
    n_road = _count_substantive_roadmap_rows(sections.get('roadmap', '') or '')
    if n_road < _RICHNESS_MIN_ROADMAP_ROWS:
        defects.append(('roadmap', 'roadmap_rows_insufficient',
                        n_road, _RICHNESS_MIN_ROADMAP_ROWS))
    # KPI rows + main-header count
    n_kpi = count_substantive_kpis(sections.get('kpis', '') or '')
    if n_kpi < _RICHNESS_MIN_KPI_ROWS:
        defects.append(('kpis', 'kpi_rows_insufficient',
                        n_kpi, _RICHNESS_MIN_KPI_ROWS))
    n_kpi_hdr = len(_KPI_MAIN_TABLE_HEADER_RE.findall(
        sections.get('kpis', '') or ''))
    if n_kpi_hdr != 1:
        defects.append(('kpis', 'kpi_main_header_count_invalid',
                        n_kpi_hdr, 1))
    # Confidence CSF + risk
    try:
        conf = sections.get('confidence', '') or ''
        n_csf = _count_csf_rows(conf)
        if n_csf < _RICHNESS_MIN_CSF_ROWS:
            defects.append(('confidence', 'csf_rows_insufficient',
                            n_csf, _RICHNESS_MIN_CSF_ROWS))
        n_risk = _count_risk_rows_with_mitigation(conf)
        if n_risk < _RICHNESS_MIN_RISK_ROWS:
            defects.append(('confidence', 'risk_rows_insufficient',
                            n_risk, _RICHNESS_MIN_RISK_ROWS))
    except Exception:
        pass
    return defects


def converge_strategy_sections(sections, lang, domain, fw_short,
                               ctx=None, doc_subtype=None,
                               max_iter=3):
    """Final convergence loop: audit-repair-reaudit until stable.

    Returns a dict:
        {'iterations': int,
         'initial_defects': [...],
         'final_defects': [...],
         'progress': bool,
         'converged': bool}

    On each iteration, re-invokes the matching synthesizer for each
    failing section family, then re-audits. Stops when:
      - no defects remain (converged=True)
      - max_iter reached
      - no progress (defect count unchanged after a full cycle)

    The returned `final_defects` is the consolidated blocker set the
    caller can use to emit ONE 422 response (prompt clause F) instead
    of letting the user discover defects one at a time.
    """
    ctx = ctx or {}
    log = {
        'iterations': 0,
        'initial_defects': [],
        'final_defects': [],
        'progress': False,
        'converged': False,
        'cycles': [],
    }
    initial = _final_strategy_audit(sections, lang, doc_subtype)
    log['initial_defects'] = [(s, t, c, m) for s, t, c, m in initial]
    if not initial:
        log['converged'] = True
        return log

    prev_defect_count = len(initial)
    for _it in range(max_iter):
        log['iterations'] = _it + 1
        cycle = {'before': prev_defect_count, 'repairs': []}

        # Group failing sections to know which synths to re-invoke
        failing_keys = {d[0] for d in
                        _final_strategy_audit(sections, lang, doc_subtype)}
        if not failing_keys:
            log['converged'] = True
            log['final_defects'] = []
            log['cycles'].append(cycle)
            break

        # Re-invoke synthesizers for failing families. Each synth is
        # idempotent on a clean section and append/replace on a thin
        # one — running again is safe.
        # FORCE-CLEAR ON RETRY (prompt Part A clauses 4+5+6 — make
        # rebuild deterministic for vision/pillars):
        # On iteration ≥ 2, if vision OR pillars STILL fail audit, clear
        # the section's content before re-invoking synth. This bypasses
        # the synth's own idempotent early-return paths
        # (`_existing_with_init >= _RICHNESS_MIN_PILLARS_LOCAL` etc.)
        # which would otherwise keep a prior-cycle output that the
        # audit considers thin. Forces synth's full canonical rebuild
        # path to fire, which is guaranteed to produce 3 substantive
        # pillars + 4 SO rows from the priority bank. Replaces stale
        # content; does not append. Only applies to vision/pillars per
        # prompt Part A clause 7 (no other family logic touched).
        if 'vision' in failing_keys:
            _v_before = count_valid_objective_rows(
                sections.get('vision', '') or '')
            if _it >= 1:
                _v_text = sections.get('vision', '') or ''
                _so_hdr = _ts_re.search(
                    r'###\s+(?:Strategic\s+Objectives|الأهداف(?:\s+الاستراتيجية)?)'
                    r'[^\n]*',
                    _v_text, _ts_re.IGNORECASE,
                )
                if _so_hdr:
                    sections['vision'] = (
                        _v_text[:_so_hdr.start()].rstrip() + '\n')
                else:
                    # Fallback: AI may have omitted the ### Strategic
                    # Objectives sub-heading and placed the table
                    # directly. Clear from the table header so the
                    # synth rebuilds from scratch.
                    _tbl_hdr_fc = _ts_re.search(
                        r'^\|\s*#\s*\|'
                        r'\s*(?:Objective|الهدف(?:\s+الاستراتيجي)?'
                        r'|الأهداف)\s*\|',
                        _v_text,
                        _ts_re.IGNORECASE | _ts_re.MULTILINE,
                    )
                    if _tbl_hdr_fc:
                        sections['vision'] = (
                            _v_text[:_tbl_hdr_fc.start()].rstrip()
                            + '\n')
            try:
                synthesize_objectives_depth(
                    sections, lang, domain=domain, fw_short=fw_short,
                    sector=ctx.get('sector', 'General'),
                    org_name=ctx.get('org_name', 'The Organization'),
                    org_structure_is_none=ctx.get(
                        'org_structure_is_none', False),
                    challenge_flags=ctx.get('challenge_flags', {}),
                    diagnostic_gaps=ctx.get('diagnostic_gaps', []),
                    maturity=ctx.get('maturity', 'initial'),
                    generation_mode=ctx.get('generation_mode', 'drafting'),
                )
                _v_after = count_valid_objective_rows(
                    sections.get('vision', '') or '')
                cycle['repairs'].append(
                    f'objectives:{_v_before}->{_v_after}')
            except Exception as _e:
                cycle['repairs'].append(f'objectives_failed:{_e}')
        if 'pillars' in failing_keys:
            _pillars_text_before = sections.get('pillars', '') or ''
            _p_matches_b = list(
                _PILLAR_HEADING_RE_GLOBAL.finditer(_pillars_text_before))
            _p_all_h3_b = list(_ts_re.finditer(
                r'^###[^#\n][^\n]*$', _pillars_text_before,
                _ts_re.MULTILINE))
            if len(_p_all_h3_b) > len(_p_matches_b):
                _p_matches_b = _p_all_h3_b
            _p_before = sum(
                1 for i, m in enumerate(_p_matches_b)
                if _pillar_has_substantive_initiative(
                    _pillars_text_before[
                        m.end():_p_matches_b[i + 1].start()
                        if i + 1 < len(_p_matches_b)
                        else len(_pillars_text_before)]))
            if _it >= 1:
                # Force-clear pillars on retry — bypass synth's
                # `n_before_strict >= _RICHNESS_MIN_PILLARS_LOCAL`
                # early-return so the bank rebuild fires.
                sections['pillars'] = ''
            try:
                synthesize_pillars_depth(
                    sections, lang, domain=domain, fw_short=fw_short,
                    sector=ctx.get('sector', 'General'),
                    org_name=ctx.get('org_name', 'The Organization'),
                    maturity=ctx.get('maturity', 'initial'),
                    generation_mode=ctx.get('generation_mode', 'drafting'),
                    diagnostic_gaps=ctx.get('diagnostic_gaps', []),
                    risks=ctx.get('risks', []),
                    objectives=ctx.get('objectives', []),
                    org_structure_is_none=ctx.get(
                        'org_structure_is_none', False),
                    challenge_flags=ctx.get('challenge_flags', {}),
                    technologies=ctx.get('technologies', []),
                )
                _pillars_text_after = sections.get('pillars', '') or ''
                _p_matches_a = list(_PILLAR_HEADING_RE_GLOBAL.finditer(
                    _pillars_text_after))
                _p_all_h3_a = list(_ts_re.finditer(
                    r'^###[^#\n][^\n]*$', _pillars_text_after,
                    _ts_re.MULTILINE))
                if len(_p_all_h3_a) > len(_p_matches_a):
                    _p_matches_a = _p_all_h3_a
                _p_after = sum(
                    1 for i, m in enumerate(_p_matches_a)
                    if _pillar_has_substantive_initiative(
                        _pillars_text_after[
                            m.end():_p_matches_a[i + 1].start()
                            if i + 1 < len(_p_matches_a)
                            else len(_pillars_text_after)]))
                cycle['repairs'].append(f'pillars:{_p_before}->{_p_after}')
            except Exception as _e:
                cycle['repairs'].append(f'pillars_failed:{_e}')
        if 'environment' in failing_keys:
            try:
                synthesize_environment_context(
                    sections, lang, domain=domain, fw_short=fw_short,
                    sector=ctx.get('sector', 'General'),
                    org_name=ctx.get('org_name', 'The Organization'),
                    generation_mode=ctx.get('generation_mode', 'drafting'),
                    maturity=ctx.get('maturity', 'initial'),
                    challenges=ctx.get('challenges', ''),
                    frameworks=ctx.get('frameworks', []),
                )
                cycle['repairs'].append('environment')
            except Exception as _e:
                cycle['repairs'].append(f'environment_failed:{_e}')
        if 'gaps' in failing_keys:
            try:
                synthesize_gaps_depth(
                    sections, lang, domain=domain, fw_short=fw_short,
                    sector=ctx.get('sector', 'General'),
                    org_name=ctx.get('org_name', 'The Organization'),
                    org_structure_is_none=ctx.get(
                        'org_structure_is_none', False),
                    challenge_flags=ctx.get('challenge_flags', {}),
                    technologies=ctx.get('technologies', []),
                    diagnostic_gaps=ctx.get('diagnostic_gaps', []),
                    maturity=ctx.get('maturity', 'initial'),
                    generation_mode=ctx.get('generation_mode', 'drafting'),
                )
                cycle['repairs'].append('gaps')
            except Exception as _e:
                cycle['repairs'].append(f'gaps_failed:{_e}')
        if 'roadmap' in failing_keys:
            try:
                synthesize_roadmap_depth(
                    sections, lang, domain=domain, fw_short=fw_short,
                    generation_mode=ctx.get('generation_mode', 'drafting'),
                    org_structure_is_none=ctx.get(
                        'org_structure_is_none', False),
                    challenge_flags=ctx.get('challenge_flags', {}),
                    diagnostic_gaps=ctx.get('diagnostic_gaps', []),
                    technologies=ctx.get('technologies', []),
                    sector=ctx.get('sector', 'General'),
                    org_name=ctx.get('org_name', 'The Organization'),
                )
                cycle['repairs'].append('roadmap')
            except Exception as _e:
                cycle['repairs'].append(f'roadmap_failed:{_e}')
        if 'kpis' in failing_keys:
            # KPI repair is special: re-canonicalize via rebuild
            # function which both synthesizes rows AND collapses any
            # duplicate main-table headers.
            try:
                synthesize_kpi_depth(
                    sections, lang, domain=domain, fw_short=fw_short,
                    generation_mode=ctx.get('generation_mode', 'drafting'),
                    org_structure_is_none=ctx.get(
                        'org_structure_is_none', False),
                    challenge_flags=ctx.get('challenge_flags', {}),
                    diagnostic_gaps=ctx.get('diagnostic_gaps', []),
                    sector=ctx.get('sector', 'General'),
                    org_name=ctx.get('org_name', 'The Organization'),
                )
                rebuild_canonical_kpi_section(
                    sections, lang, domain, fw_short)
                cycle['repairs'].append('kpis')
            except Exception as _e:
                cycle['repairs'].append(f'kpis_failed:{_e}')
        if 'confidence' in failing_keys:
            try:
                synthesize_confidence_depth(
                    sections, lang, domain=domain, fw_short=fw_short,
                    org_name=ctx.get('org_name', 'The Organization'),
                    maturity=ctx.get('maturity', 'initial'),
                    generation_mode=ctx.get('generation_mode', 'drafting'),
                )
                cycle['repairs'].append('confidence')
            except Exception as _e:
                cycle['repairs'].append(f'confidence_failed:{_e}')

        # Re-audit after this cycle's repairs.
        post = _final_strategy_audit(sections, lang, doc_subtype)
        cycle['after'] = len(post)
        log['cycles'].append(cycle)

        if not post:
            log['converged'] = True
            log['final_defects'] = []
            log['progress'] = (len(post) < prev_defect_count)
            break
        if len(post) >= prev_defect_count and _it >= 1:
            # No progress after at least two repair cycles (iteration 0
            # attempts preserve-and-top-up; iteration ≥ 1 force-clears
            # pillars/vision for a clean rebuild). Bail only after the
            # force-clear path has had a chance to fire.
            log['final_defects'] = [(s, t, c, m) for s, t, c, m in post]
            log['progress'] = False
            break
        prev_defect_count = len(post)
        log['progress'] = True

    if not log['converged'] and not log['final_defects']:
        # Reached max_iter still failing — capture final state.
        log['final_defects'] = [
            (s, t, c, m) for s, t, c, m
            in _final_strategy_audit(sections, lang, doc_subtype)
        ]
    return log


# ────────────────────────────────────────────────────────────────────────────
# PASS-10 ARABIC FAMILY INTEGRITY HELPERS
#
# These run AFTER resection + KPI top-up and BEFORE the contamination
# validator. Their job: collapse same-family duplicates that resection or
# tier repairs may have produced, then remove EN template residue from
# Arabic strategy tables.
# ────────────────────────────────────────────────────────────────────────────

# Per-section family-heading patterns (## N. canonical title in EN+AR).
_FAMILY_HEADINGS_BY_SECTION = {
    'vision':      [r'##\s*1\.\s*(?:Vision|الرؤية)[^\n]*'],
    'pillars':     [r'##\s*2\.\s*(?:Strategic|الركائز)[^\n]*'],
    'environment': [r'##\s*3\.\s*(?:Business|Regulatory|البيئة|السياق)[^\n]*'],
    'gaps':        [r'##\s*4\.\s*(?:Gap|تحليل\s+الفجوات)[^\n]*'],
    'roadmap':     [r'##\s*5\.\s*(?:Implementation|Roadmap|خارطة)[^\n]*'],
    'kpis':        [r'##\s*6\.\s*(?:Key Performance|KPI|مؤشرات)[^\n]*'],
    'confidence':  [r'##\s*7\.\s*(?:Confidence|تقييم\s+(?:الثقة|الجاهزية))[^\n]*'],
}

# Per-section subsection family-heading patterns (### / #### within the
# section that may duplicate). For each section we list the canonical
# subsection headings whose duplicates should be collapsed.
_SUBSECTION_FAMILIES = {
    'gaps': [
        r'###\s*(?:Identified Gaps|الفجوات\s+المحددة)[^\n]*',
        r'###\s*(?:Gap Implementation Guidance|أدلة\s+تنفيذ\s+الفجوات)[^\n]*',
    ],
    'kpis': [
        r'###\s*(?:KPI Assessment Guidelines|أدلة\s+تقييم\s+مؤشرات\s+الأداء)[^\n]*',
    ],
    'confidence': [
        r'###\s*(?:Critical Success Factors|عوامل\s+النجاح\s+الحرجة)[^\n]*',
        r'###\s*(?:Key Risks|المخاطر\s+الاستراتيجية|المخاطر\s+الرئيسية)[^\n]*',
    ],
}

# EN→AR template residue map. Applied ONLY to AR strategies and ONLY to
# the strategy section payload (never to raw user data). Values are the
# canonical AR equivalents already present elsewhere in the codebase.
# ────────────────────────────────────────────────────────────────────────────
# CANONICAL FRAMEWORK ALIAS RESOLUTION
#
# A single generic helper used by BOTH environment synthesis and
# environment validation so they agree on what counts as "the
# framework being mentioned".
#
# Drives equivalences like:
#   - PDPL (Personal Data Protection Law)   ↔ PDPL ↔ Personal Data Protection Law
#   - NDMO Data Governance Framework        ↔ NDMO ↔ Data Governance Framework
#   - NCA ECC (Essential Cybersecurity Controls) ↔ NCA ECC
#   - NCA DCC (Data Cybersecurity Controls) ↔ NCA DCC
#   - SDAIA AI Ethics Framework             ↔ SDAIA ↔ AI Ethics Framework
#
# Generic — does NOT hardcode any single framework family. Aliases are
# derived structurally from the label string itself, with the
# FRAMEWORK_DETAILS short field consulted as an additional source when
# present (cyber-domain frameworks have it; data/AI/etc don't).
# ────────────────────────────────────────────────────────────────────────────


def canonical_framework_aliases(name):
    """Return the set of canonical alias strings that all refer to the
    same framework as `name`. Used by env synth (to know what's
    acceptable to render) and env validation (to know what's
    acceptable to find in env text).

    Generation rules — each rule is generic, not framework-specific:

      R1. The full label as submitted (always included).
      R2. The label with leading/trailing whitespace removed.
      R3. The label with the descriptive parenthetical stripped:
            "PDPL (Personal Data Protection Law)" → "PDPL"
      R4. Just the parenthetical content (without the parens):
            "PDPL (Personal Data Protection Law)" → "Personal Data
                                                     Protection Law"
      R5. Compact-acronym prefix: the leading run of UPPERCASE-or-/
          tokens before the first lowercase word, joined with single
          spaces:
            "NDMO Data Governance Framework" → "NDMO"
            "NCA DCC (Data) Cybersecurity Controls" → "NCA DCC"
            "SDAIA AI Ethics Framework" → "SDAIA AI" (then trimmed
              further to bare "SDAIA" via R6)
      R6. The first whitespace-delimited token if it's all-caps and
          ≥ 2 chars (catches bare acronyms: "NDMO", "PDPL", "SDAIA").
      R7. Tail after acronym: the descriptive remainder when an
          acronym leads:
            "NDMO Data Governance Framework" → "Data Governance Framework"
            "SDAIA AI Ethics Framework" → "AI Ethics Framework"
      R8. FRAMEWORK_DETAILS[name]['short'] when present (cyber dom).
      R9. Stripped trailing /leading punctuation on every alias.

    Returns a list (order preserved for deterministic logging) of
    non-empty alias strings ≥ 2 chars long. Idempotent and side-effect
    free.
    """
    if name is None:
        return []
    raw = str(name).strip()
    if not raw:
        return []
    aliases = []

    def _add(s):
        if not s:
            return
        s2 = str(s).strip(' \t\r\n.,;:-—–')
        if not s2 or len(s2) < 2:
            return
        if s2 in aliases:
            return
        aliases.append(s2)

    # R1, R2
    _add(raw)

    # R3: strip the FIRST descriptive parenthetical
    _paren_m = _ts_re.search(r'\s*\(([^)]*)\)\s*', raw)
    if _paren_m:
        _stripped = (raw[:_paren_m.start()] + ' '
                     + raw[_paren_m.end():]).strip()
        # Collapse any double-space introduced by the inserted joiner
        _stripped = _ts_re.sub(r'\s{2,}', ' ', _stripped)
        _add(_stripped)
        # R4: just the parenthetical content
        _add(_paren_m.group(1))

    # Working copy without parenthetical for token analysis
    _no_paren = _ts_re.sub(r'\s*\([^)]*\)\s*', ' ', raw).strip()
    if _no_paren and _no_paren != raw:
        _add(_no_paren)

    tokens = [t for t in _ts_re.split(r'\s+', _no_paren) if t]

    # R5/R6: leading acronym run
    if tokens:
        _acronym_run = []
        for tok in tokens:
            # An "acronym-like" token: at least 2 chars and ≥ 80%
            # uppercase OR matches A/B style separators or contains a
            # slash like NCA/SAMA. Stop at the first non-acronym
            # token (the start of a descriptive phrase).
            _stripped_tok = tok.strip(' \t.,;:')
            if not _stripped_tok or len(_stripped_tok) < 2:
                break
            _alpha = ''.join(c for c in _stripped_tok if c.isalpha())
            if not _alpha:
                break
            _upper_ratio = sum(1 for c in _alpha if c.isupper()) / len(_alpha)
            if _upper_ratio < 0.8:
                break
            _acronym_run.append(_stripped_tok)
        if _acronym_run:
            # R5 — multi-token acronym (e.g., "NCA DCC", "NCA ECC")
            _add(' '.join(_acronym_run))
            # R6 — bare leading acronym (e.g., "NDMO", "PDPL", "SDAIA")
            _add(_acronym_run[0])
            # R7 — tail after the acronym run
            if len(_acronym_run) < len(tokens):
                _tail = ' '.join(tokens[len(_acronym_run):])
                _add(_tail)

    # R8: registered short from FRAMEWORK_DETAILS (cyber dom)
    try:
        _fw_details = globals().get('FRAMEWORK_DETAILS') or {}
        _short_reg = ((_fw_details.get(raw) or {}).get('short') or '').strip()
        _add(_short_reg)
    except Exception:
        pass

    return aliases


def env_text_contains_any_framework(env_text, framework_names):
    """Return (matched_framework, matched_alias) if env_text mentions
    any of `framework_names` via its canonical alias set; else
    (None, None). Used by the env validator and is logged so operators
    can see WHICH alias matched.
    """
    if not env_text or not framework_names:
        return (None, None)
    for fw in framework_names:
        for alias in canonical_framework_aliases(fw):
            if alias and alias in env_text:
                return (fw, alias)
    return (None, None)



_AR_TEMPLATE_RESIDUE_MAP = {
    # Column-header residues seen in production AR exports
    'System/Tool':              'الأداة/النظام',
    'System / Tool':            'الأداة/النظام',
    'Tool/System':              'الأداة/النظام',
    'Tool / System':            'الأداة/النظام',
    # Framework long-names (mirrored from FRAMEWORK_AR_TRANSLATIONS)
    'NDMO Data Governance Framework':
        'إطار حوكمة البيانات - مكتب إدارة البيانات الوطنية (NDMO)',
    'SDAIA AI Ethics Framework':
        'إطار أخلاقيات الذكاء الاصطناعي - سدايا (SDAIA)',
    # Common cell-content residues
    'Within ':                  'خلال ',
    ' months':                  ' أشهر',
    ' month':                   ' شهر',
}


def normalize_final_arabic_sections(sections, lang):
    """FINAL post-synthesis Arabic residue scrubber (prompt clause 1).

    Earlier in the save pipeline, `sanitize_arabic_prompt_residue` removes
    prompt/instruction artifacts. THAT pass runs BEFORE
    `_apply_final_synthesis_pass`. The final synthesis pass — and the
    KPI canonical rebuild after it — can re-introduce EN template
    tokens (e.g. "Within 6 months", "System/Tool", framework long-names)
    when they emit fallback content from EN-only synthesis banks or
    when the LLM upstream produced EN cell content the validator now
    catches as `*_contains_en_template_residue`.

    This helper applies the existing _AR_TEMPLATE_RESIDUE_MAP as
    REPLACEMENTS (not deletions) on all seven canonical sections that
    the contamination validator checks: vision, pillars, environment,
    gaps, roadmap, kpis, confidence.
    Idempotent: running twice yields the same result.

    Returns a {section_key: count_of_replacements} dict for logging.
    """
    if lang != 'ar':
        return {}
    counts = {}
    for key in ('vision', 'pillars', 'environment', 'gaps',
                'roadmap', 'kpis', 'confidence'):
        text = sections.get(key, '') or ''
        if not text:
            continue
        n = 0
        for en, ar in _AR_TEMPLATE_RESIDUE_MAP.items():
            if en in text:
                # Count occurrences before replacement for logging
                _occ = text.count(en)
                text = text.replace(en, ar)
                n += _occ
        if n:
            sections[key] = text
            counts[key] = n
    return counts


# ────────────────────────────────────────────────────────────────────────────
# INLINE DUPLICATE-FAMILY BLOCK COLLAPSE (prompt Part 5)
#
# Real production symptom: the KPI section (or any canonical section)
# sometimes contains a SECOND `## N. {canonical title}` heading inside
# its own body, producing output like:
#
#   ## 6. مؤشرات الأداء الرئيسية
#   | # | وصف المؤشر | ... |
#   | 1 | مؤشر أ     | ... |
#
#   ## 6. مؤشرات الأداء الرئيسية          ← duplicate inline heading
#   | # | وصف المؤشر | ... |              ← duplicate inline table
#   | 1 | مؤشر ب     | ... |
#
# This is the "restarted family" / "one section family overwrites
# another" failure mode the prompt explicitly calls out. The existing
# resection and family-dedupe passes catch cross-section drift (e.g.,
# KPI-ish content appearing inside `sections['gaps']`) but do NOT catch
# the intra-section duplicate-family case because they operate on the
# section dictionary, not on raw section text.
#
# This helper collapses duplicate `## N.` headings and their tables
# WITHIN a single section body. It preserves the first heading +
# separator row, concatenates any subsequent table data rows after the
# first table, and discards any duplicate-heading lines. Row numbering
# is re-sequenced where column 0 is a digit.
# ────────────────────────────────────────────────────────────────────────────

# Canonical `## N.` heading patterns per-section for both languages. Used
# to detect duplicates — we don't require an exact match since AI output
# may vary slightly (e.g., "## 6. KPIs" vs "## 6. Key Performance
# Indicators"). We match on the `## N.` prefix + a keyword test.
_DUP_HEADING_KEYWORDS = {
    'vision': (
        ('vision', 'objective', 'strategic objectives'),
        ('الرؤية', 'الأهداف'),
    ),
    'pillars': (
        ('pillars', 'strategic pillars'),
        ('الركائز',),
    ),
    'environment': (
        ('environment', 'regulatory', 'threat context',
         'business environment'),
        ('البيئة', 'التنظيمية', 'التهديدات'),
    ),
    'gaps': (
        ('gap analysis', 'gaps'),
        ('الفجوات', 'تحليل الفجوات'),
    ),
    'roadmap': (
        ('roadmap', 'implementation roadmap'),
        ('خارطة الطريق', 'خارطة طريق'),
    ),
    'kpis': (
        ('key performance indicators', 'kpis', 'kpi'),
        ('مؤشرات الأداء',),
    ),
    'confidence': (
        ('confidence', 'risks'),
        ('تقييم الثقة', 'المخاطر'),
    ),
}


def _heading_matches_family(heading_text, section_key):
    """Return True if `heading_text` (a single heading line minus the
    leading `## N.` prefix) matches the canonical family for
    `section_key` via keyword test.
    """
    if section_key not in _DUP_HEADING_KEYWORDS:
        return False
    en_keys, ar_keys = _DUP_HEADING_KEYWORDS[section_key]
    tl = heading_text.lower()
    for k in en_keys:
        if k in tl:
            return True
    for k in ar_keys:
        if k in heading_text:
            return True
    return False


def collapse_inline_duplicate_family_blocks(sections, lang):
    """Scan each canonical section's body for duplicate `## N. {family}`
    headings and collapse them. Idempotent; no-op if no duplicates
    found.

    Detection rule: within `sections[key]`, find all lines matching
    `^##\\s+\\d+\\.`. The FIRST such line is the canonical section
    heading and is always kept. Any SUBSEQUENT `## \\d+.` whose title
    passes `_heading_matches_family` for the same section_key is a
    duplicate — its heading line is dropped and any table beneath it
    is appended to the table under the FIRST heading.

    Returns dict:
      {
        'collapsed_by_section': {key: {heading_drops: N, rows_merged: M}},
        'total_collapses': N,
        'sections_touched': [...],
      }
    """
    summary = {
        'collapsed_by_section': {},
        'total_collapses': 0,
        'sections_touched': [],
    }
    for key, (en_keys, ar_keys) in _DUP_HEADING_KEYWORDS.items():
        txt = sections.get(key, '') or ''
        if not txt.strip():
            continue

        # Find all `## N.` heading matches with their positions.
        heading_re = _ts_re.compile(r'^##\s+\d+\.?[^\n]*', _ts_re.MULTILINE)
        matches = list(heading_re.finditer(txt))
        if len(matches) < 2:
            continue

        # First match is the canonical section heading. Check any
        # subsequent match for family overlap.
        first = matches[0]
        duplicates = []
        for m in matches[1:]:
            title_after_prefix = _ts_re.sub(
                r'^##\s+\d+\.?\s*', '', m.group(0)).strip()
            if _heading_matches_family(title_after_prefix, key):
                duplicates.append(m)

        if not duplicates:
            continue

        # Build new section text: keep everything up to the first
        # duplicate heading. For each duplicate, extract the table rows
        # BELOW the duplicate heading (stopping at the next `##` or end)
        # and accumulate them. Then re-emit.
        new_parts = []
        heading_drops = 0
        rows_merged = 0

        # Range of the canonical first block = txt[0 : first_dup.start()]
        first_dup = duplicates[0]
        first_block = txt[:first_dup.start()].rstrip()
        new_parts.append(first_block)

        # Extract table rows from each duplicate block.
        for i, dup in enumerate(duplicates):
            # Duplicate block extends from dup.end() to the next `##`
            # OR the next duplicate OR end of text.
            next_hash_m = _ts_re.search(r'^##\s', txt[dup.end():],
                                         _ts_re.MULTILINE)
            if next_hash_m:
                block_end = dup.end() + next_hash_m.start()
            else:
                block_end = len(txt)
            block_body = txt[dup.end():block_end]
            heading_drops += 1

            # Pull data rows (skip header + separator rows — they match
            # the canonical header already present in the first block).
            data_rows = []
            seen_header = False
            seen_separator = False
            for ln in block_body.split('\n'):
                s = ln.strip()
                if not s.startswith('|'):
                    continue
                if not seen_header:
                    seen_header = True
                    continue
                if not seen_separator and _ts_re.match(
                        r'^\|[\s\-:|]+\|$', s):
                    seen_separator = True
                    continue
                # Skip if it's actually a header row (some AI outputs
                # repeat the header multiple times)
                if _ts_re.match(r'^\|\s*#\s*\|', s):
                    continue
                data_rows.append(s)
            rows_merged += len(data_rows)

            if data_rows:
                # Append these rows directly after the first block's
                # table — no blank line separator, so the rows become
                # part of the same table and `_resequence_leading_row_numbers`
                # renumbers them correctly.
                if new_parts and not new_parts[-1].endswith('\n'):
                    new_parts[-1] = new_parts[-1].rstrip() + '\n'
                new_parts.append('\n'.join(data_rows))

        # If there was trailing text AFTER the last duplicate block's
        # TABLE (e.g., `### KPI Assessment Guides` + guide bodies) that
        # is NOT a `##` heading, preserve it. Walk the last duplicate's
        # block_body, skip table rows that were already merged, and
        # keep the rest.
        last_dup = duplicates[-1]
        next_hash_m_last = _ts_re.search(r'^##\s', txt[last_dup.end():],
                                          _ts_re.MULTILINE)
        if next_hash_m_last:
            last_block_end = last_dup.end() + next_hash_m_last.start()
        else:
            last_block_end = len(txt)
        last_block_body = txt[last_dup.end():last_block_end]

        # Find where the table ends in last_block_body — after the last
        # `|...|` line, everything else is trailing content to preserve.
        _lb_lines = last_block_body.split('\n')
        _last_pipe_idx = -1
        for _i, _ln in enumerate(_lb_lines):
            if _ln.strip().startswith('|') and _ln.strip().endswith('|'):
                _last_pipe_idx = _i
        if _last_pipe_idx >= 0 and _last_pipe_idx < len(_lb_lines) - 1:
            _trailing_non_table = '\n'.join(
                _lb_lines[_last_pipe_idx + 1:]).strip('\n')
            if _trailing_non_table.strip():
                new_parts.append(_trailing_non_table)
        # And any content AFTER next `##` heading (the "other section"
        # trailing the duplicate block)
        if next_hash_m_last:
            trailing_after_next_hash = txt[last_block_end:]
            if trailing_after_next_hash.strip():
                new_parts.append(trailing_after_next_hash.rstrip())

        # Smart join: if a part looks like pure data rows (all lines
        # begin with `|`), append directly without blank separator so
        # it merges into the preceding table. Otherwise use blank-line
        # separator to maintain block structure.
        _joined_parts = []
        for _p in new_parts:
            if not _p.strip():
                continue
            _p_clean = _p.rstrip()
            _is_pure_rows = all(
                ln.strip().startswith('|') and ln.strip().endswith('|')
                for ln in _p_clean.split('\n') if ln.strip()
            )
            if _joined_parts and _is_pure_rows:
                # Attach to previous block without blank line
                _joined_parts[-1] = _joined_parts[-1].rstrip() + '\n' + _p_clean
            else:
                _joined_parts.append(_p_clean)
        new_txt = '\n\n'.join(_joined_parts)
        if not new_txt.endswith('\n'):
            new_txt += '\n'

        # Re-sequence row numbers in the primary table of this section
        # since we just merged rows with potentially duplicate `| 1 |`
        # prefixes.
        new_txt = _resequence_leading_row_numbers(new_txt)

        sections[key] = new_txt
        summary['collapsed_by_section'][key] = {
            'heading_drops': heading_drops,
            'rows_merged': rows_merged,
        }
        summary['total_collapses'] += heading_drops
        summary['sections_touched'].append(key)

    return summary


def _resequence_leading_row_numbers(section_text):
    """For each pipe-table in `section_text`, when a data row's first
    cell is purely numeric, renumber those cells sequentially starting
    at 1. Header and separator rows are untouched.

    This is a cleanup step after collapse_inline_duplicate_family_blocks
    merges tables — without it, rows would carry the original `| 1 |`,
    `| 2 |`, `| 1 |` pattern.
    """
    if not section_text:
        return section_text
    lines = section_text.split('\n')
    out = []
    in_table = False
    counter = 0
    saw_header = False

    def _is_separator(s):
        return bool(_ts_re.match(r'^\|[\s\-:|]+\|$', s.strip()))

    def _is_header(s):
        return (s.strip().startswith('|')
                and _ts_re.search(r'\|\s*#\s*\|', s))

    for ln in lines:
        s = ln.strip()
        if not s.startswith('|') or not s.endswith('|'):
            # Not in a table
            in_table = False
            saw_header = False
            counter = 0
            out.append(ln)
            continue
        if _is_separator(s):
            out.append(ln)
            continue
        if _is_header(s):
            # Reset for new table
            in_table = True
            counter = 0
            saw_header = True
            out.append(ln)
            continue
        if not saw_header:
            # Pipe row without preceding header — leave alone.
            out.append(ln)
            continue
        # Data row under a recognized header.
        cells = [c for c in ln.split('|')]
        # split gives ['', ' a ', ' b ', ''] for '| a | b |'
        if len(cells) >= 3 and cells[1].strip().replace('.', '').isdigit():
            counter += 1
            cells[1] = f' {counter} '
            out.append('|'.join(cells))
        else:
            out.append(ln)
    return '\n'.join(out)


# ────────────────────────────────────────────────────────────────────────────
# FAIL-CLOSED VALIDATION PASS (prompt Part 7)
#
# The prompt requires: "For Technical Strategy, remove save-with-warning
# for all of these failure classes: weak diagnosis-to-document grounding,
# English template residue in Arabic sections, section family
# instability, semantic section drift, thin environment section, thin
# roadmap, thin KPI section, weak confidence/risk section, incomplete
# KPI guide coverage, prompt/template residue, missing traceability from
# diagnosis. These must return 422 with clear backend errors."
#
# Some of these already have individual gates elsewhere in the save
# path (pillars_final_integrity, kpi_final_integrity, richness gate,
# diagnosis_grounding_check). This validator adds the ones that do NOT
# currently have a hard 422 gate:
#
#   A. English template residue in Arabic sections (prompt/template
#      residue) — currently scrubbed by normalize_final_arabic_sections,
#      but if scrubbing leaves anything, that's still a defect.
#   B. Inline section-family duplication (multiple `## N.` of the same
#      family within one section body) — structural instability.
#   C. Semantic section drift: roadmap-like table inside the
#      environment section, or KPI-like table inside the roadmap
#      section.
#   D. Thin environment paragraph count (<2 substantive paragraphs in
#      the environment section beyond any table block).
#   E. English heading residue inside Arabic `##` section headings
#      (e.g., "## 6. Key Performance Indicators" when lang='ar').
#   F. Generic language left in environment (placeholder phrases or
#      no sector/framework mentions).
#   G. Placeholder mitigation text in confidence risks (any "TBD" /
#      "N/A" / empty mitigation cell).
#
# Returns a list of (defect_tag, defect_detail_en, defect_detail_ar)
# triples. Empty list = pass.
# ────────────────────────────────────────────────────────────────────────────

# English residues that must NOT survive in Arabic sections. These are
# the most damaging ones — column headers that leak through synthesis.
_AR_ENGLISH_RESIDUE_PATTERNS = [
    r'\|\s*KPI Description\s*\|',
    r'\|\s*Target Value\s*\|',
    r'\|\s*Calculation Formula\s*\|',
    r'\|\s*Justification\s*\|',
    r'\|\s*Risk\s*\|',
    r'\|\s*Likelihood\s*\|',
    r'\|\s*Impact\s*\|',
    r'\|\s*Mitigation Plan\s*\|',
    r'\|\s*Factor\s*\|',
    r'\|\s*Importance\s*\|',
    r'\|\s*Activity\s*\|',
    r'\|\s*Owner\s*\|',
    r'\|\s*Timeline\s*\|',
    r'\|\s*Deliverable\s*\|',
    r'\|\s*Gap\s*\|',
    r'\|\s*Priority\s*\|',
    r'\|\s*Status\s*\|',
    r'\|\s*Initiative\s*\|',
    r'\|\s*Objective\s*\|',
    r'\|\s*Target Metric\s*\|',
    r'^###\s+Strategic Objectives\s*$',
    r'^###\s+Key Risks\s*$',
    r'^###\s+Critical Success Factors\s*$',
    r'^###\s+Score Justification\s*$',
    # Stage scaffolding
    r'\[STAGE\]',
    r'^Output:\s',
    r'^Response:\s',
]

# Keywords/phrases that mark an Arabic section's heading as accidentally
# English — block save if found in an AR section title.
_AR_ENGLISH_HEADING_MARKERS = [
    'Key Performance Indicators',
    'Confidence Assessment',
    'Implementation Roadmap',
    'Strategic Pillars',
    'Gap Analysis',
    'Business Environment',
]

# Canonical section → family keywords for duplicate-family detection
_PART7_FAMILY_KEYWORDS = {
    'vision': (('vision', 'objective', 'strategic objectives'),
                ('الرؤية', 'الأهداف')),
    'pillars': (('pillars', 'strategic pillars'),
                 ('الركائز',)),
    'environment': (('environment', 'regulatory', 'threat context',
                     'business environment'),
                    ('البيئة', 'التنظيمية', 'التهديدات')),
    'gaps': (('gap analysis', 'gaps'),
             ('الفجوات', 'تحليل الفجوات')),
    'roadmap': (('roadmap', 'implementation roadmap'),
                ('خارطة الطريق', 'خارطة طريق')),
    'kpis': (('key performance indicators', 'kpis', 'kpi'),
             ('مؤشرات الأداء',)),
    'confidence': (('confidence', 'risks'),
                   ('تقييم الثقة', 'المخاطر')),
}


def _heading_matches_part7_family(heading_title, section_key):
    en_k, ar_k = _PART7_FAMILY_KEYWORDS.get(section_key, ((), ()))
    tl = heading_title.lower()
    for k in en_k:
        if k in tl:
            return True
    for k in ar_k:
        if k in heading_title:
            return True
    return False


def validate_strategy_fail_closed(sections, lang, diag_model=None):
    """Comprehensive fail-closed validation pass for Technical Strategy.
    Runs all 7 failure-class checks (Part 7) that don't yet have
    dedicated gates. Returns list of defect triples:
      [(tag, detail_en, detail_ar), ...]
    Empty list = pass.
    """
    defects = []
    is_ar = (lang == 'ar')

    # ── A. English template residue in Arabic sections ──
    if is_ar:
        for key in ('vision', 'pillars', 'environment', 'gaps',
                     'roadmap', 'kpis', 'confidence'):
            txt = sections.get(key, '') or ''
            if not txt:
                continue
            for pattern in _AR_ENGLISH_RESIDUE_PATTERNS:
                m = _ts_re.search(pattern, txt,
                                    _ts_re.IGNORECASE | _ts_re.MULTILINE)
                if m:
                    defects.append((
                        f'english_residue_in_ar_{key}',
                        f'English template residue in {key} section: '
                        f'{m.group(0)!r}',
                        f'بقايا إنجليزية في قسم {key}: {m.group(0)!r}',
                    ))
                    break  # one defect per section is enough

    # ── B. Inline section-family duplication ──
    for key, (en_k, ar_k) in _PART7_FAMILY_KEYWORDS.items():
        txt = sections.get(key, '') or ''
        if not txt.strip():
            continue
        hdrs = _ts_re.findall(r'^##\s+\d+\.?[^\n]*', txt,
                                _ts_re.MULTILINE)
        if len(hdrs) < 2:
            continue
        fam_matches = sum(
            1 for h in hdrs
            if _heading_matches_part7_family(
                _ts_re.sub(r'^##\s+\d+\.?\s*', '', h).strip(),
                key,
            )
        )
        if fam_matches >= 2:
            defects.append((
                f'inline_duplicate_family_{key}',
                f'{fam_matches} `## N.` headings of the same family '
                f'in the {key} section body',
                f'تكرار العنوان {fam_matches} مرات داخل قسم {key}',
            ))

    # ── C. Semantic section drift ──
    # Roadmap-like table in environment section (| Activity | or
    # | النشاط | appearing inside sections['environment']).
    env_txt = sections.get('environment', '') or ''
    if env_txt:
        if _ts_re.search(r'\|\s*(?:Activity|النشاط)\s*\|',
                          env_txt, _ts_re.IGNORECASE):
            defects.append((
                'drift_environment_contains_roadmap_table',
                'environment section contains a roadmap-like Activity '
                'table header',
                'قسم البيئة يحتوي على جدول أنشطة من خارطة الطريق',
            ))
    # KPI-like table in roadmap section
    rm_txt = sections.get('roadmap', '') or ''
    if rm_txt:
        if _ts_re.search(r'\|\s*(?:KPI Description|وصف المؤشر)\s*\|',
                          rm_txt, _ts_re.IGNORECASE):
            defects.append((
                'drift_roadmap_contains_kpi_table',
                'roadmap section contains a KPI-like table header',
                'قسم خارطة الطريق يحتوي على جدول مؤشرات',
            ))
    # Gap-table-like inside pillars
    pi_txt = sections.get('pillars', '') or ''
    if pi_txt:
        if _ts_re.search(r'\|\s*(?:Gap|الفجوة)\s*\|',
                          pi_txt, _ts_re.IGNORECASE):
            defects.append((
                'drift_pillars_contains_gap_table',
                'pillars section contains a gap-like table header',
                'قسم الركائز يحتوي على جدول فجوات',
            ))

    # ── D. Thin environment paragraph count ──
    # Prompt: "must contain at least 2 substantive Arabic narrative
    # paragraphs plus a structured summary block".
    if env_txt:
        # A paragraph is a block of non-pipe-table text separated by
        # blank lines. Count only those ≥ 100 chars (after strip).
        paragraphs = []
        buf = []
        for ln in env_txt.split('\n'):
            stripped = ln.strip()
            if stripped.startswith('|') or stripped.startswith('##') \
                    or stripped.startswith('#'):
                if buf:
                    blob = ' '.join(buf).strip()
                    if len(blob) >= 100:
                        paragraphs.append(blob)
                    buf = []
                continue
            if not stripped:
                if buf:
                    blob = ' '.join(buf).strip()
                    if len(blob) >= 100:
                        paragraphs.append(blob)
                    buf = []
            else:
                buf.append(stripped)
        if buf:
            blob = ' '.join(buf).strip()
            if len(blob) >= 100:
                paragraphs.append(blob)
        if len(paragraphs) < 2:
            defects.append((
                'environment_paragraphs_insufficient',
                f'environment section has {len(paragraphs)} substantive '
                f'paragraph(s); ≥ 2 required',
                f'قسم البيئة يحتوي على {len(paragraphs)} فقرة جوهرية؛ '
                f'المطلوب ≥ 2',
            ))

    # ── E. English heading residue in Arabic section titles ──
    if is_ar:
        for key in ('vision', 'pillars', 'environment', 'gaps',
                     'roadmap', 'kpis', 'confidence'):
            txt = sections.get(key, '') or ''
            if not txt:
                continue
            top_hdr_m = _ts_re.search(r'^##\s+\d+\.?[^\n]*', txt,
                                       _ts_re.MULTILINE)
            if not top_hdr_m:
                continue
            hdr_text = top_hdr_m.group(0)
            for marker in _AR_ENGLISH_HEADING_MARKERS:
                if marker in hdr_text:
                    defects.append((
                        f'english_heading_in_ar_{key}',
                        f'Arabic {key} section has English heading: '
                        f'{hdr_text!r}',
                        f'قسم {key} يحمل عنواناً إنجليزياً: {hdr_text!r}',
                    ))
                    break

    # ── F. Generic environment (no sector/framework mentions) ──
    if env_txt and diag_model:
        sector_val = (diag_model.get('sector') or '').strip()
        frameworks_val = diag_model.get('frameworks', []) or []
        # Ignore these generic/default sector/framework values that
        # wouldn't distinguish the strategy.
        _generic_sectors = {
            'General', 'general', 'حكومي', 'Government',
            'Not specified', 'غير محدد',
        }
        if (sector_val and sector_val not in _generic_sectors
                and sector_val.lower() not in env_txt.lower()
                and sector_val not in env_txt):
            defects.append((
                'environment_missing_sector_reference',
                f'environment section does not mention sector '
                f'{sector_val!r}',
                f'قسم البيئة لا يذكر القطاع {sector_val!r}',
            ))
        # At least one framework from the list must appear in env text.
        # ── FRAMEWORK ALIAS MATCHING (canonical, generic) ──────────
        # Uses module-level canonical_framework_aliases() which derives
        # aliases STRUCTURALLY from each framework label (full name,
        # parenthetical-stripped form, parenthetical content, leading
        # acronym, tail-after-acronym, registered short). This works
        # for any framework family, not just those in FRAMEWORK_DETAILS
        # — closing the recurring `environment_missing_framework_reference`
        # for PDPL, NDMO, SDAIA AI Ethics, etc.
        if frameworks_val:
            _matched_fw, _matched_alias = env_text_contains_any_framework(
                env_txt, frameworks_val)
            # Build per-framework alias map for log line (clause 7).
            _alias_map = {
                str(f): canonical_framework_aliases(f)
                for f in frameworks_val
            }
            print(
                '[STRATEGY-DIAG] env_framework_validation '
                f'selected={list(_alias_map.keys())} '
                f'aliases={_alias_map} '
                f'matched_framework={_matched_fw!r} '
                f'matched_alias={_matched_alias!r} '
                f'passed={_matched_fw is not None}',
                flush=True,
            )
            if _matched_fw is None:
                defects.append((
                    'environment_missing_framework_reference',
                    f'environment section does not mention any of: '
                    f'{frameworks_val} (canonical aliases checked: '
                    f'{_alias_map})',
                    f'قسم البيئة لا يذكر أياً من: {frameworks_val}',
                ))

    # ── G. Placeholder mitigation text in confidence risks ──
    conf_txt = sections.get('confidence', '') or ''
    if conf_txt:
        risk_hdr = _ts_re.compile(
            r'^\|\s*#\s*\|\s*(?:Risk|المخاطر|الخطر)\s*\|',
            _ts_re.IGNORECASE,
        )
        # Walk rows under risk header; last cell is the mitigation.
        placeholder_count = 0
        for cells in _ts_table_rows(conf_txt, risk_hdr):
            if not cells or not cells[0].replace('.', '').isdigit():
                continue
            if len(cells) < 5:  # # | Risk | Lik | Impact | Mitigation
                continue
            mitigation = cells[-1].strip()
            if (not mitigation or _ts_is_placeholder(mitigation)
                    or mitigation.lower() in ('tbd', 'n/a', '-', '—')):
                placeholder_count += 1
        if placeholder_count > 0:
            defects.append((
                'confidence_risks_placeholder_mitigation',
                f'{placeholder_count} risk row(s) have placeholder '
                f'mitigation',
                f'{placeholder_count} صف مخاطر يحمل معالجة وهمية',
            ))

    return defects


# ────────────────────────────────────────────────────────────────────────────
# ROW-LEVEL TRACEABILITY (prompt Part 3)
#
# Operational, not logged-metadata-only. Each substantive pipe-table
# data row in gaps/objectives/pillars/roadmap/KPI/confidence-risks gets
# an inline HTML-comment tag recording (a) which diagnostic signal
# drove the row and (b) cross-reference links to related rows in other
# sections.
#
# Tag grammar (single-line, keeps row formatting):
#     <!-- trace:section=S|src=SRC|key=VAL[|link=L] -->
#
# - section: gaps|objectives|pillars|roadmap|kpis|confidence
# - src: diag_structural | diag_flag:<flag> | diag_gap:<idx>
#        | tech_gap:<cat> | bank_fallback | ai_preserved
# - key: row_N identifier
# - link: cross-references to OTHER section rows, e.g.:
#     roadmap row → gap_ref=3 (points to gap row 3)
#     KPI row → roadmap_row=2 (points to roadmap row 2)
#     objective row → gap_ref=1 (points to gap row 1)
# ────────────────────────────────────────────────────────────────────────────

_TRACE_TAG_RE = _ts_re.compile(
    r'<!--\s*trace:\s*((?:[^-]|-(?!->))+?)\s*-->',
    _ts_re.IGNORECASE,
)


def make_trace_tag(section, src, key, link=None):
    """Return a single-line HTML comment tag safe for Markdown pipe-table rows.

    Fields are joined with ';' so that the comment contains no '|' characters
    and cannot create phantom table columns when a row is split on '|'.
    Legacy tags that used '|' as a separator are still readable by
    parse_trace_tag(), which accepts both delimiters.
    """
    parts = [f'section={section}', f'src={src}', f'key={key}']
    if link:
        parts.append(f'link={link}')
    return f'<!-- trace:{";".join(parts)} -->'


def parse_trace_tag(tag_text):
    """Parse ``trace:k=v;k=v;...`` body into dict.

    Accepts both the current semicolon-delimited format and the legacy
    pipe-delimited format for backward compatibility.  Returns None on
    malformed input (missing 'section' or 'src' field).
    """
    if not tag_text:
        return None
    out = {}
    # Split on either ';' (new) or '|' (legacy) to support both formats.
    for pair in _ts_re.split(r'[;|]', tag_text):
        pair = pair.strip()
        if '=' not in pair:
            continue
        k, v = pair.split('=', 1)
        out[k.strip()] = v.strip()
    if 'section' not in out or 'src' not in out:
        return None
    return out


def extract_traceability_map(sections):
    """Walk each canonical section's body and extract trace tags.
    Returns: by_section (list of tag dicts per section), substantive-row
    counts, orphan counts (substantive rows lacking tags), and totals.
    """
    out = {
        'by_section': {},
        'orphan_rows_by_section': {},
        'substantive_rows_by_section': {},
        'total_orphans': 0,
        'total_substantive': 0,
    }
    _header_tokens = _ts_re.compile(r'(?:\|\s*#\s*\|)', _ts_re.IGNORECASE)
    for key in ('vision', 'pillars', 'environment', 'gaps', 'roadmap',
                 'kpis', 'confidence'):
        txt = sections.get(key, '') or ''
        if not txt.strip():
            continue
        tags = []
        for m in _TRACE_TAG_RE.finditer(txt):
            parsed = parse_trace_tag(m.group(1))
            if parsed:
                tags.append(parsed)
        out['by_section'][key] = tags

        rows_total = 0
        saw_header = False
        for ln in txt.split('\n'):
            s = ln.strip()
            if not s.startswith('|') or not s.endswith('|'):
                saw_header = False
                continue
            if _header_tokens.search(s):
                saw_header = True
                continue
            if _ts_re.match(r'^\|[\s\-:|]+\|$', s):
                continue
            if not saw_header:
                continue
            rows_total += 1
        out['substantive_rows_by_section'][key] = rows_total
        out['total_substantive'] += rows_total
        orphans = max(0, rows_total - len(tags))
        out['orphan_rows_by_section'][key] = orphans
        out['total_orphans'] += orphans
    return out


def _build_section_row_index(sections):
    """Scan pipe-table rows in gaps/roadmap/objectives/pillars and build
    a keyword→row_number index per section. Used by
    apply_traceability_tags to resolve cross-references at link time.

    Returns dict: {
      'gaps':       [(row_num, descriptive_text_lower), ...],
      'roadmap':    [(row_num, descriptive_text_lower), ...],
      'objectives': [(row_num, descriptive_text_lower), ...],
      'pillars':    [(row_num, descriptive_text_lower), ...],
    }
    """
    index = {'gaps': [], 'roadmap': [], 'objectives': [], 'pillars': []}
    # Objectives are nested in the vision section, not a separate key.
    _mapping = {
        'gaps':       sections.get('gaps', '') or '',
        'roadmap':    sections.get('roadmap', '') or '',
        'objectives': sections.get('vision', '') or '',
        'pillars':    sections.get('pillars', '') or '',
    }
    _header_tokens = _ts_re.compile(r'(?:\|\s*#\s*\|)', _ts_re.IGNORECASE)
    for name, txt in _mapping.items():
        if not txt:
            continue
        saw_header = False
        row_n = 0
        for ln in txt.split('\n'):
            s = ln.strip()
            if not s.startswith('|') or not s.endswith('|'):
                saw_header = False
                row_n = 0
                continue
            if _header_tokens.search(s):
                saw_header = True
                row_n = 0
                continue
            if _ts_re.match(r'^\|[\s\-:|]+\|$', s):
                continue
            if not saw_header:
                continue
            # Data row. Use row counter since `#` col may not match display.
            row_n += 1
            cells = [c.strip() for c in _strip_trace_comments(s).split('|')[1:-1]]
            descriptive = ' '.join(cells[1:]) if len(cells) >= 2 else s
            index[name].append((row_n, descriptive.lower()))
    return index


def _find_linked_row(tokens, row_index):
    """Given a list of tokens (lowercase), return the first row_number
    in row_index whose descriptive text contains any of them."""
    if not tokens or not row_index:
        return None
    for tok in tokens:
        if not tok:
            continue
        tok_lc = tok.lower()
        for (rn, desc_lc) in row_index:
            if tok_lc in desc_lc:
                return rn
    return None


def apply_traceability_tags(sections, diag_model):
    """Post-synth pass: append `<!-- trace:... -->` tags to every
    substantive pipe-table row in the 7 canonical sections.

    Classifies the src by keyword matching against diagnostic signals
    (org_structure_is_none, challenge_flags, tech_gaps).

    Populates cross-reference `link=` field automatically (prompt Part
    3 residual — operational cross-references, not logged-only):
      - KPI rows → roadmap_row=N (matched by theme keywords)
      - Roadmap rows → gap_ref=N
      - Objective rows (in vision) → gap_ref=N
      - Pillar rows → gap_ref=N (when pillars are tabular)

    Idempotent: rows already bearing a tag are skipped.

    Returns dict {section_key: count_of_tags_added}.
    """
    if not diag_model:
        diag_model = {}
    is_none = diag_model.get('org_structure_is_none', False)
    flags = diag_model.get('challenge_flags', {}) or {}
    tech_gaps = diag_model.get('tech_gaps', []) or []

    # ── Build cross-reference index before any mutation ──
    # apply_traceability_tags mutates section bodies; the index must
    # be built from the CURRENT row positions (pre-tagging) so link
    # numbers reference rows as they will appear in the final output.
    row_index = _build_section_row_index(sections)

    # Keyword sets for classification + linkage (shared for both).
    _structural_en = ('governance', 'structure', 'committee', 'charter',
                      'steering', 'organizational')
    _structural_ar = ('حوكمة', 'هيكل', 'لجنة', 'ميثاق', 'توجيه')
    _awareness_en = ('awareness', 'training', 'phishing')
    _awareness_ar = ('وعي', 'تدريب', 'تصيد')
    _ir_en = ('soc', 'siem', 'incident', 'detection', 'response', 'monitor')
    _ir_ar = ('مراقبة', 'استجابة', 'حوادث', 'كشف', 'رصد')
    _staffing_en = ('staff', 'hiring', 'workforce', 'skill')
    _staffing_ar = ('كوادر', 'مهارات', 'توظيف')
    _suppliers_en = ('supplier', 'vendor', 'third-party', 'third party')
    _suppliers_ar = ('موردين', 'أطراف ثالثة')
    _compliance_en = ('compliance', 'audit', 'evidence')
    _compliance_ar = ('امتثال', 'تدقيق', 'أدلة')

    # Linkage tokens per theme (EN+AR unified for simpler match logic).
    _theme_tokens = {
        'structural':       (_structural_en + _structural_ar),
        'awareness':        (_awareness_en + _awareness_ar),
        'ir':               (_ir_en + _ir_ar),
        'staffing':         (_staffing_en + _staffing_ar),
        'suppliers':        (_suppliers_en + _suppliers_ar),
        'compliance':       (_compliance_en + _compliance_ar),
    }

    def _classify_row(row_text):
        """Return (src_tag, theme_key) for a row's content.
        theme_key is used to choose which token bag to use for link
        resolution; None for unclassified."""
        tl = row_text.lower()

        def _matches(en_tok, ar_tok):
            for t in en_tok:
                if t in tl:
                    return True
            for t in ar_tok:
                if t in row_text:
                    return True
            return False

        if is_none and _matches(_structural_en, _structural_ar):
            return ('diag_structural', 'structural')
        if flags.get('awareness') and _matches(_awareness_en, _awareness_ar):
            return ('diag_flag:awareness', 'awareness')
        if flags.get('incident_response') and _matches(_ir_en, _ir_ar):
            return ('diag_flag:incident_response', 'ir')
        if flags.get('staffing') and _matches(_staffing_en, _staffing_ar):
            return ('diag_flag:staffing', 'staffing')
        if flags.get('suppliers') and _matches(_suppliers_en, _suppliers_ar):
            return ('diag_flag:suppliers', 'suppliers')
        if flags.get('compliance') and _matches(_compliance_en, _compliance_ar):
            return ('diag_flag:compliance', 'compliance')
        for tg in tech_gaps:
            if tg.lower() in tl:
                return (f'tech_gap:{tg}', 'ir')  # tech gap → IR-related linkage
        if is_none or flags or tech_gaps:
            return ('bank_fallback', None)
        return ('ai_preserved', None)

    def _resolve_link(section_key, theme_key, row_text):
        """Return a `link=...` suffix (without the `link=` prefix) or
        None. Direction depends on section_key:
          kpis      → roadmap_row=N
          roadmap   → gap_ref=N
          objectives (in vision) → gap_ref=N
          pillars   → gap_ref=N
          gaps      → None (gaps are leaf — source of linkage)
          confidence → roadmap_row=N (risks → mitigation roadmap)
        """
        if not theme_key:
            # Try raw row_text fallback — pick 3-word prefix as tokens
            toks = row_text.lower().split()[:5]
        else:
            toks = _theme_tokens.get(theme_key, ())
        if section_key == 'kpis':
            rn = _find_linked_row(toks, row_index.get('roadmap', []))
            return f'roadmap_row={rn}' if rn else None
        if section_key == 'roadmap':
            rn = _find_linked_row(toks, row_index.get('gaps', []))
            return f'gap_ref={rn}' if rn else None
        if section_key == 'pillars':
            rn = _find_linked_row(toks, row_index.get('gaps', []))
            return f'gap_ref={rn}' if rn else None
        if section_key == 'vision':  # objectives live here
            rn = _find_linked_row(toks, row_index.get('gaps', []))
            return f'gap_ref={rn}' if rn else None
        if section_key == 'confidence':
            rn = _find_linked_row(toks, row_index.get('roadmap', []))
            return f'roadmap_row={rn}' if rn else None
        return None

    # ── Walk each section and tag rows ──
    _header_tokens = _ts_re.compile(r'(?:\|\s*#\s*\|)', _ts_re.IGNORECASE)
    added = {}

    for section_key in ('vision', 'pillars', 'environment', 'gaps',
                         'roadmap', 'kpis', 'confidence'):
        txt = sections.get(section_key, '') or ''
        if not txt.strip():
            continue
        new_lines = []
        saw_header = False
        row_counter = 0
        tags_added_here = 0

        for ln in txt.split('\n'):
            s = ln.strip()
            if not s.startswith('|') or not s.endswith('|'):
                saw_header = False
                row_counter = 0
                new_lines.append(ln)
                continue
            if _header_tokens.search(s):
                saw_header = True
                row_counter = 0
                new_lines.append(ln)
                continue
            if _ts_re.match(r'^\|[\s\-:|]+\|$', s):
                new_lines.append(ln)
                continue
            if not saw_header:
                new_lines.append(ln)
                continue
            # Data row. Skip if already tagged (idempotent).
            if _TRACE_TAG_RE.search(s):
                new_lines.append(ln)
                row_counter += 1
                continue

            row_counter += 1
            # Strip any existing trace comments before splitting (idempotency:
            # the row already has a tag from a prior run — avoid double-counting).
            cells = [c.strip() for c in _strip_trace_comments(s).split('|')[1:-1]]
            descriptive = ' '.join(cells[1:]) if len(cells) >= 2 else s
            src_tag, theme_key = _classify_row(descriptive)
            link_suffix = _resolve_link(section_key, theme_key, descriptive)
            key_val = f'row_{row_counter}'
            tag = make_trace_tag(section_key, src_tag, key_val,
                                  link=link_suffix)

            # Insert the tag INSIDE the last cell so the row keeps its
            # trailing `|`. `ln.rsplit('|', 1)` splits off the final
            # pipe boundary; we append the tag before reassembling.
            if ln.rstrip().endswith('|'):
                stripped_ln = ln.rstrip()
                # Drop trailing pipe, append ' <tag> |'
                without_tail = stripped_ln[:-1].rstrip()
                new_ln = without_tail + ' ' + tag + ' |'
                new_lines.append(new_ln)
            else:
                new_lines.append(ln)
                new_lines.append(tag)
            tags_added_here += 1

        if tags_added_here:
            sections[section_key] = '\n'.join(new_lines)
            added[section_key] = tags_added_here
    return added


def _ts_collapse_table_blocks(text, header_re):
    """Find all (header, separator, rows...) table occurrences in `text`
    that match `header_re`. Keep the FIRST header+separator and concatenate
    all data rows under it. Renumber rows sequentially in column 0 if
    column 0 is a digit.

    This is what makes the user's two-data-row-blocks collapse into one
    continuous table after resection.
    """
    if not text:
        return text
    lines = text.split('\n')
    blocks = []  # list of (start_idx, sep_idx, end_idx, data_rows[list of cells])
    i = 0
    n = len(lines)
    while i < n:
        s = lines[i].strip()
        if header_re.match(s):
            sep_idx = i + 1 if i + 1 < n else None
            # Skip separator row if present
            if sep_idx is not None and _ts_re.match(
                r'^\|[\s\-:|]+\|$', lines[sep_idx].strip()
            ):
                j = sep_idx + 1
            else:
                sep_idx = None
                j = i + 1
            data_rows = []
            while j < n:
                t = lines[j].strip()
                if not t.startswith('|') or not t.endswith('|'):
                    break
                if _ts_re.match(r'^\|[\s\-:|]+\|$', t):
                    j += 1
                    continue
                data_rows.append(t)
                j += 1
            blocks.append((i, sep_idx, j - 1, data_rows))
            i = j
            continue
        i += 1
    if len(blocks) <= 1:
        return text

    # Multiple blocks → keep first header+separator, merge all data rows.
    first_start, first_sep, _first_end, _first_rows = blocks[0]
    all_rows = []
    for _bi, (_s, _sep, _e, rows) in enumerate(blocks):
        all_rows.extend(rows)
    # Renumber sequentially in col 0 if col 0 is digit
    renumbered = []
    counter = 1
    seen_signatures = set()
    for row in all_rows:
        cells = [c.strip() for c in row.split('|')[1:-1]]
        if cells and cells[0].replace('.', '').isdigit():
            # Dedupe based on the rest of the cells (cols 1..) — same
            # logical row repeated under different table starts gets
            # collapsed to one entry.
            sig = '||'.join(cells[1:]).strip().lower()
            if sig in seen_signatures:
                continue
            seen_signatures.add(sig)
            cells[0] = str(counter)
            counter += 1
            renumbered.append('| ' + ' | '.join(cells) + ' |')
        else:
            renumbered.append(row)
    # Reconstruct the file: lines[:first_start+1] + sep_line +
    # renumbered_rows + everything that was AFTER the last block but
    # SKIPPING all bytes between first_start and last_end
    last_end = blocks[-1][2]
    head = lines[:first_start + 1]
    sep_line = ([lines[first_sep]] if first_sep is not None else [])
    tail = lines[last_end + 1:]
    # Also collect any non-table lines that lived between blocks (rare —
    # usually blank lines or stray text). Preserve them between head
    # and renumbered rows so we don't lose narrative.
    interstitial = []
    cursor = (first_sep if first_sep is not None else first_start) + 1
    for (s, sep, e, _rows) in blocks:
        # skip lines belonging to this block
        block_start_idx = s
        if cursor < block_start_idx:
            slab = lines[cursor:block_start_idx]
            for ln in slab:
                if ln.strip():
                    interstitial.append(ln)
        cursor = e + 1
    return '\n'.join(head + sep_line + renumbered + interstitial + tail)


def cleanup_arabic_template_residue(sections, lang):
    """Replace known EN template residue with AR canonical equivalents.
    Only runs for Arabic strategies. Idempotent. Targets STRATEGY SECTION
    PAYLOAD only — never raw user input.
    """
    if lang != 'ar':
        return 0
    replacements = 0
    for k in list(sections.keys()):
        text = sections.get(k, '') or ''
        if not text:
            continue
        new_text = text
        for en, ar in _AR_TEMPLATE_RESIDUE_MAP.items():
            if en in new_text:
                count_here = new_text.count(en)
                new_text = new_text.replace(en, ar)
                replacements += count_here
        if new_text != text:
            sections[k] = new_text
    return replacements


# Broad regex for KPI guides-block heading family. Matches every variant
# the AI has historically produced, including BiDi-mark variants and
# Arabic synonyms (دليل/أدلة/إرشادات + المؤشرات/مؤشرات الأداء/المؤشرات الرئيسية)
# and English variants (KPI/Indicator + Assessment Guide(s)/Guidelines).
_KPI_GUIDES_HEADING_RE = _ts_re.compile(
    r'^###[\s\u200e\u200f\u202a-\u202e\u00a0]*'
    r'(?:'
        # English variants
        r'(?:Per[\-\s]?)?KPI[\s\u00a0]+Assessment[\s\u00a0]+Guidelines?'
        r'|Indicator[\s\u00a0]+Assessment[\s\u00a0]+Guidelines?'
        r'|KPI[\s\u00a0]+Guides?'
        # Arabic variants — أدلة / دليل / إرشادات + تقييم +
        # (المؤشرات | مؤشرات الأداء | المؤشرات الرئيسية)
        r'|(?:أدلة|دليل|إرشادات)'
        r'[\s\u00a0\u200e\u200f]+'
        r'تقييم'
        r'[\s\u00a0\u200e\u200f]+'
        r'(?:ال)?مؤشرات'
        r'(?:[\s\u00a0\u200e\u200f]+(?:الأداء|الرئيسية|الرئيسة))?'
    r')'
    r'[^\n]*$',
    _ts_re.MULTILINE | _ts_re.IGNORECASE,
)

# Broad per-KPI guide subsection heading: `#### KPI #N Assessment Guide:`
# or `#### دليل تقييم المؤشر رقم N:` and synonyms.
_PER_KPI_GUIDE_HEADING_RE = _ts_re.compile(
    r'^####[\s\u00a0\u200e\u200f]*'
    r'(?:'
        # English
        r'KPI[\s\u00a0]*#?(?P<num_en>\d+)[\s\u00a0]+Assessment[\s\u00a0]+Guides?'
        # Arabic — multiple phrasings of "دليل تقييم المؤشر رقم N"
        r'|(?:دليل|أدلة|إرشادات)'
        r'[\s\u00a0\u200e\u200f]+'
        r'تقييم'
        r'[\s\u00a0\u200e\u200f]+'
        r'(?:ال)?مؤشر'
        r'(?:[\s\u00a0\u200e\u200f]+(?:رقم|#))?'
        r'[\s\u00a0]*(?P<num_ar>\d+)'
    r')'
    r'[^\n]*$',
    _ts_re.MULTILINE | _ts_re.IGNORECASE,
)

# Broad KPI-main-table header — recognizes EN and AR variants regardless
# of column-3/4/5 labels.
_KPI_MAIN_TABLE_HEADER_RE = _ts_re.compile(
    r'^\|[\s\u00a0]*#[\s\u00a0]*\|'
    r'[\s\u00a0]*(?:KPI[\s\u00a0]+Description|وصف[\s\u00a0]+المؤشر|KPI|المؤشر|Metric)'
    r'[\s\u00a0]*\|',
    _ts_re.MULTILINE | _ts_re.IGNORECASE,
)

# ── PASS-11 CANONICAL KPI REBUILDER ────────────────────────────────────
def rebuild_canonical_kpi_section(sections, lang, domain, fw_short):
    """Reconstruct sections['kpis'] from three canonical components:
        a) ## 6. <KPI section title>            (one)
        b) one canonical KPI main table         (merged from any duplicates)
        c) one canonical KPI guides heading     (### أدلة تقييم...)
        d) per-KPI guides, deduplicated by N    (one block per row)

    This is what the prompt requires: "normalize first, remove duplicate
    KPI-family headings, ensure one canonical main table, ensure one
    canonical guides family, then append only missing guides".

    Returns a dict summarizing what was rebuilt. Idempotent.
    """
    kpis = sections.get('kpis', '') or ''
    is_ar = (lang == 'ar')

    # PASS-11 gap fix: empty kpis section must NOT short-circuit. Falling
    # through with empty extraction lists lets Step 3 synthesize >= 2 rows
    # and Step 4 rebuild from canonical pieces. This matches the prompt's
    # "do NOT return early leaving a 1-row KPI table in place".

    # ── Step 1: extract every KPI main table data row from anywhere in
    # the section, regardless of how many headers exist or where they sit.
    lines = kpis.split('\n')
    n = len(lines)
    main_table_rows = []  # list of cell-lists (raw, no #)
    main_table_seen_signatures = set()
    i = 0
    in_main = False
    while i < n:
        s = lines[i].strip()
        if not in_main:
            if _KPI_MAIN_TABLE_HEADER_RE.match(s):
                in_main = True
                i += 1
                # Skip separator if present
                if i < n and _ts_re.match(r'^\|[\s\-:|]+\|$',
                                            lines[i].strip()):
                    i += 1
                continue
            i += 1
            continue
        # In a KPI table
        if not s.startswith('|') or not s.endswith('|'):
            in_main = False
            i += 1
            continue
        if _ts_re.match(r'^\|[\s\-:|]+\|$', s):
            i += 1
            continue
        cells = [c.strip() for c in s.split('|')[1:-1]]
        if not cells or not cells[0].replace('.', '').isdigit():
            i += 1
            continue
        # Drop placeholder rows entirely (not substantive)
        if len(cells) >= 4 and (
            _ts_is_placeholder(cells[1])
            or _ts_is_placeholder(cells[2])
            or _ts_is_placeholder(cells[3])
        ):
            i += 1
            continue
        # Dedupe by row content signature (everything but col 0 = #)
        sig = '||'.join(cells[1:]).strip().lower()
        if sig in main_table_seen_signatures:
            i += 1
            continue
        main_table_seen_signatures.add(sig)
        main_table_rows.append(cells[1:])  # store cells WITHOUT # column
        i += 1

    # ── Step 2: extract every per-KPI guide block from anywhere in the
    # section, dedupe by KPI-number.
    per_kpi_guides = {}  # num (str) → full block text
    guide_matches = list(_PER_KPI_GUIDE_HEADING_RE.finditer(kpis))
    for idx, m in enumerate(guide_matches):
        num = m.group('num_en') or m.group('num_ar')
        if not num:
            continue
        if num in per_kpi_guides:
            continue  # keep first occurrence per num
        block_start = m.start()
        # Block ends at the start of the next subsection (####), the next
        # section (##), or another guides-block heading (###), whichever
        # comes first. Search starts AFTER the current heading line so we
        # don't accidentally match the current `####` as a `###` boundary
        # (which happens because `^###[^#]` matches when the 4th char is
        # the trailing space of `#### `).
        search_from = m.end()
        # Skip to next newline so we begin scanning at the line after the
        # heading itself.
        nl_idx = kpis.find('\n', search_from)
        if nl_idx >= 0:
            search_from = nl_idx + 1
        next_start = len(kpis)
        # Boundary: ANY heading line that is NOT itself a #### per-KPI guide
        # body marker. Pattern: `^####` is a NEW per-KPI block (boundary);
        # `^###` (3 hashes) is a guides-section heading or other ### header
        # (boundary); `^##\s` is a top-level section heading (boundary).
        bnd_re = _ts_re.compile(
            r'^(?:####|###[^#]|##[^#])', _ts_re.MULTILINE,
        )
        bnd_m = bnd_re.search(kpis, pos=search_from)
        if bnd_m and bnd_m.start() < next_start:
            next_start = bnd_m.start()
        # Also bound by any subsequent per-KPI guide match (already found)
        for next_m in guide_matches[idx + 1:]:
            if next_m.start() < next_start:
                next_start = next_m.start()
            break
        block_text = kpis[block_start:next_start].rstrip()
        # Validate: block must contain something beyond just the heading
        # line; if not, treat as empty so synthesis kicks in.
        if block_text.count('\n') < 1 or len(block_text) < 30:
            continue
        # ── Sanitize: strip any line that matches the main-table
        # header regex from inside the preserved guide block. The
        # rebuild emits exactly one canonical main-table header at
        # Step 4; if the LLM or upstream content embedded a metadata
        # row whose 2nd column is "المؤشر"/"KPI"/"وصف المؤشر" inside
        # the guide block, that line would also match the validator's
        # regex (`_KPI_MAIN_TABLE_HEADER_RE`) and produce a spurious
        # `kpis_main_table_header_count_invalid` failure. Drop those
        # lines AND the immediately-following separator/empty-row
        # so the surviving guide table stays well-formed.
        _sanitized_lines = []
        _block_lines = block_text.split('\n')
        _bi = 0
        while _bi < len(_block_lines):
            _bln = _block_lines[_bi]
            if _KPI_MAIN_TABLE_HEADER_RE.match(_bln.strip()):
                # Skip this header line + any contiguous separator
                # immediately below it
                _bi += 1
                if (_bi < len(_block_lines)
                        and _ts_re.match(r'^\|[\s\-:|]+\|$',
                                          _block_lines[_bi].strip())):
                    _bi += 1
                continue
            _sanitized_lines.append(_bln)
            _bi += 1
        block_text = '\n'.join(_sanitized_lines).rstrip()
        # If sanitization stripped the block down to just the heading,
        # treat as empty so synthesis re-creates a clean guide block.
        if block_text.count('\n') < 1 or len(block_text) < 30:
            continue
        per_kpi_guides[num] = block_text

    # ── Step 3: ensure ≥ RICHNESS_MIN_KPI_ROWS substantive rows. If fewer,
    # synthesize using a deterministic template bank so rebuild alone is
    # sufficient — no need for a later top-up pass to add more rows (which
    # risks re-introducing a duplicate table header if another section's
    # content is resected in after rebuild).
    _synth_templates_ar = [
        (f'نسبة تطبيق ضوابط {fw_short}', '≥ 95%',
         '(المطبّق ÷ الإجمالي) × 100',
         f'امتثال {domain}', 'خلال 12 شهراً'),
        ('نسبة إغلاق الفجوات', '100%',
         '(المغلق ÷ الإجمالي) × 100',
         f'نضج {domain}', 'خلال 9 أشهر'),
        ('متوسط زمن الاستجابة للحوادث', '≤ 4 ساعات',
         '(مجموع زمن الاستجابة ÷ عدد الحوادث)',
         f'جاهزية {domain} التشغيلية', 'خلال 6 أشهر'),
        ('نسبة تغطية تقييم الأطراف الثالثة', '100%',
         '(المُقيَّم ÷ الإجمالي) × 100',
         f'إدارة مخاطر موردي {domain}', 'خلال 12 شهراً'),
        ('نسبة اجتياز تدريبات الوعي', '≥ 90%',
         '(المجتازين ÷ المستهدفين) × 100',
         f'وعي الكوادر بـ{domain}', 'خلال 9 أشهر'),
        ('معدل اكتشاف الحوادث المبكر', '≥ 80%',
         '(المكتشف آلياً ÷ الإجمالي) × 100',
         f'فعالية مراقبة {domain}', 'خلال 6 أشهر'),
    ]
    _synth_templates_en = [
        (f'{fw_short} control implementation rate', '≥ 95%',
         '(Implemented ÷ Total) × 100',
         f'{domain} compliance posture', 'Within 12 months'),
        ('Gap closure rate', '100%', '(Closed ÷ Total) × 100',
         f'{domain} maturity progression', 'Within 9 months'),
        ('Mean incident response time', '≤ 4 hours',
         '(Sum response time ÷ incidents)',
         f'{domain} operational readiness', 'Within 6 months'),
        ('Third-party assessment coverage', '100%',
         '(Assessed ÷ Total) × 100',
         f'{domain} supplier risk management', 'Within 12 months'),
        ('Awareness training pass rate', '≥ 90%',
         '(Passed ÷ Enrolled) × 100',
         f'{domain} workforce awareness', 'Within 9 months'),
        ('Automated threat detection coverage', '≥ 80%',
         '(Automated ÷ Total detections) × 100',
         f'{domain} monitoring effectiveness', 'Within 6 months'),
    ]
    _min_rows = _RICHNESS_MIN_KPI_ROWS  # defined in the richness section
    while len(main_table_rows) < _min_rows:
        t_idx = len(main_table_rows)
        templates = _synth_templates_ar if is_ar else _synth_templates_en
        tpl = templates[t_idx % len(templates)]
        new_cells = list(tpl)
        sig = '||'.join(new_cells).strip().lower()
        # Disambiguate if the signature collides with an existing row
        disambig = 0
        while sig in main_table_seen_signatures and disambig < 50:
            disambig += 1
            new_cells = list(tpl)
            new_cells[0] = new_cells[0] + f' [{t_idx + 1 + disambig}]'
            sig = '||'.join(new_cells).strip().lower()
        main_table_seen_signatures.add(sig)
        main_table_rows.append(new_cells)

    # ── Step 4: rebuild from canonical pieces.
    if is_ar:
        section_heading = '## 6. مؤشرات الأداء الرئيسية'
        table_header = (
            '| # | وصف المؤشر | القيمة المستهدفة | صيغة الاحتساب '
            '| المبرر | الإطار الزمني |'
        )
        table_sep = '|---|-------------|-----------------|----------------|--------|----------------|'
        guides_heading = '### أدلة تقييم مؤشرات الأداء'
    else:
        section_heading = '## 6. Key Performance Indicators'
        table_header = (
            '| # | KPI Description | Target Value | Calculation Formula '
            '| Justification | Timeframe |'
        )
        table_sep = '|---|-----------------|--------------|---------------------|---------------|-----------|'
        guides_heading = '### KPI Assessment Guidelines'

    out_lines = [section_heading, '', table_header, table_sep]
    for n_idx, cells in enumerate(main_table_rows, start=1):
        # Pad cells to schema width if needed
        while len(cells) < 5:
            cells.append('—')
        out_lines.append('| ' + ' | '.join([str(n_idx)] + cells[:5]) + ' |')
    out_lines.append('')
    out_lines.append(guides_heading)
    out_lines.append('')

    # Per-KPI guide blocks: one per row, in row order. If a guide for
    # row N exists in per_kpi_guides, use it; else synthesize.
    for n_idx, cells in enumerate(main_table_rows, start=1):
        key_str = str(n_idx)
        if key_str in per_kpi_guides:
            block = per_kpi_guides[key_str]
            out_lines.append(block)
            out_lines.append('')
        else:
            # Synthesize deterministic guide block
            kpi_name = cells[0] if cells else f'المؤشر رقم {n_idx}'
            if is_ar:
                out_lines.extend([
                    f'#### دليل تقييم المؤشر رقم {n_idx}: {kpi_name}',
                    '',
                    '| الخطوة | الإجراء | الأداة/النظام | المسؤول | الناتج |',
                    '|--------|---------|----------------|---------|--------|',
                    f'| 1 | جمع البيانات من المصادر المعتمدة | نظام {domain} | فريق {domain} | سجل القياس |',
                    f'| 2 | تطبيق الصيغة الحسابية | لوحة التحكم | محلل {domain} | القيمة المحسوبة |',
                    f'| 3 | التحقق والمصادقة | مراجعة الإدارة | رئيس {domain} | تقرير التحقق |',
                    f'| 4 | الإبلاغ للإدارة العليا | عرض مجلس {domain} | مدير {domain} | بيان الأداء |',
                    '',
                ])
            else:
                out_lines.extend([
                    f'#### KPI #{n_idx} Assessment Guide: {kpi_name}',
                    '',
                    '| Step | Action | Tool / System | Owner | Output |',
                    '|------|--------|----------------|-------|--------|',
                    f'| 1 | Collect data from authoritative sources | {domain} platform | {domain} Team | Measurement log |',
                    f'| 2 | Apply calculation formula | Dashboard | {domain} Analyst | Computed value |',
                    f'| 3 | Validate and attest | Management review | {domain} Lead | Attestation report |',
                    f'| 4 | Report to executive governance | {domain} board pack | {domain} Director | Performance statement |',
                    '',
                ])

    sections['kpis'] = '\n'.join(out_lines).rstrip() + '\n'

    return {
        'rebuilt': True,
        'main_table_rows': len(main_table_rows),
        'guides_blocks': len([n_idx for n_idx, _ in enumerate(main_table_rows, start=1)]),
        'reused_per_kpi_guides': len([k for k in per_kpi_guides
                                       if int(k) <= len(main_table_rows)]),
    }


def dedupe_arabic_section_families(sections, lang):
    """Collapse duplicate family headings + table blocks within each
    canonical section. Applies to all 7 sections; language-agnostic
    (handles AR + EN headings).

    Returns a dict with per-section counts of what was collapsed.
    Idempotent.
    """
    summary = {}

    # Step 1: per-section, collapse repeated `## N.` family headings.
    # We keep ONLY the first occurrence; subsequent matches (and any
    # blank lines immediately following them) get removed.
    for sec_key, patterns in _FAMILY_HEADINGS_BY_SECTION.items():
        text = sections.get(sec_key, '') or ''
        if not text:
            continue
        for pat in patterns:
            head_re = _ts_re.compile(
                r'^' + pat, _ts_re.MULTILINE | _ts_re.IGNORECASE,
            )
            matches = list(head_re.finditer(text))
            if len(matches) <= 1:
                continue
            # Keep first match; remove subsequent ones plus the line
            # break immediately after.
            new_parts = [text[:matches[0].end()]]
            last = matches[0].end()
            for m in matches[1:]:
                new_parts.append(text[last:m.start()])
                # Skip the matched heading line itself (and the trailing
                # newline if present).
                end = m.end()
                if end < len(text) and text[end] == '\n':
                    end += 1
                last = end
            new_parts.append(text[last:])
            text = ''.join(new_parts)
            summary.setdefault(sec_key, {})[pat] = len(matches) - 1
        sections[sec_key] = text

    # Step 2: per-section, collapse repeated subsection family headings.
    for sec_key, patterns in _SUBSECTION_FAMILIES.items():
        text = sections.get(sec_key, '') or ''
        if not text:
            continue
        for pat in patterns:
            sub_re = _ts_re.compile(
                r'^' + pat, _ts_re.MULTILINE | _ts_re.IGNORECASE,
            )
            matches = list(sub_re.finditer(text))
            if len(matches) <= 1:
                continue
            new_parts = [text[:matches[0].end()]]
            last = matches[0].end()
            for m in matches[1:]:
                new_parts.append(text[last:m.start()])
                end = m.end()
                if end < len(text) and text[end] == '\n':
                    end += 1
                last = end
            new_parts.append(text[last:])
            text = ''.join(new_parts)
            summary.setdefault(sec_key + '_sub', {})[pat] = len(matches) - 1
        sections[sec_key] = text

    # Step 3: collapse duplicate KPI / Gap guide subsections (#### with
    # same N) inside their respective sections. Keeps first occurrence.
    def _collapse_numbered_subsections(text, regex):
        if not text:
            return text, 0
        seen = set()
        # Find all matches with their numeric ID. Build new_text
        # selectively — drop second-and-later occurrences of each ID
        # by removing the full subsection block (heading + body up to
        # next #### or ##).
        # NOTE: body uses [^\n]*\n? (line-bounded) instead of .*\n?
        # because under (?s) the . matches \n and greedily eats past
        # the negative lookahead, swallowing later subsections.
        block_re = _ts_re.compile(
            r'(?m)' + regex
            + r'(?P<body>(?:(?!^####\s|^##\s)[^\n]*\n?)*)',
        )
        out_parts = []
        cursor = 0
        removed = 0
        for m in block_re.finditer(text):
            num = m.group('num')
            if num in seen:
                # Drop this whole match
                out_parts.append(text[cursor:m.start()])
                cursor = m.end()
                removed += 1
            else:
                seen.add(num)
        out_parts.append(text[cursor:])
        return ''.join(out_parts), removed

    kpi_guide_pat = (
        r'^####\s*(?:KPI\s*#?(?P<num>\d+)\s*Assessment Guide'
        r'|دليل\s+تقييم\s+المؤشر\s*(?:رقم|#)?\s*(?P<num2>\d+))[^\n]*\n'
    )
    # Need a single named group — split into separate passes
    kpi_en_re = (
        r'^####\s*KPI\s*#?(?P<num>\d+)\s*Assessment Guide[^\n]*\n'
    )
    kpi_ar_re = (
        r'^####\s*دليل\s+تقييم\s+المؤشر\s*(?:رقم|#)?\s*(?P<num>\d+)[^\n]*\n'
    )
    if 'kpis' in sections and sections['kpis']:
        s, r1 = _collapse_numbered_subsections(sections['kpis'], kpi_en_re)
        s, r2 = _collapse_numbered_subsections(s, kpi_ar_re)
        sections['kpis'] = s
        if r1 + r2:
            summary.setdefault('kpis_guides_dedup', 0)
            summary['kpis_guides_dedup'] += r1 + r2

    gap_en_re = (
        r'^####\s*Gap\s*#?(?P<num>\d+)\s*Implementation Guide[^\n]*\n'
    )
    gap_ar_re = (
        r'^####\s*دليل\s+(?:تنفيذ|معالجة)\s+الفجوة\s*(?:رقم|#)?\s*(?P<num>\d+)[^\n]*\n'
    )
    if 'gaps' in sections and sections['gaps']:
        s, r1 = _collapse_numbered_subsections(sections['gaps'], gap_en_re)
        s, r2 = _collapse_numbered_subsections(s, gap_ar_re)
        sections['gaps'] = s
        if r1 + r2:
            summary.setdefault('gaps_guides_dedup', 0)
            summary['gaps_guides_dedup'] += r1 + r2

    # Step 4: collapse multiple consecutive table-data-row blocks under
    # the same canonical table header into ONE merged table.
    table_collapse_targets = [
        ('gaps',        r'^\|\s*#\s*\|\s*(?:Gap|الفجوة|الفجوات)\s*\|'),
        ('kpis',        r'^\|\s*#\s*\|\s*(?:KPI Description|وصف\s+المؤشر|KPI)\s*\|'),
        ('vision',
         r'^\|\s*#\s*\|\s*(?:Objective|الهدف(?:\s+الاستراتيجي)?|الأهداف)\s*\|'),
    ]
    for sec_key, hdr_pat in table_collapse_targets:
        text = sections.get(sec_key, '') or ''
        if not text:
            continue
        hdr_re = _ts_re.compile(hdr_pat, _ts_re.IGNORECASE)
        new_text = _ts_collapse_table_blocks(text, hdr_re)
        if new_text != text:
            summary.setdefault('tables_collapsed', []).append(sec_key)
            sections[sec_key] = new_text

    # Step 5: collapse 3+ consecutive blank lines created by removals.
    for k in list(sections.keys()):
        sections[k] = _ts_re.sub(r'\n{3,}', '\n\n', sections.get(k, '') or '')

    return summary


def enforce_arabic_section_order(sections, lang):
    """Verify each canonical section's first `## N.` heading matches its
    expected number. Returns a list of (section_key, expected_n,
    found_n) tuples for any mismatches. Read-only — does not mutate.
    """
    expected_map = {
        'vision': 1, 'pillars': 2, 'environment': 3, 'gaps': 4,
        'roadmap': 5, 'kpis': 6, 'confidence': 7,
    }
    mismatches = []
    for sec_key, exp_n in expected_map.items():
        text = sections.get(sec_key, '') or ''
        if not text.strip():
            continue
        m = _ts_re.search(r'^##\s*(\d+)\.', text, _ts_re.MULTILINE)
        if m:
            found_n = int(m.group(1))
            if found_n != exp_n:
                mismatches.append((sec_key, exp_n, found_n))
    return mismatches


# ────────────────────────────────────────────────────────────────────────────
# PASS-12 CROSS-SECTION FAMILY RESTART / HEADING-ONLY RESIDUE HELPERS
#
# Per-section dedupe (pass-10) catches duplicates WITHIN the same section.
# But when the AI emits `## 4. تحليل الفجوات` inside sections['environment']
# AND inside sections['gaps'], the concatenated final content has two
# `## 4.` headings — per-section validator misses this entirely.
#
# The pass-12 helpers operate GLOBALLY (across the full sections dict):
#   - detect_arabic_family_restarts   — returns per-family occurrence counts
#   - collapse_arabic_family_restarts — moves non-canonical occurrences into
#                                        their canonical section + dedupes
#   - detect_heading_only_residue    — flags headings with no valid body
#   - validate_arabic_family_uniqueness — returns 422 defects
# ────────────────────────────────────────────────────────────────────────────

# Canonical family heading patterns with the section they SHOULD live in.
# Each entry: (canonical_section_key, english_pattern, arabic_pattern)
_FAMILY_GLOBAL_PATTERNS = [
    ('vision',      r'##\s*1\.\s*(?:Executive\s+)?Vision(?:\s+&\s+(?:Objectives|Strategic\s+Mandate))?',
                    r'##\s*1\.\s*الرؤية(?:\s+والأهداف(?:\s+الاستراتيجية)?)?'),
    ('pillars',     r'##\s*2\.\s*(?:Strategic\s+Pillars|The\s+Three\s+Pillars|Three\s+Pillars)',
                    r'##\s*2\.\s*الركائز(?:\s+الاستراتيجية)?'),
    ('environment', r'##\s*3\.\s*(?:Business\s+Environment|Regulatory\s+Context|Business\s+Context)',
                    r'##\s*3\.\s*(?:السياق\s+التنظيمي|البيئة\s+التنظيمية|البيئة(?:\s+التنظيمية)?)'),
    ('gaps',        r'##\s*4\.\s*(?:Gap\s+Analysis|Current\s+State\s+Assessment)',
                    r'##\s*4\.\s*تحليل\s+الفجوات'),
    ('roadmap',     r'##\s*5\.\s*(?:Implementation\s+Roadmap|Roadmap|\d+-Month\s+Implementation)',
                    r'##\s*5\.\s*خارطة(?:\s+التنفيذ|\s+الطريق)?'),
    ('kpis',        r'##\s*6\.\s*(?:Key\s+Performance\s+Indicators|KPI|Integrated\s+Performance)',
                    r'##\s*6\.\s*مؤشرات\s+الأداء(?:\s+الرئيسية)?'),
    ('confidence',  r'##\s*7\.\s*(?:Confidence(?:\s+Assessment)?)',
                    r'##\s*7\.\s*تقييم\s+(?:الثقة|الجاهزية)(?:\s+والمخاطر)?'),
]

# Compiled combined (EN|AR) regex per family, MULTILINE + IGNORECASE.
_FAMILY_GLOBAL_RE = {
    key: _ts_re.compile(
        r'^(?:' + en_pat + r'|' + ar_pat + r')[^\n]*$',
        _ts_re.MULTILINE | _ts_re.IGNORECASE,
    )
    for key, en_pat, ar_pat in _FAMILY_GLOBAL_PATTERNS
}


def detect_arabic_family_restarts(sections, lang):
    """Scan each section for family-heading occurrences and return a list
    of (family_key, locations) tuples where locations is a list of
    (section_key, match_offset_within_section) entries. A family with
    more than one total location across all sections is a restart.

    Read-only. Used by validators + as input to the collapse helper.
    """
    results = []
    for fam_key, fam_re in _FAMILY_GLOBAL_RE.items():
        locations = []
        for sec_key in ('vision', 'pillars', 'environment', 'gaps',
                        'roadmap', 'kpis', 'confidence'):
            text = sections.get(sec_key, '') or ''
            for m in fam_re.finditer(text):
                locations.append((sec_key, m.start(), m.end()))
        if len(locations) > 1:
            results.append((fam_key, locations))
    return results


def collapse_arabic_family_restarts(sections, lang):
    """For each family that has > 1 global occurrences, keep the occurrence
    that sits in the canonical section for that family; for every other
    occurrence, cut out the family's body (from its heading up to the
    next top-level `##` heading) and move it into the canonical section.
    The MOVED body is appended to the canonical section AFTER the first
    occurrence of the canonical heading, so per-section dedupe can then
    collapse duplicate main-tables and guide blocks.

    Returns list of (family_key, source_section, target_section) moves.
    Idempotent.
    """
    moves = []
    # Pre-compile a generic 'next section heading' detector
    next_section_re = _ts_re.compile(r'^##\s*\d+\.', _ts_re.MULTILINE)

    for fam_key, fam_re in _FAMILY_GLOBAL_RE.items():
        canonical = fam_key
        # Collect occurrences across all non-canonical sections
        non_canonical_blocks = []
        for sec_key in ('vision', 'pillars', 'environment', 'gaps',
                        'roadmap', 'kpis', 'confidence'):
            if sec_key == canonical:
                continue
            text = sections.get(sec_key, '') or ''
            if not text:
                continue
            matches = list(fam_re.finditer(text))
            if not matches:
                continue
            # For each match, extract its body (heading line + everything
            # until the next `##` heading OR end-of-text).
            new_text = text
            for m in reversed(matches):
                # Find next top-level heading after this match
                search_from = m.end()
                # Start search on the next line
                nl = new_text.find('\n', search_from)
                if nl >= 0:
                    nxt = next_section_re.search(new_text, pos=nl + 1)
                    end_pos = nxt.start() if nxt else len(new_text)
                else:
                    end_pos = len(new_text)
                block = new_text[m.start():end_pos].rstrip()
                # Cut from source section
                new_text = new_text[:m.start()] + new_text[end_pos:]
                # Collapse 3+ blank lines from the cut
                new_text = _ts_re.sub(r'\n{3,}', '\n\n', new_text)
                non_canonical_blocks.append((sec_key, block))
            sections[sec_key] = new_text.rstrip() + ('\n' if new_text.endswith('\n') else '')

        if not non_canonical_blocks:
            continue

        # Target = canonical section. Append all moved blocks after its
        # first occurrence of the canonical heading (or at the end if
        # it has no heading yet).
        target_text = sections.get(canonical, '') or ''
        target_match = fam_re.search(target_text)
        if target_match:
            # Insert after the end-of-line of the canonical heading, so
            # body continues immediately.
            eol = target_text.find('\n', target_match.end())
            if eol < 0:
                eol = len(target_text)
            merged = (
                target_text[:eol + 1]
                + '\n'
                + '\n\n'.join(b for _, b in non_canonical_blocks)
                + '\n'
                + target_text[eol + 1:]
            )
        else:
            merged = target_text.rstrip() + '\n\n' + '\n\n'.join(
                b for _, b in non_canonical_blocks
            ) + '\n'
        sections[canonical] = _ts_re.sub(r'\n{3,}', '\n\n', merged)
        for src_key, _ in non_canonical_blocks:
            moves.append((fam_key, src_key, canonical))

    return moves


# ────────────────────────────────────────────────────────────────────────────
# PASS-14 SUBHEADING-LEVEL RESIDUE CLEANUP + PROMPT RESIDUE SANITIZATION
# ────────────────────────────────────────────────────────────────────────────

def cleanup_subheading_residue(sections, lang):
    """Extract stray family subheadings from non-canonical sections.

    Pass-12 collapse handles `##`-level family blocks. Stray `###` and
    `####` subheadings that aren't wrapped in their own `##` block
    (e.g. `### أدلة تقييم المؤشرات` trailing under `## 5. خارطة`) evade
    collapse. This helper hunts them, relocates substantive blocks to
    the canonical section, and DELETES heading-only residues.

    Returns list of (action, source, target, kind) tuples. Idempotent.
    """
    results = []

    next_heading_re = _ts_re.compile(
        r'^(?:####|###[^#]|##[^#])', _ts_re.MULTILINE,
    )

    def _extract_block(text, match):
        block_start = match.start()
        nl = text.find('\n', match.end())
        search_from = (nl + 1) if nl >= 0 else match.end()
        nxt = next_heading_re.search(text, pos=search_from)
        block_end = nxt.start() if nxt else len(text)
        return block_start, block_end, text[block_start:block_end]

    def _has_substantive_body(block):
        lines = block.split('\n')
        if len(lines) < 2:
            return False
        body = '\n'.join(lines[1:]).strip()
        if len(body) < 30:
            return False
        has_table = any(
            ln.strip().startswith('|') and ln.strip().endswith('|')
            for ln in lines[1:]
        )
        has_narrative = any(
            len(ln.split()) >= 5
            and not ln.strip().startswith(('|', '#'))
            for ln in lines[1:]
        )
        return has_table or has_narrative

    residue_hunts = [
        (_KPI_GUIDES_HEADING_RE, 'kpis', 'kpi_guides_subheading'),
        (_PER_KPI_GUIDE_HEADING_RE, 'kpis', 'per_kpi_guide'),
        (
            _ts_re.compile(
                r'^###[\s\u00a0\u200e\u200f]*'
                r'(?:Identified\s+Gaps|Gap\s+Implementation\s+Guidance'
                r'|الفجوات\s+المحددة|أدلة\s+تنفيذ\s+الفجوات)'
                r'[^\n]*$',
                _ts_re.MULTILINE | _ts_re.IGNORECASE,
            ),
            'gaps',
            'gap_subheading',
        ),
        (
            _ts_re.compile(
                r'^####[\s\u00a0\u200e\u200f]*'
                r'(?:Gap[\s\u00a0]*#?\d+[\s\u00a0]+Implementation[\s\u00a0]+Guide'
                r'|(?:دليل|أدلة|إرشادات)[\s\u00a0\u200e\u200f]+'
                r'(?:تنفيذ|معالجة)[\s\u00a0\u200e\u200f]+'
                r'(?:ال)?فجوة'
                r'(?:[\s\u00a0\u200e\u200f]+(?:رقم|#))?'
                r'[\s\u00a0]*\d+)'
                r'[^\n]*$',
                _ts_re.MULTILINE | _ts_re.IGNORECASE,
            ),
            'gaps',
            'per_gap_guide',
        ),
    ]

    all_sections = ('vision', 'pillars', 'environment', 'gaps',
                    'roadmap', 'kpis', 'confidence')

    for hunt_re, canonical, kind in residue_hunts:
        for src_key in all_sections:
            if src_key == canonical:
                continue
            text = sections.get(src_key, '') or ''
            if not text:
                continue
            matches = list(hunt_re.finditer(text))
            if not matches:
                continue
            relocate_blocks = []
            new_text = text
            for m in reversed(matches):
                b_start, b_end, block = _extract_block(new_text, m)
                substantive = _has_substantive_body(block)
                new_text = new_text[:b_start] + new_text[b_end:]
                if substantive:
                    relocate_blocks.append(block.strip())
                    results.append(('relocated', src_key, canonical, kind))
                else:
                    results.append(('deleted', src_key, canonical, kind))
            new_text = _ts_re.sub(r'\n{3,}', '\n\n', new_text).rstrip()
            if new_text and not new_text.endswith('\n'):
                new_text += '\n'
            sections[src_key] = new_text

            if relocate_blocks:
                tgt = sections.get(canonical, '') or ''
                if kind == 'kpi_guides_subheading':
                    gm = _KPI_GUIDES_HEADING_RE.search(tgt)
                    if gm:
                        eol = tgt.find('\n', gm.end())
                        if eol < 0:
                            eol = len(tgt)
                        body_to_insert = '\n\n'.join(
                            b.split('\n', 1)[1].strip() if '\n' in b else ''
                            for b in reversed(relocate_blocks)
                        ).strip()
                        if body_to_insert:
                            tgt = (
                                tgt[:eol + 1] + '\n'
                                + body_to_insert + '\n'
                                + tgt[eol + 1:]
                            )
                    else:
                        tgt = (tgt.rstrip() + '\n\n'
                               + '\n\n'.join(reversed(relocate_blocks))
                               + '\n')
                else:
                    tgt = (tgt.rstrip() + '\n\n'
                           + '\n\n'.join(reversed(relocate_blocks))
                           + '\n')
                sections[canonical] = _ts_re.sub(r'\n{3,}', '\n\n', tgt)

    # Extra pass: strip trailing orphan '### الفجوات المحددة:' / similar
    # heading-only residues that may remain at end of any section with
    # NO body at all (less than 10 chars after heading line).
    orphan_trailing_patterns = [
        r'\n###\s*الفجوات\s+المحددة[:\s]*\s*$',
        r'\n###\s*Identified\s+Gaps[:\s]*\s*$',
        r'\n###\s*أدلة\s+تقييم\s+مؤشرات\s+الأداء[:\s]*\s*$',
        r'\n###\s*KPI\s+Assessment\s+Guidelines[:\s]*\s*$',
        r'\n###\s*أدلة\s+تنفيذ\s+الفجوات[:\s]*\s*$',
        r'\n###\s*Gap\s+Implementation\s+Guidance[:\s]*\s*$',
    ]
    for sec_key in all_sections:
        text = sections.get(sec_key, '') or ''
        if not text:
            continue
        orig = text
        for pat in orphan_trailing_patterns:
            text = _ts_re.sub(pat, '', text, flags=_ts_re.MULTILINE | _ts_re.IGNORECASE)
        if text != orig:
            sections[sec_key] = text.rstrip() + ('\n' if text.endswith('\n') else '')
            results.append(('trimmed_trailing_orphan', sec_key, None, 'orphan_heading'))

    return results


# ── PASS-14 PROMPT/INSTRUCTION RESIDUE SANITIZATION ─────────────────────────
#
# Strip known prompt residue patterns that sometimes leak into final output:
#   - "write two paragraphs" / "Draft the following" directives
#   - template-instruction lines like "[Insert narrative here]"
#   - advisory meta-notes intended for the model not the reader
#
# Targeted — only matches well-known residue patterns. Never blind deletion.
# ────────────────────────────────────────────────────────────────────────────

_PROMPT_RESIDUE_PATTERNS = [
    # English meta-directives
    r'(?i)^.*\b(?:write|draft|compose|produce|generate)\s+(?:the\s+following|two|three|\d+)\s+(?:paragraphs?|sentences?|sections?|lines?)\b[^\n]*\n?',
    r'(?i)^.*\b(?:please\s+)?(?:include|ensure|make\s+sure)\s+(?:at\s+least|that\s+the\s+following|each|every)\b[^\n]*\n?',
    r'(?i)^\[\s*(?:insert|add|provide|include|write|note|fill|describe|specify|detail)[^\]]*\]\s*\n?',
    r'(?i)^<[^<>\n]*(?:insert|placeholder|instruction|example|template)[^<>\n]*>\s*\n?',
    r'(?i)^\(\s*(?:insert|add|describe|note|placeholder|to be)\s+[^)]*\)\s*\n?',
    r'(?i)^.*\b(?:as\s+an?\s+(?:AI|assistant|model)|do\s+not\s+include|avoid\s+mentioning)\b[^\n]*\n?',
    r'(?i)^.*\b(?:note\s+(?:to|for)\s+(?:the\s+)?(?:model|editor|reviewer|draft(?:er)?|writer)|reminder\s+(?:to|for)\s+(?:the\s+)?(?:model|editor))\s*:[^\n]*\n?',
    r'(?i)^.*\b(?:here\s+is|below\s+is|following\s+is)\s+(?:a|the)\s+(?:draft|template|example|placeholder)\b[^\n]*\n?',
    # Arabic meta-directives
    r'^.*\b(?:اكتب|حرّر|حرر|قدّم|قدم|استخرج)\s+(?:فقرتين|ثلاث\s+فقرات|فقرة|\d+\s+فقرات?)\b[^\n]*\n?',
    r'^\[[^\]]{0,50}(?:أدخل|ضع|اكتب|أضف|مثال|قالب)[^\]]*\]\s*\n?',
    r'^\(\s*(?:أدخل|ضع|اكتب|أضف|ملاحظة|قالب|توضيح)\s+[^)]*\)\s*\n?',
    r'^.*\bملاحظة\s+(?:للنموذج|للمحرر|داخلية)\b[^\n]*\n?',
    r'^.*\b(?:تأكد\s+من\s+تضمين|يرجى\s+تضمين|يجب\s+أن\s+تحتوي)\b[^\n]*\n?',
    # Visible placeholder markers
    r'^\s*(?:TBD|TODO|FIXME|XXX|\[TBD\]|\[TODO\])[:\s]?[^\n]*\n?',
    r'^\s*\[PLACEHOLDER(?:[^\]]*)\]\s*\n?',
    r'^\s*\[\[.*?\]\]\s*\n?',
    # Chat / template stage markers that leak into final output
    # (prompt clause G). Matches lines such as "System:", "Tool:",
    # "User:", "Assistant:", "System/Tool" used as stage labels at the
    # start of a line. Conservative: whole-line replacement and only
    # the well-known stage vocabulary, so body prose containing the
    # word "system" never matches.
    r'(?i)^\s*(?:System|Tool|User|Assistant|Human|Model)\s*(?:/\s*(?:System|Tool|User|Assistant|Human|Model))?\s*:[^\n]*\n?',
    r'(?i)^\s*<\|?\s*(?:system|tool|user|assistant|endoftext|im_start|im_end)\s*\|?>\s*\n?',
    r'(?i)^\s*```(?:system|tool|prompt|instruction)\s*\n(?:.|\n)*?^```\s*\n?',
    # Generic "Output:" / "Response:" / "Answer:" stage labels when
    # left as the first token on a line. Body text that uses these as
    # table headers or sentence fragments won't match (these require
    # start-of-line, the colon, and nothing else between).
    r'(?i)^\s*(?:Output|Response|Answer|Prompt|Instruction)\s*:\s*$',
]

_PROMPT_RESIDUE_COMPILED = [
    _ts_re.compile(p, _ts_re.MULTILINE) for p in _PROMPT_RESIDUE_PATTERNS
]


def sanitize_arabic_prompt_residue(sections, lang):
    """Strip known prompt/instruction residue patterns from strategy
    sections. Returns dict with per-section removal counts.

    Targets ALL languages — EN patterns can leak into AR payloads and
    vice versa. Safe: only removes whole lines that match well-known
    patterns; never touches table rows, canonical headings, or numeric
    data.
    """
    summary = {}
    for sec_key in ('vision', 'pillars', 'environment', 'gaps',
                    'roadmap', 'kpis', 'confidence'):
        text = sections.get(sec_key, '') or ''
        if not text:
            continue
        orig = text
        removed = 0
        for rx in _PROMPT_RESIDUE_COMPILED:
            new_text, n = rx.subn('', text)
            if n:
                removed += n
                text = new_text
        if removed:
            # Collapse blank-line runs introduced by removals
            text = _ts_re.sub(r'\n{3,}', '\n\n', text)
            sections[sec_key] = text
            summary[sec_key] = removed
    return summary


def detect_arabic_prompt_residue(sections, lang):
    """Return list of (defect_tag, detail) for surviving prompt residue.
    Runs AFTER sanitization so the gate can block save if sanitization
    failed to remove everything.
    """
    defects = []
    for sec_key in ('vision', 'pillars', 'environment', 'gaps',
                    'roadmap', 'kpis', 'confidence'):
        text = sections.get(sec_key, '') or ''
        if not text:
            continue
        for rx in _PROMPT_RESIDUE_COMPILED:
            m = rx.search(text)
            if m:
                excerpt = m.group(0).strip()[:80]
                defects.append((
                    f'{sec_key}_contains_prompt_residue',
                    f'Prompt-residue pattern matched in {sec_key}: {excerpt!r}',
                ))
                break  # one defect per section is enough
    return defects


def detect_heading_only_residue(sections, lang):
    """Return list of (defect_tag, detail) tuples for stray residues:
      - `## 6. مؤشرات` heading with no KPI main-table header beneath it
      - `### أدلة تقييم ...` heading in a section that is not kpis
      - `## 4. تحليل الفجوات` heading with no gap-table beneath it
      - `### KPI/Gap Assessment Guide` heading with no #### per-item guide

    Targets the final assembled sections dict after all collapse/dedupe.
    """
    defects = []

    # A) stray '### أدلة تقييم المؤشرات' or '### KPI Assessment Guidelines'
    # in non-kpis sections.
    for sec_key in ('vision', 'pillars', 'environment', 'gaps',
                    'roadmap', 'confidence'):
        text = sections.get(sec_key, '') or ''
        if not text:
            continue
        if _KPI_GUIDES_HEADING_RE.search(text):
            defects.append((
                f'{sec_key}_contains_kpi_guides_heading_residue',
                f'KPI-guides heading appears in {sec_key} section',
            ))

    # B) KPI main heading with no main table beneath it. Check sections['kpis']
    # — heading exists (pass-11 rebuild ensures this) but must be followed
    # by a KPI main-table header within ~30 lines.
    kpis_text = sections.get('kpis', '') or ''
    if kpis_text:
        kpi_main_hdr = _ts_re.search(
            r'^##\s*6\.\s*(?:Key\s+Performance\s+Indicators|KPI|مؤشرات\s+الأداء)',
            kpis_text, _ts_re.MULTILINE | _ts_re.IGNORECASE,
        )
        if kpi_main_hdr:
            # Look for table header within 30 lines of the section heading.
            slice_after = kpis_text[kpi_main_hdr.end():
                                     kpi_main_hdr.end() + 3000]
            if not _KPI_MAIN_TABLE_HEADER_RE.search(slice_after):
                defects.append((
                    'kpis_heading_without_main_table',
                    'KPI section heading has no main table within 30 lines',
                ))

    # C) Gap analysis heading with no gap-table beneath it (within 30 lines).
    gaps_text = sections.get('gaps', '') or ''
    if gaps_text:
        gap_main_hdr = _ts_re.search(
            r'^##\s*4\.\s*(?:Gap\s+Analysis|تحليل\s+الفجوات)',
            gaps_text, _ts_re.MULTILINE | _ts_re.IGNORECASE,
        )
        if gap_main_hdr:
            slice_after = gaps_text[gap_main_hdr.end():
                                     gap_main_hdr.end() + 3000]
            gap_table_re = _ts_re.compile(
                r'^\|\s*#\s*\|\s*(?:Gap|الفجوة|الفجوات)\s*\|',
                _ts_re.MULTILINE | _ts_re.IGNORECASE,
            )
            if not gap_table_re.search(slice_after):
                defects.append((
                    'gaps_heading_without_table',
                    'Gap-analysis heading has no gap table within 30 lines',
                ))

    # D) KPI guides heading present in kpis section with no #### per-KPI guide
    # beneath it.
    if kpis_text:
        guides_hdr = _KPI_GUIDES_HEADING_RE.search(kpis_text)
        if guides_hdr:
            slice_after = kpis_text[guides_hdr.end():
                                     guides_hdr.end() + 10000]
            if not _PER_KPI_GUIDE_HEADING_RE.search(slice_after):
                defects.append((
                    'kpis_guides_heading_without_per_kpi_blocks',
                    'KPI-guides heading has no per-KPI guide blocks beneath it',
                ))

    return defects


def validate_arabic_family_uniqueness(sections, lang):
    """Return list of (defect_tag, detail) tuples for any family that
    appears more than once across the concatenated final sections content.
    This is the GLOBAL check that catches cross-section restarts the
    per-section dedupe misses.
    """
    defects = []
    restarts = detect_arabic_family_restarts(sections, lang)
    for fam_key, locations in restarts:
        where = ', '.join(f'{sk}@{off}' for sk, off, _ in locations)
        defects.append((
            f'{fam_key}_family_restart_detected',
            f'{fam_key} family heading appears {len(locations)} times: {where}',
        ))
    return defects


def validate_arabic_section_family_integrity(sections, lang):
    """After dedupe, verify no family duplicates remain and section
    headings are correct. Returns a list of (defect_tag, detail) tuples.
    Empty list = clean.
    """
    defects = []
    # Check 1: each section should have at most ONE `## N.` heading.
    for sec_key in _FAMILY_HEADINGS_BY_SECTION:
        text = sections.get(sec_key, '') or ''
        if not text:
            continue
        all_h = _ts_re.findall(
            r'^##\s*\d+\.\s', text, _ts_re.MULTILINE,
        )
        if len(all_h) > 1:
            defects.append((
                f'{sec_key}_family_duplicated',
                f'{len(all_h)} `## N.` headings found in {sec_key}',
            ))
    # Check 2: section order — found_n must equal expected_n.
    for sec_key, exp_n, found_n in enforce_arabic_section_order(sections, lang):
        defects.append((
            f'{sec_key}_section_order_wrong',
            f'expected ## {exp_n} but found ## {found_n}',
        ))
    # Check 3: KPI Assessment Guidelines / Gap Implementation Guidance
    # subsection headings must each appear at most once.
    sub_check_targets = {
        'gaps': [
            (r'###\s*(?:Identified Gaps|الفجوات\s+المحددة)',
             'gaps_identified_subhead_duplicated'),
            (r'###\s*(?:Gap Implementation Guidance|أدلة\s+تنفيذ\s+الفجوات)',
             'gaps_guides_subhead_duplicated'),
        ],
        'kpis': [
            # PASS-11: keep the strict per-section subhead check, AND ALSO
            # apply the broad KPI guides regex below so synonym variants
            # don't slip past.
            (r'###\s*(?:KPI Assessment Guidelines|أدلة\s+تقييم\s+مؤشرات\s+الأداء)',
             'kpis_guides_subhead_duplicated'),
        ],
    }
    # PASS-11 broad KPI-guides-heading duplicate check (catches synonyms
    # like دليل/إرشادات + المؤشرات/المؤشرات الرئيسية, EN "KPI Guides" etc.)
    _kpis_text_check = sections.get('kpis', '') or ''
    if _kpis_text_check:
        _broad_count = len(_KPI_GUIDES_HEADING_RE.findall(_kpis_text_check))
        if _broad_count > 1:
            defects.append((
                'kpis_guides_subhead_duplicated_broad',
                f'{_broad_count} KPI-guides headings (broad regex) in kpis',
            ))
        # KPI main table must have ≥ 1 header occurrence — duplicates count
        _main_count = len(_KPI_MAIN_TABLE_HEADER_RE.findall(_kpis_text_check))
        if _main_count > 1:
            defects.append((
                'kpis_main_table_duplicated',
                f'{_main_count} KPI main-table headers in kpis',
            ))
    for sec_key, patterns in sub_check_targets.items():
        text = sections.get(sec_key, '') or ''
        if not text:
            continue
        for pat, tag in patterns:
            count = len(_ts_re.findall(
                r'^' + pat, text, _ts_re.MULTILINE | _ts_re.IGNORECASE,
            ))
            if count > 1:
                defects.append((tag, f'{count} occurrences in {sec_key}'))
    # Check 4: Arabic strategies must not contain known EN template
    # residue strings (only those for which we have AR equivalents).
    if lang == 'ar':
        for k in ('vision', 'pillars', 'environment', 'gaps',
                  'roadmap', 'kpis', 'confidence'):
            text = sections.get(k, '') or ''
            for en in _AR_TEMPLATE_RESIDUE_MAP:
                if en in text:
                    defects.append((
                        f'{k}_contains_en_template_residue',
                        f'{en!r} found in {k}',
                    ))
                    break  # one per section is enough to flag
    return defects


def _resection_misrouted_content(sections, lang):
    """Surgically move misrouted table blocks between canonical sections.

    Scenarios handled (observed in production Arabic output):
      - environment contains a Gap table / Gap Implementation Guide →
        extract those blocks, move to gaps (merge or replace empty)
      - roadmap contains a KPI main table / KPI Assessment Guide →
        extract those blocks, move to kpis
      - kpis contains Phase/Quarter roadmap headings → extract to roadmap
      - gaps contains Confidence Score block → extract to confidence
      - vision contains KPI/Gap tables → extract to kpis/gaps

    After resection, each canonical section contains ONLY its own
    schema's content. Returns a list of (source_section, target_section,
    block_kind) tuples describing what was moved, for logging.

    Idempotent — running twice yields the same result. Language-agnostic:
    regex patterns match both Arabic and English headers/table schemas.
    """
    moves = []

    # Regex: detect contiguous table blocks / guide sections by their
    # canonical table header. Each pattern captures the ENTIRE block
    # from its header/heading to the next '##' section boundary, next
    # '### ' subsection boundary, or end-of-string — whichever comes
    # first.
    gap_table_block_re = _ts_re.compile(
        r'(?ms)'
        r'(?:^###\s*(?:Identified Gaps|الفجوات(?:\s+المحددة)?)[^\n]*\n+)?'
        r'^\|\s*#\s*\|\s*(?:Gap|الفجوة|الفجوات)\s*\|[^\n]*\n'
        r'(?:^\|[^\n]*\n)+'
    )
    gap_guides_block_re = _ts_re.compile(
        r'(?ms)'
        r'(?:^###\s*(?:Gap Implementation Guidance|أدلة تنفيذ الفجوات)[^\n]*\n+)?'
        r'^####\s*(?:Gap\s*#?\d+\s*Implementation Guide'
        r'|دليل\s+(?:تنفيذ|معالجة)\s+الفجوة\s*(?:رقم|#)?\s*\d+)[^\n]*\n'
        r'(?:(?!^##\s|^###\s[^#]).*\n?)+'
    )
    kpi_table_block_re = _ts_re.compile(
        r'(?ms)'
        r'(?:^###\s*(?:KPI Summary|مؤشرات الأداء)[^\n]*\n+)?'
        r'^\|\s*#\s*\|\s*(?:KPI Description|وصف المؤشر|KPI)\s*\|[^\n]*\n'
        r'(?:^\|[^\n]*\n)+'
    )
    kpi_guides_block_re = _ts_re.compile(
        r'(?ms)'
        r'(?:^###\s*(?:KPI Assessment Guidelines|أدلة تقييم مؤشرات الأداء)[^\n]*\n+)?'
        r'^####\s*(?:KPI\s*#?\d+\s*Assessment Guide'
        r'|دليل تقييم المؤشر\s*(?:رقم|#)?\s*\d+)[^\n]*\n'
        r'(?:(?!^##\s|^###\s[^#]).*\n?)+'
    )
    phase_block_re = _ts_re.compile(
        r'(?ms)'
        r'^###\s*(?:Phase\s*\d|Quarter\s*\d|المرحلة\s*\d|الربع\s*\d)[^\n]*\n'
        r'(?:(?!^##\s|^###\s[^#]).*\n?)+'
    )
    conf_score_block_re = _ts_re.compile(
        r'(?ms)'
        r'\*\*(?:Confidence Score|درجة الثقة)\s*:?\s*\*\*[^\n]*\n'
        r'(?:(?!^##\s).*\n?)*'
    )

    def _extract_and_move(src_key, tgt_key, pattern, kind):
        src = sections.get(src_key, '') or ''
        if not src:
            return
        matches = list(pattern.finditer(src))
        if not matches:
            return
        # Pull out all matched blocks, merge them, and remove from source.
        extracted_parts = [m.group(0) for m in matches]
        # Remove matched spans from src (iterate in reverse to preserve offsets)
        new_src = src
        for m in reversed(matches):
            new_src = new_src[:m.start()] + new_src[m.end():]
        new_src = _ts_re.sub(r'\n{3,}', '\n\n', new_src).rstrip() + '\n'
        sections[src_key] = new_src
        tgt = (sections.get(tgt_key, '') or '').rstrip()
        merged_blocks = '\n\n'.join(p.strip() for p in extracted_parts
                                     if p.strip())
        if tgt:
            sections[tgt_key] = tgt + '\n\n' + merged_blocks + '\n'
        else:
            # Target section empty — prepend the canonical heading so
            # downstream identify_section / audit can see it.
            canonical_heading = {
                ('gaps', 'ar'):        '## 4. تحليل الفجوات\n\n',
                ('gaps', 'en'):        '## 4. Gap Analysis\n\n',
                ('kpis', 'ar'):        '## 6. مؤشرات الأداء الرئيسية\n\n',
                ('kpis', 'en'):        '## 6. Key Performance Indicators\n\n',
                ('roadmap', 'ar'):     '## 5. خارطة التنفيذ\n\n',
                ('roadmap', 'en'):     '## 5. Implementation Roadmap\n\n',
                ('confidence', 'ar'):  '## 7. تقييم الثقة والمخاطر\n\n',
                ('confidence', 'en'):  '## 7. Confidence Assessment & Risks\n\n',
            }.get((tgt_key, lang), '')
            sections[tgt_key] = canonical_heading + merged_blocks + '\n'
        moves.append((src_key, tgt_key, kind, len(matches)))

    # environment → gaps
    _extract_and_move('environment', 'gaps', gap_table_block_re,    'gap_table')
    _extract_and_move('environment', 'gaps', gap_guides_block_re,   'gap_guides')
    # PASS-10 prompt clause B: environment must NOT contain KPI tables/guides.
    _extract_and_move('environment', 'kpis', kpi_table_block_re,    'kpi_table_from_environment')
    _extract_and_move('environment', 'kpis', kpi_guides_block_re,   'kpi_guides_from_environment')
    # roadmap → kpis
    _extract_and_move('roadmap',     'kpis', kpi_table_block_re,    'kpi_table')
    _extract_and_move('roadmap',     'kpis', kpi_guides_block_re,   'kpi_guides')
    # kpis → roadmap (phase headings)
    _extract_and_move('kpis',        'roadmap', phase_block_re,     'phase_heading')
    # gaps → confidence (score block)
    _extract_and_move('gaps',        'confidence', conf_score_block_re, 'conf_score')
    # vision → kpis / gaps (tables that leaked into SO section)
    _extract_and_move('vision',      'kpis', kpi_table_block_re,    'kpi_table_from_vision')
    _extract_and_move('vision',      'gaps', gap_table_block_re,    'gap_table_from_vision')
    # pillars → gaps / kpis / roadmap (rare AI section-misordering: gap or
    # KPI tables sometimes leak into pillars when AI emits sections out of
    # order and parser routes content by position)
    _extract_and_move('pillars',     'gaps', gap_table_block_re,    'gap_table_from_pillars')
    _extract_and_move('pillars',     'gaps', gap_guides_block_re,   'gap_guides_from_pillars')
    _extract_and_move('pillars',     'kpis', kpi_table_block_re,    'kpi_table_from_pillars')
    _extract_and_move('pillars',     'kpis', kpi_guides_block_re,   'kpi_guides_from_pillars')

    return moves


def _topup_kpi_main_table_rows(sections, lang, domain, fw_short):
    """Ensure KPI main table has at least 2 substantive rows.

    If count_substantive_kpis(sections['kpis']) < 2 after resection, append
    deterministic rows to bring it up to ≥ 2. Uses the same bilingual
    schema the KPI force-inject uses elsewhere, so the audit + completeness
    helpers continue to recognize the rows.

    Returns count of rows added.
    """
    kpis = sections.get('kpis', '') or ''
    current = count_substantive_kpis(kpis)
    if current >= 2:
        return 0

    is_ar = (lang == 'ar')
    needed = 2 - current
    # Determine which row numbers are NOT yet present so we append unique rows.
    existing_row_nums = set()
    hdr_re = _ts_re.compile(
        r'^\|\s*#\s*\|\s*(?:KPI Description|وصف المؤشر|KPI)\s*\|',
        _ts_re.IGNORECASE,
    )
    for cells in _ts_table_rows(kpis, hdr_re):
        if cells and cells[0].replace('.', '').isdigit():
            existing_row_nums.add(int(cells[0]))
    next_n = max(existing_row_nums) + 1 if existing_row_nums else 1

    # If kpis section lacks the KPI main-table header entirely, inject
    # heading + table skeleton.
    has_header = bool(hdr_re.search(kpis))
    added = 0
    if not has_header:
        if is_ar:
            skeleton = (
                ('## 6. مؤشرات الأداء الرئيسية\n\n' if '## 6' not in kpis else '')
                + '| # | وصف المؤشر | القيمة المستهدفة | صيغة الاحتساب | المبرر | الإطار الزمني |\n'
                + '|---|-------------|-----------------|----------------|--------|----------------|\n'
            )
        else:
            skeleton = (
                ('## 6. Key Performance Indicators\n\n' if '## 6' not in kpis else '')
                + '| # | KPI Description | Target Value | Calculation Formula | Justification | Timeframe |\n'
                + '|---|-----------------|--------------|---------------------|---------------|-----------|\n'
            )
        kpis = kpis.rstrip() + ('\n\n' if kpis.strip() else '') + skeleton

    # Build deterministic rows
    templates_ar = [
        (f'نسبة تطبيق ضوابط {fw_short}', '≥ 95%', '(المطبّق ÷ الإجمالي) × 100',
         f'امتثال {domain}', 'خلال 12 شهراً'),
        ('نسبة إغلاق الفجوات', '100%', '(المغلق ÷ الإجمالي) × 100',
         f'نضج {domain}', 'خلال 9 أشهر'),
        ('معدل الاستجابة للحوادث', '≤ 4 ساعات',
         '(مجموع زمن الاستجابة ÷ عدد الحوادث)',
         f'جاهزية {domain} التشغيلية', 'خلال 6 أشهر'),
    ]
    templates_en = [
        (f'{fw_short} control implementation rate', '≥ 95%',
         '(Implemented ÷ Total) × 100', 'Compliance posture', 'Within 12 months'),
        ('Gap closure rate', '100%', '(Closed ÷ Total) × 100',
         'Maturity progression', 'Within 9 months'),
        ('Incident response time', '≤ 4 hours',
         '(Sum response time ÷ incidents)', 'Operational readiness', 'Within 6 months'),
    ]
    templates = templates_ar if is_ar else templates_en

    # Find last table line to append rows after it.
    lines = kpis.split('\n')
    insert_after = -1
    in_tbl = False
    for idx, ln in enumerate(lines):
        s = ln.strip()
        if not in_tbl:
            if hdr_re.match(s):
                in_tbl = True
            continue
        if s.startswith('|') and s.endswith('|'):
            insert_after = idx
        else:
            break
    if insert_after < 0:
        # Header was injected but separator/rows not yet present — append.
        insert_after = len(lines) - 1

    new_rows = []
    for offset in range(needed):
        tpl = templates[offset % len(templates)]
        new_rows.append(
            f'| {next_n + offset} | {tpl[0]} | {tpl[1]} | {tpl[2]} | {tpl[3]} | {tpl[4]} |'
        )
    added = len(new_rows)

    lines = lines[:insert_after + 1] + new_rows + lines[insert_after + 1:]
    sections['kpis'] = '\n'.join(lines)
    return added


# ────────────────────────────────────────────────────────────────────────────
# PASS-14 DETERMINISTIC ARABIC PDF FONT REGISTRATION
#
# Called once at PDF-export time. Caches the registered font name in
# module-level globals so subsequent exports reuse the same registration
# instead of re-scanning the filesystem each time. Always returns
# (font_name_or_helvetica, bold_variant_or_helvetica_bold).
#
# Raises FontRegistrationError if the calling code explicitly requires
# an Arabic font and registration truly fails — never silently returns
# Helvetica for Arabic.
# ────────────────────────────────────────────────────────────────────────────
_ARABIC_PDF_FONT_REGISTERED = False
_ARABIC_PDF_FONT_NAME = 'Helvetica'
_ARABIC_PDF_FONT_BOLD = 'Helvetica-Bold'
_ARABIC_PDF_FONT_PATH = None


class FontRegistrationError(Exception):
    """Raised when Arabic font registration is required but fails."""
    pass


def _ensure_arabic_pdf_font(required=False):
    """Register an Arabic-capable font once and return (regular, bold)
    names. If already registered in this process, short-circuits.

    Arguments:
      required: if True and registration fails, raises
                FontRegistrationError. If False, returns
                ('Helvetica', 'Helvetica-Bold') with a warning log.

    Font search order:
      1. Noto Sans Arabic / Noto Naskh Arabic (preferred)
      2. Amiri (bundled fallback)
      3. DejaVu Sans (generic with Arabic support)
      4. Liberation Sans
      5. Any font matching glob [Aa]rabic*.ttf / [Aa]miri*.ttf
    """
    global _ARABIC_PDF_FONT_REGISTERED, _ARABIC_PDF_FONT_NAME
    global _ARABIC_PDF_FONT_BOLD, _ARABIC_PDF_FONT_PATH

    if _ARABIC_PDF_FONT_REGISTERED:
        return _ARABIC_PDF_FONT_NAME, _ARABIC_PDF_FONT_BOLD

    try:
        from reportlab.pdfbase import pdfmetrics
        from reportlab.pdfbase.ttfonts import TTFont
        import os as _os_fr
        import glob as _glob_fr
    except ImportError as ie:
        msg = f'reportlab not available: {ie}'
        if required:
            raise FontRegistrationError(msg)
        print(f'[FONT-REG] {msg} — falling back to Helvetica', flush=True)
        _ARABIC_PDF_FONT_REGISTERED = True
        return _ARABIC_PDF_FONT_NAME, _ARABIC_PDF_FONT_BOLD

    font_paths = [
        '/usr/share/fonts/truetype/noto/NotoSansArabic-Regular.ttf',
        '/usr/share/fonts/opentype/noto/NotoSansArabic-Regular.ttf',
        '/usr/share/fonts/truetype/noto/NotoNaskhArabic-Regular.ttf',
        'static/fonts/Amiri-Regular.ttf',
        'static/fonts/NotoSansArabic-Regular.ttf',
        '/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf',
        '/usr/share/fonts/truetype/freefont/FreeSans.ttf',
        '/usr/share/fonts/truetype/liberation/LiberationSans-Regular.ttf',
        '/usr/share/fonts/TTF/DejaVuSans.ttf',
        '/usr/local/share/fonts/Amiri-Regular.ttf',
    ]
    # Also search via glob
    try:
        font_paths = (
            _glob_fr.glob('/usr/share/fonts/**/[Nn]oto*[Aa]rabic*.ttf', recursive=True)
            + _glob_fr.glob('/usr/share/fonts/**/[Aa]miri*.ttf', recursive=True)
            + _glob_fr.glob('/usr/share/fonts/**/[Aa]rabic*.ttf', recursive=True)
            + font_paths
        )
    except Exception:
        pass

    for font_path in font_paths:
        if not _os_fr.path.exists(font_path):
            continue
        try:
            pdfmetrics.registerFont(TTFont('ArabicFont', font_path))
            _ARABIC_PDF_FONT_NAME = 'ArabicFont'
            # Try to register a bold variant if available
            bold_candidates = [
                font_path.replace('Regular', 'Bold'),
                font_path.replace('-Regular', '-Bold'),
                font_path.replace('Sans', 'SansBold'),
            ]
            bold_registered = False
            for bold_path in bold_candidates:
                if bold_path != font_path and _os_fr.path.exists(bold_path):
                    try:
                        pdfmetrics.registerFont(
                            TTFont('ArabicFontBold', bold_path))
                        _ARABIC_PDF_FONT_BOLD = 'ArabicFontBold'
                        bold_registered = True
                        break
                    except Exception:
                        pass
            if not bold_registered:
                # Reuse regular as bold — Arabic glyphs still render.
                _ARABIC_PDF_FONT_BOLD = 'ArabicFont'
            _ARABIC_PDF_FONT_PATH = font_path
            _ARABIC_PDF_FONT_REGISTERED = True
            print(f'[FONT-REG] Arabic PDF font registered: {font_path} '
                  f'(regular={_ARABIC_PDF_FONT_NAME}, '
                  f'bold={_ARABIC_PDF_FONT_BOLD})', flush=True)
            return _ARABIC_PDF_FONT_NAME, _ARABIC_PDF_FONT_BOLD
        except Exception as fe:
            print(f'[FONT-REG] Failed to register {font_path}: {fe}',
                  flush=True)
            continue

    # None of the paths worked.
    msg = ('No Arabic-capable TTF font found on this system. Install '
           'fonts-noto-core / fonts-noto-unhinted, or place '
           'static/fonts/Amiri-Regular.ttf in the repo.')
    if required:
        raise FontRegistrationError(msg)
    print(f'[FONT-REG] {msg} — falling back to Helvetica '
          '(Arabic glyphs will render as boxes)', flush=True)
    _ARABIC_PDF_FONT_REGISTERED = True
    return _ARABIC_PDF_FONT_NAME, _ARABIC_PDF_FONT_BOLD


# Startup preflight (prompt clause F): attempt Arabic-font registration
# once at import time so operators see the registration outcome in logs
# before the first PDF export. Non-required: a failure here logs a
# warning but does NOT raise — real enforcement still happens at export
# time via _ensure_arabic_pdf_font(required=True), which returns a 500
# with a bilingual error message if no Arabic-capable font is available.
try:
    _pf_name, _pf_bold = _ensure_arabic_pdf_font(required=False)
    print(f'[FONT-REG] startup_preflight arabic_font={_pf_name!r} '
          f'bold={_pf_bold!r} path={_ARABIC_PDF_FONT_PATH!r}', flush=True)
except Exception as _pfe:
    print(f'[FONT-REG] startup_preflight_failed: {_pfe}', flush=True)


def _enforce_technical_strategy_completeness(sections, lang, domain, fw_short,
                                              sector='General',
                                              org_name='The Organization',
                                              maturity='initial',
                                              generation_mode='drafting'):
    """Apply all PASS-6 completeness fixes in the correct order:
      1. Dedupe confidence (idempotent — runs even if no duplicates).
      2. Enrich placeholder KPI rows.
      3. Synthesize missing per-KPI guides.
      4. Synthesize missing per-gap guides.
      5. Semantic-richness synthesis (environment / roadmap / KPI-depth /
         confidence) — uses sector / org_name / maturity / generation_mode
         to produce context-aware fallbacks when AI output is thin.
    Returns a list of completeness flags that COULD NOT be repaired and
    must trigger a save-block: ('so_rows_insufficient', 'placeholder_kpis',
    'kpi_guide_coverage', 'gap_guide_coverage').
    """
    flags = []
    # 1. Dedupe confidence
    dedupe_confidence_section(sections, lang)
    # 2. Enrich placeholder KPI rows
    if 'kpis' in sections and sections['kpis']:
        before = count_placeholder_kpi_rows(sections['kpis'])
        if before:
            sections['kpis'] = enrich_placeholder_kpi_rows(
                sections['kpis'], domain, fw_short)
        after = count_placeholder_kpi_rows(sections['kpis'])
        if after:
            flags.append(('placeholder_kpis', after))
    # 3. KPI guide coverage
    ensure_kpi_guide_coverage(sections, lang, domain, fw_short)
    n_kpis = count_substantive_kpis(sections.get('kpis', ''))
    n_kpi_guides = count_kpi_guides(sections.get('kpis', ''))
    if n_kpis > 0 and n_kpi_guides < n_kpis:
        flags.append(('kpi_guide_coverage', f'{n_kpi_guides}/{n_kpis}'))
    # 4. Gap guide coverage
    ensure_gap_guide_coverage(sections, lang, domain, fw_short)
    n_gaps = count_substantive_gaps(sections.get('gaps', ''))
    n_gap_guides = count_gap_guides(sections.get('gaps', ''))
    if n_gaps > 0 and n_gap_guides < n_gaps:
        flags.append(('gap_guide_coverage', f'{n_gap_guides}/{n_gaps}'))
    # 5. SO row count check — attempt one last-ditch force-inject before
    #    flagging (PASS-6 prompt clause A: "Regenerate Strategic Objectives
    #    section if needed before final failure"). The Tier-4 force-inject
    #    upstream may not have triggered if the audit's stricter SO check
    #    didn't flag the issue but the completeness counter (which rejects
    #    placeholder cells too) does.
    n_so = count_valid_objective_rows(sections.get('vision', ''))
    if n_so < _RICHNESS_MIN_SO_ROWS:
        try:
            _force_inject_mandatory_section(
                sections, 'strategic_objectives_rows_insufficient', lang,
                domain=domain, fw_short=fw_short,
            )
            n_so = count_valid_objective_rows(sections.get('vision', ''))
        except Exception:
            pass
    if n_so < _RICHNESS_MIN_SO_ROWS:
        flags.append(('so_rows_insufficient',
                      f'{n_so}/{_RICHNESS_MIN_SO_ROWS}'))

    # NOTE: Semantic richness synthesizers (synthesize_environment_context,
    # synthesize_roadmap_depth, synthesize_kpi_depth, synthesize_confidence_depth)
    # used to run here. They have been MOVED to _apply_final_synthesis_pass()
    # which runs AFTER resection / dedupe / family-collapse / residue cleanup,
    # so synthesis operates on the FINAL canonical payload rather than on a
    # mid-pipeline state where misrouted content may still confuse the
    # synthesizers' emptiness checks. See prompt clause B4:
    # "operate on the FINAL canonical Arabic payload AFTER: repair, resection,
    # dedupe, residue cleanup, family collapse, placeholder cleanup."
    # The completeness pass here is now scoped to STRUCTURAL fixes only
    # (confidence dedup, placeholder enrichment, guide coverage, SO-row
    # count). The `sector`, `org_name`, `maturity`, `generation_mode` kwargs
    # are still accepted to preserve backward compatibility with any caller
    # that constructs them.

    return flags


# ────────────────────────────────────────────────────────────────────────────
# TECHNICAL STRATEGY DETERMINISTIC DEPTH ENRICHMENT
#
# enforce_technical_strategy_depth() is the single authoritative entry point
# for adding consulting-grade technical depth to an Arabic (or English)
# Cybersecurity Technical Strategy.  It runs AFTER
# _apply_final_synthesis_pass and BEFORE validate_arabic_strategy_semantic_
# richness / _sections_to_json / DB save / preview export.
#
# All enrichment is DETERMINISTIC — no additional AI call is made. The
# function inspects each section and appends only what is missing, so it
# is fully idempotent when called twice on an already-rich payload.
# ────────────────────────────────────────────────────────────────────────────

# Minimum number of initiative rows every synthesized pillar must carry.
_RICHNESS_MIN_PILLAR_INITIATIVES = 3


def _count_pillar_initiative_rows(pillar_body):
    """Return the number of data rows in the initiative table inside a
    pillar body (pipe-table rows that are not header or separator lines).
    """
    if not pillar_body:
        return 0
    count = 0
    in_tbl = False
    for ln in pillar_body.splitlines():
        s = ln.strip()
        if s.startswith('|') and s.endswith('|'):
            if _ts_re.match(r'^\|[\s\-:|]+\|$', s):
                continue
            cells = [c.strip() for c in s.split('|')[1:-1]]
            # Header row: first non-separator pipe-line with '#' in first cell
            if cells and cells[0].strip('#').strip() == '':
                in_tbl = True
                continue
            if in_tbl and cells and cells[0].replace('.', '').isdigit():
                count += 1
        elif s and not s.startswith('|'):
            pass
    # Fallback: count any data row (not separator) if in_tbl never fired
    if count == 0:
        for ln in pillar_body.splitlines():
            s = ln.strip()
            if (s.startswith('|') and s.endswith('|') and
                    not _ts_re.match(r'^\|[\s\-:|]+\|$', s)):
                cells = [c.strip() for c in s.split('|')[1:-1]]
                if (cells and cells[0].replace('.', '').isdigit()
                        and len(cells) >= 3
                        and sum(1 for c in cells[1:]
                                if not _ts_is_placeholder(c)) >= 2):
                    count += 1
    return count


def _add_pillar_initiative_rows(body, needed, is_ar, domain='Cyber Security',
                                 fw_short='NCA ECC', pillar_title=''):
    """Append `needed` extra initiative rows to an existing pillar body.
    Rows are deterministic and reference domain/fw_short.  Returns the
    updated body string.
    """
    # Count how many rows exist already to continue numbering
    existing = _count_pillar_initiative_rows(body)
    start = existing + 1
    if is_ar:
        extra_rows_ar = [
            (f'سجل ضوابط {fw_short}',
             f'توثيق وتتبع حالة تطبيق ضوابط {fw_short} مع تحديد أصحاب كل ضابط',
             f'سجل ضوابط {fw_short} المُحدَّث + حالة الامتثال'),
            ('مصفوفة RACI للأدوار والمسؤوليات',
             f'توثيق مصفوفة RACI لجميع أدوار ومسؤوليات {domain} داخل {pillar_title or "هذه الركيزة"}',
             'مصفوفة RACI المعتمدة + توصيف الوظائف المحدَّث'),
            (f'خطة المعالجة والمتابعة',
             f'إعداد خطة معالجة الفجوات ذات الصلة بهذه الركيزة مع مؤشرات قياس دورية',
             'خطة المعالجة + لوحة متابعة + تقارير دورية'),
            ('التحقق والمراجعة الدورية',
             f'إجراء مراجعة دورية للالتزام بمتطلبات {fw_short} ضمن نطاق هذه الركيزة',
             'تقارير المراجعة + الإجراءات التصحيحية الموثقة'),
        ]
        rows_to_add = extra_rows_ar[:needed]
    else:
        extra_rows_en = [
            (f'{fw_short} Control Register',
             f'Document and track implementation status of {fw_short} controls with designated owners',
             f'Updated {fw_short} control register + Compliance status'),
            ('RACI Matrix for Roles & Responsibilities',
             f'Document the RACI matrix for all {domain} roles under this pillar',
             'Approved RACI matrix + Updated job descriptions'),
            ('Remediation & Monitoring Plan',
             f'Develop a gap remediation plan for this pillar with periodic KPI tracking',
             'Remediation plan + Progress dashboard + Periodic reports'),
            ('Periodic Verification & Review',
             f'Conduct periodic compliance reviews against {fw_short} requirements within this pillar scope',
             'Review reports + Documented corrective actions'),
        ]
        rows_to_add = extra_rows_en[:needed]

    # Find the last pipe-table data row and append after it
    lines = body.split('\n')
    last_row_idx = -1
    for i in range(len(lines) - 1, -1, -1):
        s = lines[i].strip()
        if (s.startswith('|') and s.endswith('|') and
                not _ts_re.match(r'^\|[\s\-:|]+\|$', s)):
            last_row_idx = i
            break

    new_lines = []
    for j, row in enumerate(rows_to_add):
        new_lines.append(f'| {start + j} | {row[0]} | {row[1]} | {row[2]} |')

    if last_row_idx >= 0:
        lines = lines[:last_row_idx + 1] + new_lines + lines[last_row_idx + 1:]
    else:
        lines.extend(new_lines)
    return '\n'.join(lines)


def enforce_technical_strategy_depth(sections, lang, domain='Cyber Security',
                                      fw_short='NCA ECC', sector='General',
                                      org_name='The Organization',
                                      maturity='initial',
                                      generation_mode='drafting',
                                      diagnostic_gaps=None):
    """Deterministic depth-enrichment pass for Technical Strategy only.

    Runs after _apply_final_synthesis_pass and before
    validate_arabic_strategy_semantic_richness / _sections_to_json /
    DB save / preview export.

    Contract:
      A. Ensures each pillar has ≥ _RICHNESS_MIN_PILLAR_INITIATIVES (3)
         initiative rows.  Adds deterministic rows when short.
      B. Ensures the Strategic Objectives section has ≥ 5 rows for
         cybersecurity strategies.  Adds canonical cybersecurity
         objective rows when the AI produced thin output.
      C. Ensures the KPI section has ≥ 6 rows with richer column
         metadata (source, owner, frequency) when in consulting/assurance
         mode.
      D. Ensures the confidence/risk section has ≥ 5 risk rows with
         owner and treatment columns.
      E. In consulting/assurance mode, adds a cybersecurity capability
         coverage check: verifies key capabilities (IAM, SIEM, EDR/XDR,
         vulnerability management, incident response, backup/DR,
         awareness, third-party risk, data protection) are mentioned
         across the strategy sections and logs a warning for missing ones.

    Returns a dict summarising what was added (for diagnostic logging).
    """
    is_ar = (lang == 'ar')
    diagnostic_gaps = diagnostic_gaps or []
    _mode_lc = str(generation_mode).lower()
    summary = {
        'pillar_initiatives_added': 0,
        'so_rows_added': 0,
        'kpi_rows_added': 0,
        'risk_rows_added': 0,
        'capability_gaps': [],
    }

    # ── A. Pillar initiative depth ──────────────────────────────────────────
    pillars_text = sections.get('pillars', '') or ''
    if pillars_text.strip():
        pillar_matches = list(_PILLAR_HEADING_RE_GLOBAL.finditer(pillars_text))
        if not pillar_matches:
            pillar_matches = list(_ts_re.finditer(
                r'^###\s+[^\n]+', pillars_text, _ts_re.MULTILINE,
            ))
        if pillar_matches:
            parts = []
            for idx, m in enumerate(pillar_matches):
                p_start = m.start()
                p_end = (pillar_matches[idx + 1].start()
                         if idx + 1 < len(pillar_matches)
                         else len(pillars_text))
                heading = pillars_text[p_start:m.end()]
                body = pillars_text[m.end():p_end]
                title = _ts_re.sub(r'^###\s+', '', heading).strip()
                n_init = _count_pillar_initiative_rows(body)
                needed = _RICHNESS_MIN_PILLAR_INITIATIVES - n_init
                if needed > 0:
                    body = _add_pillar_initiative_rows(
                        body, needed, is_ar,
                        domain=domain, fw_short=fw_short,
                        pillar_title=title,
                    )
                    summary['pillar_initiatives_added'] += needed
                parts.append(heading + body)
            sections['pillars'] = ''.join(parts)

    # ── B. Strategic Objectives depth ───────────────────────────────────────
    _MIN_SO_DEPTH = 5   # consulting-grade minimum for cybersecurity
    n_so = count_valid_objective_rows(sections.get('vision', '') or '')
    if n_so < _MIN_SO_DEPTH:
        _so_to_add = _MIN_SO_DEPTH - n_so
        _so_text = sections.get('vision', '') or ''
        # Parse existing row numbers to continue numbering
        _so_hdr = _ts_re.compile(
            r'^\|\s*#\s*\|\s*(?:Objective|الهدف(?:\s+الاستراتيجي)?|الأهداف)\s*\|',
            _ts_re.IGNORECASE,
        )
        _existing_so_nums = set()
        for _cells in _ts_table_rows(_so_text, _so_hdr):
            if _cells and _cells[0].replace('.', '').isdigit():
                _existing_so_nums.add(int(_cells[0]))
        _next_so = max(_existing_so_nums) + 1 if _existing_so_nums else 1

        # Canonical cybersecurity objectives bank (bilingual)
        if is_ar:
            _so_bank = [
                ('نموذج حوكمة الأمن السيبراني',
                 '100% نضج هيكل الحوكمة',
                 f'متطلب {fw_short} وغياب هيكل حوكمة رسمي',
                 'خلال 6 أشهر'),
                (f'تطبيق ضوابط {fw_short}',
                 f'≥ 95% نسبة تطبيق ضوابط {fw_short} مع أدلة تدقيق',
                 f'امتثال تنظيمي إلزامي لقطاع {sector}',
                 'خلال 12 شهراً'),
                ('إدارة الهوية والوصول المميز (IAM/PAM)',
                 '100% تغطية الحسابات المميزة بـPAM و100% MFA',
                 'تقليل مخاطر الوصول غير المصرح به',
                 'خلال 9 أشهر'),
                ('مراقبة SIEM واستجابة للحوادث',
                 f'MTTD ≤ 60 دقيقة، MTTR ≤ 4 ساعات',
                 'ثغرات الكشف المُشخَّصة في التقييم',
                 'خلال 12 شهراً'),
                ('إدارة الثغرات والتصحيح',
                 '100% إغلاق الثغرات الحرجة خلال 30 يوماً',
                 'تقليل سطح الهجوم المعرّض',
                 'خلال 6 أشهر'),
                ('النسخ الاحتياطي والتعافي من الكوارث',
                 '100% نجاح اختبارات استعادة النسخ الاحتياطي',
                 'ضمان استمرارية الأعمال في حالات الطوارئ',
                 'خلال 9 أشهر'),
                ('التوعية ومحاكاة التصيد',
                 '≥ 90% اجتياز التدريب، ≤ 5% معدل وقوع التصيد',
                 'تقليل المخاطر البشرية للحوادث السيبرانية',
                 'خلال 12 شهراً'),
                ('مخاطر الأطراف الثالثة',
                 '100% تقييم الموردين الحرجين',
                 'إغلاق فجوة سلسلة الإمداد الرقمية',
                 'خلال 18 شهراً'),
            ]
        else:
            _so_bank = [
                ('Cybersecurity Governance Operating Model',
                 '100% governance structure maturity',
                 f'{fw_short} requirement; no formal governance structure exists',
                 'Within 6 months'),
                (f'{fw_short} Control Implementation',
                 f'≥ 95% {fw_short} control implementation rate with audit evidence',
                 f'Mandatory regulatory compliance for {sector} sector',
                 'Within 12 months'),
                ('Identity & Privileged Access Management (IAM/PAM)',
                 '100% privileged account PAM coverage + 100% MFA',
                 'Reduce risk of unauthorised access',
                 'Within 9 months'),
                ('SIEM/SOC Monitoring & Incident Response',
                 'MTTD ≤ 60 min, MTTR ≤ 4 hrs',
                 'Detection gaps identified in assessment',
                 'Within 12 months'),
                ('Vulnerability & Patch Management',
                 '100% critical vulnerability closure within 30 days',
                 'Reduce exposed attack surface',
                 'Within 6 months'),
                ('Backup, DR & Cyber Resilience',
                 '100% backup restore test success rate',
                 'Ensure business continuity in emergencies',
                 'Within 9 months'),
                ('Awareness & Phishing Resilience',
                 '≥ 90% training pass rate, ≤ 5% phishing click rate',
                 'Reduce human risk factor for cyber incidents',
                 'Within 12 months'),
                ('Third-Party / Supply-Chain Cyber Risk',
                 '100% critical supplier assessment coverage',
                 'Close digital supply-chain cyber exposure',
                 'Within 18 months'),
            ]

        # Pick rows not already represented (keyword dedup)
        _so_text_lc = _so_text.lower()
        _added_rows = []
        for _obj, _target, _just, _tf in _so_bank:
            if len(_added_rows) >= _so_to_add:
                break
            # Skip if a similar objective is already in the text
            _kws = _obj.lower().split()[:3]
            if any(len(k) > 3 and k in _so_text_lc for k in _kws):
                continue
            _added_rows.append(
                f'| {_next_so} | {_obj} | {_target} | {_just} | {_tf} |'
            )
            _next_so += 1

        if _added_rows:
            sections['vision'] = _append_rows_under_header(
                _so_text, _so_hdr, _added_rows)
            summary['so_rows_added'] = len(_added_rows)

    # ── C. KPI depth (consulting/assurance: 6+ rows with richer columns) ───
    _MIN_KPI_DEPTH = 6 if _mode_lc in ('consulting', 'assurance') else 4
    _kpi_text = sections.get('kpis', '') or ''
    _n_kpi = count_substantive_kpis(_kpi_text)
    if _n_kpi < _MIN_KPI_DEPTH:
        _kpi_to_add = _MIN_KPI_DEPTH - _n_kpi
        _kpi_hdr = _ts_re.compile(
            r'^\|\s*#\s*\|\s*(?:KPI Description|وصف المؤشر|KPI)\s*\|',
            _ts_re.IGNORECASE,
        )
        _existing_kpi_nums = set()
        for _cells in _ts_table_rows(_kpi_text, _kpi_hdr):
            if _cells and _cells[0].replace('.', '').isdigit():
                _existing_kpi_nums.add(int(_cells[0]))
        _next_kpi = max(_existing_kpi_nums) + 1 if _existing_kpi_nums else 1
