        # ── RESCUE: extract confidence content that leaked into KPIs section ──
        # Happens when the AI writes Section 7 (Confidence) without a [SECTION] separator,
        # so the section splitter assigns both KPI content AND confidence content to
        # sections['kpis'], leaving sections['confidence'] empty.
        # We detect this by scanning sections['kpis'] for a Confidence Score heading and
        # splitting it out before the fallback injector fires.
        if sections.get('kpis') and (not sections.get('confidence') or not sections['confidence'].strip()):
            _CONF_SPLIT_RE = re.compile(
                r'(?:^|\n)(?:##\s*\d*\.?\s*)?(?:Confidence Assessment|تقييم الجاهزية|تقييم الثقة)',
                re.IGNORECASE | re.MULTILINE
            )
            _CONF_SCORE_RE = re.compile(
                r'(?:^|\n)\*{0,2}(?:Confidence Score|درجة الثقة)\*{0,2}\s*:',
                re.IGNORECASE | re.MULTILINE
            )
            kpis_text = sections['kpis']
            # Try heading-based split first
            m = _CONF_SPLIT_RE.search(kpis_text)
            if not m:
                m = _CONF_SCORE_RE.search(kpis_text)
            if m:
                split_pos = m.start()
                # Trim the newline at the boundary
                sections['kpis'] = kpis_text[:split_pos].rstrip()
                sections['confidence'] = kpis_text[split_pos:].lstrip()
