@app.route('/api/tasks/stats')
@login_required
def api_task_stats():
    """Get task statistics."""
    try:
        conn = get_db()
        user_id = session['user_id']
        
        todo = conn.execute('SELECT COUNT(*) FROM project_tasks WHERE user_id=? AND status="todo"', (user_id,)).fetchone()[0]
        in_progress = conn.execute('SELECT COUNT(*) FROM project_tasks WHERE user_id=? AND status="in_progress"', (user_id,)).fetchone()[0]
        done = conn.execute('SELECT COUNT(*) FROM project_tasks WHERE user_id=? AND status="done"', (user_id,)).fetchone()[0]
        blocked = conn.execute('SELECT COUNT(*) FROM project_tasks WHERE user_id=? AND status="blocked"', (user_id,)).fetchone()[0]
        
        overdue = conn.execute(
            'SELECT COUNT(*) FROM project_tasks WHERE user_id=? AND status!="done" AND due_date < date("now") AND due_date != ""',
            (user_id,)
        ).fetchone()[0]
        
        total = todo + in_progress + done + blocked
        return jsonify({
            'success': True,
            'stats': {
                'todo': todo, 'in_progress': in_progress, 'done': done, 'blocked': blocked,
                'total': total, 'overdue': overdue,
                'completion_rate': round((done / total * 100) if total > 0 else 0)
            }
        })
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/strategy-readiness')
@login_required
def api_strategy_readiness():
    """Return which domains have generated strategy data — used by Master Plan UI badges."""
    DOMAINS = [
        ('Cyber Security',             'Cyber Security'),
        ('Data Management',            'Data Management'),
        ('Artificial Intelligence',    'AI Governance'),
        ('Digital Transformation',     'Digital Transformation'),
        ('Enterprise Risk Management', 'ERM'),
    ]
    try:
        conn    = get_db()
        user_id = session['user_id']
        result  = []
        for db_domain, label in DOMAINS:
            # Check strategies table for raw content
            row = conn.execute(
                'SELECT id FROM strategies WHERE user_id=? AND domain=? ORDER BY created_at DESC LIMIT 1',
                (user_id, db_domain)
            ).fetchone()
            # Also check project_tasks (populated by json_sync)
            tasks = conn.execute(
                "SELECT COUNT(*) FROM project_tasks WHERE user_id=? AND domain=? AND source_type='ai_json_sync'",
                (user_id, db_domain)
            ).fetchone()[0]
            result.append({
                'name':         label,
                'domain':       db_domain,
                'has_strategy': bool(row or tasks > 0),
            })
        return jsonify({'domains': result})
    except Exception as e:
        return jsonify({'domains': [], 'error': str(e)})


@app.route('/api/tasks/by-category')
@login_required
def api_tasks_by_category():
    """Get tasks grouped by category for Tasks Management tab.
    
    Categories: strategic_initiative, implementation, kpi, gap_mitigation, risk_mitigation
    Optional ?domain=... and ?category=... filters.
    """
    try:
        conn = get_db()
        user_id = session['user_id']
        domain = request.args.get('domain', '')
        category = request.args.get('category', '')
        
        query = 'SELECT * FROM project_tasks WHERE user_id = ?'
        params = [user_id]
        
        if domain:
            d1, d2 = get_bilingual_domain(domain)
            query += ' AND domain IN (?, ?)'
            params.extend([d1, d2])
        if category:
            query += ' AND category = ?'
            params.append(category)
        
        query += ' ORDER BY CASE priority WHEN "critical" THEN 0 WHEN "high" THEN 1 WHEN "medium" THEN 2 WHEN "low" THEN 3 END, created_at DESC'
        
        tasks = conn.execute(query, params).fetchall()
        
        # Category counts
        cq = 'SELECT COALESCE(category,"implementation") as cat, COUNT(*) as cnt FROM project_tasks WHERE user_id = ?'
        cp = [user_id]
        if domain:
            d1, d2 = get_bilingual_domain(domain)
            cq += ' AND domain IN (?, ?)'
            cp.extend([d1, d2])
        cq += ' GROUP BY COALESCE(category,"implementation")'
        counts = {r['cat']: r['cnt'] for r in conn.execute(cq, cp).fetchall()}
        
        return jsonify({
            'success': True,
            'tasks': [dict(t) for t in tasks],
            'counts': counts,
            'total': len(tasks)
        })
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/profile-stats')
@login_required
def api_profile_stats():
    """Live profile document counts — called by profile page for auto-refresh."""
    try:
        conn = get_db()
        uid = session['user_id']
        
        en_domains = TRANSLATIONS['en']['domains']
        ar_domains = TRANSLATIONS['ar']['domains']
        domain_en_ar = dict(zip(en_domains, ar_domains))
        
        domain_stats = {}
        for domain in en_domains:
            ar_domain = domain_en_ar.get(domain, domain)
            s = conn.execute('SELECT COUNT(*) FROM strategies WHERE user_id = ? AND domain IN (?, ?)', (uid, domain, ar_domain)).fetchone()[0]
            p = conn.execute('SELECT COUNT(*) FROM policies WHERE user_id = ? AND domain IN (?, ?) AND COALESCE(is_procedure, 0) = 0', (uid, domain, ar_domain)).fetchone()[0]
            pr = conn.execute('SELECT COUNT(*) FROM policies WHERE user_id = ? AND domain IN (?, ?) AND is_procedure = 1', (uid, domain, ar_domain)).fetchone()[0]
            a = conn.execute('SELECT COUNT(*) FROM audits WHERE user_id = ? AND domain IN (?, ?)', (uid, domain, ar_domain)).fetchone()[0]
            r = conn.execute('SELECT COUNT(*) FROM risks WHERE user_id = ? AND domain IN (?, ?)', (uid, domain, ar_domain)).fetchone()[0]
            domain_stats[domain] = {'strategies': s, 'policies': p, 'procedures': pr, 'audits': a, 'risks': r, 'total': s+p+pr+a+r}
        
        total = conn.execute('''SELECT (SELECT COUNT(*) FROM strategies WHERE user_id = ?) +
            (SELECT COUNT(*) FROM policies WHERE user_id = ?) +
            (SELECT COUNT(*) FROM audits WHERE user_id = ?) +
            (SELECT COUNT(*) FROM risks WHERE user_id = ?)''', (uid, uid, uid, uid)).fetchone()[0]
        
        tasks_count = conn.execute('SELECT COUNT(*) FROM project_tasks WHERE user_id = ?', (uid,)).fetchone()[0]
        
        return jsonify({'success': True, 'total_docs': total, 'tasks': tasks_count, 'domain_stats': domain_stats})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500

