@app.route('/api/diagnostic/run', methods=['POST'])
@login_required
def api_diagnostic_run():
    """Run structured diagnostic assessment before major document generation."""
    try:
        data = request.get_json()
        domain = data.get('domain', 'Cyber Security')
        sector = data.get('sector', 'Government')
        org_name = data.get('org_name', 'The Organization')
        maturity = data.get('maturity_level', 'initial')
        challenges = data.get('challenges', '')
        frameworks = data.get('frameworks', [])
        lang = data.get('language', 'en')
        answers = data.get('answers', {})   # {question_index: 'yes'/'no'/'partial'}
        generation_mode = data.get('generation_mode', 'consulting')

        fw_str = ', '.join(frameworks) if isinstance(frameworks, list) else str(frameworks)

        # ── Pull org memory to enrich diagnostic context ──────────────────────
        _mem_enrichment = ''
        try:
            _mem = get_db().execute(
                'SELECT risk_appetite, key_constraints, recurring_risks, unresolved_issues, '
                'governance_model, operating_model FROM org_memory WHERE user_id=? AND domain=?',
                (session['user_id'], domain)
            ).fetchone()
            if _mem:
                _parts = []
                if _mem['risk_appetite']: _parts.append(f"Known Risk Appetite: {_mem['risk_appetite']}")
                if _mem['key_constraints']: _parts.append(f"Known Constraints: {_mem['key_constraints']}")
                if _mem['governance_model']: _parts.append(f"Governance Model: {_mem['governance_model']}")
                try:
                    _rec_risks = json.loads(_mem['recurring_risks'] or '[]')
                    if _rec_risks: _parts.append(f"Recurring Risks: {'; '.join(str(r) for r in _rec_risks[:3])}")
                    _unresolv = json.loads(_mem['unresolved_issues'] or '[]')
                    if _unresolv: _parts.append(f"Prior Unresolved Issues: {'; '.join(str(u) for u in _unresolv[:3])}")
                except Exception:
                    pass
                if _parts:
                    _mem_enrichment = '\n\nPRIOR ORGANISATION MEMORY:\n' + '\n'.join(_parts)
        except Exception as _me:
            print(f"[DIAG] org memory load (non-fatal): {_me}", flush=True)

        # Build answered questions summary for AI
        q_list = (_DIAGNOSTIC_QUESTIONS_AR if lang == 'ar' else _DIAGNOSTIC_QUESTIONS).get(domain, _DIAGNOSTIC_QUESTIONS.get(domain, []))
        answered_summary = ''
        for idx, q in enumerate(q_list):
            ans = answers.get(str(idx), 'unknown')
            answered_summary += f"  Q{idx+1}: {q}\n  Answer: {ans}\n\n"

        maturity_labels = {
            'initial': 'Initial (1) — Ad-hoc, reactive',
            'developing': 'Developing (2) — Some processes exist',
            'defined': 'Defined (3) — Documented and standardised',
            'managed': 'Managed (4) — Measured and controlled',
            'optimized': 'Optimized (5) — Continuously improving',
        }
        maturity_desc = maturity_labels.get(maturity, maturity)

        if lang == 'ar':
            diag_prompt = (
                f"أنت مستشار GRC كبير من Big4. أجرِ تشخيصاً هيكلياً لـ {org_name} في مجال {domain}.\n\n"
                f"القطاع: {sector} | النضج: {maturity_desc} | الأطر: {fw_str}\n"
                f"التحديات: {challenges}\n"
                f"{_mem_enrichment}\n\n"
                f"إجابات الأسئلة التشخيصية:\n{answered_summary}\n\n"
                "أنتج النتائج بصيغة JSON فقط بدون markdown:\n"
                '{"summary":"...","confidence_score":75,"key_gaps":["gap1","gap2"],'
                '"key_assumptions":["assumption1"],"key_unknowns":["unknown1"],'
                '"missing_evidence":["evidence1"],"recommended_next_questions":["q1"],'
                '"diagnostic_grade":"B","urgency":"high"}'
            )
        else:
            diag_prompt = (
                f"You are a Big4 senior GRC partner. Conduct a structured diagnostic for {org_name} in {domain}.\n\n"
                f"Sector: {sector} | Maturity: {maturity_desc} | Frameworks: {fw_str}\n"
                f"Stated challenges: {challenges}\n"
                f"{_mem_enrichment}\n\n"
                f"Answered diagnostic questions:\n{answered_summary}\n\n"
                "Return ONLY valid JSON, no markdown fences:\n"
                '{"summary":"...","confidence_score":75,"key_gaps":["gap1","gap2"],'
                '"key_assumptions":["assumption1"],"key_unknowns":["unknown1"],'
                '"missing_evidence":["evidence1"],"recommended_next_questions":["q1"],'
                '"diagnostic_grade":"B","urgency":"high"}'
            )

        raw = generate_ai_content(diag_prompt, language=lang, task_type='generate', content_type='diagnostic')
        # Strip markdown fences if present
        import re as _re_diag
        raw = _re_diag.sub(r'^```(?:json)?\s*|\s*```$', '', raw.strip(), flags=_re_diag.MULTILINE).strip()

        try:
            result = json.loads(raw)
        except Exception:
            result = {
                'summary': raw[:500] if raw else 'Diagnostic could not be parsed.',
                'confidence_score': 50,
                'key_gaps': [],
                'key_assumptions': [],
                'key_unknowns': [],
                'missing_evidence': [],
                'recommended_next_questions': [],
                'diagnostic_grade': 'C',
                'urgency': 'medium',
            }

        # Persist diagnostic session
        conn = get_db()
        cur = conn.execute(
            '''INSERT INTO diagnostic_sessions
               (user_id, domain, sector, org_name, maturity_level, generation_mode,
                diagnostic_data, summary, confidence_score,
                key_assumptions, key_unknowns, missing_evidence)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?)''',
            (session['user_id'], domain, sector, org_name, maturity, generation_mode,
             json.dumps(answers, ensure_ascii=False),
             result.get('summary', ''),
             result.get('confidence_score', 50),
             json.dumps(result.get('key_assumptions', []), ensure_ascii=False),
             json.dumps(result.get('key_unknowns', []), ensure_ascii=False),
             json.dumps(result.get('missing_evidence', []), ensure_ascii=False))
        )
        diagnostic_id = cur.lastrowid
        conn.commit()

        return jsonify({'success': True, 'diagnostic_id': diagnostic_id, **result})

    except Exception as e:
        print(f"[DIAGNOSTIC] Error: {e}", flush=True)
        return jsonify({'success': False, 'error': str(e)}), 500


