def api_review_document():
    """Run consulting-quality review on a generated document."""
    try:
        data = request.get_json()
        doc_type = data.get('doc_type', 'strategy')
        content = data.get('content', '')
        domain = data.get('domain', 'Cyber Security')
        sector = data.get('sector', 'Government')
        org_name = data.get('org_name', 'The Organization')
        lang = data.get('language', 'en')
        doc_id = data.get('doc_id')

        if not content or len(content.strip()) < 200:
            return jsonify({'success': False, 'error': 'Insufficient content for review'}), 400

        review_prompt = (
            f"You are a Big4 senior partner conducting a quality gate review of a {doc_type} document.\n"
            f"Organization: {org_name} | Domain: {domain} | Sector: {sector}\n\n"
            f"Document excerpt (first 3000 chars):\n{content[:3000]}\n\n"
            "Assess the following dimensions (score 0-100 each):\n"
            "1. Strategic coherence — are sections aligned and logically sequenced?\n"
            "2. Consulting tone — does it read like a Big4 deliverable?\n"
            "3. Executive relevance — is it appropriate for C-suite/Board?\n"
            "4. Implementation realism — are roadmap items achievable?\n"
            "5. KPI measurability — are metrics specific, quantified, time-bound?\n"
            "6. Regulatory mapping — are framework references credible and correct?\n"
            "7. Completeness — are all required sections present and substantial?\n"
            "8. Table integrity — do tables have real data rows (not placeholders)?\n\n"
            "Return ONLY valid JSON, no markdown:\n"
            '{"overall_score":75,"dimension_scores":{"strategic_coherence":80,"consulting_tone":70,'
            '"executive_relevance":75,"implementation_realism":65,"kpi_measurability":80,'
            '"regulatory_mapping":70,"completeness":85,"table_integrity":75},'
            '"issues":[{"severity":"high","section":"KPIs","issue":"...","suggestion":"..."}],'
            '"recommendation":"management_review",'
            '"publishability":"pass",'
            '"summary":"..."}'
        )

        raw = generate_ai_content(review_prompt, language='en', task_type='review', content_type='review')
        import re as _re_rev
        raw = _re_rev.sub(r'^```(?:json)?\s*|\s*```$', '', raw.strip(), flags=_re_rev.MULTILINE).strip()

        try:
            result = json.loads(raw)
        except Exception:
            result = {
                'overall_score': 60,
                'dimension_scores': {},
                'issues': [],
                'recommendation': 'management_review',
                'publishability': 'conditional',
                'summary': raw[:400] if raw else 'Review could not be parsed.',
            }

        score = result.get('overall_score', 60)
        passed = 1 if score >= 70 else 0

        conn = get_db()
        conn.execute(
            '''INSERT INTO document_reviews
               (user_id, doc_type, doc_id, domain, publishability_score, quality_issues,
                recommendation, passed)
               VALUES (?,?,?,?,?,?,?,?)''',
            (session['user_id'], doc_type, doc_id, domain, score,
             json.dumps(result.get('issues', []), ensure_ascii=False),
             result.get('recommendation', 'management_review'), passed)
        )

        # ── Propagate review verdict to artifact table (same as v2) ──────────
        if doc_id:
            _rev_table = _DOC_TABLE_MAP.get(doc_type, 'strategies')
            # Determine new state via the enforced transition helper
            _rec = result.get('recommendation', 'draft_only')
            if score >= 70:
                _new_art_status = 'publishable'
            elif _rec == 'needs_consultant':
                _new_art_status = 'requires_consultant'
            else:
                _new_art_status = 'reviewed'
            try:
                conn.execute(
                    f'UPDATE {_rev_table} SET publishability_score=?, artifact_status=? '
                    f'WHERE id=? AND user_id=?',
                    (score, _new_art_status, doc_id, session['user_id'])
                )
            except Exception as _ue:
                print(f'[REVIEW-v1] Artifact status update failed (non-fatal): {_ue}', flush=True)

        conn.commit()

        return jsonify({'success': True, **result})

    except Exception as e:
        print(f"[REVIEW] Error: {e}", flush=True)
        return jsonify({'success': False, 'error': str(e)}), 500


