# ═══════════════════════════════════════════════════════════════════════════
# MODULE-LEVEL CONSTANTS — artifact state enforcement (used by every gate)
# ═══════════════════════════════════════════════════════════════════════════
_VALID_STATES = frozenset({
    'draft', 'reviewed', 'publishable', 'final',
    'rejected', 'requires_consultant', 'requires_evidence',
})

# Maps artifact_type string → DB table name
# 'procedure' maps to 'policies' (stored with is_procedure=1)
_DOC_TABLE_MAP: dict = {
    'strategy':  'strategies',
    'policy':    'policies',
    'procedure': 'policies',
    'audit':     'audits',
    'risk':      'risks',
}


@app.route('/api/artifact-status', methods=['PATCH'])
@login_required
def api_artifact_status():
    """Enforced artifact status update — forwards to the v2 enforced path.

    This legacy route now applies the SAME transition enforcement as v2:
    - publishable requires score >= 60
    - final requires score >= 70 and current status == publishable
    No bypass path exists — any violation returns HTTP 422.
    """
    try:
        data = request.get_json()
        artifact_type = data.get('artifact_type', 'strategy')
        artifact_id   = data.get('artifact_id')
        new_status    = data.get('status', 'draft')
        notes         = data.get('notes', '')

        if new_status not in _VALID_STATES:
            return jsonify({'success': False, 'error': f'Invalid status: {new_status}'}), 400

        table = _DOC_TABLE_MAP.get(artifact_type)
        if not table:
            return jsonify({'success': False, 'error': f'Unknown artifact type: {artifact_type}'}), 400

        conn = get_db()
        row = conn.execute(
            f'SELECT id, artifact_status, publishability_score FROM {table} WHERE id = ? AND user_id = ?',
            (artifact_id, session['user_id'])
        ).fetchone()
        if not row:
            return jsonify({'success': False, 'error': 'Artifact not found'}), 404

        # ── Enforce transition rules (same as v2) ──────────────────────────
        current_status = row['artifact_status'] or 'draft'
        current_score  = float(row['publishability_score'] or 0)
        allowed_tr, reason_tr = _check_state_transition(new_status, current_score, current_status)
        if not allowed_tr:
            return jsonify({'success': False, 'error': reason_tr, 'blocked': True}), 422

        conn.execute(
            f'UPDATE {table} SET artifact_status = ?, reviewer_notes = ? WHERE id = ? AND user_id = ?',
            (new_status, notes, artifact_id, session['user_id'])
        )
        conn.commit()
        log_action(session['user_id'], 'update_artifact_status',
                   {'type': artifact_type, 'id': artifact_id, 'status': new_status})
        return jsonify({'success': True, 'status': new_status, 'enforced': True})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


