# ── Hard publishability gate for export (internal helper — not a route) ────────
def _canonical_content_from_db(artifact_type: str, artifact_id, user_id: int) -> str:
    """Load the canonical markdown for an artifact directly from the DB.

    PURPOSE: preview and export MUST share the same repaired structured
    content. Preview reads content_json / sections_json from the DB.
    Export previously received client-submitted raw content, which could
    lag behind the repaired DB content (orphan rows, ghost continuation
    rows, truncated sections) — so PDF/DOCX downloads re-introduced
    defects that the preview had already fixed.

    This helper pulls the authoritative content for a saved strategy,
    preferring (in order):
      1. `sections_json` — per-section markdown, already repair-processed
         during save. Reassembled in canonical section order.
      2. `content` — the repair-processed raw markdown blob persisted at
         save time (also includes ensure_markdown_formatting output).
    Returns empty string when the artifact cannot be loaded — caller
    should fall back to client-submitted content (backwards compat).

    SECURITY: row is scoped by user_id; cross-user access returns ''.
    """
    if not artifact_id:
        return ''
    try:
        _art_id = int(artifact_id)
    except (TypeError, ValueError):
        return ''
    if _art_id <= 0:
        return ''
    try:
        _conn = get_db_direct()
        if artifact_type == 'strategy':
            _row = _conn.execute(
                'SELECT sections_json, content_json, content, language, domain '
                'FROM strategies WHERE id = ? AND user_id = ?',
                (_art_id, user_id)
            ).fetchone()
        else:
            _row = None
        _conn.close()
    except Exception as _e:
        print(f'[CANON] DB read failed for {artifact_type}/{artifact_id}: {_e}', flush=True)
        return ''
    if not _row:
        return ''
    _row_keys = _row.keys() if hasattr(_row, 'keys') else []

    # Prefer sections_json — per-section markdown that was normalized
    # through ensure_markdown_formatting + fix_strategic_objectives_table
    # + fix_kpi_main_table before being persisted.
    _sections_json_str = _row['sections_json'] if 'sections_json' in _row_keys else None
    if _sections_json_str:
        try:
            import json as _json_cn
            import hashlib as _hl_cn
            _secs = _json_cn.loads(_sections_json_str)
            if isinstance(_secs, dict) and _secs:
                _order = ['vision', 'pillars', 'environment', 'gaps',
                          'roadmap', 'kpis', 'confidence']
                _parts = [_secs[k] for k in _order
                          if _secs.get(k) and isinstance(_secs[k], str) and _secs[k].strip()]
                if _parts:
                    _canonical = '\n\n'.join(_parts)
                    # Apply final pass through normalizer so any late structural
                    # tweaks (ghost-row drop, cascade split) are reflected here too.
                    try:
                        _canonical = ensure_markdown_formatting(_canonical)
                    except Exception as _fmt_e:
                        print(f'[CANON] ensure_markdown_formatting failed (non-fatal): {_fmt_e}', flush=True)
                    # Parity hash — matches the hash logged at save time.
                    # Operators should see the SAME 16-char hash at save
                    # and at every subsequent export of the same artifact.
                    try:
                        _export_hash = _hl_cn.sha256(
                            (_canonical + '||' + _sections_json_str).encode('utf-8')
                        ).hexdigest()[:16]
                        print(f'[STRATEGY-PARITY] export canonical_hash={_export_hash} '
                              f'artifact={artifact_type}/{artifact_id} '
                              f'content_len={len(_canonical)}', flush=True)
                    except Exception:
                        pass
                    return _canonical
        except Exception as _e:
            print(f'[CANON] sections_json parse failed: {_e}', flush=True)

    # Fallback: the stored `content` column was also repair-processed at save.
    _content_db = _row['content'] if 'content' in _row_keys else None
    if _content_db and isinstance(_content_db, str) and _content_db.strip():
        try:
            return ensure_markdown_formatting(_content_db)
        except Exception as _fmt_e:
            print(f'[CANON] ensure_markdown_formatting failed on content (non-fatal): {_fmt_e}', flush=True)
            return _content_db

    return ''


def _compare_content_parity(db_content: str, client_content: str) -> dict:
    """Lightweight materiality check between DB-canonical content and the
    client-submitted content, used to enforce export parity.

    Returns: {'parity': bool, 'reason': str}
      parity=True  → client content matches DB structurally (same SO rows,
                     same section count, same core-section text length)
      parity=False → materially different; export path should prefer DB
                     and log the drift for investigation.
    """
    if not db_content or not client_content:
        return {'parity': True, 'reason': 'missing-side'}  # can't compare — defer to caller
    import re as _cmp_re
    def _count_so_rows(txt):
        _lines = [ln.strip() for ln in txt.splitlines()]
        _in_tbl = False
        _count = 0
        for _ln in _lines:
            if _cmp_re.match(r'^\|\s*#\s*\|\s*(?:Objective|الهدف)', _ln, _cmp_re.I):
                _in_tbl = True
                _count = 0
                continue
            if _in_tbl:
                if not _ln.startswith('|') or not _ln.endswith('|'):
                    if _ln:
                        _in_tbl = False
                    continue
                if _cmp_re.match(r'^\|[\s\-:|]+\|$', _ln):
                    continue
                _cells = [c.strip() for c in _ln.split('|')[1:-1]]
                if (len(_cells) == 5
                        and _cells[0].replace('.', '').isdigit()
                        and _cells[1] and _cells[1] != '—'):
                    _count += 1
        return _count
    _db_rows = _count_so_rows(db_content)
    _cl_rows = _count_so_rows(client_content)
    if _db_rows != _cl_rows:
        return {
            'parity': False,
            'reason': (f'Strategic Objectives row count differs '
                       f'(DB={_db_rows}, client={_cl_rows})'),
        }
    # Section-header count parity
    _db_heads = len(_cmp_re.findall(r'^##\s+\d+\.', db_content, _cmp_re.MULTILINE))
    _cl_heads = len(_cmp_re.findall(r'^##\s+\d+\.', client_content, _cmp_re.MULTILINE))
    if abs(_db_heads - _cl_heads) > 1:
        return {
            'parity': False,
            'reason': (f'Section count differs '
                       f'(DB={_db_heads}, client={_cl_heads})'),
        }
    return {'parity': True, 'reason': 'ok'}


def _enforce_export_gate(artifact_type: str, artifact_id, content: str,
                         generation_mode: str, user_id: int) -> dict:
    """Centralised fail-CLOSED export gate used by EVERY export path.

    Returns dict: {'allowed': bool, 'reason': str, 'score': float|None, 'status': str|None}
    On ANY exception the caller MUST treat as DENIED — callers wrap in try/except.

    STRICT EXPORT RULE — no exceptions, no score-based overrides:
    - Final export is allowed ONLY when artifact_status is 'publishable' or 'final'.
    - 'reviewed' is NEVER sufficient for final export, regardless of score.
    - All other states (draft, reviewed, rejected, requires_*) are BLOCKED.
    - Structural issues (≥3) → BLOCKED before any state check.
    - No artifact_id → BLOCKED (artifact must be saved and promoted first).
    - Any exception in gate logic → BLOCKED (fail-closed, no allowed=True on exception).
    """

    # ── Layer 1: Structural content check (always first) ────────────────────
    if content:
        struct_issues = _quick_structural_check(content)
        if len(struct_issues) >= 3:
            return {
                'allowed': False,
                'reason': (f'Export blocked — {len(struct_issues)} structural issues detected: '
                           + '; '.join(struct_issues[:3])
                           + '. Run Quality Review before exporting.'),
                'score': None, 'status': 'draft'
            }

    # ── Layer 2: No artifact_id ──────────────────────────────────────────────
    # Consulting/Assurance: must be saved and reviewed — block immediately.
    # Drafting: pass-through for operational/derived exports (risk register,
    #   risk appetite, unsaved working drafts). Layer 1 structural check is
    #   the only gate. This path does NOT apply to saved artifacts — those
    #   go through Layer 3 where publishable/final is required.
    if not artifact_id:
        if generation_mode in ('consulting', 'assurance'):
            return {
                'allowed': False,
                'reason': ('Export blocked — document has not been saved and reviewed. '
                           'Complete the Quality Review process, promote to Publishable, '
                           'then export. Draft saves are still available from the form.'),
                'score': None, 'status': 'draft'
            }
        # Drafting mode + no artifact_id → structural check already passed (Layer 1).
        # Allow the export (working/derived document, not a formal GRC artifact).
        return {
            'allowed': True,
            'reason': 'Drafting mode — operational export of unsaved document.',
            'score': None, 'status': 'draft'
        }

    # ── Drafting mode + artifact_id: allow export without publishable gate ────
    # In drafting mode the quality/state gate does NOT apply — the user is working
    # iteratively and must be able to download at any point.  Consulting/Assurance
    # modes enforce the full publishable/final requirement (Layer 3 below).
    if generation_mode == 'drafting':
        return {
            'allowed': True,
            'reason': 'Drafting mode — export allowed for saved draft.',
            'score': None, 'status': 'draft'
        }

    # ── Layer 3: DB artifact state — ONLY publishable/final allowed ───────────
    # Applies only to consulting / assurance generation modes.
    table = _DOC_TABLE_MAP.get(artifact_type, 'strategies')
    conn  = get_db()
    row   = conn.execute(
        f'SELECT artifact_status, publishability_score FROM {table} WHERE id=? AND user_id=?',
        (artifact_id, user_id)
    ).fetchone()

    if not row:
        return {'allowed': False,
                'reason': 'Export blocked — artifact not found or not owned by current user.',
                'score': None, 'status': 'unknown'}

    status = row['artifact_status'] or 'draft'
    score  = float(row['publishability_score'] or 0)

    # The ONLY two states that permit final export
    if status not in ('publishable', 'final'):
        if status == 'reviewed':
            reason = (
                f'Export blocked — artifact is in "reviewed" state (score: {score:.0f}%) '
                f'but has not been promoted to "publishable". '
                f'To export: from the artifact status bar click "Mark Final" after the '
                f'Quality Review score reaches ≥70%, or use the Quality Review panel to '
                f'promote the artifact to Publishable state first.'
            )
        elif status == 'draft':
            reason = (
                'Export blocked — document has not been reviewed. '
                'Run Quality Review (score ≥60% required), then promote to '
                'Publishable state before exporting.'
            )
        elif status in ('rejected', 'requires_consultant', 'requires_evidence'):
            reason = (
                f'Export blocked — artifact status is "{status}". '
                'Resolve all outstanding issues and promote to Publishable before exporting.'
            )
        else:
            reason = (
                f'Export blocked — artifact status "{status}" is not eligible for final export. '
                'Only "publishable" or "final" artifacts may be exported.'
            )
        return {'allowed': False, 'status': status, 'score': score, 'reason': reason}

    # ── Layer 4: Traceability check (publishable/final only) ──────────────────
    if artifact_type in ('strategy', 'policy', 'procedure', 'audit', 'risk'):
        try:
            tr_count = conn.execute(
                'SELECT COUNT(*) FROM traceability_records '
                'WHERE artifact_type=? AND artifact_id=? AND user_id=?',
                (artifact_type, artifact_id, user_id)
            ).fetchone()[0]
            if tr_count == 0 and generation_mode in ('consulting', 'assurance'):
                return {
                    'allowed': False,
                    'reason': ('Export blocked — no traceability records for this artifact. '
                               'Generate in Consulting or Assurance mode to capture traceability.'),
                    'score': score, 'status': status
                }
        except Exception as _tr_e:
            # Traceability check failure → ALWAYS fail-closed (no mode bypass)
            print(f'[GATE] Traceability check error — denying export: {_tr_e}', flush=True)
            return {
                'allowed': False,
                'reason': f'Export gate error during traceability check — denied for safety: {_tr_e}',
                'score': score, 'status': status
            }

    # ── Approved: publishable or final only ───────────────────────────────────
    if status in ('publishable', 'final'):
        return {'allowed': True, 'status': status, 'score': score,
                'reason': f'Export approved — status "{status}", score {score:.0f}%.'}

    # Catch-all: any path not explicitly approved → blocked (fail-closed)
    return {'allowed': False, 'status': status, 'score': score,
            'reason': f'Export blocked — gate condition unresolved (status: "{status}"). '
                      f'Promote artifact to Publishable before exporting.'}


@app.route('/api/export-gate-check', methods=['POST'])
@login_required
def api_export_gate_check():
    """Public API wrapper around _enforce_export_gate. Fail-CLOSED on any exception."""
    try:
        data = request.get_json()
        result = _enforce_export_gate(
            artifact_type   = data.get('artifact_type', 'strategy'),
            artifact_id     = data.get('artifact_id'),
            content         = data.get('content', ''),
            generation_mode = data.get('generation_mode', 'drafting'),
            user_id         = session['user_id']
        )
        return jsonify(result)
    except Exception as e:
        # FAIL CLOSED — any gate exception denies export
        print(f"[GATE] Exception — denying export: {e}", flush=True)
        return jsonify({'allowed': False, 'reason': f'Gate error — export denied for safety: {str(e)}'}), 403


def _quick_structural_check(content: str) -> list:
    """Fast structural check — returns list of issue strings, empty if clean."""
    import re as _re_sc
    issues = []
    lines = content.split('\n')
    # Check for placeholder-only sections
    placeholder_re = _re_sc.compile(r'^\|[\s|—\-]*\|$')
    placeholder_count = sum(1 for l in lines if placeholder_re.match(l.strip()))
    if placeholder_count > 5:
        issues.append(f'{placeholder_count} placeholder-only table rows detected')
    # Check for bracket placeholders
    bracket_re = _re_sc.compile(r'\[(?:insert|placeholder|TBD|TODO|add here)[^\]]*\]', _re_sc.IGNORECASE)
    bracket_hits = bracket_re.findall(content)
    if bracket_hits:
        issues.append(f'{len(bracket_hits)} unfilled placeholder(s) detected')
    # Check for empty section headings (heading followed immediately by next heading)
    heading_re = _re_sc.compile(r'^#{1,4}\s+\S', _re_sc.MULTILINE)
    headings = [m.start() for m in heading_re.finditer(content)]
    for i in range(len(headings) - 1):
        section_text = content[headings[i]:headings[i+1]].strip()
        if len(section_text) < 80:
            issues.append('Empty or near-empty section heading detected')
            break
    return issues


# ── Universal structural validation (extended to all doc types) ──────────────
def _validate_document_any_type(content: str, doc_type: str, lang: str = 'en') -> dict:
    """Full structural + semantic validation for every document family.

    Returns: {'valid': bool, 'issues': [str], 'score': int (0-100)}
    Covers: strategy, policy, procedure, audit, risk.
    """
    import re as _re_v
    issues = []
    score  = 100

    # ── Table parser ──────────────────────────────────────────────────────────
    def _tables_from_md(text):
        out, ls, i = [], text.split('\n'), 0
        while i < len(ls):
            ln = ls[i].strip()
            if ln.startswith('|') and ln.endswith('|'):
                hdrs = [c.strip() for c in ln.strip('|').split('|')]
                if i + 1 < len(ls) and '---' in ls[i+1] and ls[i+1].strip().startswith('|'):
                    rows, j = [], i + 2
                    while j < len(ls) and ls[j].strip().startswith('|'):
                        rows.append([c.strip() for c in ls[j].strip('|').split('|')])
                        j += 1
                    out.append((hdrs, rows))
                    i = j; continue
            i += 1
        return out

    def _is_placeholder(row):
        return all(c in ('', '—', '-', '–', '...', 'TBD') or
                   bool(_re_v.match(r'^\[.*\]$', c)) for c in row)

    def _is_timeframe(v):
        return bool(_re_v.match(
            r'^(within\s+)?\d+\s*(months?|years?|weeks?|days?|أشهر|شهر|سنوات|سنة)',
            (v or '').strip(), _re_v.IGNORECASE))

    def _norm(v):
        return (v or '').strip().lower().replace('  ', ' ')

    tables = _tables_from_md(content)
    content_lower = content.lower()

    # ── STRATEGY ──────────────────────────────────────────────────────────────
    if doc_type == 'strategy':
        if len(content.strip()) < 2000:
            issues.append('Strategy content too short (<2000 chars)')
            score -= 30

        # Required section headings
        required_hdgs = (
            ['الرؤية', 'الركائز', 'الفجوات', 'خارطة الطريق'] if lang == 'ar'
            else ['vision', 'pillar', 'gap', 'roadmap']
        )
        for h in required_hdgs:
            if h not in content_lower:
                issues.append(f'Strategy missing required section: "{h}"')
                score -= 10

        for hdrs, rows in tables:
            hdrs_norm = [_norm(h) for h in hdrs]
            real = [r for r in rows if not _is_placeholder(r)]

            # Placeholder-only table
            if not real and rows:
                issues.append(f'Table "{"|".join(hdrs[:3])}" contains only placeholder rows')
                score -= 15

            # ── Strategic Objectives: semantic validation ─────────────────────
            if any(kw in ' '.join(hdrs_norm) for kw in ('objective', 'الهدف')):
                for row in real:
                    if len(row) < 3: continue
                    # Timeframe must NOT be in Objective or Metric columns
                    if _is_timeframe(row[1]):
                        issues.append('Strategic Objectives: timeframe value found in Objective column')
                        score -= 12; break
                    if len(row) >= 4 and _is_timeframe(row[2]) and not _is_timeframe(row[-1]):
                        issues.append('Strategic Objectives: timeframe leaked into Target Metric column')
                        score -= 10; break
                    # Duplicate objective in metric column
                    if len(row) >= 3 and row[1] and row[2] and _norm(row[1]) == _norm(row[2]):
                        issues.append('Strategic Objectives: objective text duplicated in Metric column')
                        score -= 8; break

            # ── KPI table: semantic validation ────────────────────────────────
            if any(kw in ' '.join(hdrs_norm) for kw in ('kpi', 'kpis', 'مؤشر')):
                for row in real:
                    if len(row) < 4: continue
                    if _is_timeframe(row[2]) and not _is_timeframe(row[-1]):
                        issues.append('KPI table: timeframe in Target Value column (column shift)')
                        score -= 12; break
                    if row[2] == '—' and row[3] == '—':
                        issues.append('KPI table: Target Value and Formula are both empty')
                        score -= 8; break

            # ── Confidence/CSF table ──────────────────────────────────────────
            if any(kw in ' '.join(hdrs_norm) for kw in ('factor', 'confidence', 'csf', 'الثقة', 'عامل')):
                if len(real) < 3:
                    issues.append(f'Confidence/CSF table has only {len(real)} real row(s) — minimum 3 required')
                    score -= 15

            # ── Key Risks table ───────────────────────────────────────────────
            if any(kw in ' '.join(hdrs_norm) for kw in ('risk', 'likelihood', 'المخاطر', 'الاحتمالية')):
                if len(real) < 3:
                    issues.append(f'Key Risks table has only {len(real)} real row(s) — minimum 3 required')
                    score -= 12
                for row in real:
                    if len(row) < 4: continue
                    # Row number leaked into risk column
                    if row[1] and row[1].isdigit() and row[0] == row[1]:
                        issues.append('Key Risks: row number leaked into Risk column')
                        score -= 10; break

            # ── Pillars / Initiatives table ───────────────────────────────────
            if any(kw in ' '.join(hdrs_norm) for kw in ('initiative', 'pillar', 'مبادرة', 'الركيزة')):
                if len(real) < 3:
                    issues.append(f'Pillars/Initiatives table has only {len(real)} real row(s)')
                    score -= 12

            # ── Roadmap table ─────────────────────────────────────────────────
            if any(kw in ' '.join(hdrs_norm) for kw in ('roadmap', 'phase', 'timeline', 'خارطة', 'المرحلة')):
                for row in real:
                    # Roadmap row must have owner/accountable field
                    has_owner = any(
                        any(kw in _norm(cell) for kw in ('ciso', 'cdo', 'cro', 'team', 'head', 'manager', 'office', 'مدير', 'فريق', 'رئيس'))
                        for cell in row[2:]
                    )
                    if not has_owner:
                        issues.append('Roadmap table: one or more rows missing accountable owner')
                        score -= 8; break

            # ── Gap table ─────────────────────────────────────────────────────
            if any(kw in ' '.join(hdrs_norm) for kw in ('gap', 'الفجوة')):
                if len(real) < 3:
                    issues.append(f'Gap Analysis table has only {len(real)} real row(s)')
                    score -= 12

    # ── POLICY / PROCEDURE ────────────────────────────────────────────────────
    elif doc_type in ('policy', 'procedure'):
        required_sections = (
            ['الغرض', 'النطاق', 'المسؤوليات'] if lang == 'ar'
            else ['Purpose', 'Scope', 'Responsibilities']
        )
        missing = [s for s in required_sections if s.lower() not in content_lower]
        if missing:
            issues.append(f'Missing required sections: {", ".join(missing)}')
            score -= len(missing) * 12
        if len(content.strip()) < 800:
            issues.append('Policy/procedure content too short (<800 chars)')
            score -= 20
        # All tables must have real rows
        for hdrs, rows in tables:
            real = [r for r in rows if not _is_placeholder(r)]
            if not real and rows:
                issues.append(f'Policy table "{"|".join(hdrs[:3])}" is placeholder-only')
                score -= 10

    # ── AUDIT ─────────────────────────────────────────────────────────────────
    elif doc_type == 'audit':
        required = (
            ['نطاق', 'النتائج', 'التوصيات'] if lang == 'ar'
            else ['scope', 'findings', 'recommendations']
        )
        missing = [s for s in required if s not in content_lower]
        if missing:
            issues.append(f'Audit missing required sections: {", ".join(missing)}')
            score -= len(missing) * 12
        for hdrs, rows in tables:
            real = [r for r in rows if not _is_placeholder(r)]
            if not real and rows:
                issues.append(f'Audit table "{"|".join(hdrs[:3])}" is placeholder-only')
                score -= 10
        if len(content.strip()) < 1000:
            issues.append('Audit content too short (<1000 chars)')
            score -= 20

    # ── RISK ASSESSMENT ───────────────────────────────────────────────────────
    elif doc_type == 'risk':
        has_likelihood = any(
            any(kw in h.lower() for h in hdrs for kw in ('likelihood', 'احتمالية'))
            for hdrs, _ in tables
        )
        has_impact = any(
            any(kw in h.lower() for h in hdrs for kw in ('impact', 'تأثير'))
            for hdrs, _ in tables
        )
        has_mitigation = any(
            any(kw in h.lower() for h in hdrs for kw in ('mitigation', 'treatment', 'معالجة'))
            for hdrs, _ in tables
        )
        if not has_likelihood:
            issues.append('Risk document missing Likelihood column')
            score -= 20
        if not has_impact:
            issues.append('Risk document missing Impact column')
            score -= 20
        if not has_mitigation:
            issues.append('Risk document missing Mitigation/Treatment column')
            score -= 15
        if len(content.strip()) < 500:
            issues.append('Risk analysis too short (<500 chars)')
            score -= 20
        # Each risk row must have owner
        for hdrs, rows in tables:
            hdrs_norm = [_norm(h) for h in hdrs]
            if any(kw in ' '.join(hdrs_norm) for kw in ('likelihood', 'احتمالية')):
                real = [r for r in rows if not _is_placeholder(r)]
                for row in real:
                    if len(row) < 4:
                        issues.append('Risk table row missing required fields (need ≥4 columns)')
                        score -= 8; break

    # ── UNIVERSAL CHECKS (all doc types) ─────────────────────────────────────
    # Unfilled bracket placeholders
    bracket_count = len(_re_v.findall(
        r'\[(?:insert|placeholder|TBD|TODO|add here|أضف)[^\]]*\]',
        content, _re_v.IGNORECASE))
    if bracket_count:
        issues.append(f'{bracket_count} unfilled placeholder(s) detected in document body')
        score -= min(bracket_count * 5, 30)

    # Empty section headings
    hdg_re = _re_v.compile(r'^#{1,4}\s+\S', _re_v.MULTILINE)
    hdg_positions = [m.start() for m in hdg_re.finditer(content)]
    for idx in range(len(hdg_positions) - 1):
        section_text = content[hdg_positions[idx]:hdg_positions[idx+1]].strip()
        if len(section_text) < 60:
            issues.append('Empty or near-empty section heading detected')
            score -= 8; break

    score = max(0, min(100, score))
    return {'valid': len(issues) == 0, 'issues': issues, 'score': score}


@app.route('/api/validate-document', methods=['POST'])
@login_required
def api_validate_document():
    """Universal structural validation for any document type."""
    try:
        data = request.get_json()
        doc_type = data.get('doc_type', 'strategy')
        content  = data.get('content', '')
        lang     = data.get('language', 'en')
        artifact_id = data.get('artifact_id')

        if not content or len(content.strip()) < 50:
            return jsonify({'valid': False, 'issues': ['No content provided'], 'score': 0})

        result = _validate_document_any_type(content, doc_type, lang)

        # Persist publishability verdict
        if artifact_id:
            table = _DOC_TABLE_MAP.get(doc_type, 'strategies')
            conn = get_db()
            conn.execute(
                f'UPDATE {table} SET publishability_score=?, artifact_status=? WHERE id=? AND user_id=?',
                (result['score'],
                 'publishable' if result['valid'] and result['score'] >= 70 else 'reviewed',
                 artifact_id, session['user_id'])
            )
            conn.execute(
                '''INSERT INTO publishability_verdicts
                   (user_id, artifact_type, artifact_id, overall_score, gate_passed,
                    blocking_issues, recommendation)
                   VALUES (?,?,?,?,?,?,?)''',
                (session['user_id'], doc_type, artifact_id, result['score'],
                 1 if result['valid'] else 0,
                 json.dumps(result['issues'], ensure_ascii=False),
                 'publishable' if result['score'] >= 70 else 'management_review')
            )
            conn.commit()

        return jsonify({'success': True, **result})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/org-memory/full', methods=['GET'])
@login_required
def api_get_org_memory_full():
    """Return enriched org memory including v2 fields."""
    domain = request.args.get('domain', 'Cyber Security')
    conn = get_db()
    row = conn.execute('SELECT * FROM org_memory WHERE user_id=? AND domain=?',
                       (session['user_id'], domain)).fetchone()
    if not row:
        return jsonify({'success': True, 'memory': None})
    d = dict(row)
    for f in ('preferred_frameworks', 'approved_roles', 'approved_committees',
              'recurring_risks', 'approved_decisions', 'stakeholder_objections',
              'unresolved_issues', 'prior_artifact_outcomes', 'publishability_history'):
        try:
            d[f] = json.loads(d[f]) if d[f] else []
        except Exception:
            d[f] = []
    return jsonify({'success': True, 'memory': d})


@app.route('/api/org-memory/full', methods=['POST'])
@login_required
def api_save_org_memory_full():
    """Save enriched org memory including v2 advisory fields."""
    try:
        data = request.get_json()
        domain = data.get('domain', 'Cyber Security')
        conn = get_db()

        def _j(v):
            return json.dumps(v, ensure_ascii=False) if isinstance(v, (list, dict)) else v

        conn.execute(
            '''INSERT INTO org_memory
               (user_id, domain, org_name, sector, risk_appetite,
                preferred_frameworks, approved_roles, approved_committees,
                key_constraints, terminology_notes,
                operating_model, governance_model, preferred_doc_style,
                recurring_risks, approved_decisions, stakeholder_objections,
                unresolved_issues, prior_artifact_outcomes, publishability_history,
                updated_at)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,CURRENT_TIMESTAMP)
               ON CONFLICT(user_id, domain) DO UPDATE SET
                 org_name=excluded.org_name, sector=excluded.sector,
                 risk_appetite=excluded.risk_appetite,
                 preferred_frameworks=excluded.preferred_frameworks,
                 approved_roles=excluded.approved_roles,
                 approved_committees=excluded.approved_committees,
                 key_constraints=excluded.key_constraints,
                 terminology_notes=excluded.terminology_notes,
                 operating_model=excluded.operating_model,
                 governance_model=excluded.governance_model,
                 preferred_doc_style=excluded.preferred_doc_style,
                 recurring_risks=excluded.recurring_risks,
                 approved_decisions=excluded.approved_decisions,
                 stakeholder_objections=excluded.stakeholder_objections,
                 unresolved_issues=excluded.unresolved_issues,
                 prior_artifact_outcomes=excluded.prior_artifact_outcomes,
                 publishability_history=excluded.publishability_history,
                 updated_at=CURRENT_TIMESTAMP''',
            (session['user_id'], domain,
             data.get('org_name'), data.get('sector'), data.get('risk_appetite'),
             _j(data.get('preferred_frameworks', [])),
             _j(data.get('approved_roles', [])),
             _j(data.get('approved_committees', [])),
             data.get('key_constraints'), data.get('terminology_notes'),
             data.get('operating_model'), data.get('governance_model'),
             data.get('preferred_doc_style', 'Big4'),
             _j(data.get('recurring_risks', [])),
             _j(data.get('approved_decisions', [])),
             _j(data.get('stakeholder_objections', [])),
             _j(data.get('unresolved_issues', [])),
             _j(data.get('prior_artifact_outcomes', [])),
             _j(data.get('publishability_history', [])))
        )
        conn.commit()
        log_action(session['user_id'], 'save_org_memory_v2', {'domain': domain})
        return jsonify({'success': True})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


