# ── Traceability auto-capture after strategy generation ───────────────────────
def _auto_capture_traceability(user_id, strategy_id, data, sections, diagnostic_id, generation_mode):
    """Persist a traceability record for a newly generated strategy.

    Captures: frameworks, org inputs, gap/KPI names, roadmap action names,
    inferred assumptions, unresolved ambiguities, and evidence level derived
    from generation mode.
    """
    try:
        frameworks = data.get('frameworks', [])
        org_inputs = {
            'org_name':     data.get('org_name'),
            'sector':       data.get('sector'),
            'maturity':     data.get('maturity_level'),
            'size':         data.get('size'),
            'technologies': data.get('technologies', []),
            'domain':       data.get('domain'),
        }
        gaps_section    = sections.get('gaps', '')
        kpis_section    = sections.get('kpis', '')
        roadmap_section = sections.get('roadmap', '')
        risks_section   = sections.get('confidence', '')  # confidence has key risks table

        import re as _re_tr
        gap_names     = _re_tr.findall(r'\|\s*\d+\s*\|\s*([^|]{5,60})\s*\|', gaps_section)[:8]
        kpi_names     = _re_tr.findall(r'\|\s*\d+\s*\|\s*([^|]{5,60})\s*\|', kpis_section)[:6]
        roadmap_names = _re_tr.findall(r'\|\s*\d+\s*\|\s*([^|]{5,80})\s*\|', roadmap_section)[:8]
        risk_names    = _re_tr.findall(r'\|\s*\d+\s*\|\s*([^|]{5,80})\s*\|', risks_section)[:6]

        evidence_level = (
            'high'   if generation_mode == 'assurance' else
            'medium' if generation_mode == 'consulting' else
            'low'
        )

        assumptions = [
            'Maturity self-assessment may not reflect actual control implementation',
            'Budget allocation may change after strategy approval',
            'Technology landscape assumed stable for strategy horizon',
        ]
        ambiguities = [
            'Exact resource availability for roadmap execution unconfirmed',
            'Regulatory timelines subject to change',
        ]
        # Enrich ambiguities from diagnostic if available
        if diagnostic_id:
            try:
                _dc = get_db_direct()
                _diag = _dc.execute(
                    'SELECT key_unknowns FROM diagnostic_sessions WHERE id=? AND user_id=?',
                    (diagnostic_id, user_id)
                ).fetchone()
                if _diag and _diag['key_unknowns']:
                    _unkn = json.loads(_diag['key_unknowns'] or '[]')
                    ambiguities = (_unkn[:4] + ambiguities)[:6]
                _dc.close()
            except Exception:
                pass

        conn = get_db_direct()
        conn.execute(
            '''INSERT INTO traceability_records
               (user_id, artifact_type, artifact_id, section_key,
                source_frameworks, source_diagnostic_id, inferred_assumptions,
                user_inputs_used, unresolved_ambiguities, evidence_sufficiency,
                linked_gaps, linked_kpis, linked_roadmap_tasks, linked_risks)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)''',
            (user_id, 'strategy', strategy_id, 'full',
             json.dumps(frameworks,     ensure_ascii=False),
             diagnostic_id,
             json.dumps(assumptions,    ensure_ascii=False),
             json.dumps(org_inputs,     ensure_ascii=False),
             json.dumps(ambiguities,    ensure_ascii=False),
             evidence_level,
             json.dumps(gap_names,      ensure_ascii=False),
             json.dumps(kpi_names,      ensure_ascii=False),
             json.dumps(roadmap_names,  ensure_ascii=False),
             json.dumps(risk_names,     ensure_ascii=False))
        )
        conn.commit(); conn.close()
        print(f'[TRACEABILITY] Captured for strategy {strategy_id} (mode={generation_mode})', flush=True)
    except Exception as _te:
        print(f"[TRACEABILITY] Auto-capture error (non-fatal): {_te}", flush=True)
