# ============================================================================
# ── PHASE 4: FAIL-CLOSED FINAL LAYER ─────────────────────────────────────
# Repair Engine · State Enforcement · Memory Reuse · Universal Traceability
# ============================================================================

def _repair_and_revalidate(content: str, doc_type: str, lang: str) -> tuple:
    """Attempt targeted repair of common structural problems, then re-validate.

    Returns (repaired_content, validation_result_dict).
    If repair is impossible, returns (original_content, failed_result).
    This is the last line of defence before save/export is blocked.
    """
    import re as _re_r

    # ── Pass 1: Remove orphan headings (heading immediately followed by another heading) ──
    lines = content.split('\n')
    cleaned = []
    i = 0
    while i < len(lines):
        ln = lines[i]
        if _re_r.match(r'^#{1,4}\s+\S', ln):
            # Check if next non-empty line is also a heading
            j = i + 1
            while j < len(lines) and not lines[j].strip():
                j += 1
            if j < len(lines) and _re_r.match(r'^#{1,4}\s+\S', lines[j]):
                # Orphan heading — skip it
                i += 1
                continue
        cleaned.append(ln)
        i += 1
    content = '\n'.join(cleaned)

    # ── Pass 2: Remove unfilled placeholder cells in tables ────────────────────
    def _clean_table_row(line):
        if not line.strip().startswith('|'):
            return line
        cells = line.strip().strip('|').split('|')
        cleaned_cells = []
        for cell in cells:
            c = cell.strip()
            # Replace empty bracket placeholders with em-dash
            if _re_r.match(r'^\[(?:insert|placeholder|TBD|TODO|add here)[^\]]*\]$', c, _re_r.IGNORECASE):
                cleaned_cells.append(' — ')
            else:
                cleaned_cells.append(cell)
        return '| ' + ' | '.join(cleaned_cells).strip() + ' |'

    content = '\n'.join(_clean_table_row(l) for l in content.split('\n'))

    # ── Pass 3: Remove lines that are pure separator noise ─────────────────────
    content = _re_r.sub(r'\n{4,}', '\n\n\n', content)

    # ── Re-validate after repair ────────────────────────────────────────────────
    result = _validate_document_any_type(content, doc_type, lang)
    return content, result


# ── api_artifact_status: enforce score requirement before state upgrade ───────
# Override: add score enforcement to the existing PATCH endpoint
_ORIG_ARTIFACT_STATUS_ROUTE = None  # sentinel — prevents re-registration


def _check_state_transition(new_status: str, current_score, current_status: str) -> tuple:
    """Return (allowed: bool, reason: str) for a state transition.

    Enforced rules (fail-closed — any unmatched path is blocked):
    - * → draft:                        always allowed (regression / reset)
    - * → rejected / requires_*:       always allowed (blocking states)
    - draft → reviewed:                always allowed (no score required)
    - reviewed → publishable:          requires score ≥ 60
    - draft → publishable:             BLOCKED — must go through reviewed first
    - publishable → final:             requires score ≥ 70
    - reviewed → final:                BLOCKED — must reach publishable first
    - draft → final:                   BLOCKED
    - final → *:                       BLOCKED (final is terminal)
    """
    score = float(current_score or 0)

    # Terminal / always-allowed targets
    if new_status in ('draft', 'rejected', 'requires_consultant', 'requires_evidence'):
        return True, 'OK'

    # reviewed: only requires leaving draft/rejected/requires_* states
    if new_status == 'reviewed':
        if current_status == 'final':
            return False, 'Cannot revert a final artifact to reviewed.'
        return True, 'OK'

    # publishable: must already be reviewed AND score ≥ 60
    if new_status == 'publishable':
        if current_status == 'draft':
            return (False,
                    'Cannot mark publishable from draft — run Quality Review first '
                    '(document must reach "reviewed" state before "publishable").')
        if current_status not in ('reviewed', 'publishable'):
            return (False,
                    f'Cannot mark publishable from "{current_status}". '
                    'Resolve outstanding issues, then run Quality Review.')
        if score < 60:
            return (False,
                    f'Cannot mark publishable — review score {score:.0f}% is below '
                    'the 60% minimum. Re-run Quality Review and address issues.')
        return True, 'OK'

    # final: must be publishable AND score ≥ 70
    if new_status == 'final':
        if current_status != 'publishable':
            return (False,
                    f'Cannot mark final from "{current_status}" — '
                    'document must be in "publishable" state first '
                    '(requires Quality Review with score ≥ 70%).')
        if score < 70:
            return (False,
                    f'Cannot mark final — review score {score:.0f}% is below '
                    'the 70% required for final state. Improve and re-review.')
        return True, 'OK'

    # Catch-all: unknown target state
    return False, f'Unknown target state "{new_status}" — transition blocked.'


# Patch api_artifact_status to enforce transitions
# (We monkey-patch by replacing the route handler after definition)
_orig_api_artifact_status = app.view_functions.get('api_artifact_status')
if _orig_api_artifact_status:
    @app.route('/api/artifact-status-v2', methods=['PATCH'])
    @login_required
    def api_artifact_status_enforced():
        """State-transition-enforcing version of artifact status update."""
        try:
            data = request.get_json()
            artifact_type = data.get('artifact_type', 'strategy')
            artifact_id   = data.get('artifact_id')
            new_status    = data.get('status', 'draft')
            notes         = data.get('notes', '')

            if new_status not in _VALID_STATES:
                return jsonify({'success': False, 'error': f'Invalid status: {new_status}'}), 400

            table = _DOC_TABLE_MAP.get(artifact_type)
            if not table:
                return jsonify({'success': False, 'error': f'Unknown type: {artifact_type}'}), 400

            conn = get_db()
            row = conn.execute(
                f'SELECT id, artifact_status, publishability_score FROM {table} WHERE id=? AND user_id=?',
                (artifact_id, session['user_id'])
            ).fetchone()
            if not row:
                return jsonify({'success': False, 'error': 'Artifact not found'}), 404

            current_status = row['artifact_status'] or 'draft'
            current_score  = row['publishability_score'] or 0

            # Enforce transition rules
            allowed, reason = _check_state_transition(new_status, current_score, current_status)
            if not allowed:
                return jsonify({'success': False, 'error': reason, 'blocked': True}), 422

            conn.execute(
                f'UPDATE {table} SET artifact_status=?, reviewer_notes=? WHERE id=? AND user_id=?',
                (new_status, notes, artifact_id, session['user_id'])
            )
            conn.commit()
            log_action(session['user_id'], 'update_artifact_status',
                       {'type': artifact_type, 'id': artifact_id, 'status': new_status})
            return jsonify({'success': True, 'status': new_status, 'previous': current_status})
        except Exception as e:
            return jsonify({'success': False, 'error': str(e)}), 500


# ── Org memory injection into strategy generation context ─────────────────────
def _get_org_memory_context(user_id: int, domain: str, lang: str = 'en') -> str:
    """Pull org memory and format as strategy prompt enrichment block.
    Returns empty string if no memory found."""
    try:
        conn = get_db()
        mem = conn.execute(
            '''SELECT org_name, sector, risk_appetite, governance_model, operating_model,
                      approved_roles, approved_committees, key_constraints, terminology_notes,
                      recurring_risks, approved_decisions, stakeholder_objections, unresolved_issues
               FROM org_memory WHERE user_id=? AND domain=?''',
            (user_id, domain)
        ).fetchone()
        if not mem:
            return ''
        parts = []
        if mem['org_name']:          parts.append(f"Organisation: {mem['org_name']}")
        if mem['sector']:            parts.append(f"Sector: {mem['sector']}")
        if mem['risk_appetite']:     parts.append(f"Risk Appetite: {mem['risk_appetite']}")
        if mem['governance_model']:  parts.append(f"Governance Model: {mem['governance_model']}")
        if mem['operating_model']:   parts.append(f"Operating Model: {mem['operating_model']}")
        if mem['key_constraints']:   parts.append(f"Known Constraints: {mem['key_constraints']}")
        if mem['terminology_notes']: parts.append(f"Approved Terminology: {mem['terminology_notes']}")
        for field, label in [
            ('approved_roles',        'Approved Roles'),
            ('approved_committees',   'Approved Committees'),
            ('approved_decisions',    'Prior Approved Decisions'),
            ('recurring_risks',       'Known Recurring Risks'),
            ('stakeholder_objections','Known Stakeholder Objections'),
            ('unresolved_issues',     'Unresolved Issues'),
        ]:
            try:
                val = json.loads(mem[field] or '[]') if mem[field] else []
                if val:
                    parts.append(f"{label}: {'; '.join(str(v) for v in val[:4])}")
            except Exception:
                pass
        if not parts:
            return ''
        header = 'سياق المنظمة من الذاكرة المؤسسية' if lang == 'ar' else 'ORGANISATION MEMORY CONTEXT'
        footer = ('استخدم هذه المصطلحات والأدوار ومتطلبات الحوكمة في جميع أنحاء الوثيقة — '
                  'لا تتناقض مع القرارات المعتمدة المذكورة أعلاه.' if lang == 'ar' else
                  'Use these terms, roles, governance requirements, and decisions throughout — '
                  'do not contradict prior approved decisions listed above.')
        return f"\n\n{'='*40}\n{header}:\n" + '\n'.join(parts) + f"\n{footer}\n{'='*40}\n"
    except Exception as _e:
        print(f"[ORG-MEMORY] context load (non-fatal): {_e}", flush=True)
        return ''


