@app.route('/api/review-document-v2', methods=['POST'])
@login_required
def api_review_document_v2():
    """Review endpoint upgraded with org memory + traceability context."""
    try:
        data = request.get_json()
        doc_type   = data.get('doc_type', 'strategy')
        content    = data.get('content', '')
        domain     = data.get('domain', 'Cyber Security')
        sector     = data.get('sector', 'Government')
        org_name   = data.get('org_name', 'The Organization')
        lang       = data.get('language', 'en')
        doc_id     = data.get('doc_id')

        if not content or len(content.strip()) < 200:
            return jsonify({'success': False, 'error': 'Insufficient content for review'}), 400

        # Pull org memory for review context
        mem_ctx = _get_org_memory_context(session['user_id'], domain, lang)

        # Pull evidence gaps and unresolved issues for this artifact
        evidence_ctx = ''
        if doc_id:
            try:
                conn = get_db()
                gaps = conn.execute(
                    'SELECT gap_title, severity FROM evidence_gaps WHERE user_id=? AND artifact_type=? AND artifact_id=? AND resolution_status="open"',
                    (session['user_id'], doc_type, doc_id)
                ).fetchall()
                if gaps:
                    gap_list = '; '.join(f"{g['gap_title']} [{g['severity']}]" for g in gaps[:5])
                    evidence_ctx = f"\nKNOWN EVIDENCE GAPS (must factor into review): {gap_list}\n"
            except Exception:
                pass

        review_prompt = (
            f"You are a Big4 senior partner conducting a quality gate review of a {doc_type} document.\n"
            f"Organisation: {org_name} | Domain: {domain} | Sector: {sector}\n"
            f"{mem_ctx}{evidence_ctx}\n"
            f"Document excerpt (first 3000 chars):\n{content[:3000]}\n\n"
            "Assess these dimensions (0-100 each):\n"
            "1. Strategic coherence\n2. Consulting tone\n3. Executive relevance\n"
            "4. Implementation realism\n5. KPI measurability\n"
            "6. Regulatory mapping\n7. Completeness\n8. Table integrity\n\n"
            "If org memory specifies approved terminology or roles, penalise deviations.\n"
            "If evidence gaps exist, penalise sections that do not acknowledge them.\n\n"
            "Return ONLY valid JSON:\n"
            '{"overall_score":75,"dimension_scores":{"strategic_coherence":80},'
            '"issues":[{"severity":"high","section":"KPIs","issue":"...","suggestion":"..."}],'
            '"recommendation":"management_review","publishability":"conditional","summary":"..."}'
        )

        raw = generate_ai_content(review_prompt, language='en', task_type='review', content_type='review')
        import re as _re_rv
        raw = _re_rv.sub(r'^```(?:json)?\s*|\s*```$', '', raw.strip(), flags=_re_rv.MULTILINE).strip()
        try:
            result = json.loads(raw)
        except Exception:
            result = {'overall_score': 60, 'dimension_scores': {}, 'issues': [],
                      'recommendation': 'management_review', 'publishability': 'conditional',
                      'summary': raw[:400] if raw else 'Review could not be parsed.'}

        score  = result.get('overall_score', 60)
        passed = 1 if score >= 70 else 0

        # Persist review verdict + update artifact status
        conn = get_db()
        conn.execute(
            '''INSERT INTO document_reviews
               (user_id, doc_type, doc_id, domain, publishability_score, quality_issues,
                recommendation, passed)
               VALUES (?,?,?,?,?,?,?,?)''',
            (session['user_id'], doc_type, doc_id, domain, score,
             json.dumps(result.get('issues', []), ensure_ascii=False),
             result.get('recommendation', 'management_review'), passed)
        )
        if doc_id:
            table = _DOC_TABLE_MAP.get(doc_type, 'strategies')
            new_status = 'publishable' if score >= 70 else ('reviewed' if score >= 50 else 'draft')
            conn.execute(
                f'UPDATE {table} SET publishability_score=?, artifact_status=? WHERE id=? AND user_id=?',
                (score, new_status, doc_id, session['user_id'])
            )
        conn.commit()
        return jsonify({'success': True, **result})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


# ── Upgraded handoff pack — pulls from all evidence sources ──────────────────
# (Replaces the body of api_handoff_pack at line 25775)
# We add a helper that enriches the context before generation


def _build_handoff_context(user_id: int, domain: str, diagnostic_id,
                            artifact_type: str, artifact_id) -> dict:
    """Pull all evidence sources for handoff pack generation."""
    ctx = {
        'diagnostic': '', 'org_memory': '', 'traceability': '',
        'review_findings': '', 'evidence_gaps': '', 'unresolved_issues': ''
    }
    try:
        conn = get_db()

        # Diagnostic session
        if diagnostic_id:
            diag = conn.execute(
                'SELECT summary, confidence_score, key_gaps, key_assumptions, key_unknowns, missing_evidence '
                'FROM diagnostic_sessions WHERE id=? AND user_id=?',
                (diagnostic_id, user_id)
            ).fetchone()
            if diag:
                ctx['diagnostic'] = (
                    f"DIAGNOSTIC SUMMARY: {diag['summary']}\n"
                    f"Confidence: {diag['confidence_score']}%\n"
                    f"Key Gaps: {diag['key_gaps']}\n"
                    f"Assumptions: {diag['key_assumptions']}\n"
                    f"Unknowns: {diag['key_unknowns']}\n"
                    f"Missing Evidence: {diag['missing_evidence']}\n"
                )

        # Org memory
        mem = conn.execute(
            'SELECT risk_appetite, key_constraints, unresolved_issues, recurring_risks, '
            'stakeholder_objections, governance_model FROM org_memory WHERE user_id=? AND domain=?',
            (user_id, domain)
        ).fetchone()
        if mem:
            parts = []
            if mem['risk_appetite']:       parts.append(f"Risk Appetite: {mem['risk_appetite']}")
            if mem['governance_model']:    parts.append(f"Governance: {mem['governance_model']}")
            if mem['key_constraints']:     parts.append(f"Constraints: {mem['key_constraints']}")
            try:
                issues = json.loads(mem['unresolved_issues'] or '[]')
                if issues: parts.append(f"Unresolved Issues: {'; '.join(str(i) for i in issues[:4])}")
                risks = json.loads(mem['recurring_risks'] or '[]')
                if risks: parts.append(f"Recurring Risks: {'; '.join(str(r) for r in risks[:4])}")
                obj = json.loads(mem['stakeholder_objections'] or '[]')
                if obj: parts.append(f"Stakeholder Objections: {'; '.join(str(o) for o in obj[:3])}")
            except Exception:
                pass
            ctx['org_memory'] = '\n'.join(parts)

        # Traceability
        if artifact_id and artifact_type:
            tr_rows = conn.execute(
                'SELECT evidence_sufficiency, inferred_assumptions, unresolved_ambiguities, '
                'linked_gaps, linked_risks, source_frameworks '
                'FROM traceability_records WHERE user_id=? AND artifact_type=? AND artifact_id=?',
                (user_id, artifact_type, artifact_id)
            ).fetchall()
            if tr_rows:
                tr_parts = []
                for r in tr_rows:
                    tr_parts.append(f"Evidence Level: {r['evidence_sufficiency']}")
                    try:
                        ambig = json.loads(r['unresolved_ambiguities'] or '[]')
                        if ambig: tr_parts.append(f"Ambiguities: {'; '.join(str(a) for a in ambig[:3])}")
                    except Exception:
                        pass
                ctx['traceability'] = '\n'.join(tr_parts)

        # Latest review findings
        if artifact_id and artifact_type:
            review = conn.execute(
                'SELECT publishability_score, quality_issues, recommendation FROM document_reviews '
                'WHERE user_id=? AND doc_type=? AND doc_id=? ORDER BY reviewed_at DESC LIMIT 1',
                (user_id, artifact_type, artifact_id)
            ).fetchone()
            if review:
                try:
                    issues = json.loads(review['quality_issues'] or '[]')
                    issue_strs = [f"{i.get('section','?')}: {i.get('issue','?')}" for i in issues[:5]]
                    ctx['review_findings'] = (
                        f"Last Review Score: {review['publishability_score']}% | "
                        f"Recommendation: {review['recommendation']}\n"
                        f"Issues: {'; '.join(issue_strs)}"
                    )
                except Exception:
                    ctx['review_findings'] = f"Score: {review['publishability_score']}% | {review['recommendation']}"

        # Evidence gaps
        if artifact_id and artifact_type:
            eg_rows = conn.execute(
                'SELECT gap_title, severity, regulatory_reference FROM evidence_gaps '
                'WHERE user_id=? AND artifact_type=? AND artifact_id=? AND resolution_status="open"',
                (user_id, artifact_type, artifact_id)
            ).fetchall()
            if eg_rows:
                ctx['evidence_gaps'] = '; '.join(
                    f"{g['gap_title']} [{g['severity']}]" for g in eg_rows[:6]
                )

    except Exception as _e:
        print(f"[HANDOFF-CTX] Error (non-fatal): {_e}", flush=True)

    return ctx



