def _build_audit_prompt(data, user_id):
    """Build audit prompt. File content must already be extracted and stored in data['_file_text']."""
    lang         = data.get('language', 'en')
    domain       = data.get('domain', 'Cyber Security')
    framework    = data.get('framework', 'NCA ECC')
    audit_scope  = data.get('audit_scope', 'full')
    audit_topic  = data.get('audit_topic', '').strip()
    policy_text  = data.get('policy_content', '').strip()
    file_text    = data.get('_file_text', '').strip()

    document_to_audit = policy_text or file_text or ''
