@app.route('/api/generate-audit-async', methods=['POST'])
@login_required
def api_generate_audit_async():
    """Start async audit generation. Reads file uploads synchronously, then spawns worker."""
    import uuid as _uuid_aa

    _rl_ok, _rl_retry = check_generation_rate_limit('audit')
    if not _rl_ok:
        return jsonify({
            'success': False,
            'error': 'Too many generation requests. Please wait a moment and try again.',
            'retry_after': _rl_retry,
        }), 429

    domain      = request.form.get('domain', 'Cyber Security')
    framework   = request.form.get('framework', 'NCA ECC')
    lang        = request.form.get('language', 'en')
    audit_scope = request.form.get('audit_scope', 'full')
    audit_topic = request.form.get('audit_topic', '')
    policy_text = request.form.get('policy_content', '')

    can_gen, used, limit = check_usage_limit(session['user_id'], 'audits', domain)
    if not can_gen:
        return jsonify({
            'success': False, 'limit_reached': True,
            'error': f'Limit reached for {domain}: {used}/{limit} audits used.'
        }), 429

    # Read file uploads synchronously before thread spawn (Werkzeug file objects aren't thread-safe)
    file_text = ''
    try:
        evidence_files = request.files.getlist('evidence')
        for f in evidence_files:
            if not f or not f.filename:
                continue
            try:
                if f.filename.lower().endswith('.pdf'):
                    import io as _io_aa
                    pdf_bytes = f.read()
                    try:
                        import fitz
                        doc = fitz.open(stream=pdf_bytes, filetype='pdf')
                        txt = ''.join(page.get_text() for page in doc)
                        doc.close()
                        if txt.strip():
                            file_text += f'\n--- {f.filename} ---\n{txt[:5000]}\n'
                    except Exception:
                        try:
                            from PyPDF2 import PdfReader
                            reader = PdfReader(_io_aa.BytesIO(pdf_bytes))
                            txt = ''.join((p.extract_text() or '') for p in reader.pages)
                            if txt.strip():
                                file_text += f'\n--- {f.filename} ---\n{txt[:5000]}\n'
                        except Exception:
                            pass
                elif f.filename.lower().endswith(('.txt', '.md', '.csv')):
                    txt = f.read().decode('utf-8', errors='ignore')
                    if txt.strip():
                        file_text += f'\n--- {f.filename} ---\n{txt[:5000]}\n'
            except Exception as _fe:
                print(f'[AUDIT-ASYNC] file read (non-fatal): {_fe}', flush=True)
    except Exception:
        pass

    job_data = {
        'domain': domain, 'language': lang, 'framework': framework,
        'audit_scope': audit_scope, 'audit_topic': audit_topic,
        'policy_content': policy_text, '_file_text': file_text,
    }
    job_data['_prompt'] = _build_audit_prompt(job_data, session['user_id'])

    task_id = str(_uuid_aa.uuid4())
    create_background_task(task_id, session['user_id'], domain)
    import threading as _thr_aa
    t = _thr_aa.Thread(target=_run_audit_generation_task,
                       args=(task_id, session['user_id'], job_data), daemon=True)
    t.start()
    print(f'[AUDIT-ASYNC] task {task_id[:8]} started — domain={domain!r}', flush=True)
    return jsonify({'task_id': task_id})


@app.route('/api/audit-status/<task_id>')
@login_required
def api_audit_status(task_id):
    """Poll audit task status."""
    task = get_background_task(task_id)
    if not task:
        return jsonify({'status': 'not_found'}), 404
    if task['status'] == 'done':
        try:
            result = _json_async.loads(task['result'])
        except Exception:
            result = {'success': False, 'error': 'Result parse error'}
        audit_id = result.get('audit_id')
        if audit_id:
            try:
                conn = get_db_direct()
                row = conn.execute(
                    'SELECT content, language, artifact_status, publishability_score '
                    'FROM audits WHERE id=? AND user_id=?',
                    (audit_id, task['user_id'])
                ).fetchone()
                conn.close()
                if row:
                    result['content']              = row['content']
                    result['language']             = row['language']
                    result['artifact_status']      = row['artifact_status']
                    result['publishability_score'] = row['publishability_score']
            except Exception as _re:
                print(f'[AUDIT-STATUS] DB reload (non-fatal): {_re}', flush=True)
        return jsonify({'status': 'done', 'result': result})
    if task['status'] == 'error':
        return jsonify({'status': 'error', 'error': task['error'] or 'Unknown'}), 500
    return jsonify({'status': 'pending'})


