def _run_risk_generation_task(task_id, user_id, data):
    """Background worker: generate + repair + save risk analysis."""
    try:
        lang       = data.get('language', 'en')
        domain     = data.get('domain', 'Cyber Security')
        asset      = data.get('asset', '')
        threat     = data.get('threat', '')
        category   = data.get('category', 'Operational')
        risk_level = data.get('_risk_level', 'HIGH')
        prompt     = data.get('_prompt', '')

        if not prompt:
            fail_background_task(task_id, 'Prompt missing — async job cannot proceed')
            return

        content = generate_ai_content(prompt, lang, content_type='risk')
        try:
            content = ensure_markdown_formatting(content)
        except Exception:
            pass
        content, val = _repair_and_revalidate(content, 'risk', lang)

        risk_id = None
        try:
            conn = get_db_direct()
            conn.execute(
                '''INSERT INTO risks
                   (user_id, domain, asset_name, threat, risk_level, analysis,
                    language, artifact_status, publishability_score)
                   VALUES (?,?,?,?,?,?,?,?,?)''',
                (user_id, domain, asset, threat, risk_level, content, lang,
                 'reviewed' if val['valid'] else 'draft', val['score'])
            )
            conn.commit()
            risk_id = conn.execute('SELECT last_insert_rowid()').fetchone()[0]

            if risk_id:
                try:
                    conn.execute(
                        '''INSERT INTO traceability_records
                           (user_id, artifact_type, artifact_id, section_key,
                            source_frameworks, user_inputs_used,
                            evidence_sufficiency, unresolved_ambiguities)
                           VALUES (?,?,?,?,?,?,?,?)''',
                        (user_id, 'risk', risk_id, 'full',
                         _json_async.dumps([], ensure_ascii=False),
                         _json_async.dumps({'domain': domain, 'asset': asset,
                                            'threat': threat, 'risk_level': risk_level},
                                           ensure_ascii=False),
                         'medium' if val['valid'] else 'low',
                         _json_async.dumps(val['issues'], ensure_ascii=False))
                    )
                    conn.commit()
                except Exception as _te:
                    print(f'[RISK-ASYNC] traceability (non-fatal): {_te}', flush=True)
            conn.close()
        except Exception as dbe:
            print(f'[RISK-ASYNC] DB save error: {dbe}', flush=True)

        # Auto-create mitigation task for high-severity risks
        if risk_id and risk_level in ('CRITICAL', 'HIGH'):
            try:
                _score = 25 if risk_level == 'CRITICAL' else 16
                auto_create_mitigation_task(user_id, risk_id,
                                            f'{threat} → {asset}', _score, domain)
            except Exception:
                pass

        log_action(user_id, 'analyze_risk',
                   {'domain': domain, 'asset': asset, 'threat': threat,
                    'risk_level': risk_level, 'async': True})

        result = _json_async.dumps({
            'success': True,
            'risk_id': risk_id,
            'analysis': content,
            'risk_level': risk_level,
            'language': lang,
            'artifact_status': 'reviewed' if val['valid'] else 'draft',
            'publishability_score': val['score'],
            'validation_issues': val['issues'],
        }, ensure_ascii=False)
        complete_background_task(task_id, result)
        print(f'[RISK-ASYNC] task {task_id[:8]} done — risk_id={risk_id}', flush=True)

    except Exception as exc:
        print(f'[RISK-ASYNC] task {task_id[:8]} ERROR: {exc}\n{_tb_async.format_exc()}',
              flush=True)
        fail_background_task(task_id, str(exc))


def _classify_risk_level(data):
    """Derive risk level from likelihood/impact or explicit field."""
    explicit = (data.get('risk_level') or '').upper()
    if explicit in ('CRITICAL', 'HIGH', 'MEDIUM', 'LOW'):
        return explicit
    try:
        likelihood = float(data.get('likelihood', 3))
        impact     = float(data.get('impact', 3))
        score      = likelihood * impact
        if score >= 20:  return 'CRITICAL'
        if score >= 12:  return 'HIGH'
        if score >= 6:   return 'MEDIUM'
        return 'LOW'
    except Exception:
        return 'HIGH'


def _build_risk_prompt(data):
    """Build risk analysis prompt (thread-safe, no Flask context needed)."""
    lang     = data.get('language', 'en')
    domain   = data.get('domain', 'Cyber Security')
    asset    = data.get('asset', 'Information System')
    threat   = data.get('threat', 'Unauthorized Access')
    category = data.get('category', 'Operational')
    context  = data.get('context', '')
    controls = data.get('existing_controls', '')
    risk_lvl = data.get('_risk_level', 'HIGH')

    if lang == 'ar':
        prompt = (
            f'أنت محلل مخاطر GRC متخصص. أجرِ تحليل مخاطر شاملاً.\n\n'
            f'الأصل: {asset}\nالتهديد: {threat}\nالفئة: {category}\n'
            f'مستوى الخطر الأولي: {risk_lvl}\n\n'
            f'أنشئ تقرير تحليل مخاطر بتنسيق Markdown يتضمن:\n'
            f'1. وصف السيناريو\n'
            f'2. جدول تقييم المخاطر (الاحتمالية | التأثير | الدرجة | الخطورة)\n'
            f'3. التأثير التجاري والتنظيمي\n'
            f'4. جدول استراتيجية المعالجة (الضابط | النوع | الأولوية | الجدول الزمني | المالك)\n'
            f'5. مقاييس KPI للمراقبة\n'
            f'6. توصيات التنفيذ الفوري\n'
            f'جميع الجداول يجب أن تحتوي على بيانات حقيقية. الحد الأدنى 1200 كلمة.'
        )
    else:
        context_clause = f'\nAdditional Context: {context}\n' if context else ''
        controls_clause = f'\nExisting Controls: {controls}\n' if controls else ''
        prompt = (
            f'You are a Big4-grade GRC risk analyst. Conduct a comprehensive risk analysis.\n\n'
            f'Asset: {asset}\nThreat: {threat}\nCategory: {category}\n'
            f'Domain: {domain}\nInitial Risk Level: {risk_lvl}\n'
            f'{context_clause}{controls_clause}\n'
            f'Produce a formal risk analysis report in Markdown with:\n'
            f'1. Threat Scenario Description\n'
            f'2. Risk Assessment Matrix (table: Likelihood | Impact | Score | Rating)\n'
            f'3. Business & Regulatory Impact Analysis\n'
            f'4. Treatment Strategy (table: Control | Type | Priority | Timeline | Owner)\n'
            f'5. Residual Risk after Controls\n'
            f'6. KPI / Monitoring Metrics (table)\n'
            f'7. Immediate Action Recommendations\n'
            f'All tables must have real populated rows. Minimum 1200 words.'
        )
    return prompt


@app.route('/api/generate-risk-async', methods=['POST'])
@login_required
def api_generate_risk_async():
    """Start async risk analysis. Returns {task_id} immediately."""
    import uuid as _uuid_ra
    data   = request.json or {}
    domain = data.get('domain', 'Cyber Security')

    _rl_ok, _rl_retry = check_generation_rate_limit('risk')
    if not _rl_ok:
        return jsonify({
            'success': False,
            'error': 'Too many generation requests. Please wait a moment and try again.',
            'retry_after': _rl_retry,
        }), 429

    can_gen, used, limit = check_usage_limit(session['user_id'], 'risks', domain)
    if not can_gen:
        return jsonify({
            'success': False, 'limit_reached': True,
            'error': f'Limit reached for {domain}: {used}/{limit} risk analyses used.'
        }), 429

    risk_level = _classify_risk_level(data)
    job_data = dict(data)
    job_data['_risk_level'] = risk_level
    job_data['_prompt']     = _build_risk_prompt(job_data)

    task_id = str(_uuid_ra.uuid4())
    create_background_task(task_id, session['user_id'], domain)
    import threading as _thr_ra
    t = _thr_ra.Thread(target=_run_risk_generation_task,
                       args=(task_id, session['user_id'], job_data), daemon=True)
    t.start()
    print(f'[RISK-ASYNC] task {task_id[:8]} started — domain={domain!r}', flush=True)
    return jsonify({'task_id': task_id})


